class Strategy_SELFISH_44(BaseStrategy):
    """
    Defect by default, and only switch to cooperation after observing two
    consecutive rounds in which every opponent cooperated. Immediately revert
    to defection after any round with less than full opponent cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = Action.D
        self.streak = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_opponents = max(0, self.game_description.n_players - 1)
        total_observed = history.round_number
        while self._processed_rounds < total_observed:
            x_t = int(history.opponent_cooperators[self._processed_rounds])
            if x_t >= n_opponents:
                self.streak += 1
                if self.streak >= 2:
                    self.mode = Action.C
            else:
                self.streak = 0
                self.mode = Action.D
            self._processed_rounds += 1
        if history.round_number == 0:
            return Action.D
        if self.mode == Action.C:
            return Action.C
        if self.streak >= 2:
            self.mode = Action.C
            return Action.C
        return Action.D

