class Strategy_SELFISH_49(BaseStrategy):
    """
    Defect by default.
    Cooperate only when recent opponent cooperation has been consistently high:
    - never cooperate in round 1 or the final round
    - in intermediate rounds, cooperate only if the last up to 3 observed opponent
      cooperation rates are all at least 0.75 and their recent average is at least 0.75
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._threshold = 0.75

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        num_opponents = max(1, n_players - 1)
        recent_counts = history.opponent_cooperators
        available = min(3, round_number)
        if available <= 0:
            return Action.D
        recent_rates = []
        for idx in range(round_number - available, round_number):
            h_t = int(recent_counts[idx])
            q_t = h_t / num_opponents
            recent_rates.append(q_t)
        for q_t in recent_rates:
            if q_t < self._threshold:
                return Action.D
        avg_q = sum(recent_rates) / len(recent_rates)
        if avg_q < self._threshold:
            return Action.D
        return Action.C

