class Strategy_SELFISH_55(BaseStrategy):
    """
    Defect by default. Cooperate only when opponent cooperation is strong,
    stable, and non-decreasing, and never in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._permanent_defect = False
        self._saw_cooperation_condition = False
        self._processed_rounds = 0

    def _cooperation_rate(self, opponent_cooperators: int) -> float:
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        return opponent_cooperators / n_opponents

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        start = self._processed_rounds
        end = current_round
        if start < end:
            for t in range(start, end):
                q_t = self._cooperation_rate(int(history.opponent_cooperators[t]))
                if self._saw_cooperation_condition and q_t < 0.5:
                    self._permanent_defect = True
                q_prev = q_t >= 2.0 / 3.0
                avg_window_start = max(0, t - 2)
                window = history.opponent_cooperators[avg_window_start:t + 1]
                if len(window) > 0:
                    avg_q = float(np.mean(window)) / max(1, self.game_description.n_players - 1)
                else:
                    avg_q = 0.0
                if q_prev and avg_q >= 2.0 / 3.0:
                    if t >= 1:
                        q_t_minus_1 = self._cooperation_rate(int(history.opponent_cooperators[t - 1]))
                        trend = q_t_minus_1 - self._cooperation_rate(int(history.opponent_cooperators[t - 2])) if t >= 2 else 0.0
                    else:
                        trend = 0.0
                    if trend >= 0:
                        self._saw_cooperation_condition = True
        self._processed_rounds = current_round
        if current_round == 0:
            return Action.D
        if current_round >= n_rounds - 1:
            return Action.D
        if self._permanent_defect:
            return Action.D
        last_q = self._cooperation_rate(int(history.opponent_cooperators[-1]))
        recent_count = min(3, current_round)
        recent_rates = [self._cooperation_rate(int(history.opponent_cooperators[i])) for i in range(current_round - recent_count, current_round)]
        avg_q = float(np.mean(recent_rates)) if recent_rates else 0.0
        trend = 0.0
        if current_round >= 2:
            q_t_minus_1 = self._cooperation_rate(int(history.opponent_cooperators[-1]))
            q_t_minus_2 = self._cooperation_rate(int(history.opponent_cooperators[-2]))
            trend = q_t_minus_1 - q_t_minus_2
        if last_q >= 2.0 / 3.0 and avg_q >= 2.0 / 3.0 and (trend >= 0.0):
            return Action.C
        return Action.D

class Strategy_SELFISH_56(BaseStrategy):
    """
    Defect by default; cooperate only in a stable, strongly cooperative regime,
    with a limited probe when cooperation is already high and there is enough
    time left to recover from any downside.
    """
    THETA_HIGH = 0.75
    THETA_LOW = 0.4
    L = 2
    ALPHA = 0.5

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n_players - 1)
        self.s_prev = 0.0
        self.u_prev = 0
        self.last_seen_share = 0.0
        self.last_processed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        completed_rounds = int(history.round_number)
        total_rounds = self.n_rounds
        current_t = completed_rounds + 1
        if completed_rounds == 0:
            self.s_prev = 0.0
            self.u_prev = 0
            self.last_seen_share = 0.0
            self.last_processed_rounds = 0
            return Action.D
        s = 0.0
        u = 0
        last_share = 0.0
        denom = float(self.n_opponents)
        if denom <= 0.0:
            denom = 1.0
        for idx in range(completed_rounds):
            m_t = int(history.opponent_cooperators[idx])
            share = m_t / denom
            last_share = share
            if share >= self.THETA_HIGH:
                u += 1
            else:
                u = 0
            s = self.ALPHA * share + (1.0 - self.ALPHA) * s
        self.s_prev = s
        self.u_prev = u
        self.last_seen_share = last_share
        self.last_processed_rounds = completed_rounds
        if current_t >= total_rounds:
            return Action.D
        if self.s_prev >= self.THETA_HIGH and self.u_prev >= self.L:
            return Action.C
        if self.s_prev <= self.THETA_LOW:
            return Action.D
        if total_rounds - current_t >= 3 and self.last_seen_share >= self.THETA_HIGH:
            return Action.C
        return Action.D

