class Strategy_SELFISH_63(BaseStrategy):
    """
    Conditional free-rider strategy:
    - Defect in the first round and in the final round.
    - In intermediate rounds, cooperate only when observed opponent cooperation
      is high enough to justify maintaining reciprocity for the remaining game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(self.n_players - 1, 0)
        self.k_over_n = self.k / self.n_players if self.n_players > 0 else 0.0
        self.immediate_gain_defect = 1.0 - self.k_over_n

    def __call__(self, history: PlayerHistory) -> Action:
        h = int(history.round_number)
        if h == 0:
            return Action.D
        if h >= self.n_rounds - 1:
            return Action.D
        if self.n_opponents <= 0:
            return Action.D
        total_observed_rounds = h
        if total_observed_rounds <= 0:
            return Action.D
        S = int(np.sum(history.opponent_cooperators[:h])) if h > 0 else 0
        denom = total_observed_rounds * self.n_opponents
        p = S / denom if denom > 0 else 0.0
        future_rounds_after_next = self.n_rounds - h - 1
        if future_rounds_after_next <= 0:
            return Action.D
        delta_future = p * self.k_over_n * future_rounds_after_next
        if delta_future > self.immediate_gain_defect:
            return Action.C
        return Action.D

