class Strategy_SELFISH_66(BaseStrategy):
    """
    Cooperate only in the middle rounds after observing unanimous cooperation
    from all opponents in every previously observed round. Defect immediately
    and permanently after any observed defection, and defect in the first and
    last rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.k = game_description.k
        self._permanent_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = self.n_rounds
        n_opponents = self.n_players - 1
        if round_number == 0:
            self._permanent_defect = False
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        if self._permanent_defect:
            return Action.D
        observed = history.opponent_cooperators
        if len(observed) == 0:
            return Action.D
        unanimous = True
        for c in observed:
            if int(c) < n_opponents:
                unanimous = False
                break
        if not unanimous:
            self._permanent_defect = True
            return Action.D
        recent = observed[-3:]
        if len(recent) == 0 or n_opponents <= 0:
            return Action.D
        q_values = [int(c) / n_opponents for c in recent]
        bar_q = sum(q_values) / len(q_values)
        if abs(bar_q - 1.0) <= 1e-12:
            return Action.C
        return Action.D

