class Strategy_SELFISH_69(BaseStrategy):
    """
    Defect by default. Cooperate only after two consecutive near-universal
    cooperation rounds have been observed, and never in the opening or closing
    rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.high_streak = 0
        self.last_total = None
        self.prev_total = None

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        round_number = history.round_number
        current_round = round_number + 1
        if round_number == 0 or r <= 2:
            return Action.D
        if current_round == r:
            return Action.D
        my_last = 1 if bool(history.my_actions[-1]) else 0
        opp_last = int(history.opponent_cooperators[-1])
        t_prev = my_last + opp_last
        t_prev2 = None
        if round_number >= 2:
            my_prev2 = 1 if bool(history.my_actions[-2]) else 0
            opp_prev2 = int(history.opponent_cooperators[-2])
            t_prev2 = my_prev2 + opp_prev2
        if n == 2:
            high_round_prev = t_prev == 2
            high_round_prev2 = t_prev2 == 2 if t_prev2 is not None else False
        else:
            high_round_prev = t_prev >= n - 1
            high_round_prev2 = t_prev2 >= n - 1 if t_prev2 is not None else False
        if high_round_prev:
            self.high_streak += 1
        else:
            self.high_streak = 0
        self.last_total = t_prev
        self.prev_total = t_prev2
        enough_future_rounds = current_round <= r - 2
        if enough_future_rounds and high_round_prev and high_round_prev2:
            return Action.C
        return Action.D

class Strategy_SELFISH_70(BaseStrategy):
    """
    Selfish threshold strategy for the N-player Public Goods Game.

    - Starts in defect mode.
    - Requires strong and repeated opponent cooperation before entering cooperate mode.
    - Cooperate mode is temporary and exits immediately when cooperation weakens.
    - Never cooperates in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.H = math.ceil(n - k) + 1
        self.L = math.ceil(n - k)
        self._default_mode = 'defect'

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.D
        current_round = round_number + 1
        if n_rounds > 0 and current_round >= n_rounds:
            return Action.D
        opp = history.opponent_cooperators
        observed_rounds = len(opp)
        mode = self._default_mode
        if observed_rounds >= 1:
            if opp[0] >= self.H:
                mode = 'cooperate_pending'
            else:
                mode = 'defect'
        for t in range(3, observed_rounds + 1):
            s_tm1 = int(opp[t - 2])
            s_tm2 = int(opp[t - 3])
            if mode == 'cooperate':
                if s_tm1 >= self.L:
                    mode = 'cooperate'
                else:
                    mode = 'defect'
            elif s_tm1 >= self.H and s_tm2 >= self.H:
                mode = 'cooperate'
            else:
                mode = 'defect'
        if mode == 'cooperate':
            if observed_rounds >= 1 and int(opp[-1]) >= self.L:
                return Action.C
            return Action.D
        if round_number == 1:
            return Action.D
        if observed_rounds >= 2:
            if int(opp[-1]) >= self.H and int(opp[-2]) >= self.H:
                return Action.C
        return Action.D

class Strategy_SELFISH_71(BaseStrategy):
    """
    Defect by default; cooperate only when recent opponent cooperation is already
    high, stable, and not declining. Maintains a 2-round cooldown after any low
    cooperation observation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        k = float(game_description.k)
        self.theta = max(0.5, 1.0 - 1.0 / k) if k > 0 else 0.5
        self.cooldown_remaining = 0
        self._processed_observations = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        t = history.round_number + 1
        if history.round_number == 0:
            self._processed_observations = 0
            return Action.D
        observed_len = len(history.opponent_cooperators)
        start_idx = min(self._processed_observations, observed_len)
        for idx in range(start_idx, observed_len):
            if self.cooldown_remaining > 0:
                self.cooldown_remaining -= 1
            opp_count = int(history.opponent_cooperators[idx])
            if n_opponents > 0:
                q = opp_count / n_opponents
            else:
                q = 0.0
            if q < self.theta:
                self.cooldown_remaining = 2
            self._processed_observations = idx + 1
        if t == n_rounds:
            return Action.D
        if self.cooldown_remaining > 0:
            self.cooldown_remaining -= 1
            return Action.D
        if observed_len <= 0 or n_opponents <= 0:
            return Action.D
        q_prev = int(history.opponent_cooperators[-1]) / n_opponents
        m = min(3, history.round_number)
        if m <= 0:
            avg_m = 0.0
        else:
            recent = history.opponent_cooperators[-m:]
            avg_m = float(np.mean(recent)) / n_opponents if n_opponents > 0 else 0.0
        if history.round_number >= 2:
            q_prev2 = int(history.opponent_cooperators[-2]) / n_opponents
            drop = q_prev - q_prev2
        else:
            drop = 0.0
        if q_prev >= self.theta and avg_m >= self.theta and (history.round_number < 2 or drop <= 0.0):
            return Action.C
        return Action.D

