class Strategy_SELFISH_76(BaseStrategy):
    """
    Cautious conditional cooperator:
    - Starts with defection.
    - Builds trust only after repeated strong cooperation by others.
    - Resets trust on zero observed cooperation.
    - Defects in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.trust = 0
        self.coop_rate = 0.0
        self.good_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number + 1
        if history.round_number == 0:
            self.trust = 0
            self.coop_rate = 0.0
            self.good_streak = 0
            return Action.D
        trust = 0
        good_streak = 0
        last_coop_rate = 0.0
        n_opponents = max(1, n - 1)
        for idx in range(history.round_number):
            opp_count = int(history.opponent_cooperators[idx])
            coop_rate = opp_count / n_opponents
            last_coop_rate = coop_rate
            if opp_count == 0:
                trust = 0
            elif coop_rate >= 0.5:
                trust = min(3, trust + 1)
            else:
                trust = max(0, trust - 1)
            if coop_rate >= 2.0 / 3.0:
                good_streak += 1
            else:
                good_streak = 0
        self.trust = trust
        self.coop_rate = last_coop_rate
        self.good_streak = good_streak
        if t >= r - 1:
            return Action.D
        if self.trust >= 2 and self.good_streak >= 2 and (self.coop_rate >= 2.0 / 3.0):
            return Action.C
        return Action.D

