class Strategy_SELFISH_78(BaseStrategy):
    """
    Cooperate only after two consecutive rounds in which all opponents cooperated,
    and defect in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        unanimous_opponents = max(0, n_players - 1)
        current_round = history.round_number
        if current_round == 0 or current_round < 2 or current_round >= n_rounds - 2:
            return Action.D
        last_two = history.opponent_cooperators[-2:]
        if len(last_two) < 2:
            return Action.D
        if int(last_two[0]) == unanimous_opponents and int(last_two[1]) == unanimous_opponents:
            return Action.C
        return Action.D

class Strategy_SELFISH_79(BaseStrategy):
    """
    Defect by default, cooperate only after two consecutive sufficiently
    cooperative rounds by opponents, and never cooperate in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        n_opponents = max(0, self.n_players - 1)
        high = 1.0 - 1.0 / self.k if self.k != 0 else 0.0
        self.threshold = int(math.ceil(high * n_opponents))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        if t >= self.n_rounds - 1:
            return Action.D
        if t <= 2:
            return Action.D
        if history.round_number < 2:
            return Action.D
        x_prev1 = int(history.opponent_cooperators[-1])
        x_prev2 = int(history.opponent_cooperators[-2])
        if x_prev1 >= self.threshold and x_prev2 >= self.threshold:
            return Action.C
        return Action.D

