class Strategy_SELFISH_83(BaseStrategy):
    """
    Threshold-based conditional cooperator for the repeated N-player public goods game.

    - Defects in round 1 and in the final round.
    - Cooperates only when recent opponent cooperation is clearly above the
      profitability threshold.
    - Falls back to defection after sharp recent drops, and resumes cooperation
      only after cooperation has recovered.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k) if game_description.k is not None else 1.0
        if k <= 0:
            k = 1.0
        self.threshold = n / k - 0.5
        self.eps = 1e-12

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = int(self.game_description.n_rounds)
        if t == 0:
            return Action.D
        if t >= r - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        avg_coop = float(np.mean(opp))
        recent_drop = False
        if len(opp) >= 2:
            if int(opp[-1]) - int(opp[-2]) <= -2:
                recent_drop = True
        if len(opp) >= 3:
            if int(opp[-2]) - int(opp[-3]) <= -2:
                recent_drop = True
        last3_all_high = False
        if len(opp) >= 3:
            last3 = opp[-3:]
            last3_all_high = bool(np.all(last3 > self.threshold + self.eps))
        if avg_coop <= self.threshold + self.eps:
            return Action.D
        if recent_drop:
            return Action.D
        if last3_all_high:
            return Action.C
        if avg_coop > self.threshold + self.eps:
            return Action.C
        return Action.D

class Strategy_SELFISH_84(BaseStrategy):
    """
    Cooperate only after sustained near-universal cooperation; defect otherwise,
    always defecting in the first and final rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'idle'

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        if history.round_number == 0:
            self.mode = 'idle'
            return Action.D
        if history.round_number >= n_rounds - 1:
            self.mode = 'idle'
            return Action.D
        prev_coop = int(history.opponent_cooperators[-1]) if history.round_number >= 1 else 0
        if prev_coop < n - 1:
            self.mode = 'idle'
        m = min(3, history.round_number)
        if m <= 0:
            return Action.D
        recent = history.opponent_cooperators[-m:]
        total_recent_coop = int(np.sum(recent))
        denom = m * (n - 1)
        q_m = total_recent_coop / denom if denom > 0 else 0.0
        threshold = (n - 2) / (n - 1) if n > 1 else 0.0
        if self.mode == 'idle':
            if prev_coop == n - 1:
                if history.round_number == 1:
                    can_reenter = True
                else:
                    second_prev_coop = int(history.opponent_cooperators[-2])
                    can_reenter = second_prev_coop == n - 1
                if can_reenter:
                    self.mode = 'committed'
                    return Action.C
            return Action.D
        if prev_coop == n - 1 and q_m >= threshold:
            return Action.C
        self.mode = 'idle'
        return Action.D

class Strategy_SELFISH_85(BaseStrategy):
    """
    Conservative conditional-cooperation strategy for the repeated N-player
    public goods game.

    - Start by defecting.
    - Cooperate only after sustained evidence of high opponent cooperation.
    - Immediately fall back to defection if cooperation appears to drop.
    - In all ambiguous cases, defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.n_players = n
        self.n_rounds = int(game_description.n_rounds)
        self.k = k
        self.theta = 1.0 - 1.0 / k if k != 0 else 0.0
        self.high_threshold = math.ceil((n - 1) * self.theta + 1)
        self.low_threshold = math.ceil((n - 1) * self.theta)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t >= self.n_rounds - 1:
            return Action.D
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        my = history.my_actions
        total_obs = (self.n_players - 1) * t
        total_coops = int(np.sum(opp)) if t > 0 else 0
        p_t = total_coops / total_obs if total_obs > 0 else 0.0
        last_m = int(opp[-1]) if t > 0 else 0
        last_two_high = False
        if t >= 2:
            last_two_high = int(opp[-1]) >= self.high_threshold and int(opp[-2]) >= self.high_threshold
        last_two_defected = False
        if t >= 2:
            last_two_defected = not bool(my[-1]) and (not bool(my[-2]))
        if bool(my[-1]) and last_m < self.low_threshold:
            return Action.D
        if t == 1:
            return Action.C if last_m >= self.high_threshold else Action.D
        if t == 2:
            return Action.C if last_two_high else Action.D
        if last_two_defected and last_two_high:
            return Action.C
        if p_t > self.theta + 0.1:
            return Action.C
        if p_t < self.theta - 0.05:
            return Action.D
        if last_two_high:
            return Action.C
        return Action.D

