class Strategy_SELFISH_93(BaseStrategy):
    """
    Defect by default; only cooperate after two consecutive rounds of near-universal
    opponent cooperation, and never in the first or last round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        if self.n_players == 2:
            self.required_opponents = 1
        else:
            self.required_opponents = max(0, self.n_players - 2)
        self.streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            self.streak = 0
            return Action.D
        recent_opponents = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        if recent_opponents >= self.required_opponents:
            self.streak += 1
        else:
            self.streak = 0
        if round_number >= self.n_rounds - 1:
            return Action.D
        if self.streak >= 2:
            return Action.C
        return Action.D

