class Strategy_SELFISH_95(BaseStrategy):
    """
    Start with defection. Enter cooperation only after observing two consecutive
    rounds where every opponent cooperated. Defect in the last two rounds.
    Any observed opponent defection immediately breaks trust.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.trust = False
        self.streak = 0
        self._processed_rounds = 0

    def _all_opponents_cooperated(self, history: PlayerHistory, round_index: int) -> bool:
        if round_index < 0 or round_index >= history.round_number:
            return False
        n_opponents = max(0, self.game_description.n_players - 1)
        if n_opponents == 0:
            return True
        return int(history.opponent_cooperators[round_index]) >= n_opponents

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = max(0, int(self.game_description.n_rounds))
        current_round_index = history.round_number
        start = self._processed_rounds
        end = min(history.round_number, n_rounds)
        for r_idx in range(start, end):
            if self._all_opponents_cooperated(history, r_idx):
                self.streak += 1
            else:
                self.streak = 0
                self.trust = False
            self._processed_rounds = r_idx + 1
        if current_round_index >= n_rounds:
            return Action.D
        if current_round_index >= max(0, n_rounds - 2):
            return Action.D
        if history.round_number == 0:
            return Action.D
        last_unanimous = self._all_opponents_cooperated(history, history.round_number - 1)
        if self.trust:
            if last_unanimous:
                return Action.C
            self.trust = False
            self.streak = 0
            return Action.D
        if self.streak >= 2 and last_unanimous:
            self.trust = True
            return Action.C
        return Action.D

