class Strategy_SELFISH_98(BaseStrategy):
    """
    Moving-average public-goods strategy:
    - Start with defection.
    - Near the end, defect.
    - In between, cooperate only when recent opponent cooperation is high
      and the short-term trend is non-decreasing; otherwise mostly defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.n_opponents = max(1, n_players - 1)
        h = max(0.65, 1.0 - k / (2.0 * n_players))
        self.high_threshold = float(h)
        self.low_threshold = float(h - 0.15)

    def _last_window_mean(self, values: NDArray[np.int_], window: int) -> float:
        size = int(len(values))
        if size <= 0:
            return 0.0
        start = max(0, size - max(1, window))
        segment = values[start:size]
        if len(segment) == 0:
            return 0.0
        return float(np.mean(segment))

    def _moving_average(self, history: PlayerHistory, upto: int) -> float:
        if upto <= 0:
            return 0.0
        window = min(3, upto)
        coop_counts = history.opponent_cooperators[:upto]
        if len(coop_counts) == 0:
            return 0.0
        rates = coop_counts / float(self.n_opponents)
        return self._last_window_mean(rates, window)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            return Action.D
        if round_number >= max(0, n_rounds - 1):
            return Action.D
        last_coop_rate = float(history.opponent_cooperators[-1]) / float(self.n_opponents)
        current_avg = self._moving_average(history, round_number)
        if round_number >= 2:
            prev_avg = self._moving_average(history, round_number - 1)
        else:
            prev_avg = current_avg
        trend = 1 if current_avg >= prev_avg else 0
        if current_avg <= self.low_threshold or last_coop_rate <= self.low_threshold:
            return Action.D
        if current_avg >= self.high_threshold and trend == 1:
            return Action.C
        if len(history.my_actions) > 0:
            return Action.C if bool(history.my_actions[-1]) else Action.D
        return Action.D

class Strategy_SELFISH_99(BaseStrategy):
    """
    Opens with defection, defects in the final round, and cooperates only when
    opponent cooperation is high and stable. Uses only aggregate opponent
    cooperation counts from the last two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self._n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        rounds_remaining = self.n_rounds - round_number
        if rounds_remaining <= 1:
            return Action.D
        if self._n_opponents <= 0:
            return Action.D
        prev_count = int(history.opponent_cooperators[-1])
        x_prev = prev_count / self._n_opponents
        if x_prev <= 0.25:
            return Action.D
        if x_prev >= 0.75:
            return Action.C
        if round_number == 1:
            return Action.D
        prevprev_count = int(history.opponent_cooperators[-2])
        x_prevprev = prevprev_count / self._n_opponents
        if x_prevprev >= x_prev:
            return Action.C
        return Action.D

class Strategy_SELFISH_100(BaseStrategy):
    """
    Always defect in every round of the public goods game.
    Defaults to defection whenever history is unavailable or ambiguous.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', None)
        self.n_rounds = getattr(game_description, 'n_rounds', None)
        self.k = getattr(game_description, 'k', None)

    def __call__(self, history: PlayerHistory) -> Action:
        if history is None:
            return Action.D
        round_number = getattr(history, 'round_number', None)
        if round_number is None:
            return Action.D
        return Action.D

