class Strategy_SELFISH_102(BaseStrategy):
    """
    Conservative public-goods strategy:
    - Default to defection.
    - Cooperate only after two consecutive rounds of sufficient opponent cooperation.
    - Immediately defect if cooperation drops below the threshold.
    - Defect in the last two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        self.theta = max(0, int(math.ceil(max(n - 1, 0) * k / max(n, 1))))
        self.h = 0
        self.b = 0
        self.last_processed_round = -1
        self.last_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        r = int(self.game_description.n_rounds)
        if t == 0:
            self.h = 0
            self.b = 0
            self.last_processed_round = 0
            self.last_action = Action.D
            return Action.D
        if t >= max(r - 2, 0):
            self.last_action = Action.D
            self.last_processed_round = t
            return Action.D
        q = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if q >= self.theta:
            self.h += 1
            self.b = 0
        else:
            self.b += 1
            self.h = 0
        if self.h >= 2 and q >= self.theta:
            action = Action.C
        else:
            action = Action.D
        if q < self.theta:
            action = Action.D
        self.last_action = action
        self.last_processed_round = t
        return action

