class Strategy_SELFISH_104(BaseStrategy):
    """
    Conservative cooperation strategy:
    - Defect in the first and last rounds.
    - Cooperate only when the previous two rounds were full-opposition cooperation,
      and we personally cooperated in the immediately previous round.
    - After any breakdown (a round with less than full opponent cooperation),
      defect for the next two rounds before considering cooperation again.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.full_opponent_cooperators = max(0, self.n_players - 1)
        self.last_seen_round = -1
        self.cooldown_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.last_seen_round = 0
            self.cooldown_remaining = 0
            return Action.D
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            self.last_seen_round = round_number
            return Action.D
        opp = history.opponent_cooperators
        my_actions = history.my_actions
        last_opp = int(opp[-1]) if len(opp) >= 1 else 0
        prev_opp = int(opp[-2]) if len(opp) >= 2 else -1
        if last_opp < self.full_opponent_cooperators:
            self.cooldown_remaining = 2
        elif self.cooldown_remaining > 0:
            self.cooldown_remaining -= 1
        self.last_seen_round = round_number
        if self.cooldown_remaining > 0:
            return Action.D
        if last_opp != self.full_opponent_cooperators:
            return Action.D
        if prev_opp != self.full_opponent_cooperators:
            return Action.D
        if len(my_actions) >= 1 and (not bool(my_actions[-1])):
            return Action.D
        return Action.C

