class Strategy_SELFISH_106(BaseStrategy):
    """
    Protective threshold-based public goods strategy with short-memory cooperation detection.
    Cooperates only in strongly stable and highly cooperative environments, defects otherwise,
    and always defects in the first and last rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.m = max(0, self.n - 1)
        self.h = min(3, max(0, self.r - 1))
        self.base_threshold = 1.0 if self.n == 2 else 0.75
        self.min_quorum = math.ceil(0.5 * self.m) if self.m > 0 else 0
        self.high_quorum = math.ceil(0.75 * self.m) if self.m > 0 else 0

    def _window_average(self, values) -> float:
        if len(values) == 0:
            return 0.0
        return float(sum(values)) / float(len(values))

    def _recent_all_full(self, history: PlayerHistory, window_len: int) -> bool:
        if window_len <= 0:
            return False
        if history.round_number < window_len:
            return False
        recent = history.opponent_cooperators[-window_len:]
        return bool(np.all(recent == self.m))

    def _should_reset_to_normal(self, history: PlayerHistory) -> bool:
        if self.h <= 0:
            return True
        return self._recent_all_full(history, self.h)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        current_round = t + 1
        if t == 0:
            return Action.D
        if current_round == self.r:
            return Action.D
        if self.r <= 3:
            if current_round != 2:
                return Action.D
            if history.round_number >= 1 and history.opponent_cooperators[0] == self.m:
                return Action.C
            return Action.D
        x_prev = int(history.opponent_cooperators[-1]) if history.round_number >= 1 else 0
        q_hist = [float(x) / float(self.m) for x in history.opponent_cooperators] if self.m > 0 else [0.0 for _ in range(len(history.opponent_cooperators))]
        if self.h > 0:
            recent_q = q_hist[-self.h:]
            a_prev = self._window_average(recent_q)
        else:
            a_prev = 0.0
        if self.min_quorum > 0 and np.any(history.opponent_cooperators < self.min_quorum):
            if not self._should_reset_to_normal(history):
                return Action.D
        if current_round == self.r - 1:
            if a_prev == 1.0 and x_prev == self.m:
                return Action.C
            return Action.D
        threshold = self.base_threshold
        if self.m == 1:
            if self._should_reset_to_normal(history):
                return Action.C
            return Action.D
        if a_prev < threshold:
            return Action.D
        if x_prev < self.high_quorum:
            return Action.D
        if current_round >= 3:
            x_prev2 = int(history.opponent_cooperators[-2])
            if x_prev < x_prev2:
                return Action.D
        return Action.C

