class Strategy_SELFISH_109(BaseStrategy):
    """
    Defect by default. Cooperate only in intermediate rounds when recent
    opponent cooperation is stable and at or above the threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.threshold = int(math.ceil((n - 1) / k)) if k > 0 else n
        self.n_rounds = int(game_description.n_rounds)
        self.force_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if self.force_defect:
            return Action.D
        my_actions = history.my_actions
        opp_counts = history.opponent_cooperators
        H = self.threshold
        if round_number >= 2:
            coop_before = bool(my_actions[:-1].any())
            if coop_before:
                prev_my_coop_rounds = np.flatnonzero(my_actions[:-1])
                for idx in prev_my_coop_rounds:
                    next_round = idx + 1
                    if next_round < len(opp_counts) and opp_counts[next_round] < H:
                        self.force_defect = True
                        return Action.D
        if opp_counts[-1] < H:
            self.force_defect = True
            return Action.D
        if round_number == 1:
            return Action.C
        if opp_counts[-2] < H:
            return Action.D
        if opp_counts[-1] < opp_counts[-2]:
            return Action.D
        return Action.C

class Strategy_SELFISH_110(BaseStrategy):
    """
    Default-defect strategy with brief opportunistic cooperation only when
    opponent cooperation is very high and recent history is strongly supportive.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.locked_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if self.locked_defect:
            return Action.D
        if round_number == 0:
            return Action.D
        if len(history.my_actions) >= 1 and len(history.opponent_cooperators) >= 1:
            if bool(history.my_actions[-1]):
                n_opponents = max(self.n - 1, 1)
                last_q = float(history.opponent_cooperators[-1]) / n_opponents
                if last_q < 0.6:
                    self.locked_defect = True
                    return Action.D
        if round_number >= self.r - 1:
            return Action.D
        if len(history.my_actions) < 2:
            return Action.D
        if len(history.opponent_cooperators) < 1:
            return Action.D
        n_opponents = max(self.n - 1, 1)
        current_t = round_number + 1
        L = min(3, current_t - 1)
        if L <= 0 or len(history.opponent_cooperators) < L:
            return Action.D
        recent_counts = history.opponent_cooperators[-L:]
        if len(recent_counts) == 0:
            return Action.D
        recent_rates = [float(x) / n_opponents for x in recent_counts]
        Q_t = float(np.mean(recent_rates)) if len(recent_rates) > 0 else 0.0
        m_prev = int(history.opponent_cooperators[-1])
        threshold_m = int(math.ceil(0.75 * n_opponents))
        played_c_last_two = bool(history.my_actions[-1]) or bool(history.my_actions[-2])
        if Q_t >= 0.8 and m_prev >= threshold_m and (current_t <= self.r - 2) and (not played_c_last_two):
            return Action.C
        return Action.D

