class Strategy_SELFISH_119(BaseStrategy):
    """
    Defect by default, and cooperate only after observing a fully stable
    window of recent opponent cooperation.

    Cooperation occurs only when:
    - the last up to 3 observed rounds are all "stable" (at least n-2
      opponents cooperated in each round), and
    - the average opponent cooperation rate over that window is 1.0,
      meaning all opponents cooperated in every observed round.

    The final round is always defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.trust = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        total_rounds = self.game_description.n_rounds
        played_rounds = history.round_number
        if played_rounds == 0:
            return Action.D
        if played_rounds >= total_rounds - 1:
            return Action.D
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.D
        m = min(3, played_rounds)
        if m <= 0:
            return Action.D
        recent = history.opponent_cooperators[-m:]
        if len(recent) != m:
            return Action.D
        threshold = n - 2
        stable = True
        total_cooperators = 0
        for count in recent:
            if count < threshold:
                stable = False
            total_cooperators += int(count)
        if not stable:
            return Action.D
        if total_cooperators == m * n_opponents:
            return Action.C
        return Action.D

class Strategy_SELFISH_120(BaseStrategy):
    """
    Default-defect public goods strategy with strict cooperation only under
    sustained full cooperation, and unconditional defection in the first and
    last rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.window_size = 3
        self.eps = 1e-12

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            return Action.D
        if t >= self.n_rounds:
            return Action.D
        denom = self.n_players - 1
        if denom <= 0:
            return Action.D
        past_counts = history.opponent_cooperators
        if len(past_counts) == 0:
            return Action.D
        q_prev = float(past_counts[-1]) / denom
        window_len = min(self.window_size, len(past_counts))
        recent_q = [float(x) / denom for x in past_counts[-window_len:]]
        full_recent = all((abs(q - 1.0) <= self.eps for q in recent_q))
        nondecreasing = all((recent_q[i] <= recent_q[i + 1] + self.eps for i in range(len(recent_q) - 1)))
        if (abs(q_prev - 1.0) <= self.eps or abs(sum(recent_q) / window_len - 1.0) <= self.eps) and full_recent and nondecreasing:
            return Action.C
        return Action.D

class Strategy_SELFISH_121(BaseStrategy):
    """
    Conditional cooperator with short-memory filtering, immediate punishment for
    noncooperation, and forced defection in the first and last rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.score = 0.0
        self.consecutive_low = 0
        self.lock_remaining = 0
        self.last_processed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = int(self.game_description.n_players)
        n_opponents = max(0, n_players - 1)
        n_rounds = int(self.game_description.n_rounds)
        k = float(self.game_description.k)
        if history.round_number == 0:
            self.last_processed_round = 0
            return Action.D
        current_round = history.round_number
        prev_round = current_round - 1
        if self.last_processed_round < prev_round:
            if n_opponents > 0:
                prev_coop_count = int(history.opponent_cooperators[-1])
                x_prev = prev_coop_count / n_opponents
            else:
                x_prev = 0.0
            threshold = 1.0 / k if k > 0 else float('inf')
            self.score = 0.7 * self.score + (x_prev - threshold)
            if x_prev == 0:
                self.consecutive_low = 0
            elif x_prev < threshold:
                self.consecutive_low += 1
            else:
                self.consecutive_low = 0
            if self.consecutive_low >= 2:
                self.lock_remaining = 2
                self.consecutive_low = 0
            self.last_processed_round = prev_round
        if current_round >= n_rounds - 1:
            if self.lock_remaining > 0:
                self.lock_remaining -= 1
            return Action.D
        if self.lock_remaining > 0:
            self.lock_remaining -= 1
            return Action.D
        if n_opponents > 0:
            prev_coop_count = int(history.opponent_cooperators[-1])
            x_prev = prev_coop_count / n_opponents
        else:
            x_prev = 0.0
        threshold = 1.0 / k if k > 0 else float('inf')
        if x_prev == 0:
            return Action.D
        if self.score >= 0.1 and x_prev >= threshold:
            return Action.C
        return Action.D

class Strategy_SELFISH_122(BaseStrategy):
    """
    Conditional cooperation strategy for the repeated N-player Public Goods Game.

    - Defect in round 1.
    - Cooperate only when the observed cooperation rate among opponents has been
      at or above the threshold 1 - k/n for the last two observed rounds
      (when applicable), and there has been no recent drop.
    - Defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.opponent_count = max(1, self.n_players - 1)
        self.threshold = 1.0 - self.k / self.n_players if self.n_players > 0 else 1.0
        self.drop_tolerance = 1.0 / self.n_players if self.n_players > 0 else 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t >= self.n_rounds - 1:
            return Action.D
        prev_count = int(history.opponent_cooperators[-1])
        prev_q = prev_count / self.opponent_count if self.opponent_count > 0 else 0.0
        recent_drop = False
        if t >= 2:
            prev2_count = int(history.opponent_cooperators[-2])
            prev2_q = prev2_count / self.opponent_count if self.opponent_count > 0 else 0.0
            recent_drop = prev_q < prev2_q - self.drop_tolerance
        if prev_q >= self.threshold:
            if t == 1:
                return Action.C
            if t >= 2:
                prev2_q = history.opponent_cooperators[-2] / self.opponent_count if self.opponent_count > 0 else 0.0
                if prev2_q >= self.threshold and (not recent_drop):
                    return Action.C
        return Action.D

