class Strategy_SELFISH_126(BaseStrategy):
    """
    Always defects in every round, regardless of history or observed cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._always_defect = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        if history is None:
            return self._always_defect
        round_number = getattr(history, 'round_number', 0)
        if not isinstance(round_number, int) or round_number < 0:
            return self._always_defect
        return self._always_defect

class Strategy_SELFISH_127(BaseStrategy):
    """
    Permanent defection strategy for the repeated public goods game.
    Always plays D, regardless of history or opponent cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        self.mode = Action.D
        return Action.D

class Strategy_SELFISH_128(BaseStrategy):
    """
    Always defects in every round of the repeated public goods game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.n_players = getattr(game_description, 'n_players', 0)
        self.k = getattr(game_description, 'k', 0.0)

    def __call__(self, history: PlayerHistory) -> Action:
        if history is None:
            return Action.D
        round_number = getattr(history, 'round_number', 0)
        if round_number is None or round_number <= 0:
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_33(BaseStrategy):
    """
    Adaptive public-goods strategy that defects at the start and end,
    cooperates only after sustained high cooperation, and punishes low
    cooperation immediately with a short defect lockout.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'DEFECT'
        self.streak = 0
        self.last_rate = 0.0
        self.defect_lock = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        round_number = history.round_number
        if round_number == 0:
            self.mode = 'DEFECT'
            self.streak = 0
            self.last_rate = 0.0
            self.defect_lock = 0
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        n_opponents = n_players - 1
        if n_opponents <= 0:
            return Action.D
        x = int(history.opponent_cooperators[-1])
        rate = x / n_opponents
        if n_players == 2:
            if rate >= 1.0:
                self.streak += 1
            else:
                self.streak = 0
                self.mode = 'DEFECT'
            action = Action.C if self.streak >= 2 and round_number <= n_rounds - 2 else Action.D
            if action == Action.C:
                self.mode = 'COOPERATE'
            self.last_rate = rate
            return action
        if self.defect_lock > 0:
            self.defect_lock -= 1
            if rate < 1.0 / 3.0:
                self.mode = 'DEFECT'
                self.streak = 0
                self.defect_lock = 1
            elif rate >= 2.0 / 3.0:
                self.streak += 1
                if self.streak >= 2:
                    self.mode = 'COOPERATE'
            self.last_rate = rate
            return Action.D
        if rate < 1.0 / 3.0:
            self.mode = 'DEFECT'
            self.streak = 0
            self.defect_lock = 1
            self.last_rate = rate
            return Action.D
        if rate >= 2.0 / 3.0:
            self.streak += 1
        if self.mode == 'COOPERATE':
            if rate >= 2.0 / 3.0 and self.last_rate >= 2.0 / 3.0 and (round_number <= n_rounds - 2):
                action = Action.C
            else:
                action = Action.D
        elif rate >= 2.0 / 3.0 and self.streak >= 2 and (round_number <= n_rounds - 2):
            self.mode = 'COOPERATE'
            action = Action.C
        else:
            action = Action.D
        if action == Action.D and rate >= 2.0 / 3.0:
            if self.streak >= 2:
                self.mode = 'COOPERATE'
        self.last_rate = rate
        return action

class Strategy_SELFINTERESTED_34(BaseStrategy):
    """
    Two-stage threshold strategy for the repeated N-player Public Goods Game.

    Starts outside, requires two consecutive rounds of sufficient opponent
    cooperation to enter, then stays inside while cooperation remains above
    the hold threshold. Never cooperates in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.theta_enter = 1.0 / k if k > 0 else 1.0
        self.theta_hold = max(0.5, self.theta_enter - 1.0 / (2.0 * n))
        self.mode = 'OUTSIDE'
        self.streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        if round_number >= n_rounds - 1:
            return Action.D
        if round_number == 0:
            self.mode = 'OUTSIDE'
            self.streak = 0
            return Action.D
        n_opponents = max(1, int(self.game_description.n_players) - 1)
        last_opp_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        rho_prev = last_opp_coops / n_opponents
        if self.mode == 'OUTSIDE':
            if rho_prev >= self.theta_enter:
                self.streak += 1
            else:
                self.streak = 0
            if self.streak >= 2:
                self.mode = 'INSIDE'
            return Action.D
        if rho_prev >= self.theta_hold:
            return Action.C
        self.mode = 'OUTSIDE'
        self.streak = 0
        return Action.D

class Strategy_SELFINTERESTED_35(BaseStrategy):
    """
    Always defect in every round, ignoring all history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.k = getattr(game_description, 'k', 0.0)

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_36(BaseStrategy):
    """
    Threshold-based conditional cooperater for the repeated public goods game.

    - Starts by defecting.
    - Cooperates only after sufficiently strong and stable observed cooperation
      among opponents, with extra caution when the public good multiplier k is
      close to 1.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.theta = math.ceil(n / k) - 1
        self.strong_k_threshold = 1.1
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        last_m = int(opp[-1])
        ell = min(3, round_number)
        recent = opp[-ell:]
        recent_mean = float(np.mean(recent)) if len(recent) > 0 else 0.0
        if np.any(recent == 0):
            return Action.D
        if round_number == self.n_rounds - 1:
            if round_number >= 2:
                if int(opp[-1]) >= self.theta + 1 and int(opp[-2]) >= self.theta + 1:
                    return Action.C
            return Action.D
        required = self.theta + 1 if self.game_description.k <= self.strong_k_threshold else self.theta
        if last_m < required:
            return Action.D
        if last_m >= self.theta and recent_mean >= self.theta:
            if round_number >= 3:
                last_three = opp[-3:]
                if np.all(last_three >= self.theta):
                    return Action.C
            return Action.C
        my_actions = history.my_actions
        if len(my_actions) > 0 and bool(my_actions[-1]):
            if last_m < self.theta:
                return Action.D
        if round_number >= 2:
            if int(opp[-1]) >= self.theta + 1 and int(opp[-2]) >= self.theta + 1:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_37(BaseStrategy):
    """
    Three-state strategy for the N-player Public Goods Game:
    open, cautious, and locked out.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        k = float(game_description.k)
        self.tau = 1.0 - 1.0 / k if k != 0 else 1.0
        self._terminal_threshold = int(math.ceil(game_description.n_players / k)) if k > 0 else game_description.n_rounds
        self._drop_threshold = 2.0 / (game_description.n_players - 1) if game_description.n_players > 1 else float('inf')

    def _fraction_cooperators(self, history: PlayerHistory, idx: int) -> float:
        n_opponents = self.game_description.n_players - 1
        if n_opponents <= 0:
            return 0.0
        return float(history.opponent_cooperators[idx]) / float(n_opponents)

    def _reconstruct_state(self, history: PlayerHistory) -> str:
        """
        Reconstruct the internal state after processing all completed rounds.
        """
        state = 'open'
        prev_f = None
        prev_prev_f = None
        for t in range(history.round_number):
            f_t = self._fraction_cooperators(history, t)
            if state == 'open':
                if f_t < self.tau:
                    state = 'cautious'
            elif state == 'cautious':
                if f_t < self.tau:
                    state = 'locked_out'
                elif prev_f is not None and prev_f >= self.tau and (f_t >= self.tau):
                    state = 'open'
            elif prev_f is not None and prev_f >= self.tau and (f_t >= self.tau):
                state = 'cautious'
            if prev_f is not None and prev_f - f_t >= self._drop_threshold and (f_t < self.tau):
                state = 'locked_out'
            prev_prev_f = prev_f
            prev_f = f_t
        return state

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        remaining_rounds = self.game_description.n_rounds - t
        if remaining_rounds <= self._terminal_threshold:
            return Action.D
        state = self._reconstruct_state(history)
        f_prev = self._fraction_cooperators(history, t - 1)
        ell = min(3, t - 1)
        if ell <= 0:
            bar_f = f_prev
        else:
            start = t - ell
            vals = [self._fraction_cooperators(history, idx) for idx in range(start, t)]
            bar_f = float(np.mean(vals)) if len(vals) > 0 else 0.0
        if state == 'locked_out':
            return Action.D
        if f_prev >= self.tau and bar_f >= self.tau:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_38(BaseStrategy):
    """
    Always defects in every round of the repeated Public Goods Game.
    Ignores all historical information and never switches to cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_rounds = getattr(game_description, 'n_rounds', 0)

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_39(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Defect in round 1
    - Track exponentially weighted cooperation h_t from observed opponent cooperation
    - Cooperate only when cooperation is stable, but defect in the final 2 rounds
    - React to short-term collapse/recovery streaks with forced defect/cooperate modes
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.high = 0.6
        self.low = 0.4
        self.h_decay = 0.7
        self.h_weight = 0.3

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        rounds_played = history.round_number
        total_rounds = self.game_description.n_rounds
        if rounds_played == 0:
            return Action.D
        if rounds_played >= total_rounds - 2:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        n_opponents = max(1, n - 1)
        h = 0.0
        for x in opp:
            p = float(x) / n_opponents
            h = self.h_decay * h + self.h_weight * p
        last_x = int(opp[-1])
        high_count = self.high * n_opponents
        low_count = self.low * n_opponents
        last_two_low = False
        if len(opp) >= 2:
            last_two_low = int(opp[-1]) < low_count and int(opp[-2]) < low_count
        last_three_high = False
        if len(opp) >= 3:
            last_three_high = int(opp[-1]) >= high_count and int(opp[-2]) >= high_count and (int(opp[-3]) >= high_count)
        if last_two_low and h <= self.high:
            return Action.D
        if last_three_high and h >= self.low:
            return Action.C
        if history.my_actions[-1] and last_x >= high_count:
            return Action.C
        if h >= self.high:
            return Action.C
        if h <= self.low:
            return Action.D
        if last_x >= n_opponents / 2.0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_40(BaseStrategy):
    """
    Threshold-based public goods strategy with short-memory cooperation pressure,
    last-two-round boost, and a simple recovery/persistence mechanism.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.m = max(0, self.n_players - 1)
        self.theta = 1.0 / self.k if self.k != 0 else float('inf')
        self.last_action = None
        self.last_pressure = None
        self.above_streak = 0
        self.locked_defect = False

    def _approx_equal(self, a: float, b: float, tol: float=1e-12) -> bool:
        return abs(a - b) <= tol

    def _pressure_from_history(self, opponent_cooperators) -> float:
        if self.m <= 0:
            return 0.0
        last_rate = float(opponent_cooperators[-1]) / self.m
        recent = opponent_cooperators[-3:]
        q = float(np.mean(recent)) / self.m
        return max(last_rate, q)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            self.last_action = Action.C
            self.last_pressure = None
            self.above_streak = 0
            self.locked_defect = False
            return Action.C
        opp = history.opponent_cooperators
        my = history.my_actions
        above_streak = 0
        locked = False
        for idx in range(1, t):
            if idx >= 2 and bool(my[idx - 1]):
                if int(opp[idx - 1]) <= int(opp[idx - 2]) - 2:
                    locked = True
            prev_slice = opp[:idx]
            if self.m > 0:
                s = float(prev_slice[-1]) / self.m
                recent = prev_slice[-3:]
                q = float(np.mean(recent)) / self.m
                p = max(s, q)
            else:
                p = 0.0
            if p > self.theta + 1e-12:
                above_streak += 1
            else:
                above_streak = 0
            if locked and p > self.theta + 1e-12:
                locked = False
        if self.m > 0:
            s = float(opp[-1]) / self.m
            recent = opp[-3:]
            q = float(np.mean(recent)) / self.m
            p = max(s, q)
        else:
            s = 0.0
            q = 0.0
            p = 0.0
        final_two = t >= max(0, self.n_rounds - 2)
        if final_two:
            action = Action.C if p >= self.theta - 1e-12 else Action.D
        elif locked and (not p > self.theta + 1e-12):
            action = Action.D
        elif p > self.theta + 1e-12:
            action = Action.C
        elif self._approx_equal(p, self.theta):
            prev_majority = int(opp[-1]) > self.m - int(opp[-1])
            action = Action.C if prev_majority else Action.D
        else:
            action = Action.D
        self.last_action = action
        self.last_pressure = p
        self.above_streak = above_streak + (1 if p > self.theta + 1e-12 else 0)
        self.locked_defect = locked and (not p > self.theta + 1e-12)
        return action

class Strategy_SELFINTERESTED_41(BaseStrategy):
    """
    Default-defect public-goods strategy with a probing phase, conditional
    cooperation when recent opponent cooperation is consistently high, and an
    irreversible retreat mode after any sharp drop below the cooperation threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.tau = 1.0 - 1.0 / self.k if self.k != 0 else 1.0
        self.threshold = int(math.ceil(max(0.0, (self.n - 1) * self.tau)))
        self.mode = 'probe'
        self.consecutive_good = 0

    def _q_bar(self, history: PlayerHistory) -> float:
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return 0.0
        n_opponents = max(1, self.n - 1)
        last_k = opp[max(0, len(opp) - 3):]
        rates = [float(x) / n_opponents for x in last_k]
        return float(np.mean(rates)) if rates else 0.0

    def _round_satisfies_conditions(self, history: PlayerHistory, round_idx: int) -> bool:
        """
        Evaluate whether the strategy would cooperate in a non-final decision round
        based on information available up to and including round_idx.
        """
        if round_idx < 0 or round_idx >= len(history.opponent_cooperators):
            return False
        m_prev = int(history.opponent_cooperators[round_idx])
        if m_prev < self.threshold:
            return False
        q_bar = self._q_bar(PlayerHistory(my_actions=history.my_actions[:round_idx + 1], my_payoffs=history.my_payoffs[:round_idx + 1], opponent_cooperators=history.opponent_cooperators[:round_idx + 1]))
        if q_bar < self.tau:
            return False
        if round_idx >= 1:
            m_prev2 = int(history.opponent_cooperators[round_idx - 1])
            if m_prev < m_prev2:
                return False
        return True

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            self.mode = 'probe'
            self.consecutive_good = 0
            return Action.D
        if t == self.r - 1:
            return Action.D
        last_m = int(history.opponent_cooperators[-1])
        if last_m < self.threshold:
            self.mode = 'retreat'
        if self.mode == 'retreat':
            return Action.D
        last_round_good = self._round_satisfies_conditions(history, t - 1)
        if last_round_good:
            self.consecutive_good += 1
        else:
            self.consecutive_good = 0
        if self.consecutive_good >= 2:
            self.mode = 'conditional'
        if last_round_good:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_42(BaseStrategy):
    """
    Conservative public-goods strategy:
    - Defect in the first round and the final two rounds.
    - Cooperate only after sustained cooperation, with a one-round probe allowed
      at round 2 if the immediately preceding round meets the threshold.
    - Reset to defection immediately after any sub-threshold round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.threshold = math.ceil((max(n, 1) - 1) / k) if k > 0 else max(n - 1, 0)
        self.mode_cooperate = False
        self.consecutive_good = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        r = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        if t == 0:
            self.mode_cooperate = False
            self.consecutive_good = 0
            self._last_processed_round = 0
            return Action.D
        end_round = min(t, len(history.opponent_cooperators))
        for idx in range(self._last_processed_round, end_round):
            s = int(history.opponent_cooperators[idx])
            if s >= self.threshold:
                self.consecutive_good += 1
            else:
                self.consecutive_good = 0
                self.mode_cooperate = False
            if self.consecutive_good >= 2:
                self.mode_cooperate = True
        self._last_processed_round = max(self._last_processed_round, end_round)
        if r > 0 and t >= r - 1:
            self.mode_cooperate = False
            return Action.D
        if t == 1:
            return Action.C if self.consecutive_good >= 1 else Action.D
        return Action.C if self.mode_cooperate else Action.D

class Strategy_SELFINTERESTED_43(BaseStrategy):
    """
    Two-mode threshold strategy for the repeated N-player public goods game.

    Starts in D-mode, plays D in round 1 and the final round, and otherwise:
    - In D-mode, cooperates only after two consecutive rounds with enough
      cooperating opponents.
    - In C-mode, keeps cooperating while recent cooperation remains above
      the maintenance threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        if k > 0:
            self.entry_threshold = max(0, math.ceil(n / k) - 1)
        else:
            self.entry_threshold = 0
        self.maintenance_threshold = max(0, self.entry_threshold - 1)
        self.mode = 'D'

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            self.mode = 'D'
            return Action.D
        if round_number + 1 >= n_rounds:
            self.mode = 'D'
            return Action.D
        opp = history.opponent_cooperators
        last_opponents = int(opp[-1]) if len(opp) > 0 else 0
        prev2_opponents = int(opp[-2]) if len(opp) > 1 else last_opponents
        if self.mode == 'D':
            if last_opponents >= self.entry_threshold and prev2_opponents >= self.entry_threshold:
                self.mode = 'C'
                return Action.C
            self.mode = 'D'
            return Action.D
        if last_opponents >= self.maintenance_threshold:
            self.mode = 'C'
            return Action.C
        self.mode = 'D'
        return Action.D

class Strategy_SELFINTERESTED_44(BaseStrategy):
    """
    Three-state public goods strategy:
    - Start with defection.
    - Require two consecutive stable rounds before testing cooperation.
    - Promote TEST -> C only after one successful test round.
    - Defect immediately on weakness and enforce a 2-round lockout.
    - Defect unconditionally in the endgame window.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        r = max(2, int(game_description.n_rounds))
        k = float(game_description.k)
        self.S = max(0, math.ceil(n / k) - 1) if k > 0 else 0
        self.L = max(1, math.ceil(r / 5))
        self.endgame_start = r - self.L

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t > self.endgame_start:
            return Action.D
        opp = history.opponent_cooperators
        history_len = len(opp)
        state = 'D'
        lockout_remaining = 0
        for u in range(1, t):
            if lockout_remaining > 0:
                lockout_remaining -= 1
                state = 'D'
                continue
            x_prev = int(opp[u - 1])
            if state == 'C':
                if x_prev >= self.S:
                    pass
                else:
                    state = 'D'
                    lockout_remaining = 2
            elif state == 'TEST':
                if x_prev >= self.S:
                    state = 'C'
                else:
                    state = 'D'
                    lockout_remaining = 2
            else:
                x_prev2 = int(opp[u - 2]) if u >= 2 else -1
                if x_prev >= self.S and x_prev2 >= self.S:
                    state = 'TEST'
        if lockout_remaining > 0:
            return Action.D
        x_prev = int(opp[-1])
        if state == 'C':
            if x_prev >= self.S:
                return Action.C
            return Action.D
        if state == 'TEST':
            return Action.C
        if history_len >= 2:
            x_prev2 = int(opp[-2])
            if x_prev >= self.S and x_prev2 >= self.S:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_45(BaseStrategy):
    """
    Start with defection, then cooperate only after sustained majority cooperation
    by opponents, and permanently defect after any clear withdrawal or in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.good = True
        self._threshold = math.ceil((self.game_description.n_players - 1) / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        last_round_index = self.game_description.n_rounds - 1
        if round_number == 0 or round_number >= last_round_index:
            return Action.D
        if not self.good:
            return Action.D
        if round_number > 0 and np.any(history.opponent_cooperators == 0):
            self.good = False
            return Action.D
        x_prev = int(history.opponent_cooperators[-1])
        if round_number == 1:
            x_prevprev = self.game_description.n_players - 1
        else:
            x_prevprev = int(history.opponent_cooperators[-2])
        if x_prev >= self._threshold and x_prev >= x_prevprev:
            return Action.C
        self.good = False
        return Action.D

class Strategy_SELFINTERESTED_46(BaseStrategy):
    """
    Threshold-based conditional cooperator:
    - Starts by defecting.
    - Enters cooperation only after two consecutive rounds of sufficiently high opponent cooperation.
    - Reverts to punishment after any weak-opposition round.
    - Defects in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 2))
        self.r = int(getattr(game_description, 'n_rounds', 0))
        self.k = float(getattr(game_description, 'k', 1.0))
        if self.n == 2:
            self.threshold = 1
        else:
            raw_h = math.ceil((self.n - 1) * (1.0 - 1.0 / self.k)) if self.k != 0 else self.n - 1
            self.threshold = max(0, min(self.n - 1, int(raw_h)))
        self.full_coop_threshold = self.n - 1 if self.n > 1 else 1
        self.mode = 'probe'
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            self.mode = 'probe'
            self._last_seen_round = 0
            return Action.D
        start_idx = self._last_seen_round
        end_idx = round_number
        if start_idx < 0:
            start_idx = 0
        for idx in range(start_idx, end_idx):
            if idx < 0 or idx >= len(history.opponent_cooperators):
                continue
            s_prev = int(history.opponent_cooperators[idx])
            if idx >= self.r - 2:
                pass
            elif self.mode == 'cooperate':
                required = self.full_coop_threshold if self.k >= self.n - 1e-09 else self.threshold
                if s_prev >= required:
                    self.mode = 'cooperate'
                else:
                    self.mode = 'punish'
            elif self.mode == 'punish':
                if idx >= 1:
                    s_prev2 = int(history.opponent_cooperators[idx - 1])
                    if s_prev >= self.threshold and s_prev2 >= self.threshold:
                        self.mode = 'cooperate'
            elif idx >= 1:
                s_prev2 = int(history.opponent_cooperators[idx - 1])
                if s_prev >= self.threshold and s_prev2 >= self.threshold:
                    self.mode = 'cooperate'
        self._last_seen_round = round_number
        if round_number >= self.r - 2:
            return Action.D
        last_s = int(history.opponent_cooperators[-1])
        if self.mode == 'punish':
            if round_number >= 1 and last_s >= self.threshold:
                if len(history.opponent_cooperators) >= 2:
                    prev_s = int(history.opponent_cooperators[-2])
                    if prev_s >= self.threshold and last_s >= self.threshold:
                        self.mode = 'cooperate'
            return Action.D
        if self.mode == 'cooperate':
            required = self.full_coop_threshold if self.k >= self.n - 1e-09 else self.threshold
            if last_s >= required:
                return Action.C
            self.mode = 'punish'
            return Action.D
        if len(history.opponent_cooperators) >= 2:
            prev_s = int(history.opponent_cooperators[-2])
            if last_s >= self.threshold and prev_s >= self.threshold:
                self.mode = 'cooperate'
        return Action.D

class Strategy_SELFINTERESTED_47(BaseStrategy):
    """
    Defect by default, and only cooperate when recent opponent cooperation has
    been very high, stable, and the game is still far enough from the end.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.window_size = 3
        self.low_streak = 0
        self.always_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t >= self.n_rounds - 2:
            return Action.D
        if self.always_defect:
            return Action.D
        opp_counts = history.opponent_cooperators
        n_opponents = max(self.n_players - 1, 0)
        if t < 2 or n_opponents <= 0:
            return Action.D
        if self.n_players == 2:
            if t >= 2 and opp_counts[-1] >= 1 and (opp_counts[-2] >= 1):
                return Action.C
            return Action.D
        h = min(self.window_size, t)
        if h < 2:
            return Action.D
        recent_counts = opp_counts[-h:]
        if len(recent_counts) < h:
            return Action.D
        recent_rates = recent_counts.astype(float) / float(n_opponents)
        avg_h = float(np.mean(recent_rates))
        last_rate = float(recent_rates[-1])
        threshold = float(self.n_players - 2) / float(self.n_players - 1)
        eps = 1e-12
        can_cooperate = avg_h > threshold + eps and last_rate > avg_h - 1.0 / float(self.n_players - 1) + eps and (t <= self.n_rounds - 3)
        if can_cooperate:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_48(BaseStrategy):
    """
    Belief-based public goods strategy:
    - Round 1: defect.
    - Afterwards, estimate the number of other cooperators using an EWMA-like rule
      with conservative fallback for volatile opponents.
    - Cooperate only when the estimated cooperation level makes cooperation
      individually profitable.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 0) or 0)
        self.r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.n_opponents = max(0, self.n - 1)
        if self.k > 0 and self.n > 0:
            self.threshold = self.n / self.k - 1.0
        else:
            self.threshold = float('inf')

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        if opp is None or len(opp) == 0:
            return Action.D
        counts = [int(x) for x in opp.tolist()]
        if self.threshold > self.n_opponents:
            return Action.D
        if self.threshold <= 0:
            return Action.C
        b = float(counts[0])
        for idx in range(1, len(counts)):
            x_t = float(counts[idx])
            x_prev = float(counts[idx - 1])
            if x_t == x_prev:
                b = x_t
                continue
            if abs(x_t - x_prev) >= 2:
                b = min(x_t, x_prev)
                continue
            lam = 0.5 if idx == 1 else 1.0 / 3.0
            b = lam * x_t + (1.0 - lam) * b
            if b < 0.0:
                b = 0.0
            elif b > self.n_opponents:
                b = float(self.n_opponents)
        if b < 0.0:
            b = 0.0
        elif b > self.n_opponents:
            b = float(self.n_opponents)
        return Action.C if b >= self.threshold else Action.D

class Strategy_SELFINTERESTED_49(BaseStrategy):
    """
    Unconditional defection strategy: play D in every round, regardless of history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._default_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        return self._default_action

class Strategy_SELFINTERESTED_50(BaseStrategy):
    """
    Conservative public-goods strategy:
    - Start by defecting.
    - Cooperate only after observing sustained majority cooperation.
    - Defect immediately on collapse or in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.n_players = n
        self.n_rounds = r
        self.threshold_high = math.ceil((n - 1) / 2) if n >= 2 else 0
        self.threshold_low = math.ceil((n - 1) / 3) if n >= 2 else 0
        self.confirmation = 2
        self.streak = 0
        self.in_cooperation_mode = False
        self.last_action = Action.D
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if self.n_players < 2 or self.n_rounds < 2:
            self.last_action = Action.D
            self._last_processed_round = round_number
            return Action.D
        if round_number == 0:
            self.streak = 0
            self.in_cooperation_mode = False
            self.last_action = Action.D
            self._last_processed_round = round_number
            return Action.D
        if round_number >= self.n_rounds - 1:
            self.last_action = Action.D
            self._last_processed_round = round_number
            return Action.D
        opponent_counts = getattr(history, 'opponent_cooperators', None)
        my_actions = getattr(history, 'my_actions', None)
        if opponent_counts is None or len(opponent_counts) < 1:
            self.streak = 0
            self.in_cooperation_mode = False
            self.last_action = Action.D
            self._last_processed_round = round_number
            return Action.D
        try:
            m_t = int(opponent_counts[-1])
        except Exception:
            self.streak = 0
            self.in_cooperation_mode = False
            self.last_action = Action.D
            self._last_processed_round = round_number
            return Action.D
        if m_t < 0 or m_t > max(0, self.n_players - 1):
            self.streak = 0
            self.in_cooperation_mode = False
            self.last_action = Action.D
            self._last_processed_round = round_number
            return Action.D
        m_tm1 = None
        m_tm2 = None
        if len(opponent_counts) >= 2:
            try:
                m_tm1 = int(opponent_counts[-2])
            except Exception:
                m_tm1 = None
        if len(opponent_counts) >= 3:
            try:
                m_tm2 = int(opponent_counts[-3])
            except Exception:
                m_tm2 = None
        last_my_action = None
        if my_actions is not None and len(my_actions) >= 1:
            try:
                last_my_action = Action.C if bool(my_actions[-1]) else Action.D
            except Exception:
                last_my_action = None
        if m_t >= self.threshold_high:
            self.streak += 1
        else:
            self.streak = 0
        good_t = m_t >= self.threshold_high
        if last_my_action == Action.C and m_t < self.threshold_low:
            self.in_cooperation_mode = False
            self.streak = 0
            self.last_action = Action.D
            self._last_processed_round = round_number
            return Action.D
        action = Action.D
        if self.streak >= self.confirmation and good_t and (m_tm1 is not None) and (m_tm1 >= self.threshold_high):
            if round_number < 3 or (m_tm1 is not None and m_t >= m_tm1 and (m_tm2 is None or m_tm1 >= m_tm2)):
                action = Action.C
                self.in_cooperation_mode = True
            else:
                action = Action.D
                self.in_cooperation_mode = False
        elif self.in_cooperation_mode and good_t and (self.streak >= self.confirmation):
            action = Action.C
        else:
            action = Action.D
            if not good_t:
                self.in_cooperation_mode = False
        self.last_action = action
        self._last_processed_round = round_number
        return action

class Strategy_SELFINTERESTED_51(BaseStrategy):
    """
    Two-threshold public-goods strategy with a short confirmation delay:
    - Defect initially and in the final round.
    - Enter cooperation only after two consecutive rounds of high observed
      opponent cooperation (q >= 2/3).
    - While cooperating, continue as long as observed cooperation stays at
      least 1/2; otherwise immediately defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'defect'
        self.high_streak = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        current_round = history.round_number
        if current_round >= n_rounds - 1:
            return Action.D
        if current_round == 0:
            return Action.D
        if len(history.opponent_cooperators) == 0 or n_opponents <= 0:
            return Action.D
        if self._last_processed_round < current_round:
            observed_cooperators = int(history.opponent_cooperators[-1])
            q = observed_cooperators / n_opponents if n_opponents > 0 else 0.0
            if q >= 2.0 / 3.0:
                self.high_streak += 1
            else:
                self.high_streak = 0
            if self.mode == 'defect':
                if self.high_streak >= 2:
                    self.mode = 'cooperate'
            elif q < 0.5:
                self.mode = 'defect'
                self.high_streak = 0
            self._last_processed_round = current_round
        return Action.C if self.mode == 'cooperate' else Action.D

class Strategy_SELFINTERESTED_52(BaseStrategy):
    """
    Defect by default, and cooperate only when observed opponent cooperation is
    high, stable, and non-decreasing relative to the recent moving average.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = game_description.n_players
        k = game_description.k
        self.theta_high = 1.0 - 1.0 / k if k and k != 0 else 1.0
        self.n_opponents = max(0, n - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds
        if round_number == 0:
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        if self.n_opponents <= 0:
            return Action.D
        opp_counts = history.opponent_cooperators
        x_vals = [float(q) / float(self.n_opponents) for q in opp_counts]
        x_t = x_vals[-1]
        L = min(3, round_number)
        if L <= 0:
            return Action.D
        recent_x = x_vals[-L:]
        m_t = float(np.mean(recent_x)) if len(recent_x) > 0 else 0.0
        if round_number >= 2:
            prev_L = min(3, round_number - 1)
            prev_recent_x = x_vals[-(prev_L + 1):-1] if prev_L > 0 else []
            m_prev = float(np.mean(prev_recent_x)) if len(prev_recent_x) > 0 else 0.0
        else:
            m_prev = x_t
        if m_t >= self.theta_high and x_t >= self.theta_high and (x_t >= m_prev):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_53(BaseStrategy):
    """
    Threshold-based adaptive strategy with exponentially weighted memory of opponent cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(getattr(game_description, 'n_players', 0) or 0)
        self.r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.lambda_ = 0.5
        self.ewma_opponent_coop = 0.0
        self.last_threshold = 0
        self.last_action = Action.D
        if self.k > 0:
            base = math.ceil((self.n - self.k) / self.k * self.n)
        else:
            base = self.n - 1
        self.base_threshold = max(0, min(self.n - 1, int(base))) if self.n >= 2 else 0

    def _n_opponents(self) -> int:
        return max(0, self.n - 1)

    def _all_previous_opponents_cooperated(self, history: PlayerHistory) -> bool:
        if history.round_number <= 0:
            return False
        arr = history.opponent_cooperators
        n_opps = self._n_opponents()
        for i in range(history.round_number):
            if int(arr[i]) < n_opps:
                return False
        return True

    def _all_previous_opponents_defected(self, history: PlayerHistory) -> bool:
        if history.round_number <= 0:
            return False
        arr = history.opponent_cooperators
        for i in range(history.round_number):
            if int(arr[i]) != 0:
                return False
        return True

    def _recent_high_coop(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False
        n_opps = self._n_opponents()
        threshold = max(0, self.n - 2)
        last_two = history.opponent_cooperators[-2:]
        for x in last_two:
            if int(x) < min(threshold, n_opps):
                return False
        return True

    def _adjust_threshold(self, history: PlayerHistory, base_t: int) -> int:
        t = max(0, min(self._n_opponents(), int(base_t)))
        if self.ewma_opponent_coop >= t + 1:
            t = max(0, t - 1)
        elif self.ewma_opponent_coop <= t - 2:
            t = min(self._n_opponents(), t + 1)
        if history.round_number >= 2:
            last_two = history.opponent_cooperators[-2:]
            if int(last_two[-1]) < t and int(last_two[-2]) < t:
                t = min(self._n_opponents(), t + 1)
        if history.round_number >= 3:
            last_three = history.opponent_cooperators[-3:]
            if int(last_three[-1]) >= t and int(last_three[-2]) >= t and (int(last_three[-3]) >= t):
                t = max(0, t - 1)
        return t

    def __call__(self, history: PlayerHistory) -> Action:
        round_no = int(getattr(history, 'round_number', 0) or 0)
        n_opps = self._n_opponents()
        if self.r > 0 and round_no == self.r - 1:
            return Action.D
        if round_no == 0:
            action = Action.C if self.k >= 2 else Action.D
            self.last_action = action
            self.last_threshold = self.base_threshold
            return action
        last_m = int(history.opponent_cooperators[-1]) if round_no > 0 else 0
        last_m = max(0, min(n_opps, last_m))
        self.ewma_opponent_coop = self.lambda_ * last_m + (1.0 - self.lambda_) * self.ewma_opponent_coop
        if self._all_previous_opponents_defected(history):
            self.last_threshold = self.base_threshold
            self.last_action = Action.D
            return Action.D
        if self._all_previous_opponents_cooperated(history):
            action = Action.C
            self.last_action = action
            self.last_threshold = self.base_threshold
            return action
        if self.n == 2:
            action = Action.C if last_m >= 1 and self.k > 1.5 else Action.D
            self.last_action = action
            self.last_threshold = 1
            return action
        if self.k <= 1.5 and (not self._recent_high_coop(history)):
            self.last_action = Action.D
            self.last_threshold = self.base_threshold
            return Action.D
        if self.r >= 3 and round_no >= self.r - 2:
            t_end = self._adjust_threshold(history, self.base_threshold)
            self.last_threshold = t_end
            action = Action.C if last_m >= t_end else Action.D
            self.last_action = action
            return action
        t = self._adjust_threshold(history, self.base_threshold)
        self.last_threshold = t
        action = Action.C if last_m >= t else Action.D
        self.last_action = action
        return action

class Strategy_SELFINTERESTED_54(BaseStrategy):
    """
    Threshold-based public-goods strategy:
    - Defect in round 1 and near the end of the game.
    - Cooperate only in the middle of the game when recent opponent cooperation
      has been consistently strong enough.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        if k <= 1.0:
            threshold = n - 1
        else:
            threshold = math.ceil((n - 1) * (1.0 - 1.0 / k))
        self.threshold = int(threshold)

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        n_players = int(self.game_description.n_players)
        T = self.threshold
        current_round = history.round_number + 1
        if current_round == 1:
            return Action.D
        if current_round >= max(1, n_rounds - 1):
            return Action.D
        if n_rounds <= 3:
            if current_round == 2 and history.round_number >= 1 and (n_players > 2):
                if int(history.opponent_cooperators[-1]) >= T:
                    return Action.C
            return Action.D
        hist_len = history.round_number
        if hist_len < 1:
            return Action.D
        m1 = int(history.opponent_cooperators[-1])
        if m1 < T:
            return Action.D
        if current_round >= 3:
            if hist_len < 2:
                return Action.D
            m2 = int(history.opponent_cooperators[-2])
            if m2 < T:
                return Action.D
        if current_round >= 4:
            if hist_len < 3:
                return Action.D
            m3 = int(history.opponent_cooperators[-3])
            if (m1 + m2 + m3) / 3.0 < T:
                return Action.D
        return Action.C

class Strategy_SELFINTERESTED_55(BaseStrategy):
    """
    Threshold-based smoothed-response strategy for the repeated N-player
    public goods game.

    Defect initially and in the final round, then cooperate only when recent
    opponent cooperation and the smoothed cooperation estimate both indicate
    the group can clear the payoff threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.threshold = int(math.ceil(self.n_players / self.k)) if self.k > 0 else self.n_players
        self.opponent_threshold = max(0, self.threshold - 1)
        self.smooth_prev = 0.7
        self.smooth_obs = 0.3
        self.initial_q = 0.5

    def _estimate_q(self, history: PlayerHistory) -> float:
        """
        Reconstruct the smoothed estimate q from observed opponent cooperation.
        q is updated after each observed round.
        """
        q = self.initial_q
        n_opponents = max(1, self.n_players - 1)
        for m in history.opponent_cooperators:
            m_int = int(m)
            frac = m_int / n_opponents if n_opponents > 0 else 0.0
            q = self.smooth_prev * q + self.smooth_obs * frac
        return q

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        r = self.n_rounds
        if t == 0:
            return Action.D
        if t >= r - 1:
            return Action.D
        q = self._estimate_q(history)
        pred = 1.0 + (self.n_players - 1) * q
        last_opponent_coops = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if t == r - 2:
            if len(history.opponent_cooperators) >= 2:
                prev_opponent_coops = int(history.opponent_cooperators[-2])
                if last_opponent_coops >= self.opponent_threshold and prev_opponent_coops >= self.opponent_threshold and (pred >= self.threshold):
                    return Action.C
            return Action.D
        if pred >= self.threshold and last_opponent_coops >= self.opponent_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_56(BaseStrategy):
    """
    Two-round confirmation public-goods strategy:
    - Defect in round 1.
    - Cooperate only in the middle game after two consecutive rounds
      with sufficiently many cooperating opponents.
    - Defect in the last two rounds.
    - If the game has 3 or fewer rounds, always defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0))
        k = float(getattr(game_description, 'k', 0.0))
        if k > 0:
            q = math.ceil(n / k)
        else:
            q = n
        self.q = min(max(0, int(q)), max(0, n - 1))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0))
        self.n_players = n

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        r = self.n_rounds
        if t == 0:
            return Action.D
        if r <= 3:
            return Action.D
        if t >= r - 2:
            return Action.D
        if t >= 2:
            m_prev1 = int(history.opponent_cooperators[-1])
            m_prev2 = int(history.opponent_cooperators[-2])
            if m_prev1 >= self.q and m_prev2 >= self.q:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_57(BaseStrategy):
    """
    Always defects in every round, while recording observed opponent cooperation counts.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        if current_round > len(self.observed_opponent_cooperators):
            recent_count = int(history.opponent_cooperators[-1]) if current_round > 0 else 0
            self.observed_opponent_cooperators.append(recent_count)
        return Action.D

class Strategy_SELFINTERESTED_58(BaseStrategy):
    """
    Exponentially weighted reciprocal-cooperation strategy with endgame defection,
    cooldown after weak cooperation or sharp drops, and simple stability checks.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.lambda_ = 0.7
        self.theta = 0.6
        self.theta_min = 0.4
        if self.n == 2:
            self.theta = 1.0
            self.theta_min = 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.r - 1:
            return Action.D
        n_opponents = max(self.n - 1, 1)
        S = 1.0
        cooldown = 0
        prev_q = None
        completed_rounds = min(len(history.opponent_cooperators), t)
        for i in range(completed_rounds):
            if cooldown > 0:
                cooldown -= 1
            x_i = int(history.opponent_cooperators[i])
            q_i = x_i / n_opponents
            S = self.lambda_ * S + (1.0 - self.lambda_) * q_i
            if q_i < self.theta_min:
                cooldown = 2
            if prev_q is not None and prev_q - q_i >= 0.25:
                cooldown = max(cooldown, 2)
            prev_q = q_i
        if cooldown > 0:
            return Action.D
        q_prev = None
        q_prevprev = None
        if completed_rounds >= 1:
            q_prev = int(history.opponent_cooperators[completed_rounds - 1]) / n_opponents
        if completed_rounds >= 2:
            q_prevprev = int(history.opponent_cooperators[completed_rounds - 2]) / n_opponents
        if self.n == 2:
            if q_prev is not None and q_prev >= 1.0 and (S >= self.theta):
                return Action.C
            return Action.D
        if q_prev is None:
            return Action.D
        stable_enough = completed_rounds == 1 or (q_prevprev is not None and q_prev >= q_prevprev)
        if S >= self.theta and q_prev >= self.theta_min and stable_enough:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_59(BaseStrategy):
    """
    Conditional public-goods strategy:
    - Cooperate in round 1 only if k > 2.
    - Defect in the final two decision rounds.
    - Otherwise cooperate only when recent cooperation has been sufficiently strong
      and stable near the profitability threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.tau = int(math.ceil(self.n / self.k)) if self.k > 0 else self.n
        self.rho = self.tau / self.n if self.n > 0 else 1.0
        self.coop_min = max(0, self.tau - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C if self.k > 2.0 else Action.D
        if t >= self.r - 1:
            return Action.D
        my_actions = history.my_actions
        opp_coop = history.opponent_cooperators
        last_idx = t - 1
        x_prev = int(opp_coop[last_idx]) + (1 if bool(my_actions[last_idx]) else 0)
        start_5 = max(0, t - 5)
        recent_total_frac = 0.0
        count_5 = 0
        for s in range(start_5, t):
            x_s = int(opp_coop[s]) + (1 if bool(my_actions[s]) else 0)
            recent_total_frac += x_s / self.n if self.n > 0 else 0.0
            count_5 += 1
        B_t = recent_total_frac / count_5 if count_5 > 0 else 0.0
        start_3 = max(0, t - 3)
        recent_good = 0
        for s in range(start_3, t):
            x_s = int(opp_coop[s]) + (1 if bool(my_actions[s]) else 0)
            if x_s >= self.coop_min:
                recent_good += 1
        if x_prev >= self.coop_min and recent_good >= 2 and (B_t >= self.rho):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_60(BaseStrategy):
    """
    Public goods strategy:
    - Probe with C only when the horizon is long enough.
    - Continue cooperating only after sustained evidence of cooperation.
    - Defect after any detected collapse or in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.k = game_description.k
        self.opponent_count = max(0, self.n_players - 1)
        self.threshold = 0.6 if self.k <= (self.n_players + 1) / 2 else 0.5

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        remaining_rounds = self.n_rounds - round_number
        if round_number == 0:
            return Action.C if self.n_rounds >= 4 else Action.D
        opp = history.opponent_cooperators
        if round_number >= 2:
            if opp[-1] == 0 and opp[-2] == 0:
                return Action.D
        if remaining_rounds <= 2:
            return Action.D
        if 1 <= round_number <= self.n_rounds - 3:
            last_x = int(opp[-1])
            last_p = last_x / self.opponent_count if self.opponent_count > 0 else 0.0
            recent = opp[-3:] if round_number >= 3 else opp[:]
            if self.opponent_count > 0 and len(recent) > 0:
                ma = float(np.mean(recent / self.opponent_count))
            else:
                ma = 0.0
            streak = 0
            for x in reversed(opp):
                p = int(x) / self.opponent_count if self.opponent_count > 0 else 0.0
                if p >= self.threshold:
                    streak += 1
                else:
                    break
            if ma >= self.threshold and (streak >= 2 or last_p >= self.threshold + 0.1) and (last_x > 0):
                return Action.C
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_61(BaseStrategy):
    """
    Smoothed threshold public-goods strategy with:
    - initial cooperation,
    - retaliation against zero-opponent-cooperation rounds,
    - temporary generosity after sustained cooperation,
    - endgame defection,
    - special handling for n=2 and very short games.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._p = 1.0
        self._processed_rounds = 0
        self._zero_lockout = False
        self._boost_rounds_remaining = 0

    def _sync_history(self, history: PlayerHistory) -> None:
        """Update internal estimate p and lockout state from any newly observed rounds."""
        total_rounds = history.round_number
        start = self._processed_rounds
        if start < 0:
            start = 0
        if start > total_rounds:
            start = total_rounds
        n_opponents = max(1, self.game_description.n_players - 1)
        for idx in range(start, total_rounds):
            opp = int(history.opponent_cooperators[idx])
            x_t = opp / n_opponents
            self._p = 0.7 * self._p + 0.3 * x_t
            if opp == 0:
                self._zero_lockout = True
            elif self._zero_lockout and x_t >= 0.5:
                self._zero_lockout = False
            if self._boost_rounds_remaining > 0:
                self._boost_rounds_remaining -= 1
        self._processed_rounds = total_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        self._sync_history(history)
        t = history.round_number
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        k = self.game_description.k
        if t == 0:
            return Action.C
        if n == 2:
            if t >= r - 2:
                return Action.D
            last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            return Action.C if last_opp > 0 else Action.D
        if r <= 2:
            if t >= r - 1:
                return Action.D
        if t >= r - 2:
            return Action.D
        n_opponents = max(1, n - 1)
        last_x = None
        if len(history.opponent_cooperators) > 0:
            last_x = int(history.opponent_cooperators[-1]) / n_opponents
        if self._zero_lockout:
            if last_x is not None and last_x >= 0.5:
                self._zero_lockout = False
            else:
                return Action.D
        if self._boost_rounds_remaining <= 0 and t >= 3:
            recent = history.opponent_cooperators[-3:]
            if len(recent) == 3:
                recent_x = [int(v) / n_opponents for v in recent]
                if all((x >= 0.5 for x in recent_x)):
                    self._boost_rounds_remaining = 2
        if self._boost_rounds_remaining > 0:
            self._boost_rounds_remaining -= 1
            return Action.C
        threshold = 1.0 / k if k > 0 else 1.0
        return Action.C if self._p >= threshold else Action.D

class Strategy_SELFINTERESTED_62(BaseStrategy):
    """
    Threshold-based public goods strategy with cautious start, sustained-cooperation
    requirement, and unconditional defection on the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        if k <= 0:
            self.threshold = n
        else:
            self.threshold = int(math.ceil((n - 1) / k))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if n_rounds > 0 and t == n_rounds - 1:
            return Action.D
        if t == 0:
            return Action.D

        def is_good(round_index: int) -> bool:
            if round_index < 0 or round_index >= len(history.opponent_cooperators):
                return False
            return int(history.opponent_cooperators[round_index]) >= self.threshold
        if t == 1:
            return Action.C if is_good(0) else Action.D
        good_prev = is_good(t - 1)
        good_prev2 = is_good(t - 2)
        if good_prev and good_prev2:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_63(BaseStrategy):
    """
    Adaptive threshold strategy for the repeated N-player Public Goods Game.

    - Cooperates initially.
    - Tracks opponent cooperation with an exponentially weighted belief q_t.
    - Uses a threshold tau = n/k - 1.
    - Applies windowed smoothing and several robustness overrides.
    - Defects on the final round unless everyone else cooperated in the previous round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.alpha = 0.7
        self._last_history_len = 0
        self._cached_q = 1.0

    def _opponent_rate(self, count: int) -> float:
        n_opponents = max(1, self.game_description.n_players - 1)
        return float(count) / float(n_opponents)

    def _threshold(self) -> float:
        k = float(self.game_description.k)
        if k <= 0:
            return float('inf')
        return float(self.game_description.n_players) / k - 1.0

    def _compute_belief(self, history: PlayerHistory) -> float:
        n_rounds_played = history.round_number
        if n_rounds_played <= 0:
            return 1.0
        q = 1.0
        counts = history.opponent_cooperators
        for idx in range(n_rounds_played):
            m_t = self._opponent_rate(int(counts[idx]))
            q = self.alpha * q + (1.0 - self.alpha) * m_t
        if all((int(x) == 0 for x in counts[:n_rounds_played])):
            q = 0.0
        elif all((int(x) == self.game_description.n_players - 1 for x in counts[:n_rounds_played])):
            q = 1.0
        w = min(3, n_rounds_played)
        if w > 0:
            recent = counts[n_rounds_played - w:n_rounds_played]
            recent_rates = [self._opponent_rate(int(x)) for x in recent]
            avg_recent = float(np.mean(recent_rates)) if len(recent_rates) > 0 else 0.0
            q = 0.5 * q + 0.5 * avg_recent
        return max(0.0, min(1.0, q))

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds_total = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            self._cached_q = 1.0
            self._last_history_len = 0
            return Action.C
        if t >= n_rounds_total - 1:
            prev_all_coop = False
            if t - 1 >= 0 and len(history.opponent_cooperators) >= t:
                prev_all_coop = int(history.opponent_cooperators[t - 1]) == max(0, self.game_description.n_players - 1)
            self._last_history_len = t
            self._cached_q = self._compute_belief(history)
            return Action.C if prev_all_coop else Action.D
        tau = self._threshold()
        q_t = self._compute_belief(history)
        if t >= 2:
            last = int(history.opponent_cooperators[t - 1])
            prev = int(history.opponent_cooperators[t - 2])
            if prev - last >= 2:
                w = min(3, t)
                recent = history.opponent_cooperators[t - w:t]
                recent_rates = [self._opponent_rate(int(x)) for x in recent]
                avg_recent = float(np.mean(recent_rates)) if len(recent_rates) > 0 else 0.0
                if avg_recent <= tau:
                    self._last_history_len = t
                    self._cached_q = q_t
                    return Action.D
        self._last_history_len = t
        self._cached_q = q_t
        if q_t == tau:
            return Action.D
        return Action.C if q_t > tau else Action.D

class Strategy_SELFINTERESTED_64(BaseStrategy):
    """
    Adaptive threshold public-goods strategy with a decreasing cooperation target
    and hard defection in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.lambda_ = 0.5
        n_opponents = max(1, self.n_players - 1)
        if self.k > self.n_players - 1:
            a1 = 1.0
        else:
            denom = self.k if self.k != 0 else 1.0
            a1 = math.ceil((self.n_players - 1) / denom) / n_opponents
        self.a1 = max(0.0, min(1.0, float(a1)))

    def __call__(self, history: PlayerHistory) -> Action:
        round_idx = history.round_number
        if round_idx <= 0:
            return Action.C if self.a1 > 0.0 else Action.D
        t = round_idx + 1
        if t == self.n_rounds:
            return Action.D
        opp_counts = history.opponent_cooperators
        n_opponents = max(1, self.n_players - 1)

        def coop_rate(count: int) -> float:
            return float(count) / float(n_opponents)

        def clamp01(x: float) -> float:
            return max(0.0, min(1.0, x))
        targets = [self.a1]
        max_obs = len(opp_counts)
        for idx in range(1, max_obs):
            prev_m = coop_rate(int(opp_counts[idx - 1]))
            prev_a = targets[-1]
            next_a = clamp01((self.n_players - self.k) / float(n_opponents) + self.lambda_ * (prev_a - prev_m))
            targets.append(next_a)
        last_m = coop_rate(int(opp_counts[-1]))
        last_a = targets[-1]
        if t == self.n_rounds - 1:
            if len(opp_counts) < 2 or len(targets) < 2:
                return Action.D
            prev_m = coop_rate(int(opp_counts[-2]))
            prev_a = targets[-2]
            if last_m >= last_a and prev_m >= prev_a:
                return Action.C
            return Action.D
        next_a = clamp01((self.n_players - self.k) / float(n_opponents) + self.lambda_ * (last_a - last_m))
        return Action.C if last_m >= next_a else Action.D

class Strategy_SELFINTERESTED_65(BaseStrategy):
    """
    Start with defection, defect in the final round, and cooperate only when
    recent opponent cooperation is strong enough to justify maintaining a
    cooperative pattern. After a short defection run, require a near-unanimous
    signal to re-enter cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        if self.k > 0:
            self.q = max(1, math.ceil(self.n_players / self.k) - 1)
        else:
            self.q = 1
        self.n_opponents = max(0, self.n_players - 1)
        self.standard_threshold = self.q / self.n_opponents if self.n_opponents > 0 else 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        h_last = int(opp[-1]) if len(opp) > 0 else 0
        my_actions = history.my_actions
        if len(my_actions) > 0 and bool(my_actions[-1]):
            if h_last < self.q:
                return Action.D
        if len(my_actions) >= 2 and (not bool(my_actions[-1])) and (not bool(my_actions[-2])):
            if len(opp) >= 2:
                h_prev = int(opp[-2])
            else:
                h_prev = 0
            if h_last == self.n_opponents and h_prev >= self.q:
                return Action.C
            return Action.D
        m = min(3, t)
        if m <= 0 or self.n_opponents <= 0:
            return Action.D
        recent = opp[-m:] if len(opp) >= m else opp
        avg_t = float(np.mean(recent)) / self.n_opponents if len(recent) > 0 else 0.0
        if h_last >= self.q and avg_t >= self.standard_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_66(BaseStrategy):
    """
    Adaptive threshold strategy for the N-player Public Goods Game.

    - Defects in round 1.
    - Cooperates only when recent opponent cooperation is at or above the
      profitability threshold and the recent average also supports cooperation.
    - Always defects in the final round.
    - Uses a reset/lockout rule after repeated low-cooperation rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        if k <= 0:
            threshold = n
        else:
            threshold = math.ceil(n / k)
        self.cooperation_cutoff = int(threshold)
        self.safety_target = max(0, self.cooperation_cutoff - 1)
        self.locked_defect = False
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        r = int(self.game_description.n_rounds)
        t = int(history.round_number)
        if t == 0:
            self.last_seen_round = 0
            self.locked_defect = False
            return Action.D
        if t >= r - 1:
            self.last_seen_round = t
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            self.last_seen_round = t
            return Action.D
        s = self.safety_target
        T = self.cooperation_cutoff
        last_m = int(opp[-1])
        avg_m = float(np.mean(opp)) if len(opp) > 0 else 0.0
        defection_signals = 0
        cooperation_signals = 0
        recent = min(2, len(opp))
        for i in range(1, recent + 1):
            m = int(opp[-i])
            if m < s:
                defection_signals += 1
            if m >= T:
                cooperation_signals += 1
        if defection_signals >= 2:
            self.locked_defect = True
        elif cooperation_signals >= 2:
            self.locked_defect = False
        elif last_m >= T:
            self.locked_defect = False
        if self.locked_defect:
            if last_m >= T:
                self.locked_defect = False
            else:
                self.last_seen_round = t
                return Action.D
        if last_m >= s and avg_m >= s:
            self.last_seen_round = t
            return Action.C
        self.last_seen_round = t
        return Action.D

class Strategy_SELFINTERESTED_67(BaseStrategy):
    """
    Conservative trigger strategy for repeated public goods games:
    defect initially and in the last round, cooperate only after
    sustained near-unanimous cooperation, with immediate fallback to
    defection upon any drop in observed group cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'defect'
        self.streak = 0
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number + 1
        if current_round == 1 or current_round == r:
            return Action.D
        if history.round_number <= 0:
            return Action.D

        def total_cooperators(round_index: int) -> int:
            if round_index < 0 or round_index >= history.round_number:
                return -1
            opp = int(history.opponent_cooperators[round_index])
            mine = 1 if bool(history.my_actions[round_index]) else 0
            return opp + mine
        self.mode = 'defect'
        self.streak = 0
        if history.round_number >= 2:
            for idx in range(history.round_number - 1):
                m_prev = total_cooperators(idx)
                if m_prev >= n - 1:
                    self.streak += 1
                    if self.streak >= 2:
                        self.mode = 'cooperate'
                else:
                    self.streak = 0
                    self.mode = 'defect'
        last_m = total_cooperators(history.round_number - 1)
        if current_round == 2:
            return Action.C if last_m >= n - 1 else Action.D
        if current_round == r - 1:
            if history.round_number < 2:
                return Action.D
            prev1 = total_cooperators(history.round_number - 1)
            prev2 = total_cooperators(history.round_number - 2)
            if prev1 >= n - 1 and prev2 >= n - 1:
                return Action.C
            return Action.D
        if last_m >= n - 1:
            self.streak += 1
        else:
            self.streak = 0
            self.mode = 'defect'
        if self.streak >= 2:
            self.mode = 'cooperate'
        if self.mode == 'cooperate':
            if last_m >= n - 2:
                return Action.C
            self.mode = 'defect'
            return Action.D
        return Action.D

class Strategy_SELFINTERESTED_68(BaseStrategy):
    """
    Threshold-based conditional cooperator for the repeated public goods game.

    - Defect in round 1 and in the final round.
    - Cooperate only when the previous two rounds both had sufficiently many
      cooperating opponents, using threshold T = ceil(n / k).
    - If T exceeds the maximum possible number of cooperating opponents, always defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        if k > 0:
            self.threshold = int(math.ceil(n / k))
        else:
            self.threshold = n
        self.n_players = n
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if self.threshold > self.n_players - 1:
            return Action.D
        if round_number < 2:
            return Action.D
        last_opponents = int(history.opponent_cooperators[-1])
        prev_opponents = int(history.opponent_cooperators[-2])
        if last_opponents >= self.threshold and prev_opponents >= self.threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_69(BaseStrategy):
    """
    Always defects in every round of the repeated Public Goods Game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', None)
        self.n_rounds = getattr(game_description, 'n_rounds', None)
        self.k = getattr(game_description, 'k', None)
        self.observed_opponent_cooperators = []

    def __call__(self, history: PlayerHistory) -> Action:
        if history is not None and hasattr(history, 'opponent_cooperators'):
            round_number = getattr(history, 'round_number', 0)
            if round_number > 0:
                try:
                    self.observed_opponent_cooperators.append(int(history.opponent_cooperators[-1]))
                except Exception:
                    pass
        return Action.D

class Strategy_SELFINTERESTED_70(BaseStrategy):
    """
    Defect initially and in the final round.
    Cooperate only after observing two consecutive rounds in which all opponents cooperated.
    Any loss of full opponent cooperation resets the strategy back to defecting.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'defensive'
        self.full_coop_streak = 0
        self.last_processed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        current_round = history.round_number
        if current_round >= n_rounds - 1:
            self.mode = 'defensive'
            return Action.D
        if current_round == 0:
            self.mode = 'defensive'
            self.full_coop_streak = 0
            self.last_processed_round = 0
            return Action.D
        streak = 0
        mode = 'defensive'
        for idx in range(current_round):
            opp_count = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            if n_opponents > 0 and opp_count == n_opponents:
                streak += 1
                if streak >= 2:
                    mode = 'cooperative'
            else:
                streak = 0
                mode = 'defensive'
        self.mode = mode
        self.full_coop_streak = streak
        self.last_processed_round = current_round
        if self.mode == 'cooperative':
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_71(BaseStrategy):
    """
    Threshold-based reciprocity with short punishments, exploitation of
    unexpectedly cooperative rounds, and a cooperative lock under sustained
    high cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.n_opponents = max(0, self.n_players - 1)
        self._N = self.n_opponents
        self.coop_score = 0.0
        self.last_m = 0
        self.punish_left = 0
        self.mode = 'exploit'
        self._seen_rounds = 0
        self._full_coop_streak = 0
        self._very_high_coop_streak = 0
        self._high_score_streak = 0
        self._coop_lock = False

    def _update_from_history(self, history: PlayerHistory) -> None:
        start = self._seen_rounds
        end = history.round_number
        if end <= start:
            return
        N = self._N
        low_punish_threshold = math.ceil(0.3 * N) if N > 0 else 0
        very_high_threshold = math.ceil(0.8 * N) if N > 0 else 0
        for idx in range(start, end):
            m = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            self.last_m = m
            prev_score = self.coop_score
            frac = m / N if N > 0 else 0.0
            self.coop_score = 0.7 * self.coop_score + 0.3 * frac
            if m < low_punish_threshold and prev_score < 0.5:
                self.punish_left = 2
            if m == N and N > 0:
                self._full_coop_streak += 1
            else:
                self._full_coop_streak = 0
            if m >= very_high_threshold and N > 0:
                self._very_high_coop_streak += 1
            else:
                self._very_high_coop_streak = 0
            if self.coop_score >= 0.9:
                self._high_score_streak += 1
            else:
                self._high_score_streak = 0
            if self._very_high_coop_streak >= 2:
                self._coop_lock = True
            if self._coop_lock and self.coop_score < 0.6:
                self._coop_lock = False
            self.mode = 'punish' if self.punish_left > 0 else 'reciprocate' if self._coop_lock or self.coop_score >= 0.75 else 'exploit'
        self._seen_rounds = end

    def __call__(self, history: PlayerHistory) -> Action:
        self._update_from_history(history)
        if history.round_number == 0:
            self.mode = 'exploit'
            return Action.D
        N = self._N
        last_m = self.last_m
        if history.round_number >= self.n_rounds - 2:
            if self.coop_score < 0.8:
                self.mode = 'endgame_defect'
                return Action.D
            if last_m >= math.ceil(0.7 * N) if N > 0 else True:
                self.mode = 'endgame_cooperate'
                return Action.C
            self.mode = 'endgame_defect'
            return Action.D
        if self.punish_left > 0:
            self.punish_left -= 1
            self.mode = 'punish'
            return Action.D
        if self._coop_lock:
            self.mode = 'reciprocate'
            return Action.C
        if last_m == N and self._high_score_streak < 2:
            self.mode = 'exploit'
            return Action.D
        if self.coop_score >= 0.75:
            self.mode = 'reciprocate'
            return Action.C
        if self.coop_score <= 0.25:
            self.mode = 'exploit'
            return Action.D
        if last_m >= (math.ceil(0.6 * N) if N > 0 else 0):
            self.mode = 'reciprocate'
            return Action.C
        self.mode = 'exploit'
        return Action.D

class Strategy_SELFINTERESTED_72(BaseStrategy):
    """
    Cautious public-goods strategy:
    - Defect in the first round and in the final two rounds.
    - Cooperate only after sustained opponent cooperation at or above the threshold.
    - Immediately defect for two rounds after any observed weakening.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        if self.n_players > 0:
            self.threshold = 1.0 - self.k / self.n_players
        else:
            self.threshold = 1.0
        self.mode = Action.D
        self.ewma_signal = 0.0
        self.punish_rounds_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        r = self.n_rounds
        n_opponents = max(0, self.n_players - 1)
        theta = self.threshold
        if t == 1 or t >= r - 1:
            self.mode = Action.D
            return Action.D
        if history.round_number <= 0 or n_opponents <= 0:
            self.mode = Action.D
            return Action.D
        q_values = []
        for x in history.opponent_cooperators:
            q_values.append(float(x) / float(n_opponents) if n_opponents > 0 else 0.0)
        s = q_values[0]
        for q in q_values[1:]:
            s = 0.5 * q + 0.5 * s
        current_q = q_values[-1]
        if q_values[-1] < theta:
            self.punish_rounds_remaining = 2
        elif len(q_values) >= 2 and q_values[-2] < theta:
            self.punish_rounds_remaining = max(self.punish_rounds_remaining, 1)
        if self.punish_rounds_remaining > 0:
            self.punish_rounds_remaining -= 1
            self.mode = Action.D
            return Action.D
        recent_ok = len(q_values) >= 2 and q_values[-1] >= theta and (q_values[-2] >= theta)
        if t <= r - 2 and s >= theta and (current_q >= theta) and recent_ok:
            self.mode = Action.C
            return Action.C
        self.mode = Action.D
        return Action.D

class Strategy_SELFINTERESTED_73(BaseStrategy):
    """
    Conditional cooperator with short cooldowns:
    - defects initially and in the final round
    - cooperates only when recent opponent cooperation is consistently high
    - enters a 2-round cooldown after weak cooperation or a meaningful drop
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.cooldown = 0
        self.trusted = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        k = self.game_description.k
        tau = 1.0 / k if k > 0 else 1.0
        round_number = history.round_number
        current_round = round_number + 1
        if current_round >= n_rounds:
            self.cooldown = 0
            self.trusted = 0
            return Action.D
        if self.cooldown > 0:
            self.cooldown -= 1
            self.trusted = 0
            return Action.D
        if round_number == 0:
            self.trusted = 0
            return Action.D
        x_last = int(history.opponent_cooperators[-1])
        denom = max(1, n_players - 1)
        rho_last = x_last / denom
        recent = history.opponent_cooperators[-3:]
        avg_rho_last3 = float(np.mean(recent)) / denom if len(recent) > 0 else 0.0
        if round_number >= 2:
            x_prev = int(history.opponent_cooperators[-2])
        else:
            x_prev = x_last
        if rho_last < tau or x_last < x_prev:
            self.cooldown = 2
            self.trusted = 0
            return Action.D
        if rho_last >= tau and avg_rho_last3 >= tau:
            if round_number > 1 and x_last < x_prev:
                self.trusted = 0
                return Action.D
            self.trusted += 1
            return Action.C
        self.trusted = 0
        return Action.D

class Strategy_SELFINTERESTED_74(BaseStrategy):
    """
    Always defect in every round, regardless of history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._default_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        return self._default_action

class Strategy_SELFINTERESTED_75(BaseStrategy):
    """
    Threshold-based public goods strategy with optional punishment mode:
    cooperate initially, keep cooperating only while the previous round met
    the cooperation threshold, defect on the final round, and defect during
    recovery until two consecutive sufficiently cooperative rounds are seen.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0))
        k = float(getattr(game_description, 'k', 0.0))
        if k > 0:
            self.threshold = int(math.ceil(n_players / k))
        else:
            self.threshold = n_players + 1
        self.punishment_mode = False
        self.recovery_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        total_rounds = int(getattr(self.game_description, 'n_rounds', 0))
        if round_number == 0:
            self.punishment_mode = False
            self.recovery_streak = 0
            return Action.C
        if total_rounds > 0 and round_number >= total_rounds - 1:
            return Action.D
        if len(history.my_actions) == 0 or len(history.opponent_cooperators) == 0:
            return Action.C
        last_my_action = bool(history.my_actions[-1])
        last_opponent_cooperators = int(history.opponent_cooperators[-1])
        last_total_cooperators = last_opponent_cooperators + (1 if last_my_action else 0)
        if self.punishment_mode:
            if last_total_cooperators >= self.threshold:
                self.recovery_streak += 1
            else:
                self.recovery_streak = 0
            if self.recovery_streak >= 2:
                self.punishment_mode = False
                self.recovery_streak = 0
                return Action.C
            return Action.D
        if last_total_cooperators < self.threshold:
            self.punishment_mode = True
            self.recovery_streak = 0
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_76(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Starts in defection mode.
    - Cooperates only after sustained high opponent cooperation.
    - Defects in the first and final rounds, and avoids entering cooperation too late.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.alpha = 0.7
        self.enter = 0.7
        self.stay = 0.55
        self.mode = 'DEFECT'
        self.last_seen_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        t = int(history.round_number)
        self.last_seen_round = t
        opp = history.opponent_cooperators
        if t > 0 and n > 1:
            denom = float(n - 1)
            f_vals = [float(x) / denom for x in opp[:t]]
        else:
            f_vals = []
        ema_vals = []
        for i, f in enumerate(f_vals):
            if i == 0:
                ema_vals.append(f)
            else:
                ema_vals.append(self.alpha * ema_vals[-1] + (1.0 - self.alpha) * f)
        if t == 0:
            action = Action.D
        elif t >= r - 1:
            action = Action.D
        else:
            f_prev = f_vals[-1] if f_vals else 0.0
            ema_prev = ema_vals[-1] if ema_vals else 0.0
            last_three_zero = False
            if len(f_vals) >= 3:
                last_three_zero = f_vals[-1] == 0.0 and f_vals[-2] == 0.0 and (f_vals[-3] == 0.0)
            if last_three_zero:
                self.mode = 'DEFECT'
            if self.mode == 'DEFECT':
                if t <= r - 3 and ema_prev >= self.enter and (f_prev >= self.enter):
                    action = Action.C
                else:
                    action = Action.D
            elif ema_prev >= self.stay:
                action = Action.C
            else:
                action = Action.D
        if t > 0:
            f_last = f_vals[-1] if f_vals else 0.0
            ema_last = ema_vals[-1] if ema_vals else 0.0
            if len(f_vals) >= 3 and f_vals[-1] == 0.0 and (f_vals[-2] == 0.0) and (f_vals[-3] == 0.0):
                self.mode = 'DEFECT'
            else:
                my_last_action = bool(history.my_actions[-1])
                if not my_last_action and f_last >= self.enter:
                    self.mode = 'COOPERATE'
                elif f_last < self.stay:
                    self.mode = 'DEFECT'
                else:
                    self.mode = self.mode
        return action

class Strategy_SELFINTERESTED_77(BaseStrategy):
    """
    Probe with defection, then cooperate only after two consecutive nonterminal
    rounds with sufficient opponent cooperation, and never cooperate in the
    final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        if k <= 0:
            self.threshold = n
        else:
            self.threshold = int(math.ceil((n - 1) / k))
        self.mode = 'defect'

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            self.mode = 'defect'
            return Action.D
        if round_number >= n_rounds - 1:
            self.mode = 'defect'
            return Action.D
        if round_number < 2:
            self.mode = 'defect'
            return Action.D
        last = int(history.opponent_cooperators[-1])
        prev = int(history.opponent_cooperators[-2])
        qualifies = last >= self.threshold
        qualifies_prev = prev >= self.threshold
        if self.mode == 'cooperative':
            if not qualifies:
                self.mode = 'defect'
                return Action.D
            return Action.C
        if qualifies and qualifies_prev:
            self.mode = 'cooperative'
            return Action.C
        self.mode = 'defect'
        return Action.D

class Strategy_SELFINTERESTED_78(BaseStrategy):
    """
    Tit-for-tat-style threshold strategy with a two-strike trust mechanism:
    - Cooperate on the first round.
    - Cooperate only after sufficiently high opponent cooperation in the previous round.
    - Defect after weak cooperation, escalating to a firm defection phase after two weak rounds.
    - Always defect in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        if k > 0:
            self.H = math.ceil((n - 1) / k)
        else:
            self.H = n - 1
        self.trust = True
        self.bad_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            self.trust = True
            self.bad_streak = 0
            return Action.C
        if round_number >= max(0, n_rounds - 2):
            return Action.D
        x = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if not self.trust:
            if x >= self.H:
                self.trust = True
                self.bad_streak = 0
            return Action.D
        if x >= self.H:
            self.bad_streak = 0
            self.trust = True
            return Action.C
        self.bad_streak += 1
        if self.bad_streak >= 2:
            self.trust = False
        return Action.D

class Strategy_SELFINTERESTED_79(BaseStrategy):
    """
    Always defect in every round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_80(BaseStrategy):
    """
    Tit-for-cooperative strategy with short punishment, recovery confirmation,
    and unconditional defection in the final rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_rounds = int(game_description.n_rounds)
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(1, self.n_players - 1)
        self.m = min(3, max(0, self.n_rounds - 1))
        self.endgame_length = min(2, max(0, self.n_rounds - 1))
        self.endgame_start = self.n_rounds - self.endgame_length
        self.lock = 0
        self.recovery_streak = 0
        self.recovering = False

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            self.lock = 0
            self.recovery_streak = 0
            self.recovering = False
            return Action.C
        if round_number >= self.endgame_start:
            return Action.D
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q_last = last_opponents / self.n_opponents
        if self.m > 0 and len(history.opponent_cooperators) > 0:
            recent = history.opponent_cooperators[-self.m:]
            q_vals = np.asarray(recent, dtype=float) / self.n_opponents
            avg_last = float(np.mean(q_vals)) if q_vals.size > 0 else 0.0
        else:
            avg_last = 0.0
        if self.lock > 0:
            self.lock -= 1
            self.recovery_streak = 0
            self.recovering = True
            return Action.D
        if self.recovering:
            if q_last >= 2.0 / 3.0:
                self.recovery_streak += 1
            else:
                self.recovery_streak = 0
            if self.recovery_streak >= 2:
                self.recovering = False
                self.recovery_streak = 0
            else:
                return Action.D
        if q_last < 1.0 / 3.0:
            self.lock = 2
            self.recovering = True
            self.recovery_streak = 0
            return Action.D
        if q_last >= 2.0 / 3.0:
            return Action.C
        if avg_last >= 2.0 / 3.0:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_81(BaseStrategy):
    """
    Always defect in every round, regardless of history or opponent behavior.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number > 0:
            self.observed_opponent_cooperators.append(int(history.opponent_cooperators[-1]))
        return Action.D

class Strategy_SELFINTERESTED_82(BaseStrategy):
    """
    Conditional reciprocator for the repeated N-player Public Goods Game.

    - Start by cooperating.
    - Defect in the final round.
    - In intermediate rounds, cooperate only when recent opponent cooperation
      is sufficiently high and not clearly declining.
    - Includes simple edge-case handling for small games and repeated calls.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.window = max(1, min(3, math.floor(self.n_rounds / 3)))
        self.tau = max(0.5, 1.0 / self.k) if self.k > 0 else 1.0
        self.delta = 1.0 / max(1, self.n_players - 1)
        self._last_round_number = -1
        self._last_action = Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        r = self.n_rounds
        n = self.n_players
        n_opponents = max(1, n - 1)
        if history.round_number == self._last_round_number:
            if t == r:
                return Action.D
            return self._last_action
        if t >= r:
            self._last_round_number = history.round_number
            self._last_action = Action.D
            return Action.D
        if t == 1:
            self._last_round_number = history.round_number
            self._last_action = Action.C
            return Action.C
        if n == 2:
            prev_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
            action = Action.C if prev_opp >= 1 else Action.D
            self._last_round_number = history.round_number
            self._last_action = action
            return action
        opp_hist = history.opponent_cooperators
        hist_len = len(opp_hist)
        ell = min(self.window, t - 1, hist_len)
        if ell <= 0:
            q = 0.0
        else:
            recent = opp_hist[hist_len - ell:hist_len]
            q = float(np.mean(recent)) / n_opponents if ell > 0 else 0.0
        if t >= 3 and hist_len >= 2:
            m_prev = float(opp_hist[-1]) / n_opponents
            m_prev2 = float(opp_hist[-2]) / n_opponents
            trend = m_prev - m_prev2
        else:
            trend = 0.0
        action = Action.C if q >= self.tau and trend >= -self.delta else Action.D
        self._last_round_number = history.round_number
        self._last_action = action
        return action

class Strategy_SELFINTERESTED_83(BaseStrategy):
    """
    Cooperate in round 1, defect in the final round, and otherwise cooperate
    iff the total number of cooperators in the previous round met the threshold
    ceil(n / k). If prior information is unavailable or ambiguous, defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.k = float(getattr(game_description, 'k', 0.0) or 0.0)
        if self.k > 0:
            self.threshold = math.ceil(self.n_players / self.k)
        else:
            self.threshold = self.n_players + 1
        self.last_action = None
        self.last_total_cooperators = None

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = getattr(history, 'round_number', 0)
        if round_number == 0:
            self.last_action = Action.C
            self.last_total_cooperators = None
            return Action.C
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            self.last_action = Action.D
            if len(history.opponent_cooperators) > 0 and len(history.my_actions) > 0:
                self.last_total_cooperators = int(history.opponent_cooperators[-1]) + (1 if bool(history.my_actions[-1]) else 0)
            return Action.D
        if len(history.my_actions) == 0 or len(history.opponent_cooperators) == 0:
            self.last_action = Action.D
            self.last_total_cooperators = None
            return Action.D
        my_last_cooperated = bool(history.my_actions[-1])
        opponents_last_cooperators = int(history.opponent_cooperators[-1])
        total_last_cooperators = opponents_last_cooperators + (1 if my_last_cooperated else 0)
        self.last_total_cooperators = total_last_cooperators
        if total_last_cooperators >= self.threshold:
            self.last_action = Action.C
            return Action.C
        self.last_action = Action.D
        return Action.D

class Strategy_SELFINTERESTED_84(BaseStrategy):
    """
    Always defects in every round, regardless of history or observed cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._default_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        if history is None:
            return self._default_action
        round_number = getattr(history, 'round_number', None)
        if round_number is None:
            return self._default_action
        return self._default_action

class Strategy_SELFINTERESTED_85(BaseStrategy):
    """
    Conditional cooperation strategy for the N-player Public Goods Game.

    - Defect in the first round.
    - Cooperate in round 2 only if the previous observed cooperation count
      meets the threshold B = ceil(n / k).
    - From round 3 onward, cooperate only if the previous round was both
      sufficiently cooperative and at least as cooperative as the round before.
    - Defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        if k > 0:
            self.threshold = int(math.ceil(n / k))
        else:
            self.threshold = n + 1
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.D
        if self.n_rounds > 0 and t >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if t == 1:
            return Action.C if int(opp[-1]) >= self.threshold else Action.D
        last = int(opp[-1])
        prev = int(opp[-2])
        if last >= self.threshold and last >= prev:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_86(BaseStrategy):
    """
    Always defect in every round, regardless of history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.current_round = 0
        self.observed_opponent_cooperators = []

    def __call__(self, history: PlayerHistory) -> Action:
        self.current_round = history.round_number
        if history.round_number > 0:
            self.observed_opponent_cooperators = list(history.opponent_cooperators)
        return Action.D

class Strategy_SELFINTERESTED_87(BaseStrategy):
    """
    Threshold-based contingent strategy with a short calibration phase,
    a stability-based main phase, and a conservative endgame.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.m = max(1, self.n - 1)
        self.calibration_rounds = max(1, math.ceil(self.r / 5))
        self.coop_threshold = math.ceil(0.5 * self.m)
        self.reset_active = 0
        self._processed_rounds = 0

    def _update_state_from_history(self, history: PlayerHistory) -> None:
        """
        Process any newly observed rounds exactly once.
        """
        current_len = history.round_number
        if current_len <= self._processed_rounds:
            return
        start = self._processed_rounds
        end = current_len
        for idx in range(start, end):
            x_t = int(history.opponent_cooperators[idx])
            played_c = bool(history.my_actions[idx])
            if played_c and x_t < self.coop_threshold:
                self.reset_active = 2
            if self.reset_active > 0:
                if x_t == self.m:
                    self.reset_active = 0
                else:
                    self.reset_active = max(0, self.reset_active - 1)
        self._processed_rounds = current_len

    def __call__(self, history: PlayerHistory) -> Action:
        self._update_state_from_history(history)
        t = history.round_number + 1
        if t == 1:
            return Action.C if self.k > 1 and self.n <= 3 else Action.D
        if self.reset_active > 0:
            return Action.D
        last_x = int(history.opponent_cooperators[-1]) if history.round_number >= 1 else 0
        last_p = last_x / self.m if self.m > 0 else 0.0
        if t <= self.calibration_rounds:
            return Action.C if last_p >= 0.8 else Action.D
        if t >= max(1, self.r - 2):
            if history.round_number >= 2:
                if int(history.opponent_cooperators[-1]) == self.m and int(history.opponent_cooperators[-2]) == self.m:
                    return Action.C
            elif history.round_number == 1:
                if int(history.opponent_cooperators[-1]) == self.m:
                    return Action.C
            return Action.D
        recent_count = min(3, history.round_number)
        if recent_count <= 0:
            return Action.D
        recent_slice = history.opponent_cooperators[-recent_count:]
        recent_rates = [int(x) / self.m for x in recent_slice] if self.m > 0 else [0.0] * recent_count
        avg_recent = float(np.mean(recent_rates)) if recent_rates else 0.0
        if last_x < self.coop_threshold:
            return Action.D
        if history.round_number >= 2:
            prev_x = int(history.opponent_cooperators[-2])
            if last_x < prev_x:
                return Action.D
        if avg_recent >= 0.6:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_88(BaseStrategy):
    """
    Unconditional defection strategy for the repeated N-player Public Goods Game.
    Always plays D in every round, regardless of history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', None)
