class Strategy_SELFINTERESTED_91(BaseStrategy):
    """
    Defensive public-goods strategy:
    - Start with defection.
    - Cooperate only after sustained opponent cooperation.
    - Enter a caution mode after weak cooperation and defect unless stability is restored.
    - Never cooperate in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.recent_opponent_cooperations = []
        self.caution_state = False
        self.consecutive_high_count = 0
        self.caution_rounds_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        k = self.game_description.k
        if history.round_number >= r - 1:
            return Action.D
        if history.round_number == 0:
            self.caution_state = False
            self.caution_rounds_remaining = 0
            self.consecutive_high_count = 0
            self.recent_opponent_cooperations = []
            return Action.D
        observed = history.opponent_cooperators
        self.recent_opponent_cooperations = [int(x) for x in observed.tolist()] if hasattr(observed, 'tolist') else list(observed)
        threshold = k / n
        n_opponents = n - 1
        if n_opponents <= 0:
            return Action.D
        rates = [x / n_opponents for x in self.recent_opponent_cooperations]
        last_rate = rates[-1] if rates else 0.0
        last_is_high = last_rate >= threshold
        if n == 2:
            if len(rates) >= 2 and rates[-1] >= 1.0 and (rates[-2] >= 1.0):
                self.caution_state = False
                self.caution_rounds_remaining = 0
                self.consecutive_high_count = 2
                return Action.C
            self.caution_state = True if len(rates) > 0 and rates[-1] < threshold else self.caution_state
            self.caution_rounds_remaining = max(0, self.caution_rounds_remaining - 1) if self.caution_rounds_remaining > 0 else 0
            self.consecutive_high_count = self.consecutive_high_count + 1 if last_is_high else 0
            return Action.D
        if last_is_high:
            self.consecutive_high_count += 1
        else:
            self.consecutive_high_count = 0
        if not last_is_high:
            self.caution_state = True
            self.caution_rounds_remaining = 2
        elif self.caution_rounds_remaining > 0:
            self.caution_rounds_remaining -= 1
        recent_rates = rates[-3:] if len(rates) >= 3 else rates
        avg_recent_rate = float(np.mean(recent_rates)) if recent_rates else 0.0
        last_two_high = False
        if len(rates) >= 2:
            last_two_high = rates[-1] >= threshold and rates[-2] >= threshold
        if self.consecutive_high_count >= 2:
            self.caution_state = False
            self.caution_rounds_remaining = 0
        if self.caution_state:
            if last_two_high:
                self.caution_state = False
                return Action.C
            return Action.D
        if last_is_high and avg_recent_rate >= threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_92(BaseStrategy):
    """
    Threshold-based adaptive public-goods strategy:
    - Defect initially and in the last two rounds.
    - Cooperate only when opponent cooperation is sufficiently high and stable.
    - Immediately defect after weak cooperation.
    - Re-test cooperation after two consecutive strongly cooperative rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        if k > 0:
            self.theta = int(math.ceil(n / k))
        else:
            self.theta = n
        self.delta = 1
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        n_rounds = self.n_rounds
        if t == 0:
            return Action.D
        if t >= n_rounds - 2:
            return Action.D
        opp = history.opponent_cooperators
        latest = int(opp[-1]) if len(opp) > 0 else 0
        if latest == 0:
            return Action.D
        if len(opp) >= 2:
            prev = int(opp[-2])
            if latest >= self.theta + 1 and prev >= self.theta + 1:
                return Action.C
        if latest >= self.theta:
            if t == 1:
                return Action.C
            prev = int(opp[-2]) if len(opp) >= 2 else latest
            if latest - prev >= -self.delta:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_93(BaseStrategy):
    """
    Defection first, then conditional cooperation after two consecutive fully
    cooperative rounds by all opponents. Cooperation persists only while the
    full-cooperation streak continues; any break resets to defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'DEFECT'
        self.streak = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        n_players = int(getattr(self.game_description, 'n_players', 0) or 0)
        n_opponents = max(0, n_players - 1)
        full_threshold = n_opponents
        round_number = int(history.round_number)
        opp = history.opponent_cooperators
        start = max(0, min(self._processed_rounds, round_number))
        end = max(0, min(round_number, len(opp)))
        for idx in range(start, end):
            val = opp[idx]
            try:
                s_t = int(val)
            except Exception:
                s_t = -1
            if s_t < 0 or s_t > n_opponents:
                self.streak = 0
                self.mode = 'DEFECT'
            elif s_t == full_threshold:
                self.streak += 1
                if self.streak >= 2:
                    self.mode = 'COOPERATE'
            else:
                self.streak = 0
                self.mode = 'DEFECT'
        self._processed_rounds = max(self._processed_rounds, end)
        if round_number == 0:
            return Action.D
        if round_number > len(opp):
            return Action.D
        if n_rounds > 0 and round_number == n_rounds - 1:
            return Action.C if self.mode == 'COOPERATE' and self.streak >= 2 else Action.D
        return Action.C if self.mode == 'COOPERATE' else Action.D

class Strategy_SELFINTERESTED_94(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Defect in round 1 and the final round.
    - In between, cooperate only when recent opponent cooperation is persistently
      above a break-even threshold, with small adaptive adjustments based on trend.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._ewma_alpha = 0.3
        self._ewma_beta = 0.7

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        n_players = getattr(self.game_description, 'n_players', 0)
        k = getattr(self.game_description, 'k', 0.0)
        if history is None:
            return Action.D
        if history.round_number == 0:
            return Action.D
        if n_rounds > 0 and history.round_number >= n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if opp is None or len(opp) == 0:
            return Action.D
        ewma = 0.0
        prev_m = None
        inc_streak = 0
        dec_streak = 0
        last_m = None
        for m in opp:
            try:
                m_int = int(m)
            except Exception:
                return Action.D
            if m_int < 0:
                return Action.D
            ewma = self._ewma_beta * ewma + self._ewma_alpha * m_int
            last_m = m_int
            if prev_m is not None:
                if m_int > prev_m:
                    inc_streak += 1
                    dec_streak = 0
                elif m_int < prev_m:
                    dec_streak += 1
                    inc_streak = 0
                else:
                    inc_streak = 0
                    dec_streak = 0
            prev_m = m_int
        if k <= 0:
            return Action.D
        base_threshold = n_players / k - 1.0
        adjustment = 0.0
        if inc_streak >= 2:
            adjustment -= 1.0
        elif dec_streak >= 2:
            adjustment += 1.0
        threshold = max(0.0, base_threshold + adjustment)
        if last_m is None or last_m <= 1:
            return Action.D
        if ewma > threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_95(BaseStrategy):
    """
    Always defect in every round of the repeated Public Goods Game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_96(BaseStrategy):
    """
    Cooperate only after two consecutive rounds of unanimous opponent cooperation,
    defect immediately otherwise, and always defect in the first and last rounds.
    Once any observed round falls below full opponent cooperation, defect forever.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.defect_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        last_round_index = self.game_description.n_rounds - 1
        round_number = history.round_number
        if round_number > 0:
            opp = history.opponent_cooperators
            if np.any(opp < n - 1):
                self.defect_mode = True
        if round_number == 0 or round_number == last_round_index:
            return Action.D
        if self.defect_mode:
            return Action.D
        if round_number == 1:
            return Action.C if history.opponent_cooperators[-1] == n - 1 else Action.D
        if history.opponent_cooperators[-1] == n - 1 and history.opponent_cooperators[-2] == n - 1:
            return Action.C
        self.defect_mode = True
        return Action.D

class Strategy_SELFINTERESTED_97(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Cooperate first
    - Estimate opponent cooperation rate with exponential smoothing
    - Defect after exploitation, remain cautious until two good rounds
    - Defect by default near the final round unless sustained high cooperation is observed
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        self.n_opponents = max(0, n - 1)
        self.threshold = 1.0 / k if k != 0 else float('inf')
        self.alpha = 1.0 if int(game_description.n_rounds) == 2 else 2.0 / max(1, min(10, int(game_description.n_rounds) - 1)) if int(game_description.n_rounds) > 2 else 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        T = self.threshold
        alpha = self.alpha
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        my_actions = history.my_actions
        E = 1.0
        bad_mode = False
        good_after_bad = 0
        zero_streak = 0
        high_streak = 0
        last_x = 0.0
        x_history = []
        for i in range(t):
            denom = self.n_opponents
            x = float(opp[i]) / denom if denom > 0 else 0.0
            x_history.append(x)
            last_x = x
            if i > 0:
                E = (1.0 - alpha) * E + alpha * x
            if x == 0.0:
                zero_streak += 1
            else:
                zero_streak = 0
            if x >= T + 0.1:
                high_streak += 1
            else:
                high_streak = 0
            if bad_mode:
                if x >= T:
                    good_after_bad += 1
                    if good_after_bad >= 2:
                        bad_mode = False
                        good_after_bad = 0
                else:
                    good_after_bad = 0
            elif bool(my_actions[i]) and x < T:
                bad_mode = True
                good_after_bad = 0
        last_two_x_ge_T = False
        if t >= 2:
            last_two_x_ge_T = x_history[-1] >= T and x_history[-2] >= T
        last_two_x_ge_high = False
        if t >= 2:
            last_two_x_ge_high = x_history[-1] >= T + 0.1 and x_history[-2] >= T + 0.1
        last_three_x_ge_high = False
        if t >= 3:
            last_three_x_ge_high = x_history[-1] >= T + 0.1 and x_history[-2] >= T + 0.1 and (x_history[-3] >= T + 0.1)
        if t == n_rounds - 1:
            if last_two_x_ge_high and E >= T + 0.1:
                return Action.C
            return Action.D
        if zero_streak >= 2:
            return Action.D
        if bad_mode:
            return Action.D
        if last_three_x_ge_high:
            return Action.C
        if E > T + 0.05:
            return Action.C
        if E < T - 0.05:
            return Action.D
        if last_two_x_ge_T:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_98(BaseStrategy):
    """
    Always defect in every round, regardless of history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_99(BaseStrategy):
    """
    Public goods strategy:
    - Start with D
    - Cooperate only after sustained, sufficiently strong cooperation by opponents
    - Enforce a 2-round cooldown after any drop below the support threshold
    - Always defect in the final round
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        threshold = (n - 1) * (1.0 - (k / n if n != 0 else 0.0))
        self.q = max(1, int(math.ceil(threshold)))
        self.cooldown = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        if len(history.opponent_cooperators) > 0:
            last_h = int(history.opponent_cooperators[-1])
            if last_h < self.q:
                self.cooldown = 2
        if self.cooldown > 0:
            self.cooldown -= 1
            return Action.D
        h_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
        if h_prev < self.q:
            return Action.D
        if round_number == 1:
            return Action.C
        h_prev2 = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else 0
        if h_prev2 < self.q:
            return Action.D
        if h_prev < h_prev2:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_100(BaseStrategy):
    """
    Always defects in every round, ignoring all history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_101(BaseStrategy):
    """
    Threshold-based public goods strategy:
    - Opens cooperatively (or guarded by k >= n/2).
    - Cooperates only when recent opponent cooperation supports a positive return.
    - Defects in the final round and becomes more cautious near the endgame.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.n_players = n
        self.k = k
        if n > 0 and k > 0:
            self.threshold = int(math.ceil(n / k - 1))
        else:
            self.threshold = 0
        self.guarded_opening = k >= n / 2 if n > 0 else True

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        if round_number == 0:
            return Action.C if self.guarded_opening else Action.D
        if n_rounds > 0 and round_number >= n_rounds - 1:
            return Action.D
        recent = history.opponent_cooperators
        last = int(recent[-1]) if len(recent) >= 1 else 0
        prev = int(recent[-2]) if len(recent) >= 2 else None
        T = self.threshold
        if n_rounds > 1 and round_number == n_rounds - 2:
            return Action.C if last >= T + 1 else Action.D
        if len(recent) >= 2:
            if last >= T and prev >= max(T - 1, 0):
                return Action.C
            return Action.D
        return Action.C if last >= T else Action.D

class Strategy_SELFINTERESTED_102(BaseStrategy):
    """
    Threshold-based mode strategy:
    - Start in low-cooperation mode.
    - Cooperate only when the observed opponent cooperation rate is high enough.
    - Defect in the first and last round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        self.n_players = n
        self.k = k
        self.theta_up = 1.0 - 1.0 / k if k != 0 else 1.0
        self.theta_down = max(0.0, self.theta_up - 1.0 / (n - 1)) if n > 1 else 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.n_players
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= int(self.game_description.n_rounds) - 1:
            return Action.D
        if history.opponent_cooperators is None or len(history.opponent_cooperators) == 0:
            return Action.D
        prev_coop = int(history.opponent_cooperators[-1])
        denom = n - 1
        if denom <= 0:
            return Action.D
        q = prev_coop / denom
        prev_mode_high = False
        try:
            prev_mode_high = bool(history.my_actions[-1])
        except Exception:
            prev_mode_high = False
        if q >= self.theta_up:
            mode_high = True
        elif q <= self.theta_down:
            mode_high = False
        else:
            mode_high = prev_mode_high
        return Action.C if mode_high else Action.D

class Strategy_SELFINTERESTED_103(BaseStrategy):
    """
    Start cooperative, reward sustained/strong cooperation, punish defection,
    and always defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.trust = 1
        self.trend = 0
        self.streak = 0
        self._last_f = None

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        n_opponents = max(0, n - 1)
        if history.round_number == 0:
            return Action.C
        t = history.round_number + 1
        if t > r - 1:
            x_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            f_last = x_last / n_opponents if n_opponents > 0 else 0.0
            self.trend = 1 if self._last_f is not None and f_last > self._last_f else 0
            self._last_f = f_last
            if n_opponents > 0 and x_last >= math.ceil(n_opponents / 2):
                self.streak += 1
            else:
                self.streak = 0
            return Action.D
        x = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        f = x / n_opponents if n_opponents > 0 else 0.0
        window = min(3, t - 1)
        if window > 0 and len(history.opponent_cooperators) > 0:
            recent = history.opponent_cooperators[-window:]
            if n_opponents > 0:
                f_bar = float(np.mean(recent) / n_opponents)
            else:
                f_bar = 0.0
        else:
            f_bar = f
        last_rise = 1 if self._last_f is not None and f > self._last_f else 0
        self.trend = last_rise
        self.trust = f_bar
        self._last_f = f
        if n_opponents > 0 and x >= math.ceil(n_opponents / 2):
            self.streak += 1
        else:
            self.streak = 0
        if x == n_opponents and n_opponents > 0:
            return Action.C
        if x == 0:
            return Action.D
        threshold = 0.5
        if f_bar >= threshold and (self.streak >= 1 or last_rise == 1):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_104(BaseStrategy):
    """
    Always defect in every round of the repeated Public Goods Game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.k = getattr(game_description, 'k', 0.0)

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_105(BaseStrategy):
    """
    Always defect in every round of the repeated public goods game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._always_defect = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        _ = history
        return self._always_defect

class Strategy_SELFINTERESTED_106(BaseStrategy):
    """
    Start by defecting, then cooperate only after sustained high observed cooperation.
    Defect in the final min(3, r) rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.coop_rate = 0.0
        self.stable_coop_streak = 0
        self.last_seen_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        if history.round_number == 0:
            self.coop_rate = 0.0
            self.stable_coop_streak = 0
            self.last_seen_round = 0
            return Action.D
        coop_rate = 0.0
        stable_coop_streak = 0
        n_opponents = max(0, n - 1)
        coop_threshold_count = math.ceil(0.75 * n_opponents) if n_opponents > 0 else 0
        rounds_observed = history.round_number
        for t in range(rounds_observed):
            try:
                m_t = int(history.opponent_cooperators[t])
            except Exception:
                m_t = 0
            if m_t < 0 or m_t > n_opponents:
                m_t = 0
            if n_opponents > 0:
                observed_rate = m_t / n_opponents
            else:
                observed_rate = 0.0
            coop_rate = 0.7 * coop_rate + 0.3 * observed_rate
            if m_t >= coop_threshold_count:
                stable_coop_streak += 1
            else:
                stable_coop_streak = 0
        self.coop_rate = coop_rate
        self.stable_coop_streak = stable_coop_streak
        self.last_seen_round = rounds_observed
        endgame_start = max(0, r - min(3, r))
        if history.round_number >= endgame_start:
            return Action.D
        if self.coop_rate >= 0.75 and self.stable_coop_streak >= 2:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_107(BaseStrategy):
    """
    Always defect in every round, ignoring history except for round tracking.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_108(BaseStrategy):
    """
    Always defect in every round, regardless of history or observations.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.k = getattr(game_description, 'k', 0.0)

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_SELFINTERESTED_109(BaseStrategy):
    """
    Cautious public-goods strategy:
    - Defect in the opening and endgame.
    - Cooperate only after sustained, strong cooperation.
    - Enter recovery mode after any meaningful drop and require two strong rounds to return to cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = getattr(game_description, 'n_players', 0) or 0
        n_opponents = max(0, n_players - 1)
        self.high = math.ceil(0.8 * n_opponents)
        self.stable = math.ceil(0.7 * n_opponents)

    def __call__(self, history: PlayerHistory) -> Action:
        r = getattr(self.game_description, 'n_rounds', 0) or 0
        t = history.round_number + 1
        if r > 1 and t >= r - 1:
            return Action.D
        if t == 1:
            return Action.D
        counts = history.opponent_cooperators
        num_obs = len(counts)
        in_recovery = False
        if num_obs > 0:
            if np.any(counts < self.stable):
                in_recovery = True
            if num_obs >= 2 and counts[-1] >= self.high and (counts[-2] >= self.high):
                in_recovery = False
        if in_recovery:
            if num_obs >= 2 and counts[-1] >= self.high and (counts[-2] >= self.high):
                return Action.C
            return Action.D
        if t == 2:
            return Action.C if num_obs >= 1 and counts[-1] >= self.high else Action.D
        if num_obs >= 2:
            if counts[-1] >= self.high and counts[-2] >= self.stable and (counts[-1] >= counts[-2]):
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_110(BaseStrategy):
    """
    Always defect in every round, regardless of history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._defect_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        return self._defect_action

class Strategy_SELFINTERESTED_111(BaseStrategy):
    """
    Threshold-based conditional cooperation strategy.

    - Round 1: defect.
    - Later rounds: cooperate if the previous round had at least T cooperating opponents,
      where T = max(1, ceil(n / k)).
    - Optionally supports a two-round moving average rule via `self.use_two_round_average`.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = getattr(game_description, 'n_players', 0)
        k = getattr(game_description, 'k', 0.0)
        if n is None or n < 2:
            n = 2
        if k is None or k <= 0:
            threshold = 1
        else:
            threshold = int(math.ceil(n / k))
        self.threshold = max(1, threshold)
        self.use_two_round_average = False

    def __call__(self, history: PlayerHistory) -> Action:
        if history is None:
            return Action.D
        round_number = getattr(history, 'round_number', 0)
        if round_number <= 0:
            return Action.D
        opponent_cooperators = getattr(history, 'opponent_cooperators', None)
        if opponent_cooperators is None or len(opponent_cooperators) == 0:
            return Action.D
        if self.use_two_round_average and len(opponent_cooperators) >= 2:
            last_two = opponent_cooperators[-2:]
            avg_cooperators = float(np.mean(last_two))
            return Action.C if avg_cooperators >= self.threshold else Action.D
        return Action.C if int(opponent_cooperators[-1]) >= self.threshold else Action.D

class Strategy_SELFINTERESTED_112(BaseStrategy):
    """
    Conditional contributor with a two-round cooperation test and hard endgame defection.
    Opens with defection, cooperates only after two consecutive high-cooperation rounds,
    and defects in the final two rounds regardless of history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.opponent_threshold = max(0, self.n_players - 2)
        self.bad_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        self.bad_streak = 0
        for s_t in history.opponent_cooperators:
            if int(s_t) < self.opponent_threshold:
                self.bad_streak += 1
            else:
                self.bad_streak = 0
        if round_number == 0:
            return Action.D
        if round_number >= max(0, self.n_rounds - 2):
            return Action.D
        if self.bad_streak >= 1:
            return Action.D
        if round_number >= 2:
            if int(history.opponent_cooperators[-1]) >= self.opponent_threshold and int(history.opponent_cooperators[-2]) >= self.opponent_threshold:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_113(BaseStrategy):
    """
    Cooperative until sustained high cooperation is observed, then maintains cooperation
    unless cooperation weakens; defects immediately after low cooperation and in the final
    endgame window.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.high = 0.8
        self.low = 0.5
        self.W = min(3, max(0, self.r - 1))
        self.L = min(2, max(0, self.r - 1))
        self.streak_high = 0
        self.punish = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        current_round = round_number + 1
        if round_number == 0:
            self.streak_high = 0
            self.punish = 0
            return Action.C
        n_opponents = max(1, self.n - 1)
        streak_high = 0
        punish = 0
        for idx in range(round_number):
            opp_count = int(history.opponent_cooperators[idx])
            opp_rate = opp_count / n_opponents
            if opp_rate >= self.high:
                streak_high += 1
            else:
                streak_high = 0
            if opp_rate < self.low:
                punish = self.W
            if punish > 0:
                punish -= 1
        self.streak_high = streak_high
        self.punish = punish
        if self.r > 0 and current_round > self.r - self.L:
            return Action.D
        if self.punish > 0:
            return Action.D
        if self.streak_high >= self.W:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_114(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Defect initially.
    - Track recent opponent cooperation rates.
    - Cooperate only in sustained high-cooperation phases.
    - Temporarily lock into defection after a zero-cooperation round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        denom = max(1, n - 1)
        tau_in = max(0.5, (n / k - 1.0) / denom) if k > 0 else 0.5
        tau_out = max(0.0, tau_in - 1.0 / (2.0 * denom))
        self.tau_in = float(tau_in)
        self.tau_out = float(tau_out)
        self._zero_lock_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        n_players = int(self.game_description.n_players)
        n_opponents = max(1, n_players - 1)
        if history.round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        prev_count = int(opp[-1]) if len(opp) > 0 else 0
        prev_s = prev_count / n_opponents
        if prev_count == 0:
            self._zero_lock_remaining = 1
            return Action.D
        if self._zero_lock_remaining > 0:
            self._zero_lock_remaining -= 1
            return Action.D
        window = opp[-3:] if len(opp) >= 3 else opp
        if len(window) == 0:
            running_score = 0.0
        else:
            scores = [int(x) / n_opponents for x in window]
            running_score = float(sum(scores) / len(scores))
        last_two_high = False
        if len(opp) >= 2:
            s1 = int(opp[-1]) / n_opponents
            s2 = int(opp[-2]) / n_opponents
            last_two_high = s1 >= self.tau_in and s2 >= self.tau_in
        if history.round_number == n_rounds - 1:
            return Action.C if last_two_high else Action.D
        if last_two_high:
            return Action.C
        if running_score >= self.tau_in and prev_s >= self.tau_out:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_115(BaseStrategy):
    """
    Adaptive cooperation strategy for the repeated N-player public goods game.

    - Round 1: cooperate.
    - Final round: defect.
    - Otherwise:
        * For n = 2: cooperate only if the other player cooperated in both of the
          last two rounds; with insufficient history, require cooperation in the
          available round(s).
        * For n > 2: cooperate only if recent opponent cooperation is high and
          stable:
              - with fewer than 2 observed rounds, require only the primary threshold;
              - with 2+ observed rounds, require both recent rounds to meet their
                thresholds and neither to be zero.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.primary_threshold = math.ceil(2 * max(self.n_players - 1, 0) / 3)
        self.secondary_threshold = math.ceil(max(self.n_players - 1, 0) / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        n_opponents = max(self.n_players - 1, 0)
        a = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        b = int(history.opponent_cooperators[-2]) if round_number >= 2 else a
        if self.n_players == 2:
            if round_number < 2:
                return Action.C if a >= 1 else Action.D
            return Action.C if a >= 1 and b >= 1 else Action.D
        if round_number < 2:
            return Action.C if a >= self.primary_threshold else Action.D
        if a == 0 or b == 0:
            return Action.D
        if a >= self.primary_threshold and b >= self.secondary_threshold:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_116(BaseStrategy):
    """
    Threshold-based cooperative strategy for the repeated N-player Public Goods Game.

    - Starts with defection.
    - Cooperates only after observing a sustained streak of sufficiently high
      opponent cooperation and only if the previous cooperative round was not
      unprofitable.
    - Reverts immediately to defection if the streak is broken or cooperation
      was not recently successful.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 2))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 1))
        self.k = float(getattr(game_description, 'k', 1.0))
        if self.k == 0:
            self.threshold = math.inf
        else:
            self.threshold = int(math.ceil(self.n_players / self.k) - 1)
        self.streak_length = 2 if self.n_rounds >= 4 else 1

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0 or self.n_rounds == 2:
            return Action.D
        if t < self.streak_length:
            return Action.D
        recent_opponents = history.opponent_cooperators[t - self.streak_length:t]
        if len(recent_opponents) < self.streak_length:
            return Action.D
        if not np.all(recent_opponents >= self.threshold):
            return Action.D
        if not bool(history.my_actions[-1]):
            return Action.D
        if float(history.my_payoffs[-1]) < 1.0:
            return Action.D
        return Action.C

class Strategy_SELFINTERESTED_117(BaseStrategy):
    """
    Two-state trigger strategy with hard final-round defection:
    cooperate only after two consecutive rounds of full opponent cooperation,
    and defect in the first and final rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.full_coop_threshold = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number >= 2:
            if history.opponent_cooperators[-1] == self.full_coop_threshold and history.opponent_cooperators[-2] == self.full_coop_threshold:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_118(BaseStrategy):
    """
    Two-threshold hysteresis strategy for the N-player Public Goods Game.
    Starts with defection, cooperates only after sustained opponent cooperation,
    defects quickly when cooperation drops, and always defects in the terminal round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = game_description.n_players
        k = game_description.k
        self.theta_high = max(0.5, k / n) if n > 0 else 0.5
        self.theta_low = max(0.25, self.theta_high - 0.15)
        self.last_opponent_coop_rate = None
        self.second_last_opponent_coop_rate = None
        self.last_own_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        if history.round_number >= n_rounds - 1:
            self.last_own_action = Action.D
            return Action.D
        if history.round_number == 0:
            self.second_last_opponent_coop_rate = None
            self.last_opponent_coop_rate = None
            self.last_own_action = Action.D
            return Action.D
        n_opponents = max(0, n_players - 1)
        if n_opponents == 0:
            p = 0.0
        else:
            m = int(history.opponent_cooperators[-1])
            p = m / n_opponents
        prev_p = self.last_opponent_coop_rate
        prev_prev_p = self.second_last_opponent_coop_rate
        high = self.theta_high
        low = self.theta_low
        cooperate_lock = False
        if p >= high:
            if prev_p is not None and prev_p >= high:
                cooperate_lock = True
            elif prev_prev_p is not None and prev_prev_p >= high:
                cooperate_lock = True
        if p <= low:
            action = Action.D
        elif prev_p is not None and prev_p <= low and (not cooperate_lock):
            action = Action.D
        elif p >= high and cooperate_lock:
            action = Action.C
        else:
            action = self.last_own_action
        self.second_last_opponent_coop_rate = self.last_opponent_coop_rate
        self.last_opponent_coop_rate = p
        self.last_own_action = action
        return action

class Strategy_SELFINTERESTED_119(BaseStrategy):
    """
    Threshold-triggered public-goods strategy:
    - Defect in round 1 and in the final round.
    - Cooperate only after two consecutive rounds with sufficiently many cooperating opponents.
    - Fall back to defection when cooperation becomes too weak or unstable.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0) or 0)
        n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.n_players = n_players
        self.n_rounds = n_rounds
        self.k = k
        n_opponents = max(0, n_players - 1)
        if k > 0:
            self.H = int(math.ceil(n_opponents * (k - 1.0) / k))
        else:
            self.H = 0
        self.L = max(0, self.H - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(getattr(history, 'round_number', 0) or 0)
        if round_number == 0:
            return Action.D
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.D
        state = 'alert'
        high_streak = 0
        opponent_counts = history.opponent_cooperators
        past_rounds = min(round_number, len(opponent_counts))
        for t in range(past_rounds):
            m = int(opponent_counts[t])
            if state == 'alert':
                if m >= self.H:
                    high_streak += 1
                else:
                    high_streak = 0
                if high_streak >= 2:
                    state = 'trusting'
            elif m < self.L:
                state = 'alert'
                high_streak = 0
        if state == 'trusting':
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_120(BaseStrategy):
    """
    Selective cooperation strategy for the N-player Public Goods Game.

    - Opens with cooperation as a test.
    - Defects in the final round.
    - Cooperates only under clearly favorable recent cooperation signals.
    - Uses stricter rules for very small groups.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n_players - 1)
        self.t_high = int(math.ceil(self.n_opponents / 2)) if self.n_opponents > 0 else 0
        self.t_low = int(math.floor(self.n_opponents / 3)) if self.n_opponents > 0 else 0
        self.is_small_group = self.n_players in (2, 3)
        self.is_short_horizon = self.n_rounds == 2

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t >= self.n_rounds - 1:
            return Action.D
        if self.is_short_horizon:
            return Action.C if t == 0 else Action.D
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        last_m = int(opp[-1]) if len(opp) >= 1 else 0
        prev_m = int(opp[-2]) if len(opp) >= 2 else last_m
        if self.is_small_group:
            if len(opp) >= 2 and last_m == self.n_opponents and (prev_m == self.n_opponents):
                return Action.C
            return Action.D
        if last_m <= self.t_low:
            return Action.D
        if len(opp) >= 2:
            if prev_m - last_m >= 2:
                return Action.D
            if last_m - prev_m >= 2 and last_m >= self.t_high:
                return Action.C
        if len(opp) >= 2 and prev_m >= self.t_high and (last_m >= self.t_high):
            return Action.C
        if last_m >= self.t_high:
            return Action.C
        if last_m > self.n_opponents / 2:
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_121(BaseStrategy):
    """
    Cautious first, cooperative only under sustained evidence, and always defects at the end.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.cautious_threshold = math.ceil(0.75 * max(0, self.n - 1))
        self.cooperative_threshold = math.ceil(0.6 * max(0, self.n - 1))
        self.half_threshold = math.ceil(0.5 * max(0, self.n - 1))
        self.majority_threshold = math.ceil((self.n - 1) / 2)
        self.mode = 'cautious'
        self.score = 0
        self.processed_rounds = 0
        self.last_action = Action.D
        self.drop_lock = False
        self.recovery_streak = 0
        self.coop_streak = 0
        self.coop_lock = False

    def _update_state_from_latest_round(self, history: PlayerHistory) -> None:
        current_rounds = history.round_number
        if current_rounds <= self.processed_rounds:
            return
        idx = current_rounds - 1
        observed = int(history.opponent_cooperators[-1])
        if self.last_action == Action.C:
            if observed >= self.cautious_threshold:
                self.score += 1
        elif observed <= self.half_threshold:
            self.score -= 1
        if self.score >= 2:
            self.mode = 'cooperative'
        elif self.score <= -2:
            self.mode = 'cautious'
        if observed >= self.cooperative_threshold:
            self.coop_streak += 1
        else:
            self.coop_streak = 0
        if observed >= self.cautious_threshold:
            self.recovery_streak += 1
        else:
            self.recovery_streak = 0
        if idx >= 1:
            prev_observed = int(history.opponent_cooperators[-2])
            if observed <= prev_observed - 2:
                self.drop_lock = True
                self.recovery_streak = 0
                self.mode = 'cautious'
        if self.drop_lock and self.recovery_streak >= 2:
            self.drop_lock = False
        if self.coop_streak >= 3:
            self.coop_lock = True
            self.mode = 'cooperative'
        self.processed_rounds = current_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        self._update_state_from_latest_round(history)
        t = history.round_number + 1
        n = self.n
        r = self.r
        if t == 1 or t == r:
            self.last_action = Action.D
            return Action.D
        prev_m = int(history.opponent_cooperators[-1]) if history.round_number > 0 else 0
        if n == 2:
            action = Action.C if prev_m >= 1 else Action.D
            self.last_action = action
            return action
        if self.drop_lock:
            action = Action.D
            self.last_action = action
            return action
        if self.coop_lock:
            if t >= r - 1:
                action = Action.D
            else:
                action = Action.C if prev_m >= self.cooperative_threshold else Action.D
            self.last_action = action
            return action
        if self.mode == 'cooperative':
            action = Action.C if prev_m >= self.cooperative_threshold else Action.D
        else:
            q = prev_m / (n - 1) if n > 1 else 0.0
            if q >= 0.75 and prev_m >= self.majority_threshold and (history.round_number < 2 or int(history.opponent_cooperators[-1]) >= int(history.opponent_cooperators[-2])):
                action = Action.C
            else:
                action = Action.D
        self.last_action = action
        return action

class Strategy_SELFINTERESTED_122(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Starts with defection.
    - Cooperates only when recent opponent cooperation is consistently high,
      nondecreasing, and the game is not in the final two rounds.
    - Enters strict-defection mode if opponent cooperation ever drops below 50%.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.strict_defection = False

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        n_opponents = max(0, n_players - 1)
        round_idx = history.round_number
        if round_idx > 0 and n_opponents > 0:
            last_q = int(history.opponent_cooperators[-1])
            last_s = last_q / n_opponents
            if last_s < 0.5:
                self.strict_defection = True
        if round_idx == 0:
            return Action.D
        if round_idx >= max(0, n_rounds - 2):
            return Action.D
        if self.strict_defection:
            return Action.D
        lookback = min(3, round_idx)
        if lookback <= 0 or n_opponents <= 0:
            return Action.D
        recent_rates = []
        for offset in range(1, lookback + 1):
            q = int(history.opponent_cooperators[-offset])
            recent_rates.append(q / n_opponents)
        avg_t = float(np.mean(recent_rates)) if recent_rates else 0.0
        trend_t = all((recent_rates[i] >= recent_rates[i + 1] for i in range(len(recent_rates) - 1)))
        last_rate = recent_rates[0]
        if avg_t >= 0.7 and trend_t and (last_rate >= 0.6) and (round_idx <= max(0, n_rounds - 3)):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_123(BaseStrategy):
    """
    Adaptive conditional cooperator for the repeated N-player public goods game.

    - Starts by cooperating.
    - Rewards sustained, high cooperation.
    - Responds to sharp drops with temporary defection.
    - Locks into final-round defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._processed_rounds = 0
        self._recent_baseline = 0.0
        self._low_lockout_remaining = 0
        self._perfect_cooldown_remaining = 0
        self._perfect_mode_active = False
        self._high_coop_streak = 0
        self._near_perfect_streak = 0

    def _opponent_count(self) -> int:
        return max(0, self.game_description.n_players - 1)

    def _cooperation_rate(self, m: int) -> float:
        n_opponents = self._opponent_count()
        if n_opponents <= 0:
            return 0.0
        return float(m) / float(n_opponents)

    def _recent_cooperation_rate(self, history: PlayerHistory) -> float:
        t = history.round_number
        n_opponents = self._opponent_count()
        if t <= 0 or n_opponents <= 0:
            return 0.0
        start = max(0, t - 3)
        recent = history.opponent_cooperators[start:t]
        rates = [float(m) / float(n_opponents) for m in recent.tolist()]
        while len(rates) < 3:
            rates.append(self._recent_baseline)
        if not rates:
            return self._recent_baseline
        return float(sum(rates)) / float(len(rates))

    def _update_state_from_history(self, history: PlayerHistory) -> None:
        n_opponents = self._opponent_count()
        total_rounds = history.round_number
        while self._processed_rounds < total_rounds:
            idx = self._processed_rounds
            m_t = int(history.opponent_cooperators[idx]) if idx < total_rounds else 0
            rate = self._cooperation_rate(m_t)
            if idx == 0:
                self._recent_baseline = rate
            else:
                self._recent_baseline = 2.0 / 3.0 * self._recent_baseline + 1.0 / 3.0 * rate
            if rate < 0.3:
                self._low_lockout_remaining = 2
                self._high_coop_streak = 0
            else:
                if self._low_lockout_remaining > 0:
                    if rate >= 0.7:
                        self._high_coop_streak += 1
                    else:
                        self._high_coop_streak = 0
                elif rate >= 0.7:
                    self._high_coop_streak += 1
                else:
                    self._high_coop_streak = 0
                if self._high_coop_streak >= 2:
                    self._low_lockout_remaining = 0
            near_perfect_threshold = max(0, n_opponents - 1)
            clear_deviation_threshold = max(0, n_opponents - 2)
            if m_t >= near_perfect_threshold:
                self._near_perfect_streak += 1
            else:
                self._near_perfect_streak = 0
            if self._perfect_mode_active:
                if m_t <= clear_deviation_threshold:
                    self._perfect_mode_active = False
                    self._perfect_cooldown_remaining = 2
                    self._near_perfect_streak = 0
            elif self._near_perfect_streak >= 3:
                self._perfect_mode_active = True
            self._processed_rounds += 1
        if self._low_lockout_remaining > 0:
            self._low_lockout_remaining = max(0, self._low_lockout_remaining - 1)
        if self._perfect_cooldown_remaining > 0:
            self._perfect_cooldown_remaining = max(0, self._perfect_cooldown_remaining - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        self._update_state_from_history(history)
        if history.round_number == 0:
            return Action.C
        n_rounds = int(self.game_description.n_rounds)
        n_opponents = self._opponent_count()
        current_round = history.round_number + 1
        if current_round >= n_rounds:
            return Action.D
        q_t = self._recent_cooperation_rate(history)
        if current_round == n_rounds - 1:
            if history.round_number >= 1 and n_opponents > 0:
                last_m = int(history.opponent_cooperators[-1])
                if q_t >= 0.8 and last_m >= 0.75 * n_opponents:
                    return Action.C
            return Action.D
        if self._low_lockout_remaining > 0:
            return Action.D
        if self._perfect_cooldown_remaining > 0:
            return Action.D
        if self._perfect_mode_active:
            return Action.C
        if q_t >= 0.6:
            if history.round_number < 2:
                return Action.C
            last_m = int(history.opponent_cooperators[-1])
            prev_m = int(history.opponent_cooperators[-2])
            if last_m >= prev_m - 1:
                return Action.C
        return Action.D

class Strategy_SELFINTERESTED_124(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Start with defection.
    - Cooperate only after sustained high cooperation is observed.
    - Enter defection mode after collapse signals.
    - Never cooperate in the last two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.defection_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)

        def q_at(idx: int) -> float:
            if idx < 0 or idx >= history.round_number:
                return 0.0
            return float(history.opponent_cooperators[idx]) / float(n_opponents)
        if history.round_number == 0:
            self.defection_mode = False
            return Action.D
        if history.round_number >= n_rounds - 2:
            self.defection_mode = True
            return Action.D
        last_q = q_at(history.round_number - 1)
        prev_q = q_at(history.round_number - 2)
        if self.defection_mode:
            if last_q == 1.0 or (history.round_number >= 2 and last_q >= 2.0 / 3.0 and (prev_q >= 2.0 / 3.0)):
                self.defection_mode = False
            else:
                return Action.D
        elif history.round_number >= 2 and last_q <= 1.0 / 3.0 and (prev_q <= 1.0 / 3.0):
            self.defection_mode = True
            return Action.D
        window_len = min(3, history.round_number)
        if window_len <= 0:
            avg_q = 0.0
        else:
            start = history.round_number - window_len
            qs = [q_at(i) for i in range(start, history.round_number)]
            avg_q = float(np.mean(qs)) if qs else 0.0
        trend = last_q - prev_q
        if avg_q >= 2.0 / 3.0 and prev_q >= 2.0 / 3.0 and (trend >= 0.0):
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_125(BaseStrategy):
    """
    Trust-based conditional cooperator for the repeated N-player Public Goods Game.

    Core behavior:
    - Start with D.
    - Cooperate only after sustained high observed cooperation.
    - Defect immediately in the last two rounds.
    - Enter a short punishment window after any meaningful drop in cooperation.
    - Special handling for n=2 and very short games.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.threshold = min(1.0, 1.0 / self.k) if self.k != 0 else 1.0
        self._last_decision = Action.D
        self._punishment_until_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        current_round = round_number + 1
        if round_number == 0:
            self._last_decision = Action.D
            return Action.D
        n_opponents = max(1, self.n - 1)

        def q_at(idx: int) -> float:
            if idx < 0 or idx >= len(history.opponent_cooperators):
                return 0.0
            return float(history.opponent_cooperators[idx]) / float(n_opponents)
        if self.r <= 3:
            if current_round == 2 and q_at(0) >= 1.0:
                self._last_decision = Action.C
                return Action.C
            self._last_decision = Action.D
            return Action.D
        if current_round >= self.r - 1:
            self._last_decision = Action.D
            return Action.D
        if self.n == 2:
            if round_number >= 2 and q_at(round_number - 1) >= 1.0 and (q_at(round_number - 2) >= 1.0):
                self._last_decision = Action.C
                return Action.C
            self._last_decision = Action.D
            return Action.D
        s = 0.0
        punishment_until = 0
        q_values = []
        for t in range(1, round_number + 1):
            q_t = q_at(t - 1)
            q_values.append(q_t)
            if t == 1:
                s = q_t
            else:
                s = 0.7 * s + 0.3 * q_t
            if q_t < self.threshold and t + 1 <= self.r - 2:
                punishment_until = max(punishment_until, t + 2)
        if round_number >= 3 and current_round > punishment_until:
            if q_values[-3] >= self.threshold and q_values[-2] >= self.threshold and (q_values[-1] >= self.threshold):
                s = max(s, self.threshold)
        if current_round <= punishment_until:
            self._last_decision = Action.D
            return Action.D
        t = current_round - 1
        if current_round <= self.r - 2:
            q_t = q_at(t - 1)
            if t >= 2:
                q_prev = q_at(t - 2)
            else:
                q_prev = 0.0
            can_cooperate = s >= self.threshold and q_t >= self.threshold and (t < 2 or q_t >= q_prev - 0.15)
            if can_cooperate:
                self._last_decision = Action.C
                return Action.C
        self._last_decision = Action.D
        return Action.D

class Strategy_SELFINTERESTED_126(BaseStrategy):
    """
    Conditional cooperator with a two-round threshold build-up and an endgame cutoff.
    Defects in the first round, defects in the last two rounds, and cooperates only
    after observing the cooperation threshold met in two consecutive prior rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.threshold = int(math.ceil(0.8 * max(self.n_players - 1, 0)))

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0 or self.n_rounds <= 2:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == self.n_rounds - 2:
            return Action.D
        streak = 0
        opponent_cooperators = history.opponent_cooperators
        idx = round_number - 1
        while idx >= 0:
            if int(opponent_cooperators[idx]) >= self.threshold:
                streak += 1
                idx -= 1
            else:
                break
        return Action.C if streak >= 2 else Action.D

class Strategy_SELFINTERESTED_127(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Cooperates on the opening move
    - Responds to opponents' cooperation rate with a threshold rule
    - Defects after repeated low cooperation or near the end of the match
    - Permanently defects after two consecutive rounds with zero opponent cooperation
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.trust = 1
        self.strike = 0
        self.streak = 0
        self.zero_rho_streak = 0
        self.permanent_defect = False
        self._processed_rounds = 0

    def _threshold(self) -> float:
        return 1.0 if self.game_description.n_players == 2 else 2.0 / 3.0

    def _update_state_from_history(self, history: PlayerHistory) -> None:
        n_players = self.game_description.n_players
        n_opponents = max(n_players - 1, 1)
        threshold = self._threshold()
        start = self._processed_rounds
        end = history.round_number
        for idx in range(start, end):
            h_t = int(history.opponent_cooperators[idx])
            rho_t = h_t / n_opponents if n_opponents > 0 else 0.0
            if rho_t >= threshold:
                self.trust = min(self.trust + 1, 3)
                self.strike = 0
                self.streak += 1
                self.zero_rho_streak = 0
            else:
                self.trust = max(self.trust - 1, 0)
                self.strike += 1
                self.streak = 0
                if h_t == 0:
                    self.zero_rho_streak += 1
                    if self.zero_rho_streak >= 2:
                        self.permanent_defect = True
                else:
                    self.zero_rho_streak = 0
        self._processed_rounds = end

    def __call__(self, history: PlayerHistory) -> Action:
        self._update_state_from_history(history)
        if self.permanent_defect:
            return Action.D
        t = history.round_number
        r = self.game_description.n_rounds
        if t == 0:
            return Action.C
        if t >= r - 1:
            return Action.D
        if r == 2 and t == 1:
            return Action.D
        if self.strike >= 2:
            return Action.D
        n_opponents = max(self.game_description.n_players - 1, 1)
        prev_h = int(history.opponent_cooperators[-1]) if history.round_number > 0 else 0
        rho_prev = prev_h / n_opponents if n_opponents > 0 else 0.0
        if rho_prev >= self._threshold():
            return Action.C
        return Action.D

class Strategy_SELFINTERESTED_128(BaseStrategy):
    """
    Defaults to defection, but can enter a cooperative mode after sustained
    high cooperation by the opponents. Always defects in the first and final
    rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'defect'
        n_players = int(getattr(game_description, 'n_players', 0) or 0)
        n_opponents = max(0, n_players - 1)
        self.high_threshold = math.ceil(2 * n_opponents / 3) if n_opponents > 0 else 0
        self.low_threshold = math.ceil(n_opponents / 2) if n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        t = int(history.round_number)
        if t <= 0:
            self.mode = 'defect'
            return Action.D
        last_my_action = bool(history.my_actions[-1])
        last_x = int(history.opponent_cooperators[-1])
        if last_my_action:
            if last_x < self.low_threshold:
                self.mode = 'defect'
        elif t >= 2:
            prev_x = int(history.opponent_cooperators[-2])
            if last_x >= self.high_threshold and prev_x >= self.high_threshold:
                self.mode = 'cooperate'
        elif last_x >= self.high_threshold:
            self.mode = 'cooperate'
        if n_rounds > 0 and t >= n_rounds - 1:
            return Action.D
        if self.mode == 'cooperate':
            if last_x >= self.low_threshold:
                return Action.C
            self.mode = 'defect'
            return Action.D
        if t == 1:
            if last_x >= self.high_threshold:
                return Action.C
            return Action.D
        if t >= 2:
            prev_x = int(history.opponent_cooperators[-2])
            if last_x >= self.high_threshold and prev_x >= self.high_threshold:
                self.mode = 'cooperate'
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_33(BaseStrategy):
    """
    Tit-for-stable-cooperation strategy for the N-player Public Goods Game.

    - Starts with defection.
    - Cooperates only after two consecutive highly cooperative rounds.
    - Defects in weak or unstable environments.
    - Uses a short probe during extended exploitation if cooperation seems to be returning.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        self.high_threshold = int(math.ceil(3 * (n - 1) / 4))
        self.low_threshold = int(math.ceil((n - 1) / 2))
        self.cooperative_mode = False
        self.punishment_remaining = 0
        self.exploitation_streak = 0
        self.last_probe_round = -10 ** 9

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = max(1, int(self.game_description.n_rounds))
        if round_number == 0 or round_number >= n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        x_prev = int(opp[-1]) if len(opp) >= 1 else 0
        x_prev2 = int(opp[-2]) if len(opp) >= 2 else 0
        x_prev3 = int(opp[-3]) if len(opp) >= 3 else 0
        high = self.high_threshold
        low = self.low_threshold
        if self.punishment_remaining > 0:
            self.punishment_remaining -= 1
            self.cooperative_mode = False
            self.exploitation_streak += 1
            return Action.D
        if self.cooperative_mode:
            if x_prev < low:
                self.cooperative_mode = False
                self.punishment_remaining = 2
                self.exploitation_streak = 0
                return Action.D
            if x_prev >= high:
                return Action.C
            self.cooperative_mode = False
            self.exploitation_streak += 1
            return Action.D
        if x_prev >= high and x_prev2 >= high:
            self.cooperative_mode = True
            self.exploitation_streak = 0
            return Action.C
        if x_prev < low:
            self.punishment_remaining = 2
            self.exploitation_streak = 0
            return Action.D
        if self.exploitation_streak >= 3 and round_number > self.last_probe_round + 1 and (len(opp) >= 3) and (x_prev > x_prev2 > x_prev3):
            self.last_probe_round = round_number
            self.exploitation_streak = 0
            return Action.C
        self.exploitation_streak += 1
        return Action.D

class Strategy_OPPORTUNISTIC_34(BaseStrategy):
    """
    Probe once early, defect when cooperation is stable or collapsed, and
    never cooperate in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n_players - 1)
        self.high = 0.75
        self.low = 0.25
        self.high_count = int(math.ceil(self.high * self.n_opponents))
        self.low_count = int(math.floor(self.low * self.n_opponents))
        self.last_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            self.last_action = Action.C
            return Action.C
        if t >= self.n_rounds - 1:
            self.last_action = Action.D
            return Action.D
        opponent_cooperators = history.opponent_cooperators
        if len(opponent_cooperators) == 0 or self.n_opponents == 0:
            self.last_action = Action.D
            return Action.D
        w = min(3, t)
        recent = opponent_cooperators[-w:]
        stable = bool(np.all(recent >= self.high_count))
        collapse = bool(np.all(recent <= self.low_count))
        recent_avg = float(np.mean(recent))
        recent_rate = recent_avg / self.n_opponents if self.n_opponents > 0 else 0.0
        most_recent = int(opponent_cooperators[-1])
        if stable:
            action = Action.D
        elif collapse:
            action = Action.D
        elif most_recent >= self.high_count:
            action = Action.D
        elif most_recent <= self.low_count:
            action = Action.C
        else:
            action = Action.C if recent_rate >= 0.5 else Action.D
        self.last_action = action
        return action

class Strategy_OPPORTUNISTIC_35(BaseStrategy):
    """
    Conditional cooperator that starts with defection, cooperates only after
    sufficiently strong and non-decreasing opponent cooperation, and defects
    in the final two rounds or after a failed cooperation episode.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'exploit'
        self.cooldown = 0
        n = max(2, int(game_description.n_players))
        self._n = n
        self._opp_count = max(0, n - 1)
        self._strong_threshold = math.ceil(3 * self._opp_count / 4)
        self._low_threshold = math.ceil(self._opp_count / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        r = int(self.game_description.n_rounds)
        n = self._n
        if r <= 2:
            self.mode = 'exploit'
            self.cooldown = 0
            return Action.D
        round_number = int(history.round_number)
        if round_number == 0:
            self.mode = 'exploit'
            self.cooldown = 0
            return Action.D
        cooldown = 0
        mode = 'exploit'
        for t in range(1, round_number):
            my_prev = bool(history.my_actions[t - 1])
            h_prev = int(history.opponent_cooperators[t - 1])
            if my_prev and h_prev < self._low_threshold:
                cooldown = 2
                mode = 'exploit'
            elif my_prev:
                mode = 'reciprocate'
            else:
                mode = 'exploit'
            if cooldown > 0:
                cooldown -= 1
        if round_number >= r - 2:
            self.mode = 'exploit'
            self.cooldown = 0
            return Action.D
        h_t = int(history.opponent_cooperators[-1])
        prev_h = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        if cooldown > 0:
            self.mode = 'exploit'
            self.cooldown = cooldown - 1
            return Action.D
        cooperate = False
        if h_t == n - 1:
            cooperate = True
        elif round_number >= 2:
            if h_t >= self._strong_threshold and prev_h is not None and (h_t >= prev_h):
                cooperate = True
        if cooperate:
            self.mode = 'reciprocate'
            if h_t < self._low_threshold:
                self.cooldown = 2
            else:
                self.cooldown = 0
            return Action.C
        self.mode = 'exploit'
        self.cooldown = 0
        return Action.D

class Strategy_OPPORTUNISTIC_36(BaseStrategy):
    """
    Threshold-based public goods strategy:
    - Cooperate in round 1.
    - In later rounds, cooperate only when cumulative observed opponent cooperation
      is high enough to justify cooperation.
    - Never cooperate in the final round.
    - Fallback to defection on any inconsistent or unavailable history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        if self.k > 0:
            self.q = self.n_players / self.k - 1.0
        else:
            self.q = float('inf')
        self.required_opponent_cooperators = int(math.ceil(self.q * max(self.n_players - 1, 0)))
        self.half_required_opponent_cooperators = self.required_opponent_cooperators / 2.0

    def __call__(self, history: PlayerHistory) -> Action:
        try:
            t = int(history.round_number)
        except Exception:
            return Action.D
        if t >= self.n_rounds - 1:
            return Action.D
        if t == 0:
            return Action.C
        try:
            opp = history.opponent_cooperators
            my_actions = history.my_actions
        except Exception:
            return Action.D
        if opp is None or my_actions is None:
            return Action.D
        if len(opp) < t or len(my_actions) < t:
            return Action.D
        n_opponents = self.n_players - 1
        if n_opponents <= 0:
            return Action.D
        try:
            m_prev = int(opp[t - 1])
        except Exception:
            return Action.D
        if m_prev < 0 or m_prev > n_opponents:
            return Action.D
        total_observed = 0
        for s in range(t):
            try:
                m_s = int(opp[s])
            except Exception:
                return Action.D
            if m_s < 0 or m_s > n_opponents:
                return Action.D
            total_observed += m_s
        denom = n_opponents * t
        if denom <= 0:
            return Action.D
        p_t = total_observed / denom
        if p_t > self.q:
            if m_prev >= self.required_opponent_cooperators:
                return Action.C
            return Action.D
        if p_t < self.q:
            return Action.D
        if abs(p_t - self.q) <= 1e-12:
            if m_prev > self.half_required_opponent_cooperators:
                return Action.C
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_37(BaseStrategy):
    """
    Adaptive public-goods strategy with three states:
    Open, Exploit, and Punish.

    - Starts by cooperating.
    - Uses opponent cooperation counts to decide whether to cooperate,
      exploit, or punish.
    - Caps punishment at two consecutive defections.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.k = float(game_description.k)
        denom = max(1, self.n - 1)
        self.threshold = int(math.ceil((self.n - 1) / self.k)) if self.k > 0 else denom
        self.threshold = max(0, min(denom, self.threshold))
        self.aggressive_threshold = max(0, self.threshold - 1)
        self.state = 'Open'
        self.punish_count = 0
        self.seen_high = False
        self.last_action = None
        self.last_x = None
        self.prev_x = None

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_opponents = max(1, self.n - 1)
        threshold = self.threshold
        aggressive_threshold = self.aggressive_threshold
        if round_number == 0:
            self.last_action = Action.C
            return Action.C
        last_x = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        prev_x = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        if last_x >= threshold:
            self.seen_high = True
        if round_number == self.r - 1:
            if self.state == 'Open' and last_x == n_opponents:
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.D
            return Action.D
        if round_number >= 1 and last_x == n_opponents and (self.state != 'Punish'):
            self.state = 'Open'
        if last_x == 0:
            self.state = 'Punish'
            self.punish_count = 0
        if self.state == 'Open':
            if last_x >= threshold:
                action = Action.C
            elif self.k >= 2 and last_x >= aggressive_threshold:
                action = Action.C
            elif round_number >= 2 and prev_x is not None and (last_x >= aggressive_threshold) and (prev_x <= last_x):
                action = Action.C
            else:
                action = Action.D
        elif self.state == 'Exploit':
            if last_x >= aggressive_threshold:
                action = Action.D
            else:
                self.state = 'Punish'
                self.punish_count = 0
                action = Action.D
        else:
            action = Action.D
            self.punish_count += 1
        if self.state == 'Open':
            if last_x >= threshold:
                self.state = 'Open'
            else:
                self.state = 'Punish'
                self.punish_count = 0
        elif self.state == 'Exploit':
            if last_x < aggressive_threshold:
                self.state = 'Punish'
                self.punish_count = 0
        elif self.state == 'Punish':
            if last_x >= threshold:
                self.state = 'Open'
                self.punish_count = 0
            elif self.punish_count >= 2:
                self.state = 'Open'
                self.punish_count = 0
        if self.state == 'Open' and action == Action.D and (last_x >= threshold):
            self.state = 'Exploit'
        self.last_action = action
        self.prev_x = self.last_x
        self.last_x = last_x
        return action

class Strategy_OPPORTUNISTIC_38(BaseStrategy):
    """
    Adaptive public-goods strategy that tracks opponent cooperation, shifts quickly
    toward cooperation when cooperation is sustained, and defects immediately when
    cooperation collapses.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n_players - 1)
        self.threshold_rate = self.n_players / self.k - 1.0 if self.k != 0 else float('inf')
        self.threshold_count = int(math.ceil((self.n_players - 1) * self.threshold_rate)) if self.n_players > 1 else 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        opp_counts = history.opponent_cooperators
        M = int(np.sum(opp_counts)) if len(opp_counts) > 0 else 0
        T = t
        last_m = int(opp_counts[-1]) if len(opp_counts) > 0 else 0
        last_two = opp_counts[-2:] if len(opp_counts) >= 2 else opp_counts
        last_three = opp_counts[-3:] if len(opp_counts) >= 3 else opp_counts
        if t == self.n_rounds - 1:
            if len(last_two) == 2 and all((int(x) >= self.threshold_count for x in last_two)):
                return Action.C
            return Action.D
        if len(last_two) == 2:
            if all((int(x) >= self.threshold_count for x in last_two)):
                return Action.C
            if all((int(x) < self.threshold_count for x in last_two)):
                return Action.D
        if last_m >= max(0, self.n_players - 2) and len(last_three) == 3:
            a, b, c = (int(x) for x in last_three)
            if a <= b <= c:
                return Action.C
        if last_m <= 1:
            return Action.D
        denom = self.n_opponents * T
        p_hat = M / denom if denom > 0 else 0.0
        if p_hat > self.threshold_rate:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_39(BaseStrategy):
    """
    Defect for the first two rounds, then cooperate only if opponents'
    cooperation is both sufficiently high and stable across the last two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = getattr(game_description, 'n_players', 0)
        k = getattr(game_description, 'k', 0.0)
        self.n_players = n_players
        self.n_opponents = max(0, n_players - 1)
        self.k = k
        if k > 1.0:
            theta = 1.0 - 1.0 / k
        else:
            theta = 1.0
        if self.n_opponents > 0:
            theta_minus = max(0.0, theta - 1.0 / self.n_opponents)
        else:
            theta_minus = 1.0
        self.theta = theta
        self.theta_minus = theta_minus

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number < 2:
            return Action.D
        if self.n_opponents <= 0:
            return Action.D
        last_opponents = int(history.opponent_cooperators[-1])
        prev_opponents = int(history.opponent_cooperators[-2])
        q_last = last_opponents / self.n_opponents
        q_prev = prev_opponents / self.n_opponents
        if q_last >= self.theta and q_prev >= self.theta_minus:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_40(BaseStrategy):
    """
    Adaptive public-goods strategy with threshold-based cooperation, decay-aware
    cooperation tracking, and late-game caution.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.epsilon = 1e-09
        self.midpoint_threshold = math.ceil(max(self.n - 1, 0) / 2) if self.n > 1 else 0
        self.E0 = 0.5
        self.H0 = 0
        self.L0 = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.C
        last_m = int(opp[-1])
        if self.n == 2:
            if t == 1:
                return Action.C
            prev_my = bool(history.my_actions[-1])
            return Action.C if last_m >= 1 and prev_my else Action.D if last_m == 0 else Action.C
        E = self.E0
        H = self.H0
        L = self.L0
        prev_m = None
        sharp_drop_flag = False
        for idx, m in enumerate(opp):
            m = int(m)
            s = m / max(self.n - 1, 1)
            E = 0.7 * E + 0.3 * s
            if m >= self.midpoint_threshold:
                H += 1
            else:
                H = 0
            if m == 0:
                L += 1
            else:
                L = 0
            if prev_m is not None and prev_m - m >= 2:
                sharp_drop_flag = True
            prev_m = m
        T = math.ceil((self.n - 1) / self.k) - 1 if self.k > 0 else self.n - 1
        if T < 0:
            T = 0
        if T > self.n - 1:
            T = self.n - 1
        near_one = self.k <= 1.15
        near_n = self.k >= max(self.n - 0.75, 1.0)
        if near_one:
            T = max(T, self.n - 1)
        if t >= max(self.r - 2, 1):
            if last_m >= T or E >= 0.65 or (near_n and last_m >= 1):
                return Action.C
            return Action.D
        if L >= 2:
            return Action.D
        if sharp_drop_flag and E < 0.65:
            return Action.D
        cooperate = False
        if last_m >= T:
            cooperate = True
        elif E >= (0.7 if near_one else 0.55):
            cooperate = True
        elif H >= 2:
            cooperate = True
        elif t == self.r - 1 and last_m >= 1:
            cooperate = True
        elif near_n and last_m >= 1:
            cooperate = True
        if bool(history.my_actions[-1]):
            if len(opp) >= 2:
                prev_round_m = int(opp[-2])
                if last_m < T and prev_round_m < T:
                    cooperate = False
            if last_m >= T:
                cooperate = True
        return Action.C if cooperate else Action.D

class Strategy_OPPORTUNISTIC_41(BaseStrategy):
    """
    Guarded public-goods strategy with smoothed cooperation estimates,
    trend tracking, anti-exploitation locking, and 3-round stabilization.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._processed_rounds = 0
        self._coop_rate = 0.0
        self._trend = 0.0
        self._obs_counts = []
        self._locked_defect = False
        self._prev_x = None

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n = self.game_description.n_players
        M = max(1, n - 1)
        k = self.game_description.k
        if t == 0:
            return Action.D
        high = max(0.65, 1.0 - 1.0 / k) if k != 0 else 0.65
        low = min(0.35, 1.0 - 1.0 / k - 0.15) if k != 0 else 0.35
        ceil_high_m = math.ceil(M * high)
        floor_low_m = math.floor(M * low)
        ceil_half_m = math.ceil(M * 0.5)
        while self._processed_rounds < t:
            idx = self._processed_rounds
            m_prev = int(history.opponent_cooperators[idx])
            x = m_prev / M if M > 0 else 0.0
            self._obs_counts.append(m_prev)
            if self._processed_rounds == 0:
                self._coop_rate = x
                self._trend = 0.0
            else:
                self._coop_rate = 0.7 * self._coop_rate + 0.3 * x
                if self._prev_x is not None:
                    self._trend = x - self._prev_x
                else:
                    self._trend = 0.0
            if self._processed_rounds >= 1 and idx < len(history.my_actions):
                prev_my_action = bool(history.my_actions[idx])
                prev_m = int(history.opponent_cooperators[idx - 1]) if idx - 1 >= 0 else m_prev
                if prev_my_action and prev_m - m_prev >= 2:
                    self._locked_defect = True
            self._prev_x = x
            self._processed_rounds += 1
        last3 = self._obs_counts[-3:]
        avg_last3 = sum(last3) / len(last3) if last3 else 0.0
        if self._locked_defect and (self._coop_rate >= high or avg_last3 >= high):
            self._locked_defect = False
        if t == self.game_description.n_rounds:
            return Action.D
        if self._locked_defect:
            return Action.D
        m_prev = int(history.opponent_cooperators[-1])
        x_prev = m_prev / M if M > 0 else 0.0
        m_prev2 = int(history.opponent_cooperators[-2]) if t > 1 else m_prev
        last_two_low = False
        if t > 1:
            prev2_low = m_prev2 <= floor_low_m
            prev1_low = m_prev <= floor_low_m
            last_two_low = prev2_low and prev1_low
        if avg_last3 >= high:
            return Action.C
        if avg_last3 <= low:
            return Action.D
        if self._coop_rate >= high and m_prev >= ceil_high_m and (self._trend >= -0.1):
            return Action.C
        if self._coop_rate <= low or m_prev <= floor_low_m or last_two_low:
            return Action.D
        if m_prev >= ceil_half_m:
            return Action.D
        return Action.C if m_prev > m_prev2 else Action.D

class Strategy_OPPORTUNISTIC_42(BaseStrategy):
    """
    Conservative threshold-based strategy for the repeated N-player Public Goods Game.

    - Start with defection.
    - Cooperate only after observing sufficiently high cooperation from opponents.
    - Defect again whenever cooperation drops too low.
    - In the final round, cooperate only if recent cooperation has been reliably high.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0))
        k = float(getattr(game_description, 'k', 0.0))
        if n <= 0:
            n = 1
        if k <= 0:
            k = 1.0
        self.threshold = int(math.ceil(n / k))
        self.sustain_threshold = max(1, self.threshold - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        total_rounds = int(getattr(self.game_description, 'n_rounds', 0))
        if round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        last_m = int(opp[-1]) if len(opp) > 0 else 0
        recent_high = False
        if len(opp) >= 1 and int(opp[-1]) >= self.threshold:
            recent_high = True
        if len(opp) >= 2 and int(opp[-2]) >= self.threshold:
            recent_high = True
        last_three_high = False
        if len(opp) >= 3:
            last_three_high = int(opp[-1]) >= self.threshold and int(opp[-2]) >= self.threshold and (int(opp[-3]) >= self.threshold)
        if total_rounds > 0 and round_number == total_rounds - 1:
            if last_m >= self.sustain_threshold and recent_high:
                return Action.C
            return Action.D
        if last_m < self.sustain_threshold:
            return Action.D
        if last_m >= self.threshold:
            return Action.C
        if recent_high or last_three_high:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_43(BaseStrategy):
    """
    Probe with defection, then cooperate only after two consecutive strongly
    cooperative opponent rounds; defect immediately on weak cooperation and in
    the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.coop_mode = False
        self.coop_streak = 0
        self.defect_streak = 0
        self._last_processed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        current_round = history.round_number + 1
        if current_round == 1:
            self.coop_mode = False
            self.coop_streak = 0
            self.defect_streak = 0
            self._last_processed_round = history.round_number
            return Action.D
        if current_round == n_rounds:
            self._last_processed_round = history.round_number
            return Action.D
        if history.round_number > 0 and self._last_processed_round != history.round_number:
            n_opponents = self.game_description.n_players - 1
            if n_opponents > 0:
                x_prev = int(history.opponent_cooperators[-1])
                p_prev = x_prev / n_opponents
            else:
                p_prev = 0.0
            if p_prev >= 2.0 / 3.0:
                self.coop_streak += 1
                self.defect_streak = 0
            elif p_prev <= 1.0 / 3.0:
                self.defect_streak += 1
                self.coop_streak = 0
            else:
                self.coop_streak = 0
                self.defect_streak = 0
            if self.defect_streak >= 1:
                self.coop_mode = False
            if self.coop_streak >= 2:
                self.coop_mode = True
            self._last_processed_round = history.round_number
        else:
            p_prev = 0.0
        if self.coop_mode and history.round_number > 0:
            n_opponents = self.game_description.n_players - 1
            if n_opponents > 0:
                x_prev = int(history.opponent_cooperators[-1])
                p_prev = x_prev / n_opponents
            else:
                p_prev = 0.0
            if p_prev < 0.5:
                self.coop_mode = False
                return Action.D
        return Action.C if self.coop_mode else Action.D

class Strategy_OPPORTUNISTIC_44(BaseStrategy):
    """
    Start with cooperation, then continue only when cooperation by opponents has
    been sustained and meets the threshold q. Defect in the final two rounds,
    with explicit handling for small-horizon edge cases.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        if k == 0:
            self.q = 0
        else:
            self.q = int(math.ceil((n - 1) * (k - 1) / k))
        if self.q < 0:
            self.q = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        r = int(self.game_description.n_rounds)
        if round_number == 0:
            return Action.C
        if round_number >= r - 1:
            return Action.D
        if r == 2:
            return Action.D
        if r == 3:
            if round_number == 1:
                return Action.C if history.opponent_cooperators[-1] >= self.q else Action.D
            return Action.D
        if round_number == 1:
            return Action.C if history.opponent_cooperators[-1] >= self.q else Action.D
        if round_number <= r - 3:
            if history.opponent_cooperators[-1] >= self.q and history.opponent_cooperators[-2] >= self.q:
                return Action.C
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_45(BaseStrategy):
    """
    Stay out by default, and only cooperate after sustained near-universal
    cooperation by opponents. Defect in the first and final rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        opponent_cooperators = history.opponent_cooperators
        high_streak = 0
        for idx in range(round_number - 1, -1, -1):
            if int(opponent_cooperators[idx]) == self.n_players - 1:
                high_streak += 1
            else:
                break
        recover_streak = 0
        for idx in range(round_number - 1, -1, -1):
            if int(opponent_cooperators[idx]) >= self.n_players - 2:
                recover_streak += 1
            else:
                break
        x_prev = int(opponent_cooperators[-1])
        x_prev2 = int(opponent_cooperators[-2]) if round_number >= 2 else None
        if high_streak >= 2:
            return Action.C
        if recover_streak >= 3 and x_prev2 is not None and (x_prev >= x_prev2):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_46(BaseStrategy):
    """
    Conservative, threshold-based public-goods strategy.

    - Starts with D and ends with D.
    - Cooperates only when observed cooperation is high, stable, and not declining.
    - Escalates to a simpler cooperative mode after two consecutive high-cooperation rounds.
    - Immediately reverts to defection if cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.streak = 0
        self.last_share = 0.0
        self.escalated = False
        self.valid_observation_seen = False
        self._n_opponents = max(0, self.n_players - 1)
        self._coop_count_threshold = math.ceil(self._n_opponents * (1.0 - 1.0 / self.k)) + 1 if self.k != 0 else self._n_opponents + 1
        self._share_threshold = 2.0 / 3.0
        self._reset_threshold = 1.0 / 2.0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if len(history.opponent_cooperators) == 0:
            return Action.D
        x_raw = history.opponent_cooperators[-1]
        if x_raw is None:
            return Action.D
        x = int(x_raw)
        if x < 0:
            x = 0
        if x > self._n_opponents:
            x = self._n_opponents
        share = 0.0 if self._n_opponents == 0 else x / self._n_opponents
        delta = share - self.last_share
        if share < self._reset_threshold:
            self.streak = 0
            self.escalated = False
        else:
            if share >= self._share_threshold:
                self.streak += 1
            else:
                self.streak = 0
            if self.streak >= 2:
                self.escalated = True
        cooperate_base = share >= self._share_threshold and x >= self._coop_count_threshold and (delta >= 0.0)
        if self.escalated:
            action = Action.C if share >= self._share_threshold else Action.D
        else:
            action = Action.C if cooperate_base else Action.D
        self.last_share = share
        self.valid_observation_seen = True
        return action

class Strategy_OPPORTUNISTIC_47(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Cooperate initially.
    - Track exponentially weighted opponent cooperation.
    - Defect immediately after zero-cooperation rounds until cooperation recovers.
    - Cooperate only when cooperation is sufficiently strong and stable.
    - Never cooperate in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._force_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = max(2, int(self.game_description.n_players))
        r = max(1, int(self.game_description.n_rounds))
        k = float(self.game_description.k)
        current_round = history.round_number
        if current_round >= r - 1:
            return Action.D
        if current_round == 0:
            return Action.C
        n_opponents = max(1, n - 1)
        last_m = int(history.opponent_cooperators[-1])
        coop_threshold_rate = 1.0 - 1.0 / k
        coop_threshold_count = int(math.ceil((n - 1) * coop_threshold_rate))
        if last_m == 0:
            self._force_defect = True
        elif last_m >= coop_threshold_count:
            self._force_defect = False
        if self._force_defect and last_m < coop_threshold_count and (last_m != n_opponents):
            return Action.D
        if last_m == n_opponents:
            return Action.C
        q = 1.0
        for m in history.opponent_cooperators:
            hat_p = float(m) / float(n_opponents)
            q = 0.7 * q + 0.3 * hat_p
        use_moving_average = len(history.opponent_cooperators) >= 3
        if use_moving_average:
            recent = history.opponent_cooperators[-3:]
            a_t = float(int(recent[0]) + int(recent[1]) + int(recent[2])) / (3.0 * float(n_opponents))
            if a_t >= coop_threshold_rate and last_m >= coop_threshold_count and (q >= coop_threshold_rate):
                return Action.C
            return Action.D
        if q >= coop_threshold_rate and last_m >= coop_threshold_count:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_48(BaseStrategy):
    """
    Opportunistic threshold public-goods strategy with recovery after weak
    cooperation and a mandatory defection in the first and final rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0))
        k = float(getattr(game_description, 'k', 0.0))
        if n_players <= 1 or k <= 1.0:
            self.threshold = 0
        else:
            self.threshold = int(math.ceil((n_players - 1) * (1.0 - 1.0 / k)))
        n_opponents = max(0, n_players - 1)
        if self.threshold < 0:
            self.threshold = 0
        if self.threshold > n_opponents:
            self.threshold = n_opponents

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        total_rounds = int(getattr(self.game_description, 'n_rounds', 0))
        if round_number == 0:
            return Action.D
        if total_rounds > 0 and round_number == total_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        last_m = int(opp[-1])
        if last_m < self.threshold:
            return Action.D
        if len(opp) < 2:
            return Action.C
        if int(opp[-2]) < self.threshold:
            return Action.D
        if last_m >= self.threshold and last_m >= int(opp[-2]):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_49(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Start with cooperation.
    - Track opponent cooperation with an exponential moving average.
    - Cooperate only when cooperation appears stable and sufficiently large,
      with stricter endgame protection and special handling for n=2.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.k = float(game_description.k)
        self.threshold = int(math.ceil(self.n / self.k)) if self.k > 0 else self.n + 1
        self.threshold = max(1, self.threshold)
        self.relaxed_threshold = max(1, self.threshold - 1) if self.k >= self.n - 0.5 else self.threshold
        self.H = 0.0
        self.m = 0
        self._last_round_seen = -1

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            self.H = 0.0
            self.m = 0
            self._last_round_seen = 0
            return Action.C
        opp = history.opponent_cooperators
        last_s = int(opp[-1]) if len(opp) > 0 else 0
        H = float(opp[0]) if len(opp) > 0 else 0.0
        for i in range(1, len(opp)):
            H = 0.7 * H + 0.3 * float(opp[i])
        self.H = H
        self.m = int(round(H))
        streak = 0
        for i in range(len(opp) - 1, -1, -1):
            if int(opp[i]) >= self.threshold:
                streak += 1
            else:
                break
        last_two_high = False
        if len(opp) >= 2:
            last_two_high = int(opp[-1]) >= self.threshold and int(opp[-2]) >= self.threshold
        if self.n == 2:
            if t >= self.r - 2:
                return Action.C if len(opp) >= 2 and int(opp[-1]) >= 1 and (int(opp[-2]) >= 1) and (self.H >= 1.0) else Action.D
            return Action.C if streak >= 2 else Action.D
        if t >= self.r - 2:
            if len(opp) >= 2 and last_two_high and (self.H >= self.threshold):
                return Action.C
            return Action.D
        if last_s < self.threshold - 1:
            return Action.D
        if streak >= 2:
            return Action.C
        if self.m * self.k >= self.n:
            return Action.C
        if self.k >= self.n - 0.5 and self.m * self.k >= self.n - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_50(BaseStrategy):
    """
    Opportunistic public-goods strategy:
    - Start with cooperation.
    - Cooperate early only when cooperation is already strong.
    - Probe once after a defect if the group still looks cooperative.
    - After a failed cooperative probe or a total collapse, defect temporarily.
    - In the last round, cooperate only if the previous round was fully cooperative.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        self.k = float(game_description.k)
        self.n_rounds = int(game_description.n_rounds)
        self.half_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0
        self.low_threshold = math.ceil(self.n_opponents / 3) if self.n_opponents > 0 else 0
        self.forced_defect_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        my_actions = history.my_actions
        last_m = int(opp[-1]) if len(opp) > 0 else 0
        prev_action = bool(my_actions[-1]) if len(my_actions) > 0 else True
        if t >= 2 and prev_action is False and (last_m >= self.half_threshold):
            self.forced_defect_rounds = max(self.forced_defect_rounds, 0)
        if prev_action is True and last_m == 0:
            self.forced_defect_rounds = max(self.forced_defect_rounds, 2)
        if self.forced_defect_rounds > 0:
            self.forced_defect_rounds -= 1
            if t != self.n_rounds - 1:
                return Action.D
        if t == self.n_rounds - 1:
            if last_m == self.n_opponents:
                return Action.C
            return Action.D
        if t == 1:
            return Action.C if last_m >= self.half_threshold else Action.D
        past = opp[:t]
        avg_m = float(np.mean(past)) if len(past) > 0 else 0.0
        p_t_minus_1 = avg_m / self.n_opponents if self.n_opponents > 0 else 0.0
        prev_m = int(opp[-2]) if len(opp) >= 2 else 0
        trend = (last_m - prev_m) / self.n_opponents if self.n_opponents > 0 else 0.0
        cooperate = p_t_minus_1 >= 1.0 / self.k + 0.1 and last_m >= self.half_threshold and (trend >= 0.0)
        if prev_action is False and last_m >= self.half_threshold:
            cooperate = True
        return Action.C if cooperate else Action.D

class Strategy_OPPORTUNISTIC_51(BaseStrategy):
    """
    Opportunistic public-goods strategy with endgame defection, recovery on full
    cooperation, and simple trend/stability-based cooperation support.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = game_description.n_players
        self.n_players = n
        self.n_opponents = max(0, n - 1)
        self.r_rounds = game_description.n_rounds
        self.full_coop_threshold = math.ceil(2 * self.n_opponents / 3) if self.n_opponents > 0 else 0
        self.half_coop_threshold = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        last_x = int(opp[-1])
        if t >= self.r_rounds - 1:
            return Action.D
        prev_x = int(opp[-2]) if t >= 2 else last_x
        prev2_x = int(opp[-3]) if t >= 3 else prev_x
        if t >= 3:
            last3_mean = float(np.mean(opp[-3:]))
        else:
            last3_mean = float(np.mean(opp))
        trend = last_x - prev_x
        low_count = 0
        high_count = 0
        recent_window = opp[-3:] if t >= 3 else opp
        for val in recent_window:
            x = int(val)
            if x == 0:
                low_count += 1
            if x >= self.full_coop_threshold:
                high_count += 1
        if low_count >= 2:
            return Action.C if last_x >= self.half_coop_threshold else Action.D
        if high_count >= 2:
            return Action.C if last_x >= self.half_coop_threshold else Action.D
        if history.my_actions[-1]:
            if last_x <= math.floor(self.n_opponents / 2):
                return Action.D
        elif last_x == self.n_opponents:
            return Action.C
        if t >= 3 and last_x > prev_x > prev2_x:
            return Action.C
        if last_x == self.n_opponents:
            return Action.C
        if last_x >= self.full_coop_threshold:
            return Action.C
        if last3_mean >= self.full_coop_threshold:
            return Action.C
        if last_x >= self.half_coop_threshold and trend > 0:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_52(BaseStrategy):
    """
    Defect by default, cooperate only after sustained recent cooperation among opponents,
    and always defect in the first and final rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0))
        k = float(getattr(game_description, 'k', 0.0))
        if k > 0:
            tau = math.ceil((n - 1) / k)
        else:
            tau = n - 1
        if tau < 0:
            tau = 0
        if n >= 1 and tau > n - 1:
            tau = n - 1
        self.tau = int(tau)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0))
        if round_number == 0:
            return Action.D
        if n_rounds > 0 and round_number == n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        recent_count = 0
        for idx in range(max(0, len(opp) - 3), len(opp)):
            if opp[idx] >= self.tau:
                recent_count += 1
        if opp[-1] >= self.tau and recent_count >= 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_53(BaseStrategy):
    """
    Conservative public-goods strategy with three modes:
    probe (initial defection), harvest (conditional cooperation in strongly
    cooperative environments), and punish/abandon (defect after sharp drops
    in observed cooperation).
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self._opponents = max(0, self.n_players - 1)
        self._majority_threshold = math.ceil(self._opponents / 2) if self._opponents > 0 else 0

    def _retaliation_active(self, opp_coops: NDArray[np.int_], current_round_index: int) -> bool:
        if current_round_index <= 0:
            return False
        limit = len(opp_coops)
        for d in range(1, limit):
            if int(opp_coops[d]) <= int(opp_coops[d - 1]) - 2:
                if d + 1 <= current_round_index <= d + 2:
                    return True
        return False

    def _coop_rate(self, opp_coops: NDArray[np.int_]) -> float:
        denom = len(opp_coops) * self._opponents
        if denom <= 0:
            return 0.0
        return float(np.sum(opp_coops)) / float(denom)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        if self._retaliation_active(opp, t):
            return Action.D
        if t == self.n_rounds - 1:
            cbar = self._coop_rate(opp)
            last_m = int(opp[-1]) if len(opp) > 0 else 0
            if cbar > 2.0 / 3.0 and last_m >= self._majority_threshold:
                return Action.C
            return Action.D
        if t == self.n_rounds - 2:
            cbar = self._coop_rate(opp)
            last_m = int(opp[-1]) if len(opp) > 0 else 0
            if cbar > 2.0 / 3.0 and last_m >= self._majority_threshold:
                return Action.C
            return Action.D
        cbar = self._coop_rate(opp)
        if cbar < 1.0 / 3.0:
            return Action.D
        elif cbar <= 2.0 / 3.0:
            last_m = int(opp[-1]) if len(opp) > 0 else 0
            if last_m >= self._majority_threshold:
                return Action.C
            return Action.D
        else:
            return Action.C

class Strategy_OPPORTUNISTIC_54(BaseStrategy):
    """
    Probe with cooperation, then conditionally cooperate only in sustained
    high-cooperation environments, defecting in weak or late-game rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        self.n_players = n
        self.n_rounds = max(1, int(game_description.n_rounds))
        self.k = float(game_description.k)
        self.t_high = math.ceil(2 * n / 3)
        self.t_low = math.ceil(n / 3)
        self.last_two_m = []
        self.active_coop = False
        self.coop_break = False
        self.last_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        current_round = round_number + 1
        if round_number == 0:
            self.last_action = Action.C
            self.active_coop = False
            self.coop_break = False
            self.last_two_m = []
            return Action.C
        if round_number > 0 and len(history.opponent_cooperators) > 0:
            last_m = int(history.opponent_cooperators[-1])
            if len(self.last_two_m) == 2:
                self.last_two_m.pop(0)
            self.last_two_m.append(last_m)
            if last_m <= self.t_low:
                self.coop_break = True
            if len(self.last_two_m) == 2 and self.last_two_m[-1] >= self.t_high and (self.last_two_m[-2] >= self.t_high):
                self.active_coop = True
            elif last_m <= self.t_low:
                self.active_coop = False
        if current_round >= self.n_rounds - 1:
            self.last_action = Action.D
            return Action.D
        last_m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        prev_action = Action.C if bool(history.my_actions[-1]) else Action.D
        if prev_action == Action.C:
            if last_m >= self.t_high and (not self.coop_break):
                self.last_action = Action.C
                return Action.C
            self.last_action = Action.D
            return Action.D
        if len(history.opponent_cooperators) >= 2:
            m1 = int(history.opponent_cooperators[-1])
            m2 = int(history.opponent_cooperators[-2])
            if m1 >= self.t_high and m2 >= self.t_high:
                self.active_coop = True
                self.coop_break = False
                self.last_action = Action.C
                return Action.C
        self.last_action = Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_55(BaseStrategy):
    """
    Threshold-based cooperative strategy with forgiveness:
    cooperate initially, defect in the final round, and use a two-round
    recovery rule after low participation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.threshold = int(math.ceil((self.n_players - 1) / 2))
        self.trusting = True

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        total_rounds = self.n_rounds
        if round_number == 0:
            return Action.C
        if total_rounds <= 1:
            return Action.D
        state_trusting = True
        good_streak = 0
        for x in history.opponent_cooperators:
            if int(x) >= self.threshold:
                good_streak += 1
                if not state_trusting and good_streak >= 2:
                    state_trusting = True
            else:
                good_streak = 0
                state_trusting = False
        if round_number >= total_rounds - 1:
            self.trusting = state_trusting
            return Action.D
        if round_number == total_rounds - 2:
            if round_number >= 2:
                if int(history.opponent_cooperators[-1]) >= self.threshold and int(history.opponent_cooperators[-2]) >= self.threshold:
                    self.trusting = True
                    return Action.C
            self.trusting = False
            return Action.D
        if state_trusting:
            if int(history.opponent_cooperators[-1]) >= self.threshold:
                self.trusting = True
                return Action.C
            self.trusting = False
            return Action.D
        if round_number >= 2:
            if int(history.opponent_cooperators[-1]) >= self.threshold and int(history.opponent_cooperators[-2]) >= self.threshold:
                self.trusting = True
                return Action.C
        self.trusting = False
        return Action.D

class Strategy_OPPORTUNISTIC_56(BaseStrategy):
    """
    Defect by default, cooperate only under sustained high opponent cooperation,
    with a short-memory override, a one-round probe after a possible drop, and a
    strong endgame bias toward defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        self._coop_threshold = math.ceil((n - 1) / k) if k > 0 else n
        self._baseline_threshold = (n - 1) / k if k > 0 else float('inf')

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        t = int(history.round_number)
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        last = int(opp[-1]) if len(opp) >= 1 else 0
        prev = int(opp[-2]) if len(opp) >= 2 else None
        if len(opp) > 0:
            s_prev = float(np.mean(opp))
        else:
            s_prev = 0.0
        high_last = last >= self._coop_threshold
        high_prev = prev is not None and prev >= self._coop_threshold
        low_last = last < self._coop_threshold
        low_prev = prev is not None and prev < self._coop_threshold
        if t >= n_rounds - 1:
            return Action.D
        if t == n_rounds - 2:
            if high_last and high_prev:
                return Action.C
            return Action.D
        if prev is not None:
            if high_last and high_prev:
                return Action.C
            if low_last and low_prev:
                return Action.D
        if prev is not None and high_last and (not high_prev):
            return Action.D
        if s_prev >= self._baseline_threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_57(BaseStrategy):
    """
    Threshold-based strategy with a search phase and an exploit phase.

    - Starts by defecting.
    - Enters cooperation only after sufficiently persistent cooperation is observed.
    - Continues cooperating while cooperation remains high.
    - Defects immediately if cooperation weakens or in the terminal round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        theta_enter = math.ceil((n - 1) / k) if k > 0 else n - 1
        theta_enter = max(0, min(n - 1, int(theta_enter)))
        theta_exit = max(0, theta_enter - 1)
        self.theta_enter = theta_enter
        self.theta_exit = theta_exit
        self.mode = 'search'

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            self.mode = 'search'
            return Action.D
        if round_number >= n_rounds - 1:
            self.mode = 'search'
            return Action.D
        last_q = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if self.mode == 'search':
            if round_number >= 2:
                prev_q = int(history.opponent_cooperators[-2])
                if last_q >= self.theta_enter and prev_q >= self.theta_enter:
                    self.mode = 'exploit'
                    return Action.C
            return Action.D
        if last_q >= self.theta_exit:
            return Action.C
        self.mode = 'search'
        return Action.D

class Strategy_OPPORTUNISTIC_58(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Start with cooperation.
    - Sustain cooperation only under broad observed cooperation.
    - Defect immediately when cooperation falls below the lower acceptance band.
    - After a streak of defections, probe for recovery with a single cooperation once cooperation rebounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.S = 0.0
        self.x_prev = None
        self.last_processed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        k = self.game_description.k
        denom = max(1, n - 1)
        if history.round_number == 0:
            self.S = 0.0
            self.x_prev = None
            self.last_processed_round = 0
            return Action.C
        if history.round_number == self.last_processed_round:
            return Action.C if bool(history.my_actions[-1]) else Action.D
        x = int(history.opponent_cooperators[-1])
        rate = x / denom
        T_high = max(0.6, 1.0 - 1.0 / k) if k > 0 else 0.6
        T_low = min(0.4, T_high - 0.15)
        self.S = 0.6 * self.S + rate - 0.5
        self.x_prev = x
        my_actions = history.my_actions
        d_streak = 0
        i = len(my_actions) - 1
        while i >= 0 and (not bool(my_actions[i])):
            d_streak += 1
            i -= 1
        last_played_c = len(my_actions) > 0 and bool(my_actions[-1])
        if last_played_c and rate < T_low:
            action = Action.D
        elif d_streak >= 3:
            action = Action.C if rate >= T_low else Action.D
        elif d_streak >= 2 and rate < T_low:
            action = Action.D
        elif rate >= T_high or (self.S >= 0.1 and rate >= T_low):
            action = Action.C
        else:
            action = Action.D
        self.last_processed_round = history.round_number
        return action

class Strategy_OPPORTUNISTIC_59(BaseStrategy):
    """
    Opportunistic Threshold-Reciprocity:
    - Open with cooperation when the public return is strong enough.
    - Continue cooperating only if both the most recent round and the running
      average of opponent cooperation remain at or above half.
    - In the final round, cooperate only if every opponent cooperated in the
      previous round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.k = game_description.k
        self.n_opponents = max(0, self.n_players - 1)
        self.half_opponents_ceiling = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            if self.k > 2:
                return Action.C
            if self.k < 2:
                return Action.D
            return Action.C
        m_t = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if t >= self.n_rounds - 1:
            return Action.C if m_t == self.n_opponents else Action.D
        total_opponent_cooperations = int(np.sum(history.opponent_cooperators)) if len(history.opponent_cooperators) > 0 else 0
        denom = self.n_opponents * t
        M_t = total_opponent_cooperations / denom if denom > 0 else 0.0
        if M_t >= 0.5 and m_t >= self.half_opponents_ceiling:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_60(BaseStrategy):
    """
    Threshold-plus-buffer public goods strategy:
    - Defect in the first round.
    - Cooperate only when observed opponent cooperation is sufficiently high,
      stable/non-collapsing, and above the profitability threshold.
    - In the final round, require the buffered threshold only.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.m = max(0, self.n_players - 1)
        if self.k > 0:
            self.q_threshold = int(math.ceil(self.n_players / self.k - 1.0))
        else:
            self.q_threshold = self.n_players

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        if t == 1:
            return Action.D
        if self.m <= 0:
            return Action.D
        x_prev = int(history.opponent_cooperators[-1]) if history.round_number >= 1 else 0
        rounds_observed = history.round_number
        total_observed = int(np.sum(history.opponent_cooperators)) if rounds_observed > 0 else 0
        denom = rounds_observed * self.m
        p_hat_prev = total_observed / denom if denom > 0 else 0.0
        buffer = 1 if p_hat_prev >= (self.q_threshold + 1) / self.m else 0
        threshold = self.q_threshold + buffer
        if t == self.n_rounds:
            return Action.C if x_prev >= threshold else Action.D
        if t == 2:
            return Action.C if x_prev >= self.q_threshold else Action.D
        if history.round_number >= 2:
            x_prev_prev = int(history.opponent_cooperators[-2])
            if x_prev >= threshold and x_prev >= x_prev_prev:
                return Action.C
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_61(BaseStrategy):
    """
    Defect by default; cooperate only after a sustained streak of unanimous
    cooperation by all opponents, with a sufficiently high recent moving
    average and only before the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.theta_low = 0.5
        self.theta_high = 1.0
        self.H = 2
        self.G = 2
        self.w = max(1, min(5, self.n_rounds - 1))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        r = self.n_rounds
        n_opponents = max(0, self.n_players - 1)
        if t == 1:
            return Action.D
        if t == r:
            return Action.D
        past_opponents = history.opponent_cooperators
        past_len = len(past_opponents)
        h_prev = 0
        idx = past_len - 1
        while idx >= 0 and past_opponents[idx] == n_opponents:
            h_prev += 1
            idx -= 1
        if past_len <= 0:
            m_prev = 0.0
        else:
            start = past_len - min(self.w, past_len)
            window = past_opponents[start:past_len]
            denom = float(n_opponents) if n_opponents > 0 else 1.0
            m_prev = float(np.mean(np.asarray(window, dtype=float) / denom))
        last_g_all = False
        if past_len >= self.G and self.G > 0:
            last_g_all = bool(np.all(past_opponents[past_len - self.G:past_len] == n_opponents))
        if h_prev < self.H:
            return Action.D
        if m_prev < self.theta_low:
            return Action.D
        if m_prev >= self.theta_high and last_g_all:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_62(BaseStrategy):
    """
    Adaptive public-goods strategy with smoothed cooperation tracking,
    betrayal detection, and short-term opportunistic response rules.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.s = 0.5
        self.b = 0
        self._last_processed_round = 0
        self._prev_p = None
        self._last_p = None
        self._ones_streak = 0
        self._low_streak = 0
        self._force_defect_remaining = 0
        self._persistent_defect = False

    def _observe_round(self, p_t: float) -> None:
        """Update internal state using observed opponent cooperation rate p_t."""
        prev_s = self.s
        self.s = 2.0 / 3.0 * self.s + 1.0 / 3.0 * p_t
        if p_t < prev_s - 0.2:
            self.b += 1
        else:
            self.b = max(0, self.b - 1)
        if p_t == 1.0:
            self._ones_streak += 1
        else:
            self._ones_streak = 0
        if p_t <= 0.2:
            self._low_streak += 1
        else:
            self._low_streak = 0
        if p_t == 0.0:
            self._force_defect_remaining = 2
        if self._low_streak >= 2:
            self._persistent_defect = True
        if p_t >= 1.0 / max(self.game_description.k, 1e-12):
            self._persistent_defect = False
        self._prev_p = self._last_p
        self._last_p = p_t
        self._last_processed_round += 1

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        k = self.game_description.k
        while self._last_processed_round < history.round_number:
            idx = self._last_processed_round
            opp_count = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            denom = max(n - 1, 1)
            p_t = float(opp_count) / float(denom)
            self._observe_round(p_t)
        t = history.round_number + 1
        tau = 1.0 / max(k, 1e-12)
        tau_strict = min(1.0, tau + 0.1 + 0.05 * min(self.b, 3))
        if t == 1:
            return Action.C if k >= 1.5 else Action.D
        if t == 2:
            p1 = self._last_p if self._last_p is not None else 0.0
            return Action.C if p1 >= 0.5 else Action.D
        if t == r:
            p_prev = self._last_p if self._last_p is not None else 0.0
            return Action.C if p_prev >= tau_strict and self.b == 0 else Action.D
        if self._force_defect_remaining > 0:
            self._force_defect_remaining -= 1
            return Action.D
        if self._ones_streak >= 2:
            return Action.C
        if self._persistent_defect:
            return Action.D
        p_prev = self._last_p if self._last_p is not None else 0.0
        if self.s >= tau_strict and self.b <= 1:
            if r - t > 1 or p_prev >= tau_strict:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_63(BaseStrategy):
    """
    Start by cooperating, then reward two consecutive rounds of sufficiently
    strong cooperation from opponents, but always defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(game_description.n_players)
        k = float(game_description.k)
        if k > 0:
            self.threshold = int(math.ceil((n_players - 1) / k))
        else:
            self.threshold = n_players
        self.good_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        total_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            self.good_streak = 0
            return Action.C
        streak = 0
        for x in history.opponent_cooperators:
            if int(x) >= self.threshold:
                streak += 1
            else:
                streak = 0
        self.good_streak = streak
        next_round = round_number + 1
        if next_round >= total_rounds:
            return Action.D
        if self.good_streak >= 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_64(BaseStrategy):
    """
    Adaptive public-goods strategy with:
    - initial cooperation,
    - immediate retaliation after a fully defective round,
    - threshold-based cooperation/defection,
    - opportunistic adjustment for trends,
    - conservative final-round defection unless cooperation was reliably strong.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.n_players = n
        self.n_rounds = int(game_description.n_rounds)
        denom = k * (n - 1)
        if denom <= 0:
            self.q_star = 1.0
        else:
            self.q_star = (n - k) / denom
        self.q_star = max(0.0, min(1.0, float(self.q_star)))
        self.threshold_count = int(math.ceil((n - 1) * self.q_star))
        self.threshold_count = max(0, min(n - 1, self.threshold_count))
        self.lower_margin = 1.0 / (2.0 * (n - 1)) if n > 1 else 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        last_m = int(opp[-1])
        if t == self.n_rounds - 1:
            if t >= 3:
                if int(opp[-3]) >= self.threshold_count and int(opp[-2]) >= self.threshold_count and (int(opp[-1]) >= self.threshold_count):
                    return Action.C
            return Action.D
        if last_m == 0:
            return Action.D
        total_m = int(np.sum(opp)) if t > 0 else 0
        denom = (self.n_players - 1) * t
        p_hat = total_m / denom if denom > 0 else 0.0
        if math.isclose(p_hat, self.q_star, rel_tol=0.0, abs_tol=1e-12):
            base_action = Action.C if last_m >= self.threshold_count else Action.D
        elif p_hat > self.q_star:
            base_action = Action.C
        else:
            base_action = Action.D
        if t >= 2:
            prev_m = int(opp[-2])
            if prev_m <= last_m and last_m >= self.threshold_count and (p_hat >= self.q_star - self.lower_margin):
                return Action.C
            if prev_m > last_m and p_hat < self.q_star + self.lower_margin:
                return Action.D
        return base_action

class Strategy_OPPORTUNISTIC_65(BaseStrategy):
    """
    Strict opportunistic threshold policy for the N-player Public Goods Game.

    - Defect in the first and final rounds.
    - Cooperate only during clearly strong cooperation stretches.
    - Permanently defect after any meaningful drop in opponent cooperation.
    - Tighten cooperation near the end game, with a very conservative policy.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(game_description.n_players)
        n_opponents = max(0, n_players - 1)
        self._n_opponents = n_opponents
        self._high_threshold = math.ceil(0.8 * n_opponents)
        self._low_threshold = math.floor(n_opponents / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        r = int(self.game_description.n_rounds)
        q = int(history.round_number)
        if r <= 1:
            return Action.D
        if q == 0:
            return Action.D
        if history.opponent_cooperators.size > 0:
            if np.any(history.opponent_cooperators <= self._low_threshold):
                return Action.D
        if q == r - 1:
            return Action.D
        if q >= max(0, r - 3):
            if q != r - 3:
                return Action.D
            if history.round_number < 2:
                return Action.D
            if not (history.opponent_cooperators[-1] == self._n_opponents and history.opponent_cooperators[-2] == self._n_opponents):
                return Action.D
            return Action.C
        a_prev = int(history.opponent_cooperators[-1]) if history.opponent_cooperators.size > 0 else 0
        m_t = float(np.mean(history.opponent_cooperators[-3:])) if history.opponent_cooperators.size > 0 else 0.0
        if a_prev < self._high_threshold:
            return Action.D
        if m_t < self._high_threshold:
            return Action.D
        if history.round_number >= 2:
            a_prev2 = int(history.opponent_cooperators[-2])
            if not a_prev > a_prev2:
                return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_66(BaseStrategy):
    """
    Opportunistic always-defect strategy for the repeated public goods game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._default_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        if history is None:
            return self._default_action
        if not hasattr(history, 'round_number'):
            return self._default_action
        if history.round_number <= 0:
            return self._default_action
        if not hasattr(history, 'opponent_cooperators'):
            return self._default_action
        return self._default_action

class Strategy_OPPORTUNISTIC_67(BaseStrategy):
    """
    Conditional public-goods cooperator:
    - Defects in the first and last round
    - Enters cooperation only after sustained opponent cooperation
    - Exits cooperation immediately after any observed deterioration
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.state = 'OUT'
        self.good_streak = 0
        self.bad_streak = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        k = self.game_description.k
        H = 1.0 / k if k != 0 else float('inf')
        while self._last_processed_round < history.round_number:
            idx = self._last_processed_round
            if idx < len(history.opponent_cooperators):
                opp_coop = int(history.opponent_cooperators[idx])
                denom = max(1, n_players - 1)
                q_t = opp_coop / denom
                if q_t >= H:
                    self.good_streak += 1
                    self.bad_streak = 0
                else:
                    self.bad_streak += 1
                    self.good_streak = 0
                if self.state == 'OUT' and self.good_streak >= 2:
                    self.state = 'IN'
                elif self.state == 'IN' and self.bad_streak >= 1:
                    self.state = 'OUT'
            self._last_processed_round += 1
        t = history.round_number + 1
        if t == 1 or t == n_rounds:
            return Action.D
        q_t = 0.0
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            denom = max(1, n_players - 1)
            q_t = int(history.opponent_cooperators[-1]) / denom
        if t >= n_rounds - 2 and q_t < H:
            return Action.D
        if self.state == 'IN':
            return Action.C if q_t >= H else Action.D
        required_good = 3 if t >= n_rounds - 2 else 2
        if self.good_streak >= required_good and q_t >= H:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_68(BaseStrategy):
    """
    Opportunistic cooperative strategy with smoothed trend tracking:
    - Start by cooperating.
    - Continue cooperating under sustained or recovering cooperation.
    - Defect quickly when cooperation collapses.
    - In the final round, cooperate only under near-certain full cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._processed_rounds = 0
        self._s = 0.5
        self._prev_s = 0.5
        self._trend = 0.0
        self._last_m = None
        self._prev_m = None
        self._zero_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        n_opponents = max(1, n_players - 1)
        half_threshold = int(math.ceil(n_opponents / 2))
        if history.round_number == 0:
            return Action.C
        target_rounds = history.round_number
        if target_rounds > self._processed_rounds:
            for idx in range(self._processed_rounds, target_rounds):
                m = int(history.opponent_cooperators[idx])
                prev_s = self._s
                p_hat = m / n_opponents
                self._prev_s = prev_s
                self._s = 0.7 * prev_s + 0.3 * p_hat
                self._trend = self._s - self._prev_s
                self._prev_m = self._last_m
                self._last_m = m
                if m == 0:
                    self._zero_streak += 1
                else:
                    self._zero_streak = 0
            self._processed_rounds = target_rounds
        last_m = 0 if self._last_m is None else int(self._last_m)
        prev_m = None if self._prev_m is None else int(self._prev_m)
        if history.round_number >= n_rounds - 1:
            return Action.C if last_m == n_opponents else Action.D
        if self._zero_streak >= 2:
            return Action.D
        if last_m == n_opponents:
            return Action.C
        if last_m == 0:
            return Action.D
        if prev_m is not None and prev_m - last_m >= 2:
            return Action.D
        if prev_m is not None and last_m - prev_m >= 2 and (last_m >= half_threshold):
            return Action.C
        if self._s >= 0.6 and self._trend >= -0.1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_69(BaseStrategy):
    """
    Threshold-based conditional cooperator for the repeated N-player Public Goods Game.

    - Defects in the first and final rounds.
    - Cooperates only when recent opponent cooperation has been sufficiently strong
      and persistent.
    - Uses a stricter recovery threshold to re-enter cooperation after a drop.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = getattr(game_description, 'n_players', 0)
        k = float(getattr(game_description, 'k', 0.0))
        n_opponents = max(0, n_players - 1)
        if k > 0:
            threshold = math.ceil(n_opponents / k)
        else:
            threshold = n_opponents + 1
        if n_opponents <= 0:
            threshold = 1
        else:
            threshold = max(0, min(int(threshold), n_opponents + 1))
        self.n_opponents = n_opponents
        self.threshold = threshold
        self.recovery_threshold = threshold + 1
        self.n_rounds = max(0, int(getattr(game_description, 'n_rounds', 0)))

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        last = int(opp[-1])
        if last >= self.recovery_threshold:
            return Action.C
        if round_number >= 2 and len(opp) >= 2:
            prev = int(opp[-2])
            if last >= self.threshold and prev >= self.threshold:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_70(BaseStrategy):
    """
    Join only after two consecutive rounds with broad cooperation,
    and never cooperate in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = getattr(game_description, 'n_players', 0)
        k = getattr(game_description, 'k', 0.0)
        if k and k > 0:
            self.threshold = int(math.ceil(max(n_players - 1, 0) / k))
        else:
            self.threshold = n_players
        self.h = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        if round_number == 0:
            self.h = 0
            return Action.D
        if n_rounds > 0 and round_number >= n_rounds - 1:
            return Action.D
        h = 0
        opponent_cooperators = history.opponent_cooperators
        idx = round_number - 1
        while idx >= 0:
            if opponent_cooperators[idx] >= self.threshold:
                h += 1
                idx -= 1
            else:
                break
        self.h = h
        if self.h >= 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_71(BaseStrategy):
    """
    Adaptive public-goods strategy that estimates opponent cooperation,
    exploits sustained cooperation, and probes periodically after low-cooperation
    periods.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.alpha = 0.35
        self.p_hat = 0.5
        self._processed_rounds = 0
        self._high_streak = 0
        self._low_streak = 0
        self._probe_rounds_since_low = 0
        self._in_cooperation_mode = False

    def _n_opponents(self) -> int:
        return max(1, self.game_description.n_players - 1)

    def _high_threshold(self) -> int:
        return math.ceil((self.game_description.n_players - 1) / 2)

    def _low_threshold(self) -> int:
        return math.ceil((self.game_description.n_players - 1) / 3)

    def _clamp01(self, x: float) -> float:
        return 0.0 if x < 0.0 else 1.0 if x > 1.0 else x

    def _expected_gain(self) -> float:
        n = self.game_description.n_players
        k = self.game_description.k
        return k / n * (1.0 + (n - 1) * self.p_hat) - 1.0

    def _sync_state(self, history: PlayerHistory) -> None:
        n_opponents = self._n_opponents()
        high_thr = self._high_threshold()
        low_thr = self._low_threshold()
        while self._processed_rounds < history.round_number:
            m_t = int(history.opponent_cooperators[self._processed_rounds])
            frac = m_t / n_opponents if n_opponents > 0 else 0.0
            self.p_hat = self._clamp01((1.0 - self.alpha) * self.p_hat + self.alpha * frac)
            if m_t >= high_thr:
                self._high_streak += 1
            else:
                self._high_streak = 0
            if m_t < low_thr:
                self._low_streak += 1
            else:
                self._low_streak = 0
            if self._high_streak >= 2:
                self._in_cooperation_mode = True
            if self._in_cooperation_mode and m_t < high_thr:
                self._in_cooperation_mode = False
            if self._low_streak >= 1:
                self._probe_rounds_since_low += 1
            else:
                self._probe_rounds_since_low = 0
            self._processed_rounds += 1

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        high_thr = self._high_threshold()
        low_thr = self._low_threshold()
        self._sync_state(history)
        t = history.round_number
        if t == 0:
            return Action.C
        m_prev = int(history.opponent_cooperators[-1]) if history.round_number >= 1 else 0
        m_prev2 = int(history.opponent_cooperators[-2]) if history.round_number >= 2 else None
        G = self._expected_gain()
        last_two_high = history.round_number >= 2 and int(history.opponent_cooperators[-1]) >= high_thr and (int(history.opponent_cooperators[-2]) >= high_thr)
        last_two_low = history.round_number >= 2 and int(history.opponent_cooperators[-1]) < low_thr and (int(history.opponent_cooperators[-2]) < low_thr)
        if t == 1:
            return Action.C if m_prev >= high_thr else Action.D
        if t == r - 1:
            if m_prev == n - 1:
                return Action.C
            return Action.C if G >= 0.0 else Action.D
        if history.round_number >= 3 and last_two_high:
            return Action.C if G >= -0.1 else Action.D
        if history.round_number >= 3 and last_two_low:
            return Action.D if G < 0.25 else Action.C
        probe_due = self._low_streak >= 1 and self._probe_rounds_since_low > 0 and (self._probe_rounds_since_low % 3 == 0) and (self.p_hat >= (n / self.game_description.k - 1.0) / max(1, n - 1) - 0.05)
        if probe_due:
            return Action.C
        if self._in_cooperation_mode:
            if m_prev == 0 or m_prev < low_thr:
                return Action.D
            return Action.C if G >= -0.1 else Action.D
        if G > 0.0:
            return Action.C
        if G < 0.0:
            return Action.D
        return Action.C if m_prev >= high_thr else Action.D

class Strategy_OPPORTUNISTIC_72(BaseStrategy):
    """
    Three-phase adaptive threshold strategy for the repeated N-player Public Goods Game.

    Core ideas:
    - Start with cooperation.
    - Estimate opponent cooperation with exponential smoothing.
    - Cooperate only when cooperation is broad, stable, and sufficiently high.
    - Defect quickly when cooperation weakens.
    - Apply special-case logic for n=2 and r=2.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.n_opponents = max(0, self.n_players - 1)
        self.half_threshold = int(math.ceil(self.n_opponents / 2)) if self.n_opponents > 0 else 0
        self.phase_cutoff = max(2, int(math.floor(self.n_rounds / 5)))
        self.phase_cutoff = max(0, self.phase_cutoff)

    def _phase_threshold(self, t: int) -> float:
        if t <= self.phase_cutoff:
            return 0.45
        if t < self.n_rounds - self.phase_cutoff:
            return 0.6
        return 0.7

    def _compute_smoothed_estimates(self, history: PlayerHistory):
        """
        Returns:
            smoothed[t] = ŝ_t for t in [0, round_number]
        where ŝ_0 = 0 and ŝ_t is updated from round t (1-based in the description).
        """
        rounds = history.round_number
        smoothed = [0.0] * (rounds + 1)
        prev = 0.0
        for idx in range(rounds):
            m_t = float(history.opponent_cooperators[idx])
            denom = float(self.n_opponents) if self.n_opponents > 0 else 1.0
            obs = m_t / denom if denom > 0 else 0.0
            current = 0.7 * prev + 0.3 * obs
            smoothed[idx + 1] = current
            prev = current
        return smoothed

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if self.n_players == 2:
            return Action.C if bool(history.opponent_cooperators[-1] > 0) else Action.D
        if self.n_rounds == 2:
            if t == 1:
                return Action.C if history.opponent_cooperators[0] >= self.half_threshold else Action.D
        smoothed = self._compute_smoothed_estimates(history)
        last_m = int(history.opponent_cooperators[-1])
        last_rho = float(smoothed[t])
        if t == self.n_rounds - 1:
            return Action.C if last_rho >= 0.75 and last_m >= self.half_threshold else Action.D
        if last_m == self.n_opponents and self.n_opponents > 0:
            return Action.C
        if last_m == 0:
            return Action.D
        if t >= 2:
            prev_m = int(history.opponent_cooperators[-2])
            if prev_m > 0 and last_m * 2 <= prev_m:
                return Action.D
        p_t = self._phase_threshold(t)
        rho_t = last_rho
        if t >= 2:
            prev_rho = float(smoothed[t - 1])
            p_prev = self._phase_threshold(t - 1)
            two_below = prev_rho < p_prev and rho_t < p_t
        else:
            two_below = False
        if rho_t >= p_t and last_m >= self.half_threshold and (not two_below):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_73(BaseStrategy):
    """
    Threshold-based public goods strategy with cooldown and endgame caution.

    - Starts with defection.
    - Cooperates only after two consecutive high-cooperation observations.
    - Defects immediately after low cooperation and enters a 2-round cooldown.
    - Defects in the final round always.
    - Uses a stricter requirement in the penultimate round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.k = game_description.k
        self.n_opponents = max(0, self.n_players - 1)
        self.theta = 1.0 if self.n_players == 2 else 1.0 / self.k if self.k != 0 else 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t >= self.n_rounds - 1:
            return Action.D
        if t == 0:
            return Action.D
        if t < 2:
            return Action.D

        def is_high(round_index: int) -> bool:
            if round_index < 0 or round_index >= len(history.opponent_cooperators):
                return False
            if self.n_opponents <= 0:
                return False
            q = history.opponent_cooperators[round_index] / self.n_opponents
            return q >= self.theta
        high_streak = 0
        idx = t - 1
        while idx >= 0 and is_high(idx):
            high_streak += 1
            idx -= 1
        if t == self.n_rounds - 2:
            return Action.C if high_streak >= 3 else Action.D
        if high_streak >= 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_74(BaseStrategy):
    """
    Adaptive public-goods strategy with two states:
    ENGAGE: cooperate when recent cooperation remains sufficiently high.
    EXPLOIT: defect, with periodic probe cooperations to test recovery.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.state = 'ENGAGE'
        self.state_rounds = 0
        self.pending_probe = False

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        opp_count = max(n_players - 1, 1)
        t = history.round_number + 1
        if t == n_rounds:
            return Action.D
        if history.round_number == 0:
            self.state = 'ENGAGE'
            self.state_rounds = 1
            self.pending_probe = False
            return Action.C
        past_q = [float(x) / opp_count for x in history.opponent_cooperators.tolist()]
        q_prev = past_q[-1] if past_q else 0.0
        window = min(4, len(past_q))
        m_t = float(np.mean(past_q[-window:])) if window > 0 else 0.0
        my_last = bool(history.my_actions[-1])
        my_last2 = bool(history.my_actions[-2]) if len(history.my_actions) >= 2 else None
        my_last3 = bool(history.my_actions[-3]) if len(history.my_actions) >= 3 else None
        last_two_low = len(past_q) >= 2 and past_q[-1] <= 1.0 / 3.0 and (past_q[-2] <= 1.0 / 3.0)
        last_three_high = len(past_q) >= 3 and past_q[-1] > 2.0 / 3.0 and (past_q[-2] > 2.0 / 3.0) and (past_q[-3] > 2.0 / 3.0)
        if self.pending_probe:
            if q_prev >= 2.0 / 3.0:
                self.state = 'ENGAGE'
                self.state_rounds = 0
            else:
                self.state = 'EXPLOIT'
            self.pending_probe = False
        if q_prev >= 2.0 / 3.0:
            self.state = 'ENGAGE'
        elif last_two_low:
            self.state = 'EXPLOIT'
        elif self.state == 'ENGAGE' and last_three_high and (q_prev >= 1.0 / 3.0):
            self.state = 'ENGAGE'
        if my_last and q_prev < 1.0 / 2.0 and (q_prev < 2.0 / 3.0):
            self.state = 'EXPLOIT'
        if not my_last and q_prev >= 1.0 / 2.0:
            self.state = 'ENGAGE'
        if self.state == 'ENGAGE':
            self.state_rounds += 1
            return Action.C if m_t >= 1.0 / 2.0 else Action.D
        self.state_rounds += 1
        if self.state_rounds % 3 == 0:
            self.pending_probe = True
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_75(BaseStrategy):
    """
    Reactive public-goods strategy:
    - Cooperate on the first round.
    - Defect in the endgame.
    - Cooperate only under sustained high cooperation.
    - Defect quickly under low cooperation.
    - Otherwise alternate from the previous action.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_opponents = max(0, game_description.n_players - 1)
        self.n_opponents = n_opponents
        self.high_threshold = math.ceil(n_opponents / 2) if n_opponents > 0 else 0
        self.low_threshold = math.floor(n_opponents / 3) if n_opponents > 0 else 0
        self.endgame_start = max(0, game_description.n_rounds - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n_rounds = self.game_description.n_rounds
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        my_actions = history.my_actions
        h = self.high_threshold
        l = self.low_threshold
        if t >= max(0, n_rounds - 1):
            return Action.D
        last_opp = int(opp[-1]) if len(opp) >= 1 else 0
        prev_opp = int(opp[-2]) if len(opp) >= 2 else 0
        prev2_opp = int(opp[-3]) if len(opp) >= 3 else 0
        last_action = bool(my_actions[-1]) if len(my_actions) >= 1 else False
        last_two_high = len(opp) >= 2 and prev_opp >= h and (last_opp >= h)
        last_three_high = len(opp) >= 3 and prev2_opp >= h and (prev_opp >= h) and (last_opp >= h)
        last_two_low = len(opp) >= 2 and prev_opp <= l and (last_opp <= l)
        sharp_rebound = len(opp) >= 2 and last_opp - prev_opp >= 2
        if last_three_high:
            return Action.C
        if last_two_low:
            return Action.D
        if last_opp <= l:
            return Action.D
        if last_two_high:
            return Action.C
        if not last_action:
            if last_two_high:
                return Action.C
            if last_opp >= h:
                return Action.D
            if sharp_rebound:
                return Action.C
        return Action.D if last_action else Action.C

class Strategy_OPPORTUNISTIC_76(BaseStrategy):
    """
    Threshold-based public-goods strategy:
    - Cooperate in the first round.
    - Defect in the terminal round.
    - In between, cooperate only when recent opponent cooperation is strong,
      stable, and above a threshold derived from n and k.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        n_opponents = max(0, n_players - 1)
        self.n_opponents = n_opponents
        if k > 1.0:
            tau = math.ceil(n_opponents * (1.0 - 1.0 / k))
        else:
            tau = n_opponents
        if tau < 0:
            tau = 0
        if tau > n_opponents:
            tau = n_opponents
        self.tau = int(tau)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        total_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        if round_number == 0:
            return Action.C
        if total_rounds > 0 and round_number >= total_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        recent = opp[-3:]
        s_t = float(np.mean(recent)) if len(recent) > 0 else 0.0
        q_prev = int(opp[-1])
        if q_prev < self.tau:
            return Action.D
        if s_t < self.tau:
            return Action.D
        if round_number >= 2:
            q_prev2 = int(opp[-2])
            if q_prev < q_prev2:
                return Action.D
        return Action.C

class Strategy_OPPORTUNISTIC_77(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Defects initially
    - Cooperates only under stable, sufficiently high observed cooperation
    - Uses short recovery and probe phases after exploitation
    - Becomes conservative in the final rounds
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.recovery_defect_remaining = 0
        self.recovery_probe_used = False
        self.coop_lock_active = False
        self._test_coop_streak = 0
        self.last_action = Action.D
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds
        n_opponents = max(1, self.game_description.n_players - 1)
        if round_number == 0:
            self.last_action = Action.D
            self.last_seen_round = 0
            return Action.D
        opp_counts = history.opponent_cooperators
        p_hist = [float(x) / float(n_opponents) for x in opp_counts]
        p_last = p_hist[-1] if len(p_hist) >= 1 else 0.0
        recent_window = p_hist[-2:] if len(p_hist) >= 2 else p_hist[:]
        recent = float(np.mean(recent_window)) if len(recent_window) > 0 else 0.0
        if len(p_hist) >= 4:
            prev_window = p_hist[-4:-2]
            prev_avg = float(np.mean(prev_window)) if len(prev_window) > 0 else 0.0
            trend = recent - prev_avg
        else:
            trend = 0.0
        if round_number >= 1 and self.last_action == Action.C and (p_last < 0.4):
            self.recovery_defect_remaining = 2
            self.recovery_probe_used = False
            self.coop_lock_active = False
            self._test_coop_streak = 0
        if round_number == n_rounds - 1:
            if len(p_hist) >= 2 and p_hist[-1] >= 0.75 and (p_hist[-2] >= 0.75):
                action = Action.C
            else:
                action = Action.D
            self.last_action = action
            self.last_seen_round = round_number
            return action
        if round_number == n_rounds - 2:
            if p_last >= 0.75 and trend >= 0.0:
                action = Action.C
            else:
                action = Action.D
            self.last_action = action
            self.last_seen_round = round_number
            return action
        if self.recovery_defect_remaining > 0:
            self.recovery_defect_remaining -= 1
            action = Action.D
            self.last_action = action
            self.last_seen_round = round_number
            return action
        if not self.recovery_probe_used and recent >= 0.5 and (self.last_seen_round >= 0):
            action = Action.C
            self.recovery_probe_used = True
            self.last_action = action
            self.last_seen_round = round_number
            return action
        if self.coop_lock_active:
            if recent < 0.4:
                self.coop_lock_active = False
                self._test_coop_streak = 0
                action = Action.D
            else:
                action = Action.C
            self.last_action = action
            self.last_seen_round = round_number
            return action
        if recent >= 0.75:
            self._test_coop_streak = 0
            action = Action.C
            self.last_action = action
            self.last_seen_round = round_number
            return action
        if 0.4 <= recent < 0.75 and trend >= 0.0:
            self._test_coop_streak += 1
            action = Action.C
            if self._test_coop_streak >= 2:
                self.coop_lock_active = True
            self.last_action = action
            self.last_seen_round = round_number
            return action
        if recent < 0.4 or (trend < 0.0 and recent < 0.6):
            self._test_coop_streak = 0
            action = Action.D
            self.last_action = action
            self.last_seen_round = round_number
            return action
        self._test_coop_streak = 0
        action = Action.D
        self.last_action = action
        self.last_seen_round = round_number
        return action

class Strategy_OPPORTUNISTIC_78(BaseStrategy):
    """
    Start defecting, then cooperate only after observing two consecutive rounds
    in which at least q opponents cooperated. Defect immediately after any
    round below the threshold, and re-enter cooperation only after a fresh
    two-round qualifying streak.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0) or 0)
        n_opponents = max(0, n_players - 1)
        self.n_opponents = n_opponents
        self.q = math.ceil(n_opponents / 2) if n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        prev = int(opp[-1]) if len(opp) > 0 else 0
        streak = 0
        idx = len(opp) - 1
        while idx >= 0:
            if int(opp[idx]) >= self.q:
                streak += 1
                idx -= 1
            else:
                break
        if prev >= self.q and streak >= 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_79(BaseStrategy):
    """
    Threshold-based conditional cooperator for the repeated N-player Public Goods Game.

    - Starts with defection.
    - Cooperates only when recent cooperation is strong, stable, and non-declining.
    - Defects immediately after a sharp drop in observed cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        k = float(game_description.k)
        self.theta = max(0.5, 1.0 - (1.0 / k if k > 0 else 1.0))
        self.n_opponents = max(0, int(game_description.n_players) - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        n_op = self.n_opponents

        def rho_from_count(count: int) -> float:
            return count / n_op if n_op > 0 else 0.0
        rho_last = rho_from_count(int(opp[-1]))
        if t >= 2 and bool(history.my_actions[-1]):
            prev_count = int(opp[-2])
            if int(opp[-1]) <= prev_count - 2:
                return Action.D
        if t == 1:
            return Action.C if rho_last >= self.theta else Action.D
        last_k = min(3, t)
        recent_rhos = [rho_from_count(int(x)) for x in opp[-last_k:]]
        m = float(np.mean(recent_rhos)) if recent_rhos else 0.0
        delta = rho_last - rho_from_count(int(opp[-2])) if t >= 2 else 0.0
        if rho_last >= self.theta and m >= self.theta and (delta >= 0.0):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_80(BaseStrategy):
    """
    Opportunistic public-goods strategy:
    - Default to defection.
    - Cooperate only when observed opponent cooperation is consistently high
      enough to sustain the public good.
    - Tighten cooperation in the final rounds to preserve private payoff if
      support is not clearly sufficient.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.threshold = int(math.ceil(n / k)) if k > 0 else n
        self.support_threshold = max(0, self.threshold - 1)
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        last_support = int(opp[-1])
        avg_support = float(np.mean(opp)) if len(opp) > 0 else 0.0
        recent_len = min(3, len(opp))
        recent_window = opp[-recent_len:] if recent_len > 0 else np.array([], dtype=int)
        recent_strong = bool(len(recent_window) > 0 and np.all(recent_window >= self.support_threshold))
        if t >= self.n_rounds - 1:
            return Action.C if last_support >= self.support_threshold else Action.D
        if t == self.n_rounds - 2:
            if last_support >= self.support_threshold and avg_support >= self.support_threshold:
                return Action.C if recent_strong or len(opp) < 3 else Action.C
            return Action.D
        if last_support >= self.support_threshold and avg_support >= self.support_threshold:
            return Action.C
        if recent_strong and last_support >= self.support_threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_81(BaseStrategy):
    """
    Guarded public-goods strategy:
    - Start by defecting.
    - Cooperate only after strong, repeated cooperation by opponents.
    - Defect in weak or fragmented environments.
    - In the final round, reward a sufficiently cooperative previous round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        self.high = math.ceil((n - 1) / 2)
        self.low = math.floor((n - 1) / 4)
        self.exploit = math.ceil(2 * (n - 1) / 3)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        m = int(history.opponent_cooperators[-1])
        prev_m = int(history.opponent_cooperators[-2]) if t >= 2 else None
        s = 0
        f = 0
        for val in history.opponent_cooperators[::-1]:
            v = int(val)
            if v >= self.high:
                if f > 0:
                    break
                s += 1
            elif v <= self.low:
                if s > 0:
                    break
                f += 1
            else:
                break
        stable_coop = False
        if t >= 3:
            last_three = history.opponent_cooperators[-3:]
            stable_coop = bool(np.all(last_three >= self.high))
        action = Action.D
        if m >= self.exploit:
            action = Action.C
        elif m >= self.high and (s >= 2 or stable_coop):
            action = Action.C
        elif m <= self.low:
            action = Action.D
        else:
            action = Action.D
        if t >= 2:
            last_two = history.opponent_cooperators[-2:]
            if np.all(last_two <= self.low):
                action = Action.D
        if t == self.game_description.n_rounds:
            if prev_m is not None and prev_m >= self.high:
                action = Action.C
            else:
                action = Action.D
        return action

class Strategy_OPPORTUNISTIC_82(BaseStrategy):
    """
    Always defects in every round, regardless of history or game state.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._default_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        return self._default_action

class Strategy_OPPORTUNISTIC_83(BaseStrategy):
    """
    Probe initially, then cooperate when recent cooperation is sufficiently high,
    defect on sustained downward trends, and be conservative on the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.mode = 'probe'

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.n
        r = self.r
        t = history.round_number
        if t == 0:
            self.mode = 'probe'
            return Action.C
        opp = history.opponent_cooperators

        def get_m(idx: int) -> int:
            if 0 <= idx < len(opp):
                return int(opp[idx])
            return 0
        if n == 2:
            last_m = get_m(t - 1)
            if t == r:
                self.mode = 'exploit' if last_m >= 1 else 'defend'
            else:
                self.mode = 'exploit' if last_m >= 1 else 'defend'
            return Action.C if last_m >= 1 else Action.D
        if t == r - 1:
            last_m = get_m(t - 1)
            prev_m = get_m(t - 2)
            if last_m == n - 1 and (t < 2 or prev_m == n - 1):
                self.mode = 'exploit'
                return Action.C
            self.mode = 'defend'
            return Action.D
        last_m = get_m(t - 1)
        L = min(3, t)
        recent_sum = 0
        for j in range(L):
            recent_sum += get_m(t - 1 - j)
        denom = L * max(n - 1, 1)
        avg = recent_sum / denom if denom > 0 else 0.0
        if t >= 3:
            m1 = get_m(t - 1)
            m2 = get_m(t - 2)
            m3 = get_m(t - 3)
            if m1 < m2 and m2 < m3:
                self.mode = 'defend'
                return Action.D
        if t >= 3:
            m1 = get_m(t - 1)
            m2 = get_m(t - 2)
            m3 = get_m(t - 3)
            if m3 < m2 < m1 and m1 >= math.ceil((n - 1) / 3):
                self.mode = 'exploit'
                return Action.C
        if t <= 2 and last_m >= 1:
            self.mode = 'exploit'
            return Action.C
        if last_m >= math.ceil((n - 1) / 2) or avg >= 0.6 or last_m == n - 1:
            self.mode = 'exploit'
            return Action.C
        self.mode = 'defend'
        return Action.D

class Strategy_OPPORTUNISTIC_84(BaseStrategy):
    """
    Opportunistic threshold-based strategy for the repeated N-player Public Goods Game.

    - Opens with cooperation.
    - Cooperates only when recent opponent cooperation is strong.
    - Falls back to pure defection after sustained weakness.
    - Recovers when cooperation remains strong for two consecutive rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.fallback_mode = False
        self._last_seen_rounds = 0
        self._last_H = 0.0

    def _compute_H_sequence(self, history: PlayerHistory):
        n = self.game_description.n_players
        denom = max(1, n - 1)
        H_values = [0.0]
        H = 0.0
        for q in history.opponent_cooperators:
            s = float(q) / denom
            H = 0.6 * H + 0.4 * s
            H_values.append(H)
        return H_values

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number + 1
        if history.round_number == 0:
            self.fallback_mode = False
            self._last_seen_rounds = 0
            self._last_H = 0.0
            return Action.C
        H_values = self._compute_H_sequence(history)
        H_prev = H_values[-1] if H_values else 0.0
        q_prev = int(history.opponent_cooperators[-1]) if history.opponent_cooperators.size > 0 else 0
        if len(H_values) >= 3:
            H_last = H_values[-1]
            H_before_last = H_values[-2]
            if H_last < 2.0 / 3.0 and H_before_last < 2.0 / 3.0:
                self.fallback_mode = True
            elif H_last >= 2.0 / 3.0 and H_before_last >= 2.0 / 3.0:
                self.fallback_mode = False
        elif len(H_values) == 2:
            if H_values[-1] < 2.0 / 3.0:
                self.fallback_mode = True
        self._last_seen_rounds = history.round_number
        self._last_H = H_prev
        if self.fallback_mode:
            return Action.D
        if current_round == 1:
            return Action.C
        if current_round == r:
            return Action.C if q_prev == n - 1 else Action.D
        if current_round == r - 1:
            threshold_q = math.ceil(3 * (n - 1) / 4)
            return Action.C if H_prev >= 0.75 and q_prev >= threshold_q else Action.D
        if 2 <= current_round <= r - 2:
            threshold_q = math.ceil(2 * (n - 1) / 3)
            return Action.C if H_prev >= 2.0 / 3.0 and q_prev >= threshold_q else Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_85(BaseStrategy):
    """
    Probe-based public goods strategy:
    - Defect by default
    - Cooperate only when opponent cooperation is broad and stable
    - Enter a 2-round cooldown after a failed cooperative probe
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'harvest'
        self.cooldown = 0
        self._seen_rounds = 0
        self._last_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        round_idx = history.round_number
        while self._seen_rounds < history.round_number:
            idx = self._seen_rounds
            if idx > 0 and self._last_action == Action.C:
                prev_m = int(history.opponent_cooperators[idx - 1])
                curr_m = int(history.opponent_cooperators[idx])
                if curr_m < prev_m:
                    self.cooldown = 2
                else:
                    self.cooldown = 0
            self._seen_rounds += 1
        if round_idx == 0:
            self._last_action = Action.D
            return Action.D
        if round_idx + 1 == r:
            self._last_action = Action.D
            return Action.D
        if self.cooldown > 0:
            self.cooldown -= 1
            self._last_action = Action.D
            return Action.D
        if history.round_number < 1:
            self._last_action = Action.D
            return Action.D
        m_prev = int(history.opponent_cooperators[-1])
        threshold = math.ceil((n - 1) / 2)
        if history.round_number >= 2:
            m_prev2 = int(history.opponent_cooperators[-2])
            avg2 = (m_prev + m_prev2) / 2.0
            trend = m_prev - m_prev2
        else:
            avg2 = float(m_prev)
            trend = 0
        should_cooperate = m_prev >= threshold and avg2 >= threshold and (trend >= 0) and (self.cooldown == 0) and (round_idx + 1 < r)
        action = Action.C if should_cooperate else Action.D
        self._last_action = action
        return action

class Strategy_OPPORTUNISTIC_86(BaseStrategy):
    """
    Threshold-based conditional cooperator with a cold start,
    persistent engagement, and a short punishment period after defection signals.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.threshold = math.ceil((n_players - 1) / k) if k > 0 else 0
        self.mode = 'cold'
        self.punish_left = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        if n_rounds > 0 and round_number >= n_rounds - 1:
            return Action.D
        if round_number == 0:
            self.mode = 'cold'
            self.punish_left = 0
            return Action.D
        x_last = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        x_prev = int(history.opponent_cooperators[-2]) if round_number >= 2 else 0
        if self.mode == 'cold':
            if round_number >= 2 and x_last >= self.threshold and (x_prev >= self.threshold):
                self.mode = 'engaged'
                return Action.C
            return Action.D
        if self.mode == 'engaged':
            if x_last >= self.threshold:
                return Action.C
            self.mode = 'punish'
            self.punish_left = 1
            return Action.D
        if self.mode == 'punish':
            action = Action.D
            if self.punish_left > 0:
                self.punish_left -= 1
            if self.punish_left <= 0:
                self.mode = 'cold'
                self.punish_left = 0
            return action
        self.mode = 'cold'
        self.punish_left = 0
        return Action.D

class Strategy_OPPORTUNISTIC_87(BaseStrategy):
    """
    Defect by default, cooperate only after sustained high cooperation,
    and immediately fall back to defection when cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        if n <= 2:
            self.H = 1
            self.L = 0
        else:
            self.H = int(math.ceil(0.75 * (n - 1)))
            self.L = int(math.ceil(0.5 * (n - 1)))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        my = history.my_actions
        H = self.H
        L = self.L
        mode = 'scout'
        for i in range(t):
            x = int(opp[i])
            if mode == 'collapse':
                if i >= 1 and int(opp[i - 1]) >= H and (x >= H):
                    mode = 'harvest'
                else:
                    mode = 'collapse'
            elif x <= L:
                mode = 'collapse'
            elif x >= H:
                mode = 'harvest'
        if mode == 'collapse':
            return Action.D
        if t >= 2:
            x_prev = int(opp[t - 1])
            x_prev2 = int(opp[t - 2])
            if x_prev <= L:
                return Action.D
            if x_prev >= H and x_prev2 >= H and (not bool(my[t - 1])):
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_88(BaseStrategy):
    """
    Adaptive cooperation strategy for the N-player Public Goods Game.

    - Round 1: cooperate.
    - Endgame: defect in the last two rounds.
    - Main phase: cooperate only when recent opponent cooperation is high,
      stable, and at least half of opponents cooperated.
    - Fallback: if opponent cooperation drops below half in a round, defect
      immediately and for the next two rounds as well.
    - Special handling for n = 2 follows the stated two-opponent-round rule.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.cooldown_remaining = 0
        self.last_processed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        round_number = history.round_number
        if round_number == 0:
            self.cooldown_remaining = 0
            self.last_processed_round = 0
            return Action.C
        if round_number >= max(0, n_rounds - 2):
            self.cooldown_remaining = 0
            self.last_processed_round = round_number
            return Action.D
        n_opponents = max(0, n_players - 1)
        if n_opponents > 0 and len(history.opponent_cooperators) > 0:
            last_x = int(history.opponent_cooperators[-1])
            if last_x < n_opponents / 2.0:
                self.cooldown_remaining = max(self.cooldown_remaining, 2)
        if self.cooldown_remaining > 0:
            self.cooldown_remaining -= 1
            self.last_processed_round = round_number
            return Action.D
        if n_players == 2:
            if round_number >= 2:
                if bool(history.opponent_cooperators[-1] == 1 and history.opponent_cooperators[-2] == 1):
                    self.last_processed_round = round_number
                    return Action.C
            self.last_processed_round = round_number
            return Action.D
        if n_opponents <= 0:
            self.last_processed_round = round_number
            return Action.D
        recent_x = int(history.opponent_cooperators[-1])
        q = recent_x / n_opponents
        past_x = history.opponent_cooperators[:-1]
        if len(past_x) > 0:
            start = max(0, len(past_x) - 3)
            recent_rates = [float(x) / n_opponents for x in past_x[start:]]
            qbar = float(sum(recent_rates)) / len(recent_rates)
        else:
            qbar = q
        if len(history.opponent_cooperators) >= 2:
            prev_x = int(history.opponent_cooperators[-2])
            q_prev = prev_x / n_opponents
            delta = q - q_prev
        else:
            delta = 0.0
        threshold_x = math.ceil(n_opponents / 2.0)
        if qbar >= 2.0 / 3.0 and delta >= -1.0 / 3.0 and (recent_x >= threshold_x):
            self.last_processed_round = round_number
            return Action.C
        self.last_processed_round = round_number
        return Action.D

class Strategy_OPPORTUNISTIC_89(BaseStrategy):
    """
    Conditional cooperation strategy for the N-player Public Goods Game.

    - Defects in the first round and in the endgame.
    - Only cooperates after two consecutive rounds of strong opponent cooperation.
    - Immediately defects again once cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        opponents = max(0, n - 1)
        self.entry_threshold = math.ceil(2 * opponents / 3)
        self.exit_threshold = math.floor(opponents / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        r = self.n_rounds
        t = history.round_number
        if r <= 2 or t >= r - 2:
            return Action.D
        if t == 0:
            return Action.D
        if t < 2:
            return Action.D
        x_prev = int(history.opponent_cooperators[-1])
        x_prev2 = int(history.opponent_cooperators[-2])
        if x_prev >= self.entry_threshold and x_prev2 >= self.entry_threshold:
            return Action.C
        if x_prev <= self.exit_threshold:
            return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_90(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Cooperate in round 1.
    - Track the running opponent cooperation rate.
    - Cooperate when the estimated opponent cooperation rate is profitable.
    - Defect immediately after sustained low cooperation.
    - Periodically probe for renewed cooperation.
    - Use a stricter threshold in the final 20% of rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(1, self.n_players - 1)
        self.base_threshold = 1.0 / self.k if self.k != 0 else 1.0
        self.final_threshold = min(1.0, self.base_threshold + 0.1)
        self.final_start_round = max(0, math.floor(0.8 * self.n_rounds))
        self.probe_period = max(2, math.floor(self.n_rounds / 5))

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.C
        if t == self.n_rounds - 1:
            last_rate = 0.0
            if len(history.opponent_cooperators) > 0:
                last_rate = float(history.opponent_cooperators[-1]) / self.n_opponents
            return Action.C if last_rate >= self.base_threshold else Action.D
        opp = history.opponent_cooperators
        if len(opp) > 0:
            total_opponent_coops = float(np.sum(opp))
            m_t = total_opponent_coops / (len(opp) * self.n_opponents)
        else:
            m_t = 0.0
        threshold = self.base_threshold
        if t >= self.final_start_round:
            threshold = self.final_threshold
        recent2_rate = None
        if len(opp) >= 2:
            recent2_rate = float(np.sum(opp[-2:])) / (2.0 * self.n_opponents)
        if recent2_rate is not None and recent2_rate < self.base_threshold:
            return Action.D
        if len(opp) >= 2 and t % self.probe_period == 0 and (recent2_rate is not None):
            if recent2_rate > self.base_threshold:
                return Action.C
        return Action.C if m_t >= threshold else Action.D

class Strategy_OPPORTUNISTIC_91(BaseStrategy):
    """
    Open with defection, then only cooperate after a sustained high-cooperation
    regime is observed. Defect in the first and final rounds, and immediately
    abandon cooperation when cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        h_val = (n - 1) * min(0.8, 1 - 1 / n + (k - 1) / (2 * n))
        l_val = (n - 1) * max(0.2, 0.5 - (n - k) / (2 * n))
        self.H = int(math.ceil(h_val))
        self.L = int(math.floor(l_val))
        self.mode = 'exploit'
        self.last_coop_count = None
        self.low_run = 0
        self.high_run = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = int(self.game_description.n_rounds)
        if t == 0:
            return Action.D
        if t >= r - 1:
            return Action.D
        x = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if x >= self.H:
            self.high_run += 1
            self.low_run = 0
        elif x <= self.L:
            self.low_run += 1
            self.high_run = 0
        else:
            self.high_run = 0
            self.low_run = 0
        sharp_drop_ok = self.last_coop_count is None or x >= self.last_coop_count - 1
        cooperate = self.high_run >= 2 and t < r - 1 and (x >= self.H) and sharp_drop_ok
        self.last_coop_count = x
        return Action.C if cooperate else Action.D

class Strategy_OPPORTUNISTIC_92(BaseStrategy):
    """
    Threshold-based public-goods strategy:
    - Defect initially and on the final round.
    - Cooperate only when the last two observed opponent cooperation counts
      are strong enough and non-decreasing, indicating a stable cooperative basin.
    - Otherwise defect, with an implicit fast-retreat posture when cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        if k > 1.0:
            h = math.ceil((n - 1) * (1.0 - 1.0 / k))
        else:
            h = n - 1
        self.threshold_h = max(0, min(n - 1, int(h)))
        self.last_q: int | None = None
        self.prev_q: int | None = None
        self.cooperative_mode: bool = False
        self.low_cooperation_streak: int = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            self.last_q = None
            self.prev_q = None
            self.cooperative_mode = False
            self.low_cooperation_streak = 0
            return Action.D
        q_last = int(history.opponent_cooperators[-1]) if round_number >= 1 else None
        q_prev = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        self.prev_q = q_prev
        self.last_q = q_last
        if q_last is not None and q_last < self.threshold_h:
            self.low_cooperation_streak += 1
        elif q_last is not None:
            self.low_cooperation_streak = 0
        self.cooperative_mode = q_last is not None and q_last >= self.threshold_h and (q_prev is not None and q_prev >= self.threshold_h)
        if round_number >= n_rounds - 1:
            return Action.D
        if q_last is not None and q_last >= self.threshold_h:
            if round_number == 1:
                return Action.D
            if q_prev is not None and q_prev >= self.threshold_h and (q_last >= q_prev):
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_93(BaseStrategy):
    """
    Cooperate initially, then cooperate only when recent cooperation is
    strong and stable. Defect in the final round, and after any collapse
    until cooperation recovers with two consecutive strong rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.support_threshold = math.ceil((n_players - 1) / k) if k != 0 else n_players
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        h1 = int(opp[-1]) if round_number >= 1 else 0
        h2 = int(opp[-2]) if round_number >= 2 else None
        T = self.support_threshold
        if h1 == 0:
            return Action.D
        if round_number >= 2:
            last_zero_idx = -1
            for idx in range(round_number - 1, -1, -1):
                if int(opp[idx]) == 0:
                    last_zero_idx = idx
                    break
            if last_zero_idx != -1:
                rounds_since_zero = round_number - 1 - last_zero_idx
                if rounds_since_zero < 2:
                    return Action.D
                if not (int(opp[-1]) >= T and int(opp[-2]) >= T):
                    return Action.D
        if h1 >= T and h1 > 0:
            if h2 is None or h1 >= h2:
                return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_94(BaseStrategy):
    """
    Public goods strategy:
    - Cooperate in round 1.
    - Track a small internal state g based on the previous round's opponent cooperation.
    - If opponents were near-unanimously cooperative, cooperate once; otherwise defect.
    - Always defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.g = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        threshold = max(0, n_players - 2)
        current_round = history.round_number
        if current_round == 0:
            self.g = 0
            self._last_processed_round = 0
            return Action.C
        if current_round > self._last_processed_round:
            last_m = int(history.opponent_cooperators[-1])
            if last_m >= threshold:
                self.g = min(self.g + 1, 2)
            else:
                self.g = 0
            self._last_processed_round = current_round
        if current_round == n_rounds - 1:
            return Action.D
        if self.g == 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_95(BaseStrategy):
    """
    Threshold-based public goods strategy with early caution, strong-cooperation
    override, recovery rules after extreme outcomes, and late-game opportunism.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = game_description.n_players
        k = game_description.k
        self.threshold_t = math.ceil(n / k) - 1 if k > 0 else n
        self.high_threshold_h = math.ceil((n - 1) / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0:
            return Action.C if self.game_description.k >= n - 1 else Action.D
        m_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if t > r - 2:
            base_action = Action.C if m_last >= n - 2 else Action.D
        else:
            base_action = Action.C if m_last >= self.threshold_t else Action.D
        if t >= 2 and len(history.opponent_cooperators) >= 2:
            m_prev = int(history.opponent_cooperators[-2])
            if m_last == 0 and m_prev == 0:
                base_action = Action.D
            if m_last == n - 1 and m_prev == n - 1:
                base_action = Action.C
            if t >= 2:
                prev_avg = float(np.mean(history.opponent_cooperators[:t])) if t > 0 else 0.0
                if prev_avg >= self.high_threshold_h and (not (m_last < self.threshold_t and m_prev < self.threshold_t)):
                    base_action = Action.C
        return base_action

class Strategy_OPPORTUNISTIC_96(BaseStrategy):
    """
    Threshold-based public goods strategy with Harvest and Probe states.

    - Starts by defecting.
    - Cooperates only when observed cooperation is strong enough.
    - Stops cooperating in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        r = int(getattr(game_description, 'n_rounds', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.n_players = n
        self.n_rounds = r
        self.k = k
        if k > 0:
            self.threshold = math.ceil((n + 1) / k)
        else:
            self.threshold = math.inf
        self.state = 'Probe'
        self.zero_blackout = False
        self.last_synced_round = 0

    def _sync_state(self, history: PlayerHistory) -> None:
        """
        Update internal state using any newly observed completed rounds in history.
        """
        total_rounds = history.round_number
        start = self.last_synced_round
        if total_rounds <= start:
            return
        for t in range(start, total_rounds):
            my_action = bool(history.my_actions[t])
            x_t = int(history.opponent_cooperators[t])
            if self.threshold <= 1:
                if x_t == 0:
                    self.zero_blackout = True
                elif x_t > 0:
                    self.zero_blackout = False
            elif not my_action and x_t >= self.threshold:
                self.state = 'Harvest'
            elif my_action and x_t < self.threshold - 1:
                self.state = 'Probe'
        self.last_synced_round = total_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        self._sync_state(history)
        t = history.round_number
        r = self.n_rounds
        if t == 0 or r <= 2 or t >= r - 2:
            return Action.D
        x_prev = int(history.opponent_cooperators[-1]) if t > 0 else 0
        if self.threshold <= 1:
            if x_prev == 0:
                self.zero_blackout = True
            elif x_prev > 0:
                self.zero_blackout = False
            if self.zero_blackout:
                return Action.D
            return Action.C
        if self.state == 'Harvest':
            return Action.C if x_prev >= self.threshold - 1 else Action.D
        else:
            return Action.C if x_prev >= self.threshold else Action.D

class Strategy_OPPORTUNISTIC_97(BaseStrategy):
    """
    Threshold-based public goods strategy:
    - Defect in the first and last rounds.
    - Cooperate only after sustained opponent cooperation reaches a break-even threshold.
    - Defect immediately on any weakening signal.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k) if game_description.k is not None else 1.0
        self.threshold = int(math.ceil(n / k)) if k > 0 else n
        self.recent_window = min(3, max(0, int(game_description.n_rounds) - 1))

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        n_opponents = max(0, n_players - 1)
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        if n_opponents <= 0:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        m_prev = int(opp[-1])
        if m_prev < self.threshold:
            return Action.D
        past_rounds = len(opp)
        total_coop = int(np.sum(opp)) if past_rounds > 0 else 0
        avg_coop_rate = 0.0
        if past_rounds > 0 and n_opponents > 0:
            avg_coop_rate = total_coop / (past_rounds * n_opponents)
        required_rate = self.threshold / n_opponents if n_opponents > 0 else 1.0
        L = self.recent_window
        recent_ok = True
        if L > 0:
            window = opp[-min(L, past_rounds):]
            recent_ok = len(window) == L and bool(np.all(window >= self.threshold))
        if m_prev >= self.threshold and avg_coop_rate >= required_rate and recent_ok:
            return Action.C
        if m_prev > self.threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_98(BaseStrategy):
    """
    Thresholded contingent strategy with a short probing phase.

    - Round 1: defect.
    - Thereafter: cooperate only when the observed number of cooperating opponents
      in the previous round meets the threshold T = ceil(n / k) - 1.
    - More cautiously, require the most recent cooperation level to be stable:
      cooperate when the last round met the threshold and the running average of
      observed opponent cooperation is also high enough.
    - In the final round, cooperate only if the last two observed rounds both met
      the threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        if k <= 0:
            self.threshold = n
        else:
            self.threshold = int(math.ceil(n / k) - 1)
        self.n_players = n
        self.n_rounds = int(game_description.n_rounds)
        self.n_opponents = max(0, n - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if self.n_opponents <= 0:
            return Action.C if self.threshold <= 0 else Action.D
        if self.threshold <= 0:
            return Action.C
        recent_count = int(history.opponent_cooperators[-1])
        past_counts = history.opponent_cooperators[:round_number]
        q_t = float(np.mean(past_counts)) if len(past_counts) > 0 else 0.0
        stable_enough = recent_count >= self.threshold and q_t >= self.threshold - 1
        is_final_round = round_number == self.n_rounds - 1
        if is_final_round:
            if round_number >= 2:
                last_two_ok = int(history.opponent_cooperators[-1]) >= self.threshold and int(history.opponent_cooperators[-2]) >= self.threshold
                return Action.C if last_two_ok else Action.D
            return Action.D
        if stable_enough:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_99(BaseStrategy):
    """
    Adaptive public goods strategy with:
    - initial cooperation
    - EWMA-based responsiveness to cooperation levels
    - punishment after collapse
    - recovery and trend-based overrides
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.punishment_remaining = 0
        self.last_computed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        n = self.n
        opp_counts = history.opponent_cooperators
        n_opponents = max(0, n - 1)
        if history.round_number == 0:
            self.punishment_remaining = 0
            return Action.C
        m_prev = int(opp_counts[-1]) if len(opp_counts) >= 1 else 0
        h_prev = 0.0
        if len(opp_counts) >= 1:
            if n_opponents > 0:
                h_prev = float(opp_counts[0]) / n_opponents
                for idx in range(1, len(opp_counts)):
                    h_prev = 0.7 * h_prev + 0.3 * (float(opp_counts[idx]) / n_opponents)
            else:
                h_prev = 0.0
        if t == self.r:
            return Action.C if m_prev == n_opponents else Action.D
        if n == 2:
            return Action.C if m_prev >= 1 else Action.D
        if len(opp_counts) >= 3:
            a = int(opp_counts[-3])
            b = int(opp_counts[-2])
            c = int(opp_counts[-1])
            if a < b < c:
                return Action.C
            if a > b > c:
                return Action.D
        if m_prev == 0 and self.punishment_remaining <= 0:
            self.punishment_remaining = 2
        if self.punishment_remaining > 0:
            if len(opp_counts) >= 2 and int(opp_counts[-1]) >= 1 and (int(opp_counts[-2]) >= 1):
                self.punishment_remaining = 0
            else:
                self.punishment_remaining = max(0, self.punishment_remaining - 1)
                return Action.D
        if len(history.my_actions) >= 1:
            my_prev_action = bool(history.my_actions[-1])
            if not my_prev_action and m_prev >= math.ceil((n - 1) / 2):
                return Action.C
            if my_prev_action and m_prev < math.ceil((n - 1) / 3):
                return Action.D
        if h_prev >= 0.6 or m_prev == n_opponents:
            return Action.C
        if h_prev <= 0.4 or m_prev <= n_opponents / 2:
            return Action.D
        return Action.C if t % 2 == 1 else Action.D

class Strategy_OPPORTUNISTIC_100(BaseStrategy):
    """
    Cautious threshold-based cooperation strategy for the N-player Public Goods Game.

    - Round 1: defect.
    - Round 2 onward: cooperate only if the last two observed rounds each had
      enough cooperating opponents to meet the cooperation threshold.
    - If cooperation weakens, immediately defect next round.
    - On the final round, cooperate only if the last two observed rounds were stable.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        if k <= 0:
            raw_threshold = 0
        else:
            raw_threshold = math.ceil(n / k) - 1
        if raw_threshold < 0:
            raw_threshold = 0
        self.threshold = raw_threshold
        self.coop_needed = min(max(n - 1, 0), self.threshold + 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        if round_number == 0:
            return Action.D
        if round_number == 1:
            if len(history.opponent_cooperators) < 1:
                return Action.D
            return Action.C if history.opponent_cooperators[-1] >= self.coop_needed else Action.D
        if n_rounds > 0 and round_number == n_rounds - 1:
            if len(history.opponent_cooperators) < 2:
                return Action.D
            if history.opponent_cooperators[-1] >= self.coop_needed and history.opponent_cooperators[-2] >= self.coop_needed:
                return Action.C
            return Action.D
        if len(history.opponent_cooperators) < 2:
            return Action.D
        if history.opponent_cooperators[-1] >= self.coop_needed and history.opponent_cooperators[-2] >= self.coop_needed:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_101(BaseStrategy):
    """
    Threshold-based reciprocity:
    - Start by cooperating.
    - In intermediate rounds, cooperate when recent total cooperation is high,
      defect when it is too low, and otherwise repeat the previous action.
    - Always defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k) if game_description.k is not None else 1.0
        if k == 0:
            theta_high = 1.0
            theta_low = 0.0
        else:
            theta_high = min(1.0, 1.0 / k + 1.0 / n)
            theta_low = max(0.0, 1.0 / k - 1.0 / n)
        self.n_players = n
        self.k = k
        self.theta_high = theta_high
        self.theta_low = theta_low
        self.n_rounds = max(1, int(game_description.n_rounds))

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        if round_number >= self.n_rounds - 1:
            return Action.D
        last_opponents = int(history.opponent_cooperators[-1])
        last_my_action = bool(history.my_actions[-1])
        total_cooperators = last_opponents + (1 if last_my_action else 0)
        if self.n_players > 0:
            rho = total_cooperators / self.n_players
        else:
            rho = 0.0
        if rho >= self.theta_high:
            return Action.C
        if rho <= self.theta_low:
            return Action.D
        return Action.C if last_my_action else Action.D

class Strategy_OPPORTUNISTIC_102(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Defect by default and in the final round
    - Cooperate only after sustained high cooperation
    - Maintain cooperation only while cooperation remains reliably high
    - Use short probing attempts to test for renewed cooperation
    - Enforce a two-round cooldown after failed cooperation or failed probes
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'DEFECT'
        self.cooldown = 0
        self.last_two = []
        self.m = None
        self._last_processed_round = -1
        self._last_action = Action.D
        self._probe_pending = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        if t == self._last_processed_round:
            return self._last_action
        x = []
        if t > 0 and n_opponents > 0:
            for c in history.opponent_cooperators:
                x.append(float(c) / float(n_opponents))
        elif t > 0:
            x = [0.0 for _ in range(t)]
        if t == 0:
            self.m = None
        else:
            m_val = x[0]
            for idx in range(1, t):
                m_val = 0.5 * x[idx] + 0.5 * m_val
            self.m = m_val
        if t == n_rounds - 1:
            action = Action.D
            self.mode = 'DEFECT'
            self.cooldown = 0
            self._probe_pending = False
        else:
            theta_on = 0.6
            theta_off = 0.4
            theta_probe = 0.5
            if t == 0:
                action = Action.D
                self.mode = 'DEFECT'
                self._probe_pending = False
            elif self.cooldown > 0:
                action = Action.D
                self.cooldown -= 1
                self.mode = 'DEFECT'
                self._probe_pending = False
            else:
                if self._probe_pending:
                    self._probe_pending = False
                    if t >= 1 and x[-1] >= theta_on:
                        self.mode = 'COOPERATE'
                    else:
                        self.mode = 'DEFECT'
                        self.cooldown = 2
                if self.mode == 'COOPERATE':
                    if t >= 1 and self.m is not None and (x[-1] >= theta_off) and (self.m >= theta_off):
                        action = Action.C
                    else:
                        action = Action.D
                        self.mode = 'DEFECT'
                        self.cooldown = 2
                elif t >= 3:
                    if self.m is not None and self.m >= theta_on and (x[-1] >= theta_on) and (x[-2] >= theta_on):
                        action = Action.C
                        self.mode = 'COOPERATE'
                    elif x[-3] < theta_on and x[-2] < theta_on and (x[-1] < theta_on) and (x[-2] >= theta_probe) and (x[-1] >= theta_probe):
                        action = Action.C
                        self._probe_pending = True
                    else:
                        action = Action.D
                else:
                    action = Action.D
        self._last_processed_round = t
        self._last_action = action
        return action

class Strategy_OPPORTUNISTIC_103(BaseStrategy):
    """
    Adaptive public-goods strategy with:
    - initial cooperation,
    - majority-based C/D leaning,
    - periodic probing after sustained defection,
    - final-round defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.k = game_description.k
        self.majority_threshold = math.ceil((self.n - 1) / 2) if self.n > 1 else 0
        self.leaning = 'D'
        self._last_probe_round = -1
        self._last_probe_prev_h = None
        self._last_seen_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            self._last_seen_round = history.round_number
            return Action.C
        if t == self.r:
            self._last_seen_round = history.round_number
            return Action.D
        if self._last_probe_round == history.round_number - 1 and self._last_probe_prev_h is not None:
            current_h = int(history.opponent_cooperators[-1])
            if current_h - self._last_probe_prev_h >= 2:
                self.leaning = 'C'
            else:
                self.leaning = 'D'
            self._last_probe_round = -1
            self._last_probe_prev_h = None
        h_last = int(history.opponent_cooperators[-1])
        q_last = h_last / (self.n - 1) if self.n > 1 else 0.0
        recent_h = history.opponent_cooperators[-3:]
        recent_q = [float(h) / (self.n - 1) if self.n > 1 else 0.0 for h in recent_h]
        m = float(np.mean(recent_q)) if len(recent_q) > 0 else 0.0
        H = self.majority_threshold
        majority_cooperated_last = h_last >= H
        last_two_majority = False
        if history.round_number >= 2:
            h_prev = int(history.opponent_cooperators[-2])
            last_two_majority = h_prev >= H and h_last >= H
        if history.round_number >= 2 and t < self.r:
            my_last = bool(history.my_actions[-1])
            my_prev = bool(history.my_actions[-2])
            if not my_last and (not my_prev):
                if t % 3 == 0:
                    self._last_probe_round = history.round_number
                    self._last_probe_prev_h = h_last
                    self._last_seen_round = history.round_number
                    return Action.C
        if last_two_majority:
            self.leaning = 'C'
            self._last_seen_round = history.round_number
            return Action.C
        if self.n > 1 and q_last < H / (self.n - 1):
            self.leaning = 'D'
            self._last_seen_round = history.round_number
            return Action.D
        if m >= 2.0 / 3.0:
            self.leaning = 'C'
            self._last_seen_round = history.round_number
            return Action.C
        if m <= 1.0 / 3.0:
            self.leaning = 'D'
            self._last_seen_round = history.round_number
            return Action.D
        if history.round_number >= 2:
            my_last = bool(history.my_actions[-1])
            h_prev = int(history.opponent_cooperators[-2])
            if h_last < h_prev:
                self._last_seen_round = history.round_number
                return Action.D if my_last else Action.C
        self._last_seen_round = history.round_number
        return Action.C if bool(history.my_actions[-1]) else Action.D

class Strategy_OPPORTUNISTIC_104(BaseStrategy):
    """
    Open with cooperation, then cooperate only when opponent cooperation is
    very high and stable; defect in mixed, weakening, or final-round play.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        self.n_players = n
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        opponent_count = max(0, n - 1)
        self.high_threshold = math.ceil(opponent_count * 2 / 3)
        self.low_threshold = math.floor(opponent_count / 3)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number + 1
        if history.round_number == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        x_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if x_prev >= self.high_threshold:
            if history.round_number >= 2:
                x_prev2 = int(history.opponent_cooperators[-2])
                if x_prev >= x_prev2 - 1:
                    return Action.C
            else:
                return Action.D
        return Action.D

class Strategy_OPPORTUNISTIC_105(BaseStrategy):
    """
    Threshold-based exploitation strategy with probing, short-memory
    cooperation classification, collapse detection, and endgame defection
    unless cooperation remains consistently strong.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.L = max(2, self.r // 4)
        self.T_high = math.ceil(self.n / 2) - 1
        self.T_low = 1
        self.collapse_lock = False
        self.last_action = None
        self.last_seen_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number

        def recent_average(arr: NDArray[np.int_], window: int) -> float:
            if len(arr) == 0:
                return 0.0
            w = min(window, len(arr))
            if w <= 0:
                return 0.0
            return float(np.mean(arr[-w:]))

        def has_two_consecutive_zeros(arr: NDArray[np.int_]) -> bool:
            if len(arr) < 2:
                return False
            for idx in range(1, len(arr)):
                if int(arr[idx]) == 0 and int(arr[idx - 1]) == 0:
                    return True
            return False

        def sharp_drop_detected(arr: NDArray[np.int_]) -> bool:
            if len(arr) < 2:
                return False
            return int(arr[-1]) <= int(arr[-2]) - 2

        def persistent_high(arr: NDArray[np.int_], window: int) -> bool:
            if len(arr) == 0:
                return False
            w = min(window, len(arr))
            if w <= 0:
                return False
            recent = arr[-w:]
            high_count = int(np.sum(recent >= self.T_high))
            return high_count >= max(1, w - 1)

        def spike_and_hold(arr: NDArray[np.int_], window: int) -> bool:
            if len(arr) == 0:
                return False
            w = min(window, len(arr))
            recent = arr[-w:]
            if int(np.max(recent)) < self.T_high:
                return False
            if int(recent[-1]) >= self.T_high - 1:
                return True
            return False
        if t == 0:
            self.last_action = Action.C
            self.last_seen_round = 0
            return Action.C
        opp = history.opponent_cooperators
        bar_m = recent_average(opp, self.L)
        if has_two_consecutive_zeros(opp):
            self.collapse_lock = True
        if self.collapse_lock:
            self.last_action = Action.D
            self.last_seen_round = t
            return Action.D
        if t >= self.r - 1:
            if persistent_high(opp, self.L) or (bar_m >= self.T_high and spike_and_hold(opp, self.L)):
                self.last_action = Action.C
            else:
                self.last_action = Action.D
            self.last_seen_round = t
            return self.last_action
        if sharp_drop_detected(opp):
            self.last_action = Action.D
            self.last_seen_round = t
            return Action.D
        if persistent_high(opp, self.L):
            self.last_action = Action.C
            self.last_seen_round = t
            return Action.C
        if bar_m >= self.T_high:
            self.last_action = Action.C
        elif bar_m <= self.T_low:
            self.last_action = Action.D
        elif spike_and_hold(opp, self.L):
            self.last_action = Action.C
        else:
            self.last_action = Action.D
        self.last_seen_round = t
        return self.last_action

class Strategy_OPPORTUNISTIC_106(BaseStrategy):
    """
    Defect by default, reward sustained strong cooperation with limited cooperation,
    enforce short defect streaks after weak cooperation, and always defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.high_threshold = 0.7
        self.low_threshold = 0.4
        self.ema_alpha = 0.3
        self.ema_decay = 0.7

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        n_opponents = max(0, n_players - 1)
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round == n_rounds - 1:
            if n_rounds == 2 and history.round_number == 1:
                last_x = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
                if n_opponents > 0 and last_x == n_opponents:
                    return Action.C
            return Action.D
        if n_opponents <= 0:
            return Action.D
        opp_counts = history.opponent_cooperators
        rates = [float(x) / float(n_opponents) for x in opp_counts]
        last_rate = rates[-1]
        last_low_index = -1
        for idx in range(len(rates) - 1, -1, -1):
            if rates[idx] < self.low_threshold:
                last_low_index = idx
                break
        if last_low_index != -1 and current_round - last_low_index <= 2:
            return Action.D
        if n_rounds == 2 and current_round == 1:
            return Action.C if last_rate >= 1.0 else Action.D
        m_t = 0.0
        for s_t in rates:
            m_t = self.ema_decay * m_t + self.ema_alpha * s_t
        if len(rates) >= 2 and rates[-1] >= self.high_threshold and (rates[-2] >= self.high_threshold):
            return Action.C
        if m_t >= self.high_threshold and last_rate >= self.low_threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_107(BaseStrategy):
    """
    Defect by default; cooperate only after two consecutive fully cooperative
    opponent rounds, and only if no opponent defection has ever been observed.
    Defects on the first and last rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.k = getattr(game_description, 'k', 0.0)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        last_round_index = self.n_rounds - 1
        n_opponents = max(0, self.n_players - 1)
        unanimous_count = n_opponents
        if round_number == 0 or round_number == last_round_index:
            return Action.D
        full_streak = 0
        opp = history.opponent_cooperators
        idx = round_number - 1
        while idx >= 0 and opp[idx] == unanimous_count:
            full_streak += 1
            idx -= 1
        no_defection_ever = True
        for count in opp:
            if count != unanimous_count:
                no_defection_ever = False
                break
        trust = no_defection_ever and full_streak >= 2
        if trust:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_108(BaseStrategy):
    """
    Threshold-based public goods strategy with recovery mode.

    Starts by defecting, cooperates only after sustained opponent cooperation,
    and returns to defection immediately when cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 1.0) or 1.0)
        if k <= 1.0:
            tau = n_players
        else:
            tau = math.ceil(max(0, n_players - 1) * (1.0 - 1.0 / k))
        self.tau_hi = int(tau)
        self.tau_lo = max(0, self.tau_hi - 1)
        self.last_counts = []
        self.recover_mode = False

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        round_number = int(history.round_number)
        observed_len = len(history.opponent_cooperators)
        start_idx = len(self.last_counts)
        if observed_len > start_idx:
            for idx in range(start_idx, observed_len):
                self.last_counts.append(int(history.opponent_cooperators[idx]))
        next_round = round_number + 1
        if n_rounds > 0 and next_round >= max(1, n_rounds - 1):
            return Action.D
        if round_number == 0:
            return Action.D
        recover_mode = bool(self.recover_mode)
        my_actions = history.my_actions
        for t in range(len(self.last_counts)):
            x_t = int(self.last_counts[t])
            my_played_c = bool(my_actions[t]) if t < len(my_actions) else False
            if my_played_c and x_t < self.tau_lo:
                recover_mode = True
            if t >= 1:
                if self.last_counts[t] >= self.tau_hi and self.last_counts[t - 1] >= self.tau_hi:
                    recover_mode = False
        self.recover_mode = recover_mode
        x1 = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
        x2 = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else 0
        high_recent = x1 >= self.tau_hi
        if round_number >= 2:
            high_recent = high_recent and x2 >= self.tau_hi
        stable = round_number < 3 or (x1 >= self.tau_lo and x2 >= self.tau_lo)
        if self.recover_mode:
            return Action.C if high_recent else Action.D
        return Action.C if high_recent and stable else Action.D

class Strategy_OPPORTUNISTIC_109(BaseStrategy):
    """
    Start by defecting, then cooperate only after cooperation has been
    established for at least two consecutive qualifying rounds, or when the
    previous round was unanimous cooperation and the round before also met the
    threshold. Always defect in the first and last rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        r = int(getattr(game_description, 'n_rounds', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.n_players = n
        self.n_rounds = r
        self.k = k
        if k > 0:
            self.tau = max(1, math.ceil(n / k) - 1)
        else:
            self.tau = n

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.D
        if self.n_rounds > 0 and t >= self.n_rounds - 1:
            return Action.D
        if t < 2:
            return Action.D
        m_prev = int(history.opponent_cooperators[-1])
        m_prevprev = int(history.opponent_cooperators[-2])
        if m_prev >= self.tau and (m_prevprev >= self.tau or m_prev == self.n_players - 1):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_110(BaseStrategy):
    """
    Defect initially and in the final round.
    Cooperate only after a stable pattern of high opponent cooperation:
    - average of the last up to 3 observed cooperation rates >= 2/3
    - most recent observed cooperation rate >= 2/3
    - at least 2 consecutive recent rounds with cooperation rate >= 2/3

    Special case for n=2:
    cooperate only after the opponent has cooperated in both of the last two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.n_opponents = max(0, self.n_players - 1)
        self._high_threshold = 2.0 / 3.0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        if self.n_players == 2:
            if round_number >= 2 and opp[-1] == 1 and (opp[-2] == 1):
                return Action.C
            return Action.D
        denom = self.n_players - 1
        if denom <= 0:
            return Action.D
        q_values = [float(x) / float(denom) for x in opp]
        m = min(3, round_number)
        if m <= 0:
            return Action.D
        recent_q = q_values[-m:]
        s_t = float(sum(recent_q)) / float(m)
        q_last = q_values[-1]
        h_t = 0
        for q in reversed(q_values):
            if q >= self._high_threshold:
                h_t += 1
            else:
                break
        if s_t >= self._high_threshold and q_last >= self._high_threshold and (h_t >= 2):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_111(BaseStrategy):
    """
    Probe with cooperation, harvest on sustained high cooperation, and briefly
    recover with cooperation after a collapse before returning to probing.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_opponents = max(0, game_description.n_players - 1)
        self.n_opponents = n_opponents
        self.H = math.ceil(0.7 * n_opponents)
        self.L = math.floor(0.4 * n_opponents)
        self.mode = 'PROBE'
        self.recover_rounds_used = 0
        self.processed_rounds = 0
        self.last_observed_s = None

    def _process_observation(self, round_index: int, s_t: int) -> None:
        prev_s = self.last_observed_s
        stable_high = False
        stable_low = False
        if prev_s is not None:
            stable_high = prev_s >= self.H and s_t >= self.H
            stable_low = prev_s <= self.L and s_t <= self.L
        if self.mode == 'PROBE':
            if s_t >= self.H:
                self.mode = 'HARVEST'
            else:
                self.mode = 'RECOVER'
                self.recover_rounds_used = 0
        elif self.mode == 'HARVEST':
            if stable_low:
                self.mode = 'RECOVER'
                self.recover_rounds_used = 0
            else:
                self.mode = 'HARVEST'
        elif self.mode == 'RECOVER':
            self.recover_rounds_used += 1
            if s_t >= self.H:
                self.mode = 'HARVEST'
            elif self.recover_rounds_used >= 2:
                self.mode = 'PROBE'
                self.recover_rounds_used = 0
            else:
                self.mode = 'RECOVER'
        else:
            self.mode = 'PROBE'
        self.last_observed_s = s_t
        self.processed_rounds = round_index + 1

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_rounds = self.game_description.n_rounds
        while self.processed_rounds < current_round:
            idx = self.processed_rounds
            s_t = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            self._process_observation(idx, s_t)
        if current_round == 0:
            return Action.C
        if n_rounds == 1:
            return Action.C
        if current_round == n_rounds - 1:
            return Action.D
        if self.mode == 'HARVEST':
            return Action.D
        if self.mode == 'RECOVER':
            return Action.C
        if self.mode == 'PROBE':
            return Action.C
        return Action.C

class Strategy_OPPORTUNISTIC_112(BaseStrategy):
    """
    Opportunistic public-goods strategy:
    - Defect by default.
    - Cooperate only after sustained opponent cooperation.
    - Become stricter near the end of the game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.threshold = self.n_players / self.k - 1.0 if self.k != 0 else float('inf')
        self.base_coop_threshold = self.threshold + 1.0
        self.endgame_coop_threshold = self.threshold + 2.0
        if self.k > 1.0:
            self.final_rounds = max(1, math.ceil(self.n_players / (self.k - 1.0)))
        else:
            self.final_rounds = self.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        recent_len = min(3, t)
        recent = opp[t - recent_len:t]
        if len(recent) == 0:
            return Action.D
        moving_avg = float(np.mean(recent))
        last_two_above = False
        last_two_below = False
        if t >= 2:
            last_two = opp[t - 2:t]
            last_two_above = bool(np.all(last_two >= self.base_coop_threshold))
            last_two_below = bool(np.all(last_two < self.base_coop_threshold))
        rounds_remaining = self.n_rounds - t
        in_endgame = rounds_remaining <= self.final_rounds
        if in_endgame:
            if moving_avg >= self.endgame_coop_threshold:
                return Action.C
            return Action.D
        if last_two_above:
            return Action.C
        if last_two_below:
            return Action.D
        if moving_avg > self.base_coop_threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_113(BaseStrategy):
    """
    Defect by default, only cooperating after a sustained high-cooperation streak,
    and reverting immediately when cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 2))
        self.n_rounds = int(getattr(game_description, 'n_rounds', 1))
        self.n_opponents = max(0, self.n_players - 1)
        if self.n_players == 2:
            self.high_threshold = 1
        else:
            self.high_threshold = int(math.ceil(0.9 * self.n_opponents))
        self.weak_threshold = int(math.floor(self.n_opponents / 2))

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        next_round = round_number + 1
        if round_number == 0:
            return Action.D
        if next_round >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        last_x = int(opp[-1])
        if last_x <= self.weak_threshold:
            return Action.D
        streak = 0
        for idx in range(len(opp) - 1, -1, -1):
            if int(opp[idx]) >= self.high_threshold:
                streak += 1
            else:
                break
        if streak >= 2:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_114(BaseStrategy):
    """
    Conditional cooperateur that probes early, sustains cooperation only when
    cooperation is stable, defects when support is too low or too high, and
    always defects in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        r = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.n_players = n
        self.n_rounds = r
        self.k = k
        if k > 0:
            self.S = math.ceil(n / k) - 1
        else:
            self.S = n
        self.H = n - 2 if n > 2 else 1

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if self.n_rounds > 0 and t >= self.n_rounds - 2:
            return Action.D
        if t == 0:
            return Action.C
        if t == 1:
            x_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
            return Action.C if x_prev >= self.S else Action.D
        x_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
        x_prev2 = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else 0
        if x_prev < self.S:
            return Action.D
        if x_prev >= self.H:
            return Action.D
        if x_prev >= self.S and x_prev2 >= self.S:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_115(BaseStrategy):
    """
    Adaptive public-goods strategy combining:
    - initial cooperation,
    - threshold-based reciprocity,
    - recent-history smoothing,
    - endgame conservatism,
    - defection lock after sustained low cooperation,
    - opportunistic cooperation under strong cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.theta = 0.5
        self.strong_theta = 0.8
        self.max_history_window = 3

    def _cooperation_rates(self, history: PlayerHistory) -> list[float]:
        n_opponents = max(self.n - 1, 1)
        if history.round_number <= 0:
            return []
        counts = history.opponent_cooperators[:history.round_number]
        return [float(c) / float(n_opponents) for c in counts]

    def _adjusted_rate_for_round(self, rates: list[float], t: int) -> float:
        """
        Adjusted rate used for decision at round t (0-based):
        based on rates from rounds [0, t-1].
        """
        if t <= 0 or not rates:
            return 1.0
        prev_rate = rates[t - 1]
        start = max(0, t - self.max_history_window)
        window = rates[start:t]
        hist_avg = float(np.mean(window)) if window else prev_rate
        return max(prev_rate, hist_avg) if hist_avg > prev_rate else min(prev_rate, hist_avg)

    def _past_adjusted_rates(self, history: PlayerHistory) -> list[float]:
        rates = self._cooperation_rates(history)
        adjusted = []
        for t in range(1, len(rates) + 1):
            adjusted.append(self._adjusted_rate_for_round(rates, t))
        return adjusted

    def _declining_two_rounds(self, adjusted_rates: list[float]) -> bool:
        if len(adjusted_rates) < 3:
            return False
        return adjusted_rates[-3] > adjusted_rates[-2] > adjusted_rates[-1]

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        rates = self._cooperation_rates(history)
        if not rates:
            return Action.C
        current_rate = rates[-1]
        adjusted_rates = self._past_adjusted_rates(history)
        current_adj = adjusted_rates[-1] if adjusted_rates else current_rate
        prev_adj = adjusted_rates[-2] if len(adjusted_rates) >= 2 else current_adj
        prev2_adj = adjusted_rates[-3] if len(adjusted_rates) >= 3 else prev_adj
        if t >= max(self.r - 2, 0):
            prev_meets = prev_adj >= self.theta
            prev2_meets = prev2_adj >= self.theta
            if prev_meets and prev2_meets:
                return Action.C
            if prev_meets != prev2_meets:
                return Action.C if t == self.r - 2 else Action.D
            return Action.D
        if len(adjusted_rates) >= 2 and adjusted_rates[-1] < self.theta and (adjusted_rates[-2] < self.theta):
            return Action.D
        if current_adj >= self.strong_theta:
            return Action.C
        if current_adj >= self.theta and (not self._declining_two_rounds(adjusted_rates)):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_116(BaseStrategy):
    """
    Cooperate initially, then continue cooperating only when the observed
    opponent cooperation rate and the most recent round's cooperation level
    both remain high enough to justify mutual cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.S = 0
        self.T = 0
        self.m_last = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        k = self.game_description.k
        if history.round_number == 0:
            self.S = 0
            self.T = 0
            self.m_last = 0
            return Action.C
        self.T = history.round_number
        self.S = int(np.sum(history.opponent_cooperators)) if self.T > 0 else 0
        self.m_last = int(history.opponent_cooperators[-1]) if self.T > 0 else 0
        denom = self.T * max(n - 1, 1)
        q = self.S / denom if denom > 0 else 0.0
        m_threshold = math.ceil((n - 1) / k) if k > 0 else n - 1
        if q >= 1.0 / k and self.m_last >= m_threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_117(BaseStrategy):
    """
    Test with an initial cooperation, then defect by default unless recent
    opponent cooperation has been sustainably high (exploit) or sustainably
    low (briefly rebuild after collapse).
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        if n <= 2:
            self.t_high = 1
            self.t_low = 0
        else:
            raw_high = math.ceil((n - 1) * (k - 1.0) / k) if k != 0 else n - 1
            self.t_high = max(0, min(n - 1, int(raw_high)))
            self.t_low = max(0, int(math.floor(self.t_high / 2)))
        self.h = 0
        self.m = 0
        self._last_seen_round = 0

    def _recompute_state(self, history: PlayerHistory) -> None:
        self.h = 0
        self.m = 0
        opp = history.opponent_cooperators
        for x in opp:
            if int(x) >= self.t_high:
                self.h += 1
                self.m = 0
            elif int(x) <= self.t_low:
                self.m += 1
                self.h = 0
            else:
                self.h = 0
                self.m = 0
        self._last_seen_round = history.round_number

    def __call__(self, history: PlayerHistory) -> Action:
        r_total = int(self.game_description.n_rounds)
        current_round = int(history.round_number) + 1
        if history.round_number == 0:
            self.h = 0
            self.m = 0
            self._last_seen_round = 0
            return Action.C
        if self._last_seen_round != history.round_number:
            self._recompute_state(history)
        else:
            last_x = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            if last_x >= self.t_high:
                self.h += 1
                self.m = 0
            elif last_x <= self.t_low:
                self.m += 1
                self.h = 0
            else:
                self.h = 0
                self.m = 0
            self._last_seen_round = history.round_number
        if current_round >= r_total:
            return Action.D
        if self.h >= 2:
            return Action.D
        if self.m >= 2 and current_round <= r_total - 1:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_118(BaseStrategy):
    """
    Public goods strategy:
    - Start by cooperating.
    - Continue cooperating only under sustained, strong opponent cooperation.
    - Defect quickly when cooperation weakens or becomes unstable.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(game_description.n_players)
        self.m_opponents = max(0, n_players - 1)
        if self.m_opponents == 1:
            self.high_threshold = 1
            self.low_threshold = 0
        else:
            self.high_threshold = math.ceil(2 * self.m_opponents / 3)
            self.low_threshold = math.floor(self.m_opponents / 3)
        self.final_round_index = int(game_description.n_rounds) - 1

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.C
        window = opp[-3:] if len(opp) >= 3 else opp
        bar_t = float(np.mean(window)) if len(window) > 0 else 0.0
        streak_high = 0
        streak_low = 0
        for count in opp[::-1]:
            if count >= self.high_threshold:
                streak_high += 1
            else:
                break
        for count in opp[::-1]:
            if count <= self.low_threshold:
                streak_low += 1
            else:
                break
        last_opp = int(opp[-1])
        my_last = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        if round_number == self.final_round_index:
            if last_opp >= self.high_threshold and streak_high >= 2:
                return Action.C
            return Action.D
        if streak_high >= 2 or bar_t >= 0.7 * self.m_opponents or (last_opp >= self.high_threshold and my_last):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_119(BaseStrategy):
    """
    Starts with cooperation, then cooperates only when recent opponent cooperation
    stays consistently high. Defects in the final round and after cooperation drops.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        if k > 0:
            self.threshold = math.ceil(n / k)
        else:
            self.threshold = n + 1
        self.final_round_index = max(0, int(game_description.n_rounds) - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.C
        if round_number >= self.final_round_index:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        recent = opp[max(0, len(opp) - 3):]
        if len(recent) == 0:
            return Action.D
        support = 0
        for m in recent:
            if int(m) >= self.threshold:
                support += 1
        last_m = int(recent[-1])
        required_support = (len(recent) + 1) // 2
        if last_m >= self.threshold and support >= required_support:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_120(BaseStrategy):
    """
    Threshold- and trend-based public goods strategy with:
    - initial cooperation,
    - aggressive joining when cooperation is clearly profitable,
    - immediate defection on weak or collapsing cooperation,
    - memory of stable strong cooperation and failed coordination.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        k_safe = self.k if self.k > 0 else 1.0
        self.q = self.n_players / k_safe - 1.0
        self.threshold = int(math.ceil(self.q)) + 1

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        last_m = int(opp[-1]) if len(opp) > 0 else 0
        if len(opp) >= 2 and int(opp[-1]) == 0 and (int(opp[-2]) == 0):
            return Action.D
        if len(opp) >= 3:
            if int(opp[-1]) >= self.threshold and int(opp[-2]) >= self.threshold and (int(opp[-3]) >= self.threshold):
                return Action.C
        S_t = float(np.mean(opp)) if len(opp) > 0 else 0.0
        if len(opp) >= 2:
            diffs = np.diff(opp.astype(np.int_))
            gains = np.maximum(0, diffs)
            losses = np.maximum(0, -diffs)
            T_t = float(np.mean(gains)) if len(gains) > 0 else 0.0
            L_t = float(np.mean(losses)) if len(losses) > 0 else 0.0
        else:
            T_t = 0.0
            L_t = 0.0
        E_t = 0.6 * S_t + 0.2 * T_t - 0.2 * L_t
        current_round = t + 1
        collapse_free = t < 3 or (len(opp) >= 2 and int(opp[-1]) >= int(opp[-2]) - 1) or len(opp) < 2
        observed_coop = last_m > 0
        strong_last = last_m >= self.threshold
        if current_round == 2:
            return Action.C if last_m >= self.threshold else Action.D
        if current_round == self.n_rounds:
            if len(opp) >= 2:
                prev_m = int(opp[-2])
                if strong_last and last_m >= prev_m - 1 and observed_coop:
                    return Action.C
            return Action.D
        if t < self.n_rounds and E_t > self.q + 0.25 and collapse_free and observed_coop:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_121(BaseStrategy):
    """
    Defect by default, enter 'harvest' after sustained high cooperation, and
    enter 'probe' after sustained low cooperation. Never cooperate in the
    final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        self.H = math.ceil(3 * (n - 1) / 4)
        self.L = math.floor((n - 1) / 4)
        self.mode = 'neutral'
        self.probe_phase = 0
        self.last_observed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if t == 0:
            self.mode = 'neutral'
            self.probe_phase = 0
            self.last_observed_rounds = 0
            return Action.D
        if t >= n_rounds - 1:
            self.mode = 'neutral'
            self.probe_phase = 0
            self.last_observed_rounds = t
            return Action.D
        opp = history.opponent_cooperators
        last = int(opp[-1]) if len(opp) > 0 else 0
        prev = int(opp[-2]) if len(opp) > 1 else None
        if self.mode == 'harvest' and last < self.H:
            self.mode = 'neutral'
        elif self.mode == 'probe' and len(history.my_actions) > 0:
            if bool(history.my_actions[-1]) and last <= self.L:
                self.mode = 'neutral'
                self.probe_phase = 0
        if self.mode != 'harvest':
            if len(opp) >= 2 and last >= self.H and (prev is not None) and (prev >= self.H):
                self.mode = 'harvest'
                self.probe_phase = 0
        if self.mode != 'probe' and self.mode != 'harvest':
            if len(opp) >= 2 and last <= self.L and (prev is not None) and (prev <= self.L):
                self.mode = 'probe'
                self.probe_phase = 0
        if self.mode == 'harvest':
            action = Action.C if (t + 1) % 4 == 0 else Action.D
        elif self.mode == 'probe':
            action = Action.C if self.probe_phase % 3 == 2 else Action.D
        else:
            action = Action.D
        if self.mode == 'probe':
            self.probe_phase = (self.probe_phase + 1) % 3
        else:
            self.probe_phase = 0
        self.last_observed_rounds = t
        return action

class Strategy_OPPORTUNISTIC_122(BaseStrategy):
    """
    Conservative threshold strategy for the N-player Public Goods Game.

    Cooperate only after observing sustained near-universal cooperation:
    - Round 1: defect
    - Round 2: cooperate only if the previous round was already high
    - Later rounds: cooperate only if the last two rounds were high
    - In the special case n=2, "high" means the lone opponent cooperated
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players) if game_description is not None else 0
        self.n_rounds = int(game_description.n_rounds) if game_description is not None else 0
        self.k = float(game_description.k) if game_description is not None else 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.n_players
        round_number = history.round_number

        def is_high(x: int) -> bool:
            if n <= 2:
                return x >= 1
            return x >= n - 2
        if round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        if round_number == 1:
            return Action.C if is_high(int(opp[-1])) else Action.D
        last_high = is_high(int(opp[-1]))
        prev_high = is_high(int(opp[-2]))
        if last_high and prev_high:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_123(BaseStrategy):
    """
    Defect by default, switch to cooperative build mode only after observing
    sustained high cooperation, and defect again immediately when cooperation
    weakens or near the end of the game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'exploit'
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        base_theta = max(2.0 / 3.0, 1.0 - (1.0 / k if k > 0 else 0.0))
        theta_high = min(1.0, max(0.5, base_theta))
        self.high_threshold = int(math.ceil((n - 1) * theta_high))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if t == 0:
            self.mode = 'exploit'
            return Action.D
        if t >= max(0, n_rounds - 2):
            self.mode = 'exploit'
            return Action.D
        opp = history.opponent_cooperators
        last = int(opp[-1]) if len(opp) >= 1 else 0
        prev = int(opp[-2]) if len(opp) >= 2 else None
        high_last = last >= self.high_threshold
        high_prev = prev is not None and prev >= self.high_threshold
        nondecreasing = prev is None or last >= prev
        if self.mode == 'build':
            if high_last and nondecreasing:
                return Action.C
            self.mode = 'exploit'
            return Action.D
        if len(opp) >= 2 and high_last and high_prev:
            self.mode = 'build'
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_124(BaseStrategy):
    """
    Opens with cooperation, then cooperates only after sustaining a high level
    of opponent cooperation for two consecutive rounds, while always defecting
    in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_players = self.n_players
        n_rounds = self.n_rounds
        if round_number == 0:
            return Action.C
        if round_number == n_rounds - 1:
            return Action.D
        if n_players == 2:
            threshold = 1
        else:
            threshold = n_players - 2
        prev_h = int(history.opponent_cooperators[-1])
        if round_number == 1:
            return Action.C if prev_h >= threshold else Action.D
        prev2_h = int(history.opponent_cooperators[-2])
        if prev_h >= threshold and prev2_h >= threshold:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_125(BaseStrategy):
    """
    Threshold-based conditional cooperator for the repeated N-player Public Goods Game.

    - Starts by defecting.
    - Cooperates only in a clearly cooperative environment:
      * most recent observed opponent cooperation is high enough,
      * the recent average cooperation is at least the threshold,
      * and there has been no recent dip below the lower band.
    - If cooperation environment weakens, defects until two consecutive high-cooperation
      rounds are observed again.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.theta = 1.0 - 1.0 / k if k != 0 else 0.0
        denom = max(1, n - 1)
        band = 1.0 / denom
        self.theta_low = self.theta - band
        self.theta_high = self.theta + band
        self._observed_qs = []
        self._locked_defect = True
        self._high_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = max(2, int(self.game_description.n_players))
        n_opponents = max(1, n_players - 1)
        rn = history.round_number
        if rn > len(self._observed_qs):
            start = len(self._observed_qs)
            for idx in range(start, rn):
                opp_count = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
                q = opp_count / n_opponents
                self._observed_qs.append(q)
                if q >= self.theta_high:
                    self._high_streak += 1
                else:
                    self._high_streak = 0
                if q <= self.theta_low:
                    self._locked_defect = True
        elif rn < len(self._observed_qs):
            self._observed_qs = self._observed_qs[:rn]
            self._high_streak = 0
            self._locked_defect = True
            for q in self._observed_qs:
                if q >= self.theta_high:
                    self._high_streak += 1
                else:
                    self._high_streak = 0
                if q <= self.theta_low:
                    self._locked_defect = True
        if rn == 0:
            self._locked_defect = True
            self._high_streak = 0
            return Action.D
        last_q = self._observed_qs[-1] if self._observed_qs else 0.0
        recent_qs = self._observed_qs[-3:]
        avg_q = sum(recent_qs) / len(recent_qs) if recent_qs else 0.0
        recent_two = self._observed_qs[-2:] if len(self._observed_qs) >= 2 else self._observed_qs[-1:]
        if any((q <= self.theta_low for q in recent_two)):
            self._locked_defect = True
        if self._locked_defect:
            if self._high_streak >= 2:
                self._locked_defect = False
            else:
                return Action.D
        no_recent_low = all((q > self.theta_low for q in recent_two)) if recent_two else False
        if last_q >= self.theta_high and avg_q >= self.theta and no_recent_low:
            return Action.C
        self._locked_defect = True
        return Action.D

class Strategy_OPPORTUNISTIC_126(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Start with cooperation.
    - Track recent opponent cooperation and an estimated cooperation rate p.
    - Cooperate in generally cooperative environments, defect in weak ones.
    - Probe with cooperation after a strong cooperative signal.
    - Be strict in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n_players - 1)
        self.low = math.floor(self.n_opponents / 3)
        self.medium = math.ceil(self.n_opponents / 2)
        self.high = math.ceil(2 * self.n_opponents / 3)
        self.H = 0
        self.p = 0.0
        self.mode = 'cooperative'
        self.low_streak = 0
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            self.mode = 'cooperative'
            self.H = 0
            self.p = 0.0
            self.low_streak = 0
            self._last_seen_round = 0
            return Action.C
        opp = history.opponent_cooperators
        x = int(opp[-1]) if len(opp) > 0 else 0
        prev_x = int(opp[-2]) if len(opp) > 1 else x
        completed_rounds = t
        total_opp_coops = int(np.sum(opp)) if len(opp) > 0 else 0
        denom = completed_rounds * self.n_opponents
        self.p = total_opp_coops / denom if denom > 0 else 0.0
        self.H = x
        self._last_seen_round = t
        my_last_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        if my_last_action:
            if x >= self.medium:
                self.mode = 'cooperative'
                self.low_streak = 0
            elif x < self.low:
                self.mode = 'defensive'
                self.low_streak += 1
            else:
                self.low_streak = 0
        elif x >= self.high:
            self.mode = 'probe'
            self.low_streak = 0
        elif x < self.low:
            self.low_streak += 1
            if self.low_streak >= 2:
                self.mode = 'defensive'
        else:
            self.low_streak = 0
        if t == self.n_rounds - 1:
            return Action.C if x >= self.high else Action.D
        enough_recent_coop = x >= self.medium
        stable_or_improving = x >= prev_x - 1
        if enough_recent_coop and stable_or_improving:
            return Action.C
        if self.p >= 0.5 and x >= math.ceil(self.n_opponents / 3):
            return Action.C
        if x >= self.high:
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_127(BaseStrategy):
    """
    Threshold-based public goods strategy with cooperation, recovery probing,
    and anti-slack defections driven by recent opponent cooperation history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_opponents = max(0, self.game_description.n_players - 1)
        self.n_opponents = n_opponents
        self.low_threshold = math.floor(0.4 * n_opponents)
        self.rebound_threshold = math.ceil(0.75 * n_opponents)
        self.coop_threshold = math.ceil(0.6 * n_opponents)
        self.avg_threshold = math.ceil(0.65 * n_opponents)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds
        if round_number == 0:
            return Action.C
        if round_number >= n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        last_h = int(opp[-1])
        window = opp[-3:]
        if len(window) > 0:
            ma_last = int(math.floor(float(np.mean(window))))
        else:
            ma_last = 0
        low_streak = 0
        high_streak = 0
        for h in opp[::-1]:
            h_int = int(h)
            if h_int <= self.low_threshold:
                low_streak += 1
            else:
                break
        for h in opp[::-1]:
            h_int = int(h)
            if h_int >= self.rebound_threshold:
                high_streak += 1
            else:
                break
        last_action_c = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        if low_streak >= 2:
            if last_h >= self.rebound_threshold:
                return Action.C
            return Action.D
        if high_streak >= 3 and last_action_c:
            return Action.D
        if last_h >= self.coop_threshold and ma_last >= self.avg_threshold and (low_streak == 0):
            return Action.C
        return Action.D

class Strategy_OPPORTUNISTIC_128(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Start by cooperating.
    - Continue cooperating only under sustained or clearly sufficient opponent cooperation.
    - Defect after weak cooperation.
    - In the final round, cooperate only after two strongly cooperative prior rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        self.threshold = int(math.ceil(n / k - 1)) if k > 0 else n
        self.threshold = max(0, self.threshold)
        self.strong_threshold = self.threshold + 1
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        avg_m = float(np.mean(opp)) if len(opp) > 0 else 0.0
        strong_streak = 0
        for idx in range(len(opp) - 1, -1, -1):
            if int(opp[idx]) >= self.strong_threshold:
                strong_streak += 1
            else:
                break
        last_m = int(opp[-1])
        if t == self.n_rounds - 1:
            if len(opp) >= 2 and int(opp[-1]) >= self.strong_threshold and (int(opp[-2]) >= self.strong_threshold):
                return Action.C
            return Action.D
        if last_m >= self.threshold:
            if strong_streak >= 2 or avg_m >= self.threshold:
                return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_33(BaseStrategy):
    """
    Start with defection, then cooperate only after strong and stable opponent cooperation.
    Never cooperate in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        if n == 2:
            self.high = 1
            self.low = 0
        else:
            self.high = math.ceil(0.75 * (n - 1))
            self.low = math.floor(0.5 * (n - 1))
        self._cooldown_rounds_remaining = 0
        self._cooldown_recent_counts = []

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            self._cooldown_rounds_remaining = 0
            self._cooldown_recent_counts = []
            return Action.D
        last_opp = int(history.opponent_cooperators[-1])
        last_my_action = bool(history.my_actions[-1])
        if self._cooldown_rounds_remaining > 0:
            self._cooldown_rounds_remaining -= 1
            self._cooldown_recent_counts.append(last_opp)
            if len(self._cooldown_recent_counts) > 2:
                self._cooldown_recent_counts.pop(0)
            if self._cooldown_rounds_remaining == 0:
                if len(self._cooldown_recent_counts) >= 2 and all((count >= self.high for count in self._cooldown_recent_counts[-2:])):
                    self._cooldown_recent_counts = []
                else:
                    self._cooldown_rounds_remaining = 2
            return Action.D
        if last_my_action and last_opp < self.low:
            self._cooldown_rounds_remaining = 2
            self._cooldown_recent_counts = [last_opp]
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        if round_number == 1:
            return Action.C if last_opp >= self.high else Action.D
        if round_number >= 2:
            recent = history.opponent_cooperators[-3:]
            if len(recent) > 0:
                avg_last_3 = float(np.mean(recent))
            else:
                avg_last_3 = 0.0
            if last_opp >= self.high and avg_last_3 >= self.high:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_34(BaseStrategy):
    """
    Conditional threshold strategy for the N-player Public Goods Game.

    - Defect in round 1.
    - Cooperate only when the previous round showed enough opponent cooperation.
    - In the last round, cooperate only if the last two observed rounds both met
      the cooperation threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = getattr(game_description, 'n_players', 0)
        k = getattr(game_description, 'k', 0.0)
        if not isinstance(n, int) or n < 2:
            n = 2
        if not isinstance(k, (int, float)) or k <= 0:
            k = 1.0
        self.n_players = n
        self.k = float(k)
        self.threshold = int(math.ceil(self.n_players / self.k))
        if self.threshold < 0:
            self.threshold = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(getattr(history, 'round_number', 0))
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        if round_number == 0:
            return Action.D
        opp = history.opponent_cooperators
        if opp is None or len(opp) == 0:
            return Action.D
        last_m = int(opp[-1])
        threshold = self.threshold
        if round_number >= max(1, n_rounds - 1):
            if len(opp) >= 2 and int(opp[-2]) >= threshold and (last_m >= threshold):
                return Action.C
            return Action.D
        if last_m >= threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_35(BaseStrategy):
    """
    Conditional cooperator with adaptive personal threshold, strong endgame defection,
    and conservative fallbacks when cooperation is unstable or ambiguous.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.m_opponents = max(0, self.n_players - 1)

    def _compute_threshold_and_state(self, history: PlayerHistory):
        q = 0.5
        x_list = history.opponent_cooperators
        rounds_played = history.round_number
        for t in range(rounds_played):
            x_t = int(x_list[t])
            if self.m_opponents > 0:
                if x_t >= math.ceil(self.m_opponents / 2):
                    q = min(0.9, q + 0.1)
                elif x_t <= math.floor(self.m_opponents / 4):
                    q = max(0.1, q - 0.1)
            else:
                q = 0.5
        return q

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        n_rounds = self.n_rounds
        if t == 0:
            return Action.C if self.k >= self.n_players / 2.0 else Action.D
        rounds_remaining = n_rounds - t
        if rounds_remaining <= 1:
            return Action.D
        q_t = self._compute_threshold_and_state(history)
        x_prev = int(history.opponent_cooperators[-1])
        p_prev = x_prev / self.m_opponents if self.m_opponents > 0 else 0.0
        x_prev2 = None
        p_prev2 = None
        if t >= 2:
            x_prev2 = int(history.opponent_cooperators[-2])
            p_prev2 = x_prev2 / self.m_opponents if self.m_opponents > 0 else 0.0
        if rounds_remaining == 2:
            if p_prev == 1.0 and q_t >= 0.8:
                return Action.C
            return Action.D
        if p_prev == 1.0 and rounds_remaining > 2:
            return Action.C
        near_zero_threshold = 0
        if self.m_opponents > 0:
            near_zero_threshold = 1 if self.m_opponents >= 4 else 0
        if t >= 2:
            if x_prev <= near_zero_threshold and x_prev2 <= near_zero_threshold:
                return Action.D
        oscillating = False
        if t >= 3 and x_prev2 is not None:
            x_prev3 = int(history.opponent_cooperators[-3])
            ascending = x_prev3 < x_prev2 < x_prev
            descending = x_prev3 > x_prev2 > x_prev
            oscillating = not (ascending or descending)
        if self.m_opponents <= 0:
            return Action.D
        required_rate = q_t
        if oscillating:
            required_rate = min(1.0, q_t + 1.0 / self.m_opponents)
        sharp_drop_ok = True
        if t >= 2:
            sharp_drop_ok = x_prev >= x_prev2 - 1
        if p_prev >= required_rate and sharp_drop_ok:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_36(BaseStrategy):
    """
    Self-interested threshold strategy with a short probe phase,
    discounted cooperation score, and stricter endgame cooperation criteria.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C
        opp_counts = history.opponent_cooperators
        n_opponents = max(self.n_players - 1, 1)
        q_values = [float(m) / n_opponents for m in opp_counts]
        if round_number == self.n_rounds - 1:
            if self.n_rounds == 2:
                return Action.C if q_values[-1] >= 0.6 else Action.D
            if len(q_values) >= 2 and q_values[-1] >= 0.6 and (q_values[-2] >= 0.6):
                return Action.C
            return Action.D
        score = 0.0
        for q in q_values:
            score = 0.7 * score + (q - 0.5)
        if q_values[-1] >= 0.5 and score >= 0.0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_37(BaseStrategy):
    """
    Cautious public-goods strategy with short cooldowns after weak cooperation
    and a stronger defecting mode after two consecutive weak rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        opponents = max(0, self.n_players - 1)
        self.high_threshold = int(math.ceil(0.75 * opponents))
        self.low_threshold = int(math.floor(0.5 * opponents))
        self.cooldown = 0
        self.force_defect = False
        self.weak_streak = 0
        self.strong_streak = 0
        self.last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        while self.last_processed_round < round_number:
            h = int(history.opponent_cooperators[self.last_processed_round])
            if self.cooldown > 0:
                self.cooldown -= 1
            if h < self.low_threshold:
                self.weak_streak += 1
            else:
                self.weak_streak = 0
            if h >= self.high_threshold:
                self.strong_streak += 1
            else:
                self.strong_streak = 0
            if self.weak_streak >= 2:
                self.force_defect = True
            if self.force_defect and self.strong_streak >= 2:
                self.force_defect = False
                self.weak_streak = 0
                self.strong_streak = 0
            if h <= self.low_threshold:
                self.cooldown = 2
            self.last_processed_round += 1
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if self.force_defect:
            return Action.D
        if self.cooldown > 0:
            return Action.D
        h1 = int(history.opponent_cooperators[-1]) if round_number >= 1 else 0
        h2 = int(history.opponent_cooperators[-2]) if round_number >= 2 else 0
        if h1 >= self.high_threshold:
            if round_number < 3 or h2 >= self.high_threshold:
                if round_number < 3 or h1 >= h2:
                    return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_38(BaseStrategy):
    """
    Conservative public-goods strategy:
    - Probe with cooperation on round 1
    - Cooperate only under sustained high cooperation
    - Defect quickly under weak cooperation
    - Require stable recovery after defection
    - Defect in the final rounds unless recent cooperation is consistently strong
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        theta_hi = max(0.5, 1.0 - 1.0 / k if k != 0 else 0.5)
        theta_lo = theta_hi - 0.2
        self.theta_hi = theta_hi
        self.theta_lo = theta_lo
        self._hi_count_threshold = math.ceil(theta_hi * (n - 1))
        self._lo_count_threshold = math.floor(theta_lo * (n - 1))
        self._n_opponents = max(1, n - 1)

    def _smoothed_level(self, history: PlayerHistory) -> float:
        n_opponents = self._n_opponents
        round_count = history.round_number
        if round_count <= 0:
            return 0.0
        s = 0.0
        for idx in range(round_count):
            x = int(history.opponent_cooperators[idx])
            coop_rate = x / n_opponents if n_opponents > 0 else 0.0
            if idx == 0:
                s = coop_rate
            else:
                s = 0.7 * s + 0.3 * coop_rate
        return s

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = int(self.game_description.n_rounds)
        if t == 0:
            return Action.C
        last_x = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_s = self._smoothed_level(history)
        hi_ok_last = last_x >= self._hi_count_threshold
        lo_ok_last = last_x <= self._lo_count_threshold
        if t >= max(0, r - 2):
            if len(history.opponent_cooperators) >= 2:
                x1 = int(history.opponent_cooperators[-1])
                x2 = int(history.opponent_cooperators[-2])
                if x1 >= self._hi_count_threshold and x2 >= self._hi_count_threshold:
                    return Action.C
            return Action.D
        if len(history.my_actions) >= 2 and (not bool(history.my_actions[-1])) and (not bool(history.my_actions[-2])):
            if len(history.opponent_cooperators) >= 2:
                x1 = int(history.opponent_cooperators[-1])
                x2 = int(history.opponent_cooperators[-2])
                if x1 >= self._hi_count_threshold and x2 >= self._hi_count_threshold:
                    return Action.C
            return Action.D
        if hi_ok_last and last_s >= self.theta_hi:
            return Action.C
        if lo_ok_last or last_s <= self.theta_lo:
            return Action.D
        return Action.C if bool(history.my_actions[-1]) else Action.D

class Strategy_INDIVIDUALISTIC_39(BaseStrategy):
    """
    Conservative reciprocity strategy for the repeated public goods game.

    - Defects in the first round.
    - Cooperates only after two consecutive rounds of full opponent cooperation.
    - Any deviation by opponents triggers a two-round defection cooldown.
    - Always defects in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.s = 0
        self.cooldown = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = self.game_description.n_players
        n_rounds = self.game_description.n_rounds
        while self._processed_rounds < history.round_number:
            m = int(history.opponent_cooperators[self._processed_rounds])
            if m == max(0, n_players - 1):
                self.s += 1
            else:
                self.s = 0
                self.cooldown = 2
            self._processed_rounds += 1
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        if current_round >= max(0, n_rounds - 1):
            return Action.D
        if self.cooldown > 0:
            self.cooldown -= 1
            return Action.D
        if self.s >= 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_40(BaseStrategy):
    """
    Conservative adaptive public-goods strategy:
    - Defects in the opening and final rounds.
    - Estimates opponent cooperation from recent history.
    - Cooperates only when the environment appears stably cooperative.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        denom = max(1, n - 1)
        self.q_star = (n / k - 1.0) / denom if k > 0 else 1.0
        self.margin = 0.1
        self.drop_threshold = 0.25

    def _rate(self, coop_count: int) -> float:
        n_opponents = max(1, self.game_description.n_players - 1)
        return float(coop_count) / float(n_opponents)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n_rounds = self.game_description.n_rounds
        if t == 0 or t >= n_rounds - 1:
            return Action.D
        n_opponents = max(1, self.game_description.n_players - 1)
        q = self.q_star
        m = self.margin
        rates = [self._rate(int(x)) for x in history.opponent_cooperators[:t]]
        if len(rates) >= 2 and rates[-2] - rates[-1] >= self.drop_threshold:
            return Action.D
        if len(rates) >= 3:
            if rates[-1] - rates[-2] >= self.drop_threshold and rates[-1] >= q and (rates[-2] >= q):
                return Action.C
        if len(rates) >= 2 and rates[-1] < q and (rates[-2] < q):
            return Action.D
        if len(rates) >= 3 and rates[-1] >= q + m and (rates[-2] >= q + m) and (rates[-3] >= q + m):
            return Action.C
        avg_m = float(np.mean(rates)) if rates else 0.0
        if avg_m >= q + m:
            return Action.C
        if avg_m <= q - m:
            return Action.D
        recent = rates[-3:] if len(rates) >= 3 else rates
        short_avg = float(np.mean(recent)) if recent else 0.0
        if short_avg >= q:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_41(BaseStrategy):
    """
    Conditional public-goods strategy:
    - Defect in the opening and closing phases.
    - Cooperate only after two consecutive strong-cooperation rounds
      and only when there is no recent collapse signal.
    - Immediately fall back to defection after weak or zero cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        k = float(game_description.k)
        if n == 2:
            self.q_high = 1
            self.q_low = 0
        else:
            if k <= 1.0:
                base = 1.0
            else:
                base = max(0.5, 1.0 - 1.0 / k)
            self.q_high = int(math.ceil((n - 1) * base))
            self.q_high = max(0, min(n - 1, self.q_high))
            self.q_low = max(0, self.q_high - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if t == 0 or t == 1:
            return Action.D
        if t > n_rounds - 2:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        good_streak = 0
        bad_streak = 0
        reset = 0
        for o in opp:
            if o >= self.q_high:
                good_streak += 1
                bad_streak = 0
            elif o <= self.q_low:
                bad_streak += 1
                good_streak = 0
                reset = 2
            else:
                good_streak = 0
                bad_streak = 0
            if reset > 0:
                reset -= 1
        if reset > 0:
            return Action.D
        if good_streak >= 2 and bad_streak == 0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_42(BaseStrategy):
    """
    Defect by default. Cooperate only after sustained high opponent cooperation,
    and permanently defect after any post-cooperation collapse below the low threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.m = max(0, self.n_players - 1)
        if self.k <= 1.0 or self.m <= 0:
            self.H = 0
        else:
            self.H = math.ceil(self.m * (1.0 - 1.0 / self.k))
        self.L = math.floor(self.H / 2)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        cooperated_before = False
        triggered_lockout = False
        for i in range(len(history.my_actions)):
            if bool(history.my_actions[i]):
                cooperated_before = True
                for j in range(i + 1, len(opp)):
                    if int(opp[j]) < self.L:
                        triggered_lockout = True
                        break
            if triggered_lockout:
                break
        if cooperated_before and triggered_lockout:
            return Action.D
        if self.H <= 0:
            return Action.D
        if int(opp[-1]) < self.H:
            return Action.D
        if t >= 2 and int(opp[-2]) < self.H:
            return Action.D
        ell = min(3, t)
        if ell <= 0:
            return Action.D
        recent = opp[-ell:]
        recent_sum = float(np.sum(recent)) if len(recent) > 0 else 0.0
        if recent_sum / ell < self.H:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_43(BaseStrategy):
    """
    Always defect in every round, regardless of history.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_rounds = getattr(game_description, 'n_rounds', 0)

    def __call__(self, history: PlayerHistory) -> Action:
        _ = history.round_number
        return Action.D

class Strategy_INDIVIDUALISTIC_44(BaseStrategy):
    """
    Defect initially and in the final round.
    Cooperate only after a majority of opponents cooperated in the previous round,
    but enter a punishment mode after weak cooperation and remain defecting until
    two consecutive majority-cooperation rounds are observed.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._punishment = False
        self._good_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        n_players = getattr(self.game_description, 'n_players', 2)
        m = math.ceil((n_players - 1) / 2) if n_players > 1 else 1
        if n_players == 2:
            m = 1
        if history.round_number == 0:
            self._punishment = False
            self._good_streak = 0
            return Action.D
        if n_rounds > 0 and history.round_number >= n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if opp is None or len(opp) == 0:
            return Action.D
        punishment = False
        good_streak = 0
        for q in opp:
            q_int = int(q)
            if q_int >= m:
                if punishment:
                    good_streak += 1
                    if good_streak >= 2:
                        punishment = False
                        good_streak = 0
            elif punishment:
                good_streak = 0
            else:
                punishment = True
                good_streak = 0
        self._punishment = punishment
        self._good_streak = good_streak
        last_q = int(opp[-1])
        if punishment:
            return Action.D
        return Action.C if last_q >= m else Action.D

class Strategy_INDIVIDUALISTIC_45(BaseStrategy):
    """
    Defect by default. Cooperate only after two consecutive rounds where
    opponents' cooperation meets or exceeds a strong-cooperation threshold,
    immediately retreat after weak environments, and never cooperate on the
    final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        self.H = math.ceil(2 * (n - 1) / 3) if n > 1 else 1
        self.L = math.floor((n - 1) / 2) if n > 1 else 0
        self.streak = 0
        self.lockout = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        current_round = history.round_number
        while self._processed_rounds < current_round:
            idx = self._processed_rounds
            s_t = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            my_c = bool(history.my_actions[idx]) if idx < len(history.my_actions) else False
            if s_t >= self.H:
                self.streak += 1
            else:
                self.streak = 0
            if s_t <= self.L:
                self.lockout = 2
                self.streak = 0
            if my_c and s_t < self.H:
                self.lockout = 1
                self.streak = 0
            self._processed_rounds += 1
        if current_round == 0:
            return Action.D
        if n_rounds > 0 and current_round == n_rounds - 1:
            return Action.D
        if self.lockout > 0:
            self.lockout -= 1
            return Action.D
        if self.streak >= 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_46(BaseStrategy):
    """
    Guarded threshold strategy for the N-player Public Goods Game.

    - Defect in round 1.
    - Cooperate in intermediate rounds only if the previous round met the
      cooperation threshold and the round before that was also at or above
      threshold when available.
    - In the final round, cooperate only if the two most recent observed rounds
      both met the threshold.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = game_description.n_players
        k = game_description.k
        if n is None or n < 2 or k is None or (k <= 0):
            self.threshold = math.inf
        else:
            self.threshold = math.ceil((n - 1) / k)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        total_rounds = self.game_description.n_rounds
        if round_number == 0:
            return Action.D
        last_count = int(history.opponent_cooperators[-1]) if round_number >= 1 else -1
        prev_count = int(history.opponent_cooperators[-2]) if round_number >= 2 else None
        last_good = last_count >= self.threshold
        prev_good = prev_count >= self.threshold if prev_count is not None else False
        if round_number == total_rounds - 1:
            return Action.C if round_number >= 2 and last_good and prev_good else Action.D
        if round_number >= 2:
            if last_good and prev_good:
                return Action.C
            return Action.D
        return Action.C if last_good else Action.D

class Strategy_INDIVIDUALISTIC_47(BaseStrategy):
    """
    Tit-for-sustained-cooperation strategy:
    - Starts and ends with defection.
    - Switches to an open/cooperative mode only after two consecutive rounds
      of sufficiently high opponent cooperation.
    - Leaves open mode immediately after a clear drop in cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'closed'
        self.good_streak = 0
        self.bad_streak = 0
        k = float(game_description.k)
        if k > 0:
            theta_hi = max(0.5, 1.0 - 1.0 / k)
            theta_lo = max(0.0, theta_hi - 1.0 / (2.0 * k))
        else:
            theta_hi = 1.0
            theta_lo = 1.0
        self.theta_hi = theta_hi
        self.theta_lo = theta_lo

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(0, n_players - 1)
        if history.round_number == 0:
            return Action.D
        if history.round_number >= n_rounds - 1:
            return Action.D
        x_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if n_opponents > 0:
            rho = x_prev / n_opponents
        else:
            rho = 0.0
        if self.mode == 'closed':
            if rho >= self.theta_hi:
                self.good_streak += 1
            else:
                self.good_streak = 0
            if self.good_streak >= 2:
                self.mode = 'open'
                self.bad_streak = 0
            return Action.D
        if rho < self.theta_lo:
            self.bad_streak += 1
        else:
            self.bad_streak = 0
        if self.bad_streak >= 1:
            self.mode = 'closed'
            self.good_streak = 0
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_48(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Start with defection.
    - Cooperate only after two sufficiently cooperative recent rounds.
    - Enter a short cooldown after weak cooperation and defect during cooldown.
    - Always defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.cooldown_remaining = 0
        k = float(game_description.k)
        self.accept_threshold = max(0.6, 1.0 - 1.0 / k) if k != 0 else 0.6
        self.recover_threshold = max(0.4, self.accept_threshold - 0.2)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        if round_number == 0:
            self.cooldown_remaining = 0
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        last_opponent_count = int(history.opponent_cooperators[-1])
        p_last = last_opponent_count / n_opponents
        if p_last < self.recover_threshold:
            self.cooldown_remaining = max(self.cooldown_remaining, 2)
        if self.cooldown_remaining > 0:
            self.cooldown_remaining -= 1
            return Action.D
        if p_last >= self.accept_threshold:
            if round_number < 2:
                return Action.C
            prev_opponent_count = int(history.opponent_cooperators[-2])
            p_prev = prev_opponent_count / n_opponents
            if p_prev >= self.accept_threshold:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_49(BaseStrategy):
    """
    Cooperative only when recent opponent cooperation is sustained and
    reciprocity is repeatedly observed; otherwise defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._opp_rates = []
        self._my_actions = []
        self._warning_times = []
        self._block_active = False
        self._block_start_round = -1
        self._block_successes = 0
        self._block_observed = 0

    def _threshold(self) -> float:
        k = float(self.game_description.k)
        n = int(self.game_description.n_players)
        span = max(n - 1.0, 1.0)
        low_cut = 1.0 + span / 3.0
        high_cut = 1.0 + 2.0 * span / 3.0
        if k >= high_cut:
            return 0.4
        if k <= low_cut:
            return 0.6
        return 0.5

    def _avg_recent(self, values, w: int) -> float:
        if not values:
            return 0.0
        w = max(1, min(w, len(values)))
        return float(np.mean(np.array(values[-w:], dtype=np.float64)))

    def __call__(self, history: PlayerHistory) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        k = float(self.game_description.k)
        t = history.round_number
        n_opponents = max(n - 1, 1)
        if t == 0:
            action = Action.C if k > n / 2.0 else Action.D
            self._my_actions.append(action == Action.C)
            return action
        last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        p_last = last_opp / n_opponents
        self._opp_rates.append(p_last)
        last_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        tau = self._threshold()
        warning = last_my_action and p_last < 1.0 / 3.0
        if warning:
            self._warning_times.append(t - 1)
        if len(self._warning_times) > 4:
            self._warning_times = self._warning_times[-4:]
        if len(self._warning_times) >= 2:
            if self._warning_times[-1] - self._warning_times[-2] <= 3:
                self._block_active = True
                self._block_start_round = t
                self._block_successes = 0
                self._block_observed = 0
                self._warning_times = self._warning_times[-4:]
        if self._block_active:
            self._block_observed += 1
            if p_last >= tau:
                self._block_successes += 1
            if self._block_observed >= 3:
                if self._block_successes >= 2:
                    self._block_active = False
                else:
                    self._block_observed = 3
        rounds_left_including_current = r - t
        if rounds_left_including_current <= 2:
            recent_full = False
            if len(self._opp_rates) >= 3:
                recent_full = self._opp_rates[-1] == 1.0 and self._opp_rates[-2] == 1.0 and (self._opp_rates[-3] == 1.0)
            if not recent_full:
                action = Action.D
                self._my_actions.append(False)
                return action
        if self._block_active:
            action = Action.D
            self._my_actions.append(False)
            return action
        A_t = self._avg_recent(self._opp_rates, min(3, len(self._opp_rates)))
        recent_my = self._my_actions[-3:] if len(self._my_actions) >= 3 else self._my_actions[:]
        recent_opp = self._opp_rates[-3:] if len(self._opp_rates) >= 3 else self._opp_rates[:]
        good_rounds = 0
        for ma, opp_p in zip(recent_my, recent_opp):
            if ma and opp_p > tau:
                good_rounds += 1
        if A_t > tau and good_rounds >= 2:
            action = Action.C
        else:
            action = Action.D
        self._my_actions.append(action == Action.C)
        return action

class Strategy_INDIVIDUALISTIC_50(BaseStrategy):
    """
    Self-interested conditional-cooperation strategy with probe, reward, and exploit modes.
    Starts with defection, cooperates after strong observed cooperation, defects after weak
    cooperation, and is especially cautious in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        threshold_base = (n - k) / 2.0
        self.t_high = math.ceil(threshold_base)
        self.t_low = math.floor(threshold_base)
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        last_m = int(history.opponent_cooperators[-1])
        prev_count = round_number
        if prev_count > 0:
            avg = float(np.mean(history.opponent_cooperators[:prev_count]))
        else:
            avg = 0.0
        if round_number == self.n_rounds - 1:
            if last_m >= self.t_high and avg >= self.t_high:
                return Action.C
            return Action.D
        if last_m >= self.t_high:
            return Action.C
        if last_m <= self.t_low:
            return Action.D
        if avg >= self.t_high:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_51(BaseStrategy):
    """
    Individualistic public-goods strategy:
    - Defect in round 1 and always in the final round.
    - Cooperate only when recent opponent cooperation is stable and above a threshold.
    - Use an exponential moving average of opponent cooperation to detect volatility.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_rounds = int(game_description.n_rounds)
        self.n_players = int(game_description.n_players)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n_players - 1)
        self.threshold = max(0.5, 1.0 - 1.0 / self.k) if self.k != 0 else 0.5

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        next_round = round_number + 1
        if next_round >= self.n_rounds:
            return Action.D
        if len(history.opponent_cooperators) == 0 or self.n_opponents <= 0:
            return Action.D
        q_values = []
        for count in history.opponent_cooperators:
            q_values.append(float(count) / float(self.n_opponents))
        s_values = [q_values[0]]
        for idx in range(1, len(q_values)):
            s_values.append(0.7 * s_values[-1] + 0.3 * q_values[idx])
        q_last = q_values[-1]
        s_last = s_values[-1]
        t = self.threshold
        if next_round == 2:
            return Action.C if q_last >= t and s_last >= t else Action.D
        if len(q_values) >= 2:
            q_prev = q_values[-2]
            s_prev = s_values[-2]
            if q_last >= t and q_prev >= t and (s_last >= t) and (s_prev >= t):
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_52(BaseStrategy):
    """
    Defect by default. Cooperate only after observing two consecutive rounds in
    which every opponent cooperated, and never cooperate in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_rounds = int(game_description.n_rounds) if game_description is not None else 0
        self.n_players = int(game_description.n_players) if game_description is not None else 0
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if self.n_rounds > 0 and round_number >= self.n_rounds - 1:
            return Action.D
        if round_number < 2:
            return Action.D
        last_two = history.opponent_cooperators[-2:]
        if len(last_two) == 2 and all((int(x) >= self.n_opponents for x in last_two)):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_53(BaseStrategy):
    """
    Public goods strategy:
    - Defect first round
    - Track opponent cooperation streaks and running average
    - Cooperate only after sustained high cooperation
    - Defect in the final round unless cooperation has been strongly sustained
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = max(2, int(game_description.n_players))
        self.n_rounds = max(1, int(game_description.n_rounds))
        n_opp = max(0, self.n_players - 1)
        self.high = int(math.ceil(n_opp * 2 / 3))
        self.low = int(math.floor(n_opp / 3))
        self.M = 0.0
        self._observed_count = 0
        self.s = 0
        self.q = 0
        self._processed_rounds = 0

    def _sync_state(self, history: PlayerHistory) -> None:
        target = int(history.round_number)
        if target <= self._processed_rounds:
            return
        for t in range(self._processed_rounds, target):
            m_t = int(history.opponent_cooperators[t])
            self._observed_count += 1
            if self._observed_count == 1:
                self.M = float(m_t)
            else:
                self.M += (m_t - self.M) / self._observed_count
            if m_t >= self.high:
                self.s += 1
                self.q = 0
            elif m_t <= self.low:
                self.q += 1
                self.s = 0
            else:
                self.s = 0
                self.q = 0
        self._processed_rounds = target

    def __call__(self, history: PlayerHistory) -> Action:
        self._sync_state(history)
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number == self.n_rounds - 1:
            if round_number >= 2:
                prev1 = int(history.opponent_cooperators[-1])
                prev2 = int(history.opponent_cooperators[-2])
                if prev1 >= self.high and prev2 >= self.high:
                    return Action.C
            return Action.D
        if self.s >= 2:
            return Action.C
        if self.q >= 2:
            return Action.D
        last_m = int(history.opponent_cooperators[-1])
        if last_m >= self.high:
            return Action.C
        if last_m <= self.low:
            return Action.D
        if self.M >= (self.n_players - 1) / 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_54(BaseStrategy):
    """
    Always defect in every round, regardless of history or game state.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_INDIVIDUALISTIC_55(BaseStrategy):
    """
    Majority-sensitive reciprocal strategy with trust, brief punishment after
    broad defection, and cautious endgame play.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._n = int(game_description.n_players)
        self._r = int(game_description.n_rounds)
        self._majority_threshold = math.floor((self._n - 1) / 2)
        self._last_processed_round = 0
        self._trust = 0
        self._cooldown_remaining = 0
        self._strong_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        current_round = history.round_number
        n_other = max(self._n - 1, 0)
        for t in range(self._last_processed_round, current_round):
            m_t = int(history.opponent_cooperators[t])
            my_c = bool(history.my_actions[t])
            if my_c:
                if m_t >= n_other / 2.0:
                    self._trust += 1
                else:
                    self._trust -= 2
            elif m_t >= n_other / 2.0:
                self._trust += 1
            if m_t == n_other:
                self._strong_streak += 1
                if self._strong_streak >= 2:
                    self._trust = max(self._trust, 2)
            else:
                self._strong_streak = 0
            if m_t == 0:
                self._cooldown_remaining = max(self._cooldown_remaining, 2)
        self._last_processed_round = current_round
        if current_round == 0:
            return Action.C
        m_last = int(history.opponent_cooperators[-1]) if current_round > 0 else 0
        majority_now = m_last >= self._majority_threshold
        if self._cooldown_remaining > 0:
            self._cooldown_remaining -= 1
            return Action.D
        if current_round >= max(self._r - 2, 0):
            if m_last == n_other:
                return Action.C
            if current_round >= 2:
                prev_m = int(history.opponent_cooperators[-2])
                if prev_m >= self._majority_threshold and m_last >= self._majority_threshold:
                    return Action.C
            return Action.D
        if self._trust >= 0 and majority_now:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_56(BaseStrategy):
    """
    Defect initially, cooperate only after a clear majority of opponents cooperated,
    mirror the previous action on exact balance, and permanently defect after two
    consecutive rounds with minority opponent cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._locked_defect = False
        self._consecutive_low_q = 0
        self._last_seen_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        current_round = history.round_number
        next_round = current_round + 1
        start_idx = self._last_seen_round
        end_idx = current_round
        if start_idx > end_idx:
            start_idx = 0
            self._locked_defect = False
            self._consecutive_low_q = 0
        if start_idx != end_idx:
            for idx in range(start_idx, end_idx):
                if self._locked_defect:
                    break
                opp_coop = int(history.opponent_cooperators[idx])
                if n <= 1:
                    q_is_low = True
                    q_is_high = False
                else:
                    twice_m = 2 * opp_coop
                    threshold = n - 1
                    q_is_low = twice_m < threshold
                    q_is_high = twice_m > threshold
                if q_is_low:
                    self._consecutive_low_q += 1
                    if self._consecutive_low_q >= 2:
                        self._locked_defect = True
                else:
                    self._consecutive_low_q = 0
            self._last_seen_round = current_round
        if current_round == 0:
            return Action.D
        if next_round == r:
            return Action.D
        if self._locked_defect:
            return Action.D
        last_opp_coop = int(history.opponent_cooperators[-1])
        if n <= 1:
            return Action.D
        twice_m = 2 * last_opp_coop
        threshold = n - 1
        if twice_m < threshold:
            self._consecutive_low_q += 1
            if self._consecutive_low_q >= 2:
                self._locked_defect = True
                return Action.D
            return Action.D
        self._consecutive_low_q = 0
        if twice_m > threshold:
            return Action.C
        last_my_action = bool(history.my_actions[-1])
        return Action.C if last_my_action else Action.D

class Strategy_INDIVIDUALISTIC_57(BaseStrategy):
    """
    Conditional cooperator that starts with defection, cooperates only after
    observing full cooperation in the immediately preceding round(s), and
    defects on the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        if t == self.n_rounds - 1:
            return Action.D
        n_opponents = max(self.n_players - 1, 0)
        full_coop_count = n_opponents
        last_q = int(history.opponent_cooperators[-1])
        if t == 1:
            return Action.C if last_q == full_coop_count else Action.D
        prev_q = int(history.opponent_cooperators[-2])
        if last_q == full_coop_count and prev_q == full_coop_count and (last_q >= prev_q):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_58(BaseStrategy):
    """
    Self-interested threshold strategy with calibrated retaliation and conditional generosity.

    - Cooperates initially when the public-good return is immediately attractive.
    - Uses an early-round average to bootstrap beliefs.
    - Switches to a weighted recent-average threshold rule in later rounds.
    - Defects temporarily after sharp cooperation collapses, but forgives quickly
      when cooperation recovers.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n_players - 1)
        self.theta = 1.0 - 1.0 / self.k if self.k != 0 else 1.0
        self.first_round_coop_threshold = 0.5
        self.final_round_bonus = 1.0 / (2.0 * self.k) if self.k != 0 else 0.0
        self.L = max(1, min(3, self.n_rounds))

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)

        def coop_signal_recent(opp_counts) -> float:
            if len(opp_counts) == 0 or self.n_opponents <= 0:
                return 0.0
            weights = np.arange(1, len(opp_counts) + 1, dtype=float)
            total_w = float(np.sum(weights))
            if total_w <= 0.0:
                return 0.0
            return float(np.dot(np.asarray(opp_counts, dtype=float), weights) / total_w)

        def avg_coop(opp_counts) -> float:
            if len(opp_counts) == 0:
                return 0.0
            return float(np.mean(np.asarray(opp_counts, dtype=float)))

        def is_recovering(opp_counts) -> bool:
            if len(opp_counts) < 2:
                return False
            return int(opp_counts[-1]) > int(opp_counts[-2])

        def sharp_drop_recent(opp_counts) -> bool:
            if len(opp_counts) < 2:
                return False
            return int(opp_counts[-2]) - int(opp_counts[-1]) >= 2

        def all_defected_last_round(opp_counts) -> bool:
            return len(opp_counts) > 0 and int(opp_counts[-1]) <= 0

        def recent_strong_coop(opp_counts) -> bool:
            if len(opp_counts) < 2:
                return False
            return int(opp_counts[-1]) > int(opp_counts[-2]) and (len(opp_counts) < 3 or int(opp_counts[-2]) > int(opp_counts[-3]))
        opp = history.opponent_cooperators
        if t == 0:
            return Action.C if self.k / max(1, self.n_players) >= self.first_round_coop_threshold else Action.D
        last_obs = opp[:t] if len(opp) >= t else opp
        if t >= self.n_rounds - 1:
            signal = coop_signal_recent(last_obs[-self.L:])
            threshold = self.theta + self.final_round_bonus
            if self.n_opponents <= 0:
                return Action.D
            return Action.C if signal / self.n_opponents >= threshold else Action.D
        retaliate = False
        if sharp_drop_recent(last_obs):
            retaliate = True
        if all_defected_last_round(last_obs):
            retaliate = True
        if recent_strong_coop(last_obs):
            retaliate = False
        recent_window = last_obs[-self.L:]
        signal = coop_signal_recent(recent_window)
        signal_ratio = signal / self.n_opponents if self.n_opponents > 0 else 0.0
        if t <= self.L:
            avg_signal = avg_coop(last_obs)
            avg_ratio = avg_signal / self.n_opponents if self.n_opponents > 0 else 0.0
            if retaliate and avg_ratio < self.theta:
                return Action.D
            return Action.C if avg_ratio >= self.theta else Action.D
        if retaliate and signal_ratio < self.theta:
            return Action.D
        return Action.C if signal_ratio >= self.theta else Action.D

class Strategy_INDIVIDUALISTIC_59(BaseStrategy):
    """
    Cautious conditional cooperator:
    starts with defection, tracks trust and consecutive high-cooperation
    streaks, cooperates only in stable high-trust conditions, and never
    cooperates in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.trust = 0
        self.coop_streak = 0
        self.processed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        while self.processed_rounds < history.round_number:
            idx = self.processed_rounds
            opp_coop = int(history.opponent_cooperators[idx])
            q = opp_coop / n_opponents
            if q >= 0.75:
                self.coop_streak += 1
            else:
                self.coop_streak = 0
            if q < 0.5:
                self.trust = 0
                self.coop_streak = 0
            else:
                if q >= 0.75:
                    self.trust += 1
                elif q <= 0.25:
                    self.trust -= 2
                else:
                    self.trust -= 1
                if self.trust < 0:
                    self.trust = 0
                elif self.trust > 3:
                    self.trust = 3
            self.processed_rounds += 1
        if history.round_number == 0:
            return Action.D
        if history.round_number >= n_rounds - 1:
            return Action.D
        if self.trust >= 2 and self.coop_streak >= 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_60(BaseStrategy):
    """
    Conditional cooperation strategy for the N-player Public Goods Game.

    - Round 1: defect.
    - Round 2: cooperate only if all opponents cooperated in round 1.
    - Rounds 3 through r-1: cooperate iff the number of cooperating opponents
      in each of the previous two rounds is at least the threshold H.
    - Final round: defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.threshold = 1 if self.n_players == 2 else max(0, self.n_players - 2)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number == 1:
            if len(history.opponent_cooperators) > 0:
                return Action.C if history.opponent_cooperators[-1] >= self.n_players - 1 else Action.D
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if len(history.opponent_cooperators) < 2:
            return Action.D
        x_t_minus_1 = int(history.opponent_cooperators[-1])
        x_t_minus_2 = int(history.opponent_cooperators[-2])
        if x_t_minus_1 >= self.threshold and x_t_minus_2 >= self.threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_61(BaseStrategy):
    """
    Defensive public-goods strategy:
    - Defect initially.
    - Build cooperation only after sustained, observable cooperation.
    - Use a small trust state plus recent-history smoothing.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k) if game_description.k is not None else 0.0
        self.n_players = n
        self.k = k
        self.base = math.ceil(n / k) - 1 if k > 0 else n
        self.trust = 0
        self.last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if self.base > self.n_players - 1:
            self.last_processed_round = round_number
            return Action.D
        if self.last_processed_round < round_number:
            start_idx = self.last_processed_round
            end_idx = round_number
            for idx in range(start_idx, end_idx):
                x_t = int(history.opponent_cooperators[idx])
                if self.base <= 0:
                    if x_t > 0:
                        self.trust = min(self.trust + 1, 2)
                    else:
                        self.trust = max(self.trust - 1, -2)
                elif x_t >= self.base:
                    self.trust = min(self.trust + 1, 2)
                elif x_t == 0:
                    self.trust = max(self.trust - 2, -2)
                else:
                    self.trust = max(self.trust - 1, -2)
            self.last_processed_round = round_number
        latest_x = int(history.opponent_cooperators[-1])
        if self.base <= 0:
            if np.any(history.opponent_cooperators[:round_number] > 0) and self.trust >= 0:
                return Action.C
            return Action.D
        if latest_x < self.base or self.trust < 0:
            return Action.D
        if round_number >= 2:
            last_two = history.opponent_cooperators[-2:]
            if not np.all(last_two >= self.base):
                return Action.D
        else:
            return Action.D
        if round_number >= 3:
            recent_three = history.opponent_cooperators[-3:]
            avg_recent = float(np.mean(history.opponent_cooperators))
            good_recent_three = int(np.sum(recent_three >= self.base))
            if avg_recent < self.base or good_recent_three < 2:
                return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_62(BaseStrategy):
    """
    Personal threshold-and-trend strategy for the repeated public goods game.
    Cooperate initially, then condition cooperation on smoothed opponent cooperation,
    recent trend, and special endgame/edge-case rules.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.theta = 0.55
        k = float(game_description.k) if game_description.k is not None else 1.0
        if k <= 0:
            k = 1.0
        self.theta_high = max(0.6, 1.0 - 1.0 / k)
        self.smoothing_alpha = 0.3
        self.smoothing_beta = 0.7

    def __call__(self, history: PlayerHistory) -> Action:
        n_players = int(self.game_description.n_players)
        n_rounds = int(self.game_description.n_rounds)
        n_opponents = max(n_players - 1, 1)
        t = int(history.round_number) + 1
        if t <= 1:
            return Action.C
        opp_counts = history.opponent_cooperators
        past_rounds = len(opp_counts)

        def frac_at(idx: int) -> float:
            if idx < 0 or idx >= past_rounds:
                return 0.0
            val = float(opp_counts[idx])
            if n_opponents <= 0:
                return 0.0
            return max(0.0, min(1.0, val / n_opponents))
        s = 0.5
        for i in range(past_rounds):
            s = self.smoothing_beta * s + self.smoothing_alpha * frac_at(i)
        p_prev = frac_at(past_rounds - 1)
        p_prevprev = frac_at(past_rounds - 2)
        trend = p_prev - p_prevprev if past_rounds >= 2 else 0.0
        last_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else True
        prev_action = bool(history.my_actions[-2]) if len(history.my_actions) > 1 else last_action
        if n_players == 2:
            if t >= max(1, n_rounds - 1):
                if past_rounds >= 2 and frac_at(past_rounds - 1) >= 1.0 and (frac_at(past_rounds - 2) >= 1.0):
                    return Action.C
                return Action.D
            if t == 2:
                return Action.C if p_prev >= self.theta_high else Action.D
            if past_rounds >= 1 and p_prev >= 1.0:
                return Action.C
            if past_rounds >= 1 and p_prev <= 0.0:
                return Action.D
            if past_rounds >= 2 and frac_at(past_rounds - 1) >= 1.0 and (frac_at(past_rounds - 2) >= 1.0):
                return Action.C
            if past_rounds >= 2 and frac_at(past_rounds - 1) <= 0.0 and (frac_at(past_rounds - 2) <= 0.0):
                return Action.D
            if past_rounds >= 1:
                if abs(p_prev - s) <= 0.1:
                    return Action.C if last_action else Action.D
                if p_prev - p_prevprev >= 0.2 and s >= 0.4:
                    return Action.C
                if p_prevprev - p_prev >= 0.2:
                    return Action.D
            return Action.C if s >= self.theta and trend >= -0.15 else Action.D
        if n_rounds == 2:
            return Action.C if p_prev >= self.theta_high else Action.D
        if t == n_rounds - 1:
            return Action.C if s >= self.theta_high else Action.D
        if t == n_rounds:
            if past_rounds >= 1 and p_prev >= self.theta_high and (trend >= 0.0):
                return Action.C
            return Action.D
        if past_rounds >= 1:
            if p_prev <= 0.0:
                return Action.D
            if p_prev >= 1.0:
                return Action.C
            if past_rounds >= 2:
                jump = p_prev - p_prevprev
                if jump >= 0.2 and s >= 0.4:
                    return Action.C
                if jump <= -0.2:
                    return Action.D
                if abs(p_prev - s) <= 0.1:
                    return Action.C if last_action else Action.D
        if t <= n_rounds - 2:
            if s >= self.theta and trend >= -0.15:
                return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_63(BaseStrategy):
    """
    Conservative public-goods strategy:
    - Defect initially
    - Cooperate only after sustained, stable cooperation by opponents
    - Never cooperate in the final two rounds unless unanimity has already been
      established and sustained
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        if self.k <= 1.0 or self.n < 2:
            self.threshold = 0
            self.always_defect = True
        else:
            raw_t = math.ceil(self.n / self.k) - 1
            self.threshold = max(0, min(self.n - 1, int(raw_t)))
            self.always_defect = False

    def _derive_state(self, history: PlayerHistory):
        """
        Reconstruct smoothed signal and streak from the observed history.
        Returns (s_t, streak_t), where these are the values available
        for deciding the next move.
        """
        s = 0
        streak = 0
        opp = history.opponent_cooperators
        rounds_played = history.round_number
        for t in range(1, rounds_played + 1):
            m_prev = int(opp[t - 1])
            s = math.floor((2 * s + m_prev) / 3)
            if m_prev >= self.threshold:
                streak += 1
            else:
                streak = 0
        return (s, streak)

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            return Action.D
        if self.always_defect:
            return Action.D
        rounds_played = history.round_number
        opp = history.opponent_cooperators
        if rounds_played >= self.r - 2:
            if rounds_played < 2:
                return Action.D
            if int(opp[-1]) != self.n - 1 or int(opp[-2]) != self.n - 1:
                return Action.D
        if self.threshold == 0:
            if rounds_played < 2:
                return Action.D
            if int(opp[-1]) == self.n - 1 and int(opp[-2]) == self.n - 1:
                return Action.C
            return Action.D
        s_t, streak_t = self._derive_state(history)
        m_prev = int(opp[-1])
        if m_prev >= self.threshold and streak_t >= 2 and (s_t >= self.threshold):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_64(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Starts with defection.
    - Uses a 3-state exploit/testing/commitment machine based on observed opponent cooperation.
    - Escalates to permanent defection after two consecutive zero-cooperation rounds.
    - Can enter a strong cooperation mode after two consecutive full-cooperation rounds, but exits if cooperation weakens.
    - Applies conservative endgame rules in the final two rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._state = 0
        self._permanent_defect = False
        self._permanent_cooperate = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        opps = history.opponent_cooperators
        t_played = history.round_number
        if t_played == 0:
            self._state = 0
            self._permanent_defect = False
            self._permanent_cooperate = False
            return Action.D
        denom = max(1, n - 1)
        tau = 1.0 - 1.0 / self.game_description.k
        tau_enter = min(1.0, tau + 0.15)
        tau_exit = max(0.0, tau - 0.1)
        rates = [float(x) / denom for x in opps]

        def last_rate(idx_from_end: int) -> float:
            pos = t_played - idx_from_end
            if pos < 0:
                return 0.0
            return rates[pos]
        zero_streak = False
        for i in range(1, len(rates)):
            if rates[i] == 0.0 and rates[i - 1] == 0.0:
                zero_streak = True
                break
        if zero_streak:
            self._permanent_defect = True
            self._permanent_cooperate = False
        coop_trigger_index = -1
        for i in range(1, len(rates)):
            if rates[i] >= 1.0 and rates[i - 1] >= 1.0:
                coop_trigger_index = i
        if coop_trigger_index >= 0:
            weak_after_trigger = any((rate < tau_exit for rate in rates[coop_trigger_index + 1:]))
            self._permanent_cooperate = not weak_after_trigger
            if weak_after_trigger:
                self._permanent_defect = False
        if r > 1 and t_played >= r - 2:
            if t_played >= r - 1:
                prev_rate = last_rate(1)
                return Action.C if prev_rate >= tau_enter else Action.D
            if t_played >= 2:
                return Action.C if last_rate(1) >= tau_enter and last_rate(2) >= tau_enter else Action.D
            return Action.D
        if self._permanent_defect:
            self._state = 0
            return Action.D
        if self._permanent_cooperate:
            recent_weak = any((rate < tau_exit for rate in rates[coop_trigger_index + 1:])) if coop_trigger_index >= 0 else False
            if not recent_weak:
                self._state = 2
                return Action.C
            self._permanent_cooperate = False
        state = 0
        for round_t in range(2, t_played + 1):
            r_prev = rates[round_t - 2]
            r_prev2 = rates[round_t - 3] if round_t >= 3 else 0.0
            two_round_avg = (r_prev + r_prev2) / 2.0 if round_t >= 3 else r_prev
            if state == 0:
                if round_t >= 3 and r_prev >= tau_enter and (r_prev2 >= tau_enter):
                    state = 1
                else:
                    state = 0
            elif state == 1:
                if r_prev >= tau_enter:
                    state = 2
                else:
                    state = 0
            elif two_round_avg >= tau_exit:
                state = 2
            else:
                state = 0
        self._state = state
        last_r = last_rate(1)
        prev_r = last_rate(2)
        two_round_avg_now = (last_r + prev_r) / 2.0 if t_played >= 2 else last_r
        if state == 0:
            if t_played + 1 >= 3 and last_r >= tau_enter and (prev_r >= tau_enter):
                self._state = 1
                return Action.C
            return Action.D
        if state == 1:
            if last_r >= tau_enter:
                self._state = 2
                return Action.C
            self._state = 0
            return Action.D
        if two_round_avg_now >= tau_exit:
            return Action.C
        self._state = 0
        return Action.D

class Strategy_INDIVIDUALISTIC_65(BaseStrategy):
    """
    Cooperate only after observing at least two consecutive recent rounds
    with opponent cooperation meeting or exceeding the threshold
    T = ceil((n - 1) / k). Never cooperate on the first or last round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = getattr(game_description, 'n_players', 2)
        k = getattr(game_description, 'k', 1.0)
        if k <= 0:
            self.threshold = n
        else:
            self.threshold = math.ceil(max(0, n - 1) / k)
        self.streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        total_rounds = getattr(self.game_description, 'n_rounds', 0)
        if round_number == 0:
            self.streak = 0
            return Action.D
        if total_rounds > 0 and round_number >= total_rounds - 1:
            self.streak = 0
            return Action.D
        streak = 0
        opponents = history.opponent_cooperators
        for x in opponents[::-1]:
            if x >= self.threshold:
                streak += 1
            else:
                break
        self.streak = streak
        return Action.C if self.streak >= 2 else Action.D

class Strategy_INDIVIDUALISTIC_66(BaseStrategy):
    """
    Start with defection. Cooperate only after sustained, above-threshold
    cooperation from opponents, and defect immediately when support weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_opponents = max(0, self.n_players - 1)
        k = float(game_description.k)
        self.threshold = 1.0 - 1.0 / k if k != 0 else 1.0
        self.min_cooperators = math.ceil(self.n_opponents * self.threshold) if self.n_opponents > 0 else 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number < 2:
            return Action.D
        opp_counts = history.opponent_cooperators
        if len(opp_counts) < 2:
            return Action.D
        latest_h = int(opp_counts[-1])
        prev_h = int(opp_counts[-2])
        if self.n_opponents <= 0:
            return Action.D
        latest_rho = latest_h / self.n_opponents
        prev_rho = prev_h / self.n_opponents
        total_rho = 0.0
        for h in opp_counts:
            total_rho += int(h) / self.n_opponents
        avg_rho = total_rho / len(opp_counts) if len(opp_counts) > 0 else 0.0
        if latest_rho > self.threshold and avg_rho > self.threshold and (latest_rho >= prev_rho) and (latest_h >= self.min_cooperators):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_67(BaseStrategy):
    """
    Defect by default, cooperate only after sustained broad cooperation,
    and immediately revert to defection after a cooperation drop.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.q_high = 0.75
        self.q_low = 0.5
        self.window_size = max(2, math.ceil(math.sqrt(max(1, game_description.n_rounds))))

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        t = history.round_number
        if t == 0:
            return Action.D
        if t >= max(0, n_rounds - 2):
            return Action.D
        n_opponents = max(1, n_players - 1)
        past_rounds = t
        recent_len = min(self.window_size, past_rounds)
        if recent_len <= 0:
            return Action.D
        start = past_rounds - recent_len
        opp_counts = history.opponent_cooperators[start:past_rounds]
        if len(opp_counts) == 0:
            return Action.D
        x_vals = np.asarray(opp_counts, dtype=float) / float(n_opponents)
        A = float(np.mean(x_vals))
        B = float(np.min(x_vals))
        last_x = float(x_vals[-1])
        last_my_action = bool(history.my_actions[-1])
        if last_my_action and last_x < self.q_low:
            return Action.D
        if t == 1 and last_x == 1.0:
            return Action.C
        if A >= self.q_high and B >= self.q_low:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_68(BaseStrategy):
    """
    Threshold-based conditional cooperator for the repeated N-player Public Goods Game.

    - Cooperate in round 1.
    - In intermediate rounds, cooperate only if recent opponent cooperation has been
      consistently high over a short memory window.
    - In the final round, require a stricter streak of recent cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        r = int(game_description.n_rounds)
        k = float(game_description.k)
        self.n_players = n
        self.n_rounds = r
        self.k = k
        denom = 2 * (n - 1)
        if denom <= 0:
            theta = 1.0
        else:
            theta = 0.5 + (n - k) / denom
        self.theta = min(1.0, max(0.5, float(theta)))
        self.memory_window = min(3, max(0, r - 1))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = self.n_rounds
        theta = self.theta
        if t == 0:
            return Action.C
        n_opponents = max(0, self.n_players - 1)
        if n_opponents <= 0:
            return Action.D
        is_final_round = t == r - 1
        if len(history.opponent_cooperators) == 0:
            return Action.D
        q_values = history.opponent_cooperators.astype(np.float64) / float(n_opponents)
        if is_final_round:
            needed = min(3, len(q_values))
            if needed <= 0:
                return Action.D
            recent = q_values[-needed:]
            return Action.C if np.all(recent >= theta) else Action.D
        window = min(self.memory_window, len(q_values))
        if window <= 0:
            return Action.D
        recent = q_values[-window:]
        avg_q = float(np.mean(recent)) if window > 0 else 0.0
        last_q = float(q_values[-1])
        if avg_q >= theta and last_q >= theta:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_69(BaseStrategy):
    """
    Self-protective public goods strategy:
    - Defect on the first and last rounds
    - Cooperate only after sustained high cooperation
    - Enter cooldown after low-cooperation signals
    - Enter a longer defect lock if a prior cooperation is followed by a sharp drop
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.cooldown = 0
        self.locked_defect = False

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        n_opponents = max(0, n - 1)
        high_threshold = math.ceil(0.7 * n_opponents)
        low_threshold = math.floor(0.3 * n_opponents)
        mid_threshold = math.ceil(0.5 * n_opponents)
        round_number = history.round_number
        last_round_index = self.game_description.n_rounds - 1
        if round_number == 0:
            self.cooldown = 0
            self.locked_defect = False
            return Action.D
        if round_number >= last_round_index:
            return Action.D
        recent_counts = history.opponent_cooperators
        x_last = int(recent_counts[-1]) if len(recent_counts) > 0 else 0
        start_idx = max(0, len(recent_counts) - 3)
        recent_window = recent_counts[start_idx:]
        x_avg = float(np.mean(recent_window)) if len(recent_window) > 0 else 0.0
        if self.cooldown > 0:
            self.cooldown -= 1
            return Action.D
        if len(history.my_actions) > 0 and bool(history.my_actions[-1]) and (x_last < mid_threshold):
            self.locked_defect = True
        if self.locked_defect:
            if len(recent_counts) >= 2:
                prev_x = int(recent_counts[-2])
                if prev_x >= high_threshold and x_last >= high_threshold:
                    self.locked_defect = False
                else:
                    return Action.D
            else:
                return Action.D
        if x_last <= low_threshold or (len(recent_counts) >= 2 and int(recent_counts[-2]) <= low_threshold):
            self.cooldown = 2
            return Action.D
        if x_last >= high_threshold and x_avg >= high_threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_70(BaseStrategy):
    """
    Protective threshold strategy with an exponentially weighted estimate of opponent cooperation.
    Defects in the first two rounds, near the end, and after any detected drop below the lower threshold.
    Cooperates only after sustained observed cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        k = float(game_description.k)
        self.H = 1.0 - 1.0 / k if k != 0 else 1.0
        self.L = max(0.0, self.H - 1.0 / (2.0 * k)) if k != 0 else 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        n_players = int(self.game_description.n_players)
        n_opponents = max(1, n_players - 1)
        t = history.round_number
        if t < 2 or t >= n_rounds - 2:
            return Action.D
        opp = history.opponent_cooperators
        rounds_observed = len(opp)
        if rounds_observed == 0:
            return Action.D
        p_values = []
        for x in opp:
            p_values.append(float(x) / float(n_opponents))
        s_values = []
        s_prev = 0.0
        for idx, p in enumerate(p_values):
            if idx == 0:
                s_prev = p
            else:
                s_prev = 0.5 * p + 0.5 * s_prev
            s_values.append(s_prev)
        reset_active = False
        high_streak = 0
        for p in p_values:
            if p < self.L:
                reset_active = True
                high_streak = 0
            elif p >= self.H:
                if reset_active:
                    high_streak += 1
                    if high_streak >= 2:
                        reset_active = False
                        high_streak = 0
            elif reset_active:
                high_streak = 0
        if reset_active:
            return Action.D
        if rounds_observed < 2:
            return Action.D
        p_prev = p_values[-1]
        p_prev2 = p_values[-2]
        s_prev = s_values[-1]
        if s_prev >= self.H and p_prev >= self.H and (rounds_observed < 3 or p_prev2 >= self.L):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_71(BaseStrategy):
    """
    Pure defection strategy for the repeated N-player Public Goods Game.

    - Round 1: defect.
    - Every later round: defect.
    - Last round: defect.
    - Ignores opponent identities and never rewards cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.k = float(getattr(game_description, 'k', 0.0) or 0.0)

    def __call__(self, history: PlayerHistory) -> Action:
        _ = history
        return Action.D

class Strategy_INDIVIDUALISTIC_72(BaseStrategy):
    """
    Threshold-based conditional cooperator for the repeated public goods game.

    - Cooperate in the first round.
    - Defect in the final round.
    - In intermediate rounds, cooperate only if the previous round
      and (when available) the round before that both had at least the
      threshold number of opponent cooperators.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        if k <= 0.0:
            self.threshold = math.inf
        else:
            self.threshold = math.ceil((n_players - 1) / k)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        n_rounds = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        if round_number == 0:
            return Action.C
        if n_rounds > 0 and round_number >= n_rounds - 1:
            return Action.D
        last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
        if round_number == 1:
            return Action.C if last_count >= self.threshold else Action.D
        prev_count = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else 0
        return Action.C if last_count >= self.threshold and prev_count >= self.threshold else Action.D

class Strategy_INDIVIDUALISTIC_73(BaseStrategy):
    """
    Selective, history-based cooperation strategy for the repeated public goods game.

    Defaults to defection, and cooperates only when recent cooperation is already
    high enough to make matching it locally beneficial.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = getattr(game_description, 'n_players', 0)
        k = getattr(game_description, 'k', 0.0)
        if k and k > 0:
            self.threshold = math.ceil(n / k - 1.0)
        else:
            self.threshold = math.inf
        self.n_rounds = getattr(game_description, 'n_rounds', 0)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = self.n_rounds
        threshold = self.threshold
        if round_number == 0:
            return Action.D
        recent = history.opponent_cooperators
        if len(recent) == 0:
            return Action.D
        last_m = int(recent[-1])
        if n_rounds == 2 and round_number == 1:
            return Action.C if last_m >= threshold else Action.D
        if len(recent) >= 2:
            if int(recent[-1]) < threshold and int(recent[-2]) < threshold:
                return Action.D
        window = min(3, len(recent))
        if window > 0:
            H_t = float(np.mean(recent[-window:]))
        else:
            H_t = 0.0
        if round_number < n_rounds - 1:
            if H_t >= threshold and last_m >= H_t:
                return Action.C
            return Action.D
        stable_count = 0
        if len(recent) >= 1 and int(recent[-1]) >= threshold:
            stable_count += 1
        if len(recent) >= 2 and int(recent[-2]) >= threshold:
            stable_count += 1
        if len(recent) >= 3 and int(recent[-3]) >= threshold:
            stable_count += 1
        if H_t >= threshold and last_m >= H_t and (stable_count >= 2):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_74(BaseStrategy):
    """
    Adaptive public-goods strategy that cooperates only when recent and average
    opponent cooperation are sufficiently high, while applying short punishment
    after sustained low cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        n_opponents = max(1, self.n_players - 1)
        self.theta_high = 2.0 / self.k - 1.0 if self.k != 0 else float('inf')
        self.theta_low = max(0.0, self.theta_high - 1.0 / n_opponents)
        self.theta_punish = self.theta_high - 1.0 / (2.0 * n_opponents)
        self.theta_recover = self.theta_high + 1.0 / (2.0 * n_opponents)
        self.punishment_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C if self.k >= 2.0 else Action.D
        if t >= self.n_rounds - 1:
            opp = history.opponent_cooperators
            n_opponents = max(1, self.n_players - 1)
            p_prev = float(opp[-1]) / n_opponents if len(opp) > 0 else 0.0
            avg_prev = float(np.mean(opp / n_opponents)) if len(opp) > 0 else 0.0
            return Action.C if p_prev > self.theta_high and avg_prev > self.theta_high else Action.D
        opp = history.opponent_cooperators
        n_opponents = max(1, self.n_players - 1)
        p_prev = float(opp[-1]) / n_opponents if len(opp) > 0 else 0.0
        avg_prev = float(np.mean(opp / n_opponents)) if len(opp) > 0 else 0.0
        low_streak = 0
        for x in reversed(opp):
            p = float(x) / n_opponents
            if p < self.theta_low:
                low_streak += 1
            else:
                break
        if low_streak >= 2:
            self.punishment_remaining = 2
        if self.punishment_remaining > 0:
            self.punishment_remaining -= 1
            return Action.D
        if self.k <= 2.0:
            if p_prev > self.theta_recover and avg_prev > self.theta_high:
                return Action.C
            return Action.D
        if self.k >= self.n_players - 1:
            return Action.D if p_prev < self.theta_low else Action.C
        if p_prev < self.theta_low:
            return Action.D
        if p_prev > self.theta_recover:
            return Action.C
        if avg_prev > self.theta_high:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_75(BaseStrategy):
    """
    Defect initially and in the final round.
    Cooperate only in a non-final round after observing two consecutive
    unanimous opponent-cooperation rounds immediately before it.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number < 2:
            return Action.D
        n_opponents = max(0, self.n_players - 1)
        unanimous_count = n_opponents
        if history.opponent_cooperators[-1] == unanimous_count and history.opponent_cooperators[-2] == unanimous_count:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_76(BaseStrategy):
    """
    Two-state public goods strategy with threshold-based reward/withdraw behavior,
    cooldown after a downturn, and mandatory defection in the first and last rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        k = float(game_description.k)
        n = int(game_description.n_players)
        if k > 0:
            threshold = math.ceil(n / k) - 1
        else:
            threshold = 0
        self.threshold = max(0, int(threshold))
        self.state = 'WITHDRAW'
        self.cooldown_remaining = 0
        self.consecutive_high = 0
        self.processed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(self.game_description.n_rounds)
        round_number = int(history.round_number)
        while self.processed_rounds < round_number:
            q = int(history.opponent_cooperators[self.processed_rounds])
            if q >= self.threshold:
                self.consecutive_high += 1
            else:
                self.consecutive_high = 0
            if self.consecutive_high >= 2:
                self.state = 'REWARD'
                self.cooldown_remaining = 0
            elif q <= self.threshold - 1:
                if self.state == 'REWARD':
                    self.cooldown_remaining = 2
                self.state = 'WITHDRAW'
            else:
                pass
            self.processed_rounds += 1
        if round_number == 0:
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        if n_rounds == 2:
            return Action.D
        if self.cooldown_remaining > 0:
            self.cooldown_remaining -= 1
            return Action.D
        if self.state == 'REWARD':
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_77(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Defects by default.
    - Cooperates only after sustained, stable cooperation.
    - Uses an exponentially weighted cooperation score and short-memory threshold shifts.
    - Includes a cautious recovery test after defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.lam = 0.7
        self.base_threshold = 0.65 if game_description.n_players <= 4 else 0.7
        self.threshold = self.base_threshold
        self.s = 0.0
        self.q_history = []
        self.processed_rounds = 0
        self.cooldown = 0
        self.n = game_description.n_players
        self.r = game_description.n_rounds
        self.n_opponents = max(0, self.n - 1)
        self.recovery_min_opponents = math.ceil(self.n_opponents / 2) if self.n_opponents > 0 else 0

    def _safe_q(self, history: PlayerHistory, idx: int) -> float:
        if idx < 0:
            return 0.0
        if idx >= len(history.opponent_cooperators):
            return 0.0
        m = history.opponent_cooperators[idx]
        if m is None:
            m = 0
        try:
            m_int = int(m)
        except Exception:
            m_int = 0
        if self.n_opponents <= 0:
            return 0.0
        if m_int < 0:
            m_int = 0
        if m_int > self.n_opponents:
            m_int = self.n_opponents
        return m_int / self.n_opponents

    def _update_state(self, history: PlayerHistory) -> None:
        current_round = history.round_number
        while self.processed_rounds < current_round:
            idx = self.processed_rounds
            q = self._safe_q(history, idx)
            prev_q = self.q_history[-1] if self.q_history else 0.0
            self.q_history.append(q)
            self.s = self.lam * self.s + (1.0 - self.lam) * q
            if len(self.q_history) >= 2:
                q_tm1 = self.q_history[-1]
                q_tm2 = self.q_history[-2]
                if q_tm1 >= 0.75 and q_tm2 >= 0.75:
                    self.threshold -= 0.05
                if q_tm1 <= 0.25 and q_tm2 <= 0.25:
                    self.threshold += 0.1
                self.threshold = max(0.0, min(1.0, self.threshold))
            if len(history.my_actions) > idx:
                my_prev_action = bool(history.my_actions[idx])
                if my_prev_action:
                    if len(self.q_history) >= 2:
                        if self.q_history[-2] - self.q_history[-1] > 0.2:
                            self.cooldown = max(self.cooldown, 2)
            self.processed_rounds += 1

    def __call__(self, history: PlayerHistory) -> Action:
        self._update_state(history)
        t = history.round_number
        if t == 0:
            return Action.D
        if self.r == 2:
            return Action.D
        if t == self.r - 1:
            return Action.D
        if self.n == 2:
            if self.cooldown > 0:
                self.cooldown -= 1
                return Action.D
            prev_q = self.q_history[-1] if self.q_history else 0.0
            if prev_q >= 1.0:
                return Action.C
            return Action.D
        if self.cooldown > 0:
            self.cooldown -= 1
            return Action.D
        prev_my_action = bool(history.my_actions[-1]) if len(history.my_actions) > 0 else False
        prev_m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if prev_m < 0:
            prev_m = 0
        if prev_m > self.n_opponents:
            prev_m = self.n_opponents
        if not prev_my_action and prev_m >= self.recovery_min_opponents:
            return Action.C
        if self.s >= self.threshold:
            if t >= 3:
                q_bar = float(np.mean(self.q_history)) if self.q_history else 0.0
                q_tm2 = self.q_history[-2] if len(self.q_history) >= 2 else 0.0
                if q_bar - q_tm2 >= -0.15:
                    return Action.C
                return Action.D
            else:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_78(BaseStrategy):
    """
    Default-defection strategy that cooperates only after sustained high
    cooperation by opponents, never cooperates in the first or final round,
    and uses a short cooldown after drops in cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.T = math.ceil((self.n - 1) / 2) if self.n >= 2 else 0
        self._last_action = Action.D
        self._cooldown = 0
        self._processed_rounds = 0

    def _sync_state(self, history: PlayerHistory) -> None:
        target = history.round_number
        start = self._processed_rounds
        if start > target:
            start = 0
            self._last_action = Action.D
            self._cooldown = 0
            self._processed_rounds = 0
        for idx in range(start, target):
            if idx < len(history.my_actions):
                self._last_action = Action.C if bool(history.my_actions[idx]) else Action.D
            else:
                self._last_action = Action.D
            if idx < len(history.opponent_cooperators):
                x_t = int(history.opponent_cooperators[idx])
                if x_t == 0:
                    self._cooldown = 2
                elif x_t < self.T:
                    self._cooldown = 1
            self._processed_rounds = idx + 1

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number == 0:
            self._last_action = Action.D
            self._cooldown = 0
            self._processed_rounds = 0
            return Action.D
        self._sync_state(history)
        if history.round_number >= self.r - 1:
            return Action.D
        if self._cooldown > 0:
            self._cooldown -= 1
            return Action.D
        m = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        a = int(history.opponent_cooperators[-2]) if history.round_number >= 2 and len(history.opponent_cooperators) >= 2 else 0
        if m >= self.T and a >= self.T and (self._last_action == Action.C or m == self.n - 1):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_79(BaseStrategy):
    """
    Always defect strategy for the repeated N-player Public Goods Game.

    This strategy plays D in every round, while keeping a simple history of
    observed opponent cooperation counts for bookkeeping only.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.observed_opponent_cooperations = []

    def __call__(self, history: PlayerHistory) -> Action:
        if history.round_number > 0 and len(history.opponent_cooperators) > 0:
            self.observed_opponent_cooperations.append(int(history.opponent_cooperators[-1]))
        return Action.D

class Strategy_INDIVIDUALISTIC_80(BaseStrategy):
    """
    Always defect in every round, while recording observed opponent cooperation
    counts for internal tracking only.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.observed_opponent_cooperators = []

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number > 0:
            last_opponent_cooperators = int(history.opponent_cooperators[-1])
            self.observed_opponent_cooperators.append(last_opponent_cooperators)
        return Action.D

class Strategy_INDIVIDUALISTIC_81(BaseStrategy):
    """
    Defect by default; cooperate only after two consecutive high-cooperation
    observations from opponents, and never in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.n_opponents = max(0, self.n_players - 1)
        self.high_threshold = math.ceil(0.75 * self.n_opponents)
        self.low_threshold = math.floor(0.25 * self.n_opponents)
        self.high_streak = 0
        self.low_streak = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number >= max(0, self.n_rounds - 1):
            return Action.D
        if round_number == 0:
            return Action.D
        if round_number > self._last_processed_round:
            observed = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            if observed >= self.high_threshold:
                self.high_streak += 1
            else:
                self.high_streak = 0
            if observed <= self.low_threshold:
                self.low_streak += 1
            else:
                self.low_streak = 0
            self._last_processed_round = round_number
        if self.high_streak >= 2 and self.low_streak == 0:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_82(BaseStrategy):
    """
    Conditional self-interested threshold strategy with exploit/test states.
    Cooperates only when opponent cooperation is sufficiently high, stable,
    and near the expected threshold; otherwise defects.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.k = float(game_description.k)
        self.alpha = 0.7
        self.h = 0.0
        self.state = 'test'
        self.last_m = None
        self.prev_m = None
        self.threshold = 1.0 / self.k if self.k > 0 else 1.0
        self.coop_needed = int(math.ceil((self.n - 1) * self.threshold))
        self.endgame_len = max(1, int(math.ceil(math.log2(self.r)))) if self.r > 1 else 1
        self.test_period = max(2, int(math.floor(self.n / 2)))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        last_m = int(opp[-1]) if len(opp) > 0 else 0
        prev_m = int(opp[-2]) if len(opp) > 1 else None
        if self.last_m is None and len(opp) > 0:
            h = 0.0
            for m in opp:
                denom = max(1, self.n - 1)
                h = self.alpha * h + (1.0 - self.alpha) * (float(m) / denom)
            self.h = h
        elif len(opp) > 0:
            denom = max(1, self.n - 1)
            self.h = self.alpha * self.h + (1.0 - self.alpha) * (float(last_m) / denom)
        self.prev_m = prev_m
        self.last_m = last_m
        in_endgame = t >= max(0, self.r - self.endgame_len)
        two_zero_rounds = len(opp) >= 2 and int(opp[-1]) == 0 and (int(opp[-2]) == 0)
        if two_zero_rounds:
            self.state = 'exploit'
        if self.state == 'exploit':
            if last_m >= self.coop_needed:
                self.state = 'test'
            else:
                return Action.D
        if t == self.r - 1:
            if len(opp) >= 2 and int(opp[-1]) >= self.coop_needed and (int(opp[-2]) >= self.coop_needed):
                return Action.C
            return Action.D
        if in_endgame:
            if last_m >= self.coop_needed and self.h >= self.threshold:
                return Action.C
            return Action.D
        if self.h >= self.threshold and last_m >= self.coop_needed:
            return Action.C
        near_threshold = self.threshold - 0.1 <= self.h <= self.threshold + 0.1
        last_round_met_threshold = last_m >= self.coop_needed
        mixed_last_two = len(opp) >= 2 and int(opp[-1]) != int(opp[-2])
        if mixed_last_two and near_threshold and last_round_met_threshold:
            if t % self.test_period == 0:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_83(BaseStrategy):
    """
    Defect by default, and cooperate only after a sustained, perfectly stable
    sequence of opponent cooperation. Never cooperate in the first two rounds
    or the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.n_opponents = max(0, self.n_players - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number < 2:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        opp = history.opponent_cooperators
        if opp is None or len(opp) < 2:
            return Action.D
        if int(opp[-1]) != self.n_opponents or int(opp[-2]) != self.n_opponents:
            return Action.D
        if len(opp) >= 3:
            recent = opp[-3:]
        else:
            recent = opp
        if self.n_opponents <= 0:
            return Action.D
        if float(np.mean(recent) / self.n_opponents) != 1.0:
            return Action.D
        if len(history.my_actions) == 0 or bool(history.my_actions[-1]) is True:
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_84(BaseStrategy):
    """
    Public goods strategy with trust score and defensive/cooperative modes.
    Defects on the first and final rounds, builds trust from sustained cooperation,
    and enters defensive mode after low cooperation until two consecutive strong
    cooperative rounds are observed.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.s = 0
        self.defensive = True
        self.previous_q = None

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        n_opponents = max(1, n - 1)
        round_number = history.round_number
        if round_number == 0:
            self.previous_q = None
            self.defensive = True
            return Action.D
        if round_number == self.game_description.n_rounds - 1:
            q_last = float(history.opponent_cooperators[-1]) / n_opponents if round_number > 0 else 0.0
            self.previous_q = q_last
            return Action.D
        q = float(history.opponent_cooperators[-1]) / n_opponents
        if q >= 2.0 / 3.0:
            self.s = min(2, self.s + 1)
        elif q <= 1.0 / 3.0:
            self.s = max(-2, self.s - 2)
            self.defensive = True
        if q >= 2.0 / 3.0 and self.previous_q is not None and (self.previous_q >= 2.0 / 3.0):
            self.defensive = False
        if not self.defensive and self.s >= 1 and (q >= 0.5):
            action = Action.C
        else:
            action = Action.D
        self.previous_q = q
        return action

class Strategy_INDIVIDUALISTIC_85(BaseStrategy):
    """
    Conditional cooperator for the repeated N-player Public Goods Game.

    - Round 1: defect
    - Middle rounds: cooperate iff the previous round's cooperating-opponent count
      meets the threshold ceil(n / k) - 1
    - Final round: defect
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = getattr(game_description, 'n_players', 0)
        k = getattr(game_description, 'k', 0.0)
        if isinstance(n, int) and n >= 2 and isinstance(k, (int, float)) and (k > 0):
            self.threshold_total = math.ceil(n / k)
        else:
            self.threshold_total = 0
        self.required_opponents = max(0, self.threshold_total - 1)
        self.last_observed_opponents = None

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        round_number = getattr(history, 'round_number', 0)
        if round_number == 0:
            self.last_observed_opponents = None
            return Action.D
        if isinstance(n_rounds, int) and n_rounds > 1 and (round_number >= n_rounds - 1):
            try:
                self.last_observed_opponents = int(history.opponent_cooperators[-1])
            except Exception:
                self.last_observed_opponents = None
            return Action.D
        observed = None
        try:
            observed = history.opponent_cooperators[-1]
            if observed is None:
                observed = None
            else:
                observed = int(observed)
                if observed < 0:
                    observed = None
        except Exception:
            observed = None
        self.last_observed_opponents = observed
        if observed is None:
            return Action.D
        if observed >= self.required_opponents:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_86(BaseStrategy):
    """
    Guarded threshold-and-exit policy for the repeated N-player Public Goods Game.

    - Round 0: defect.
    - Enter cooperation only after sustained strong cooperation by opponents.
    - Exit cooperation immediately when cooperation weakens.
    - Always defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        h = max(0, n - 1)
        self.enter_threshold = math.ceil(0.75 * h)
        self.exit_threshold = math.floor(0.5 * h)
        self.mode = Action.D
        self.cooldown = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = int(self.game_description.n_rounds)
        if round_number >= n_rounds - 1:
            self.mode = Action.D
            return Action.D
        if round_number == 0:
            self.mode = Action.D
            return Action.D
        last_x = int(history.opponent_cooperators[-1])
        if last_x <= self.exit_threshold - 1:
            self.cooldown = max(self.cooldown, 2)
        if self.cooldown > 0:
            self.cooldown -= 1
            self.mode = Action.D
            return Action.D
        if self.mode == Action.D:
            if last_x >= self.enter_threshold:
                if round_number == 1:
                    self.mode = Action.C
                else:
                    prev_x = int(history.opponent_cooperators[-2])
                    if prev_x >= self.enter_threshold:
                        self.mode = Action.C
            return self.mode
        if last_x > self.exit_threshold:
            self.mode = Action.C
        else:
            self.mode = Action.D
        return self.mode

class Strategy_INDIVIDUALISTIC_87(BaseStrategy):
    """
    Always defects in every round, regardless of history or game state.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        _ = getattr(history, 'round_number', 0)
        return Action.D

class Strategy_INDIVIDUALISTIC_88(BaseStrategy):
    """
    Selective cooperation strategy for the repeated public goods game.

    - Cooperate in round 1.
    - Cooperate in intermediate rounds only after sustained high cooperation
      by opponents in the previous rounds.
    - Defect immediately after any clear drop in cooperation and remain
      defecting until two consecutive high-cooperation rounds are observed.
    - Always defect in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        self.high_threshold = math.ceil(2 * (n - 1) / 3)
        self.low_threshold = math.ceil((n - 1) / 2)

    def _is_in_unstable_mode(self, history: PlayerHistory) -> bool:
        """
        Determine whether the optional tightening rule currently forces defection.
        A low-cooperation round triggers defection until two consecutive rounds
        with opponent cooperation >= high_threshold have occurred.
        """
        coop = history.opponent_cooperators
        if len(coop) == 0:
            return False
        last_low = -1
        for idx in range(len(coop) - 1, -1, -1):
            if int(coop[idx]) < self.low_threshold:
                last_low = idx
                break
        if last_low == -1:
            return False
        consecutive_high = 0
        for idx in range(len(coop) - 1, last_low, -1):
            if int(coop[idx]) >= self.high_threshold:
                consecutive_high += 1
            else:
                break
        return consecutive_high < 2

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        total_rounds = int(self.game_description.n_rounds)
        if round_number == 0:
            return Action.C
        if round_number >= total_rounds - 1:
            return Action.D
        if self._is_in_unstable_mode(history):
            return Action.D
        if round_number == 1:
            return Action.C if int(history.opponent_cooperators[-1]) >= self.high_threshold else Action.D
        if int(history.opponent_cooperators[-1]) >= self.high_threshold and int(history.opponent_cooperators[-2]) >= self.high_threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_89(BaseStrategy):
    """
    Threshold-and-probe public goods strategy with guarded start and final-round defection.
    Cooperate only when cooperation is sufficiently high and stable/rising, with rare probe
    cooperations when the group is just below the threshold after sustained defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        if k > 0.0:
            self.threshold = max(1, int(math.ceil((n - 1) / k)))
        else:
            self.threshold = max(1, n - 1)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if self.n_rounds > 0 and t >= self.n_rounds - 1:
            return Action.D
        if t == 0:
            return Action.D
        h_prev = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        if h_prev <= 0:
            return Action.D
        if t >= 3:
            last_three = history.my_actions[-3:]
            if not bool(last_three[0]) and (not bool(last_three[1])) and (not bool(last_three[2])):
                if h_prev == self.threshold - 1:
                    return Action.C
        if h_prev >= self.threshold:
            if t == 1:
                return Action.C
            h_prev2 = int(history.opponent_cooperators[-2]) if len(history.opponent_cooperators) >= 2 else 0
            if h_prev >= h_prev2:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_90(BaseStrategy):
    """
    Cautious adaptive public-goods strategy:
    - Starts conservatively.
    - Uses an exponentially smoothed estimate of opponent cooperation.
    - Adjusts a private threshold up/down from recent aggregate cooperation.
    - Temporarily defects after repeated low cooperation.
    - Recovers cooperation after repeated high cooperation.
    - Uses a conservative final-round rule.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = max(2, int(game_description.n_players))
        self.r = max(1, int(game_description.n_rounds))
        self.k = float(game_description.k)
        self.q = 0.5
        self.s = 0.5
        self.T = 0.5
        self._processed_rounds = 0
        self._low_streak = 0
        self._high_streak = 0
        self._forced_defect_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        n_opponents = max(1, self.n - 1)
        if round_number == 0:
            self.s = 0.5
            self.T = 0.5
            self._low_streak = 0
            self._high_streak = 0
            self._forced_defect_rounds = 0
            self._processed_rounds = 0
            return Action.C if self.k >= self.n - 1 else Action.D
        while self._processed_rounds < round_number:
            idx = self._processed_rounds
            raw = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            x = raw / n_opponents
            prev_x = None
            if idx - 1 >= 0 and idx - 1 < len(history.opponent_cooperators):
                prev_raw = int(history.opponent_cooperators[idx - 1])
                prev_x = prev_raw / n_opponents
            self.s = 0.7 * self.s + 0.3 * x
            if prev_x is not None:
                if x > prev_x:
                    self.T = max(0.35, self.T - 0.05)
                elif x < prev_x:
                    self.T = min(0.65, self.T + 0.05)
            if x < 0.25:
                self._low_streak += 1
            else:
                self._low_streak = 0
            if x >= 0.5:
                self._high_streak += 1
            else:
                self._high_streak = 0
            if self._low_streak >= 2:
                self._forced_defect_rounds = 2
                self._low_streak = 0
            if self._high_streak >= 2:
                self._forced_defect_rounds = 0
                self.q = 0.5
                self.T = 0.5
            self._processed_rounds += 1
        if self._forced_defect_rounds > 0:
            self._forced_defect_rounds -= 1
            return Action.D
        if round_number == self.r - 1:
            return Action.C if self.s >= 0.5 else Action.D
        if self.s > self.T:
            return Action.C
        if self.s < self.T:
            return Action.D
        if len(history.opponent_cooperators) >= 2:
            x_last = int(history.opponent_cooperators[-1]) / n_opponents
            x_prev = int(history.opponent_cooperators[-2]) / n_opponents
            if x_last >= self.T and x_prev >= self.T:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_91(BaseStrategy):
    """
    Threshold-based repeated Public Goods strategy with adaptive cooperation,
    conservative endgame defection, and a special case for n=2.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        base = math.ceil(n / k) - 1 if k > 0 else n - 1
        self.initial_threshold = max(0, min(n - 1, base))
        self.tolerance_window = 1
        self.running_threshold = self.initial_threshold
        self.running_estimate = 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        k = float(self.game_description.k)
        round_number = int(history.round_number)
        if round_number == 0:
            self.running_threshold = self.initial_threshold
            self.running_estimate = 0.0
            if n == 2:
                return Action.D
            return Action.C if k > 2 else Action.D

        def compute_threshold(p_hat: float) -> int:
            base = math.ceil(n / k) - 1 if k > 0 else n - 1
            threshold = base
            if p_hat > 0.5:
                threshold += 1
            if p_hat < 0.25:
                threshold -= 1
            return max(0, min(n - 1, threshold))
        threshold = self.initial_threshold
        coop_sum = 0.0
        denom = max(1, n - 1)
        for t in range(1, round_number):
            x_prev = int(history.opponent_cooperators[t - 1])
            p_hat = coop_sum / (t * denom) if t > 0 else 0.0
            threshold = compute_threshold(p_hat)
            my_coop_prev = bool(history.my_actions[t - 1])
            if my_coop_prev and x_prev < threshold:
                threshold = min(n - 1, threshold + 1)
            elif not my_coop_prev and x_prev >= threshold + 1:
                threshold = max(0, threshold - 1)
            coop_sum += x_prev
        p_hat_current = coop_sum / (round_number * denom) if round_number > 0 else 0.0
        threshold = compute_threshold(p_hat_current)
        if round_number == r - 1:
            return Action.D
        if round_number == r - 2:
            return Action.C if history.opponent_cooperators[-1] == n - 1 else Action.D
        if n == 2:
            return Action.C if history.opponent_cooperators[-1] >= 1 else Action.D
        x_prev = int(history.opponent_cooperators[-1])
        return Action.C if x_prev >= threshold else Action.D

class Strategy_INDIVIDUALISTIC_92(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Starts with defection.
    - Tracks a smoothed trust score and cooperation streaks.
    - Cooperates only after sustained high cooperation and sufficient trust,
      but defects immediately in the endgame or after a collapse.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.trust = 0.0
        self.streak_high = 0
        self.streak_low = 0
        self.m = min(3, game_description.n_rounds)
        self.endgame_cutoff = 2

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        if history.round_number == 0:
            return Action.D
        opp_counts = history.opponent_cooperators
        n_opponents = max(1, n - 1)
        trust = 0.0
        streak_high = 0
        streak_low = 0
        coop_rates = []
        ever_all_d = True
        for idx in range(len(opp_counts)):
            x_t = int(opp_counts[idx])
            coop_rate_t = x_t / n_opponents
            coop_rates.append(coop_rate_t)
            if x_t > 0:
                ever_all_d = False
            trust = 0.6 * trust + 0.4 * coop_rate_t
            if coop_rate_t >= 0.75:
                streak_high += 1
                streak_low = 0
            elif coop_rate_t <= 0.4:
                streak_low += 1
                streak_high = 0
        if ever_all_d:
            return Action.D
        current_round_index = history.round_number
        rounds_remaining_after_this = r - current_round_index
        if rounds_remaining_after_this <= self.endgame_cutoff:
            return Action.D
        if streak_low >= 2:
            return Action.D
        if streak_high >= 2 and trust >= 0.7:
            return Action.C
        if len(coop_rates) >= 1:
            window = coop_rates[-self.m:]
            avg_recent = float(np.mean(window)) if len(window) > 0 else 0.0
            recent_stable = False
            if len(coop_rates) >= 2:
                recent_drop = coop_rates[-2] - coop_rates[-1]
                recent_stable = recent_drop <= 0.2
            else:
                recent_stable = False
            if avg_recent >= 0.8 and recent_stable:
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_93(BaseStrategy):
    """
    Start with defection, then only test cooperation after observing sustained
    full cooperation from the other players. Continue cooperating only while
    the others remain fully cooperative; otherwise revert to permanent defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'defect'
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = max(2, int(getattr(self.game_description, 'n_players', 2)))
        current_round = int(history.round_number)
        rounds_left_after_this = int(getattr(self.game_description, 'n_rounds', 0)) - current_round - 1
        if current_round <= 0:
            return Action.D
        if rounds_left_after_this <= 0:
            return Action.D
        opp = history.opponent_cooperators
        if len(opp) == 0:
            return Action.D
        full_count = n - 1
        x_prev = int(opp[-1])
        my_actions = history.my_actions
        if len(my_actions) == 0:
            cooldown = math.inf
        else:
            coop_indices = np.where(my_actions.astype(bool))[0]
            if len(coop_indices) == 0:
                cooldown = math.inf
            else:
                last_coop_round = int(coop_indices[-1])
                cooldown = current_round - 1 - last_coop_round
        s = 0
        for idx in range(len(opp) - 1, -1, -1):
            if int(opp[idx]) == full_count:
                s += 1
            else:
                break
        if self.mode == 'test':
            if x_prev == full_count:
                return Action.C
            self.mode = 'defect'
            return Action.D
        if cooldown <= 1:
            return Action.D
        min_required_streak = 2 if current_round >= 2 else 1
        if s >= min_required_streak and x_prev == full_count:
            self.mode = 'test'
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_94(BaseStrategy):
    """
    Conservative trust-based public goods strategy.

    - Opens with defection.
    - Defects in the final round.
    - Requires sustained high cooperation before cooperating.
    - Resets trust immediately after low cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_opponents = max(0, game_description.n_players - 1)
        self.high_threshold = math.ceil(0.75 * n_opponents)
        self.low_threshold = math.floor(0.5 * n_opponents)
        self.punish = 0
        self.high_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number == 0:
            self.punish = 0
            self.high_streak = 0
            return Action.D
        if round_number >= n_rounds - 1:
            return Action.D
        opponent_counts = history.opponent_cooperators
        last_x = int(opponent_counts[-1]) if len(opponent_counts) > 0 else 0
        window = opponent_counts[-3:] if len(opponent_counts) > 0 else []
        avg3 = float(np.mean(window)) if len(window) > 0 else 0.0
        if last_x < self.low_threshold:
            self.high_streak = 0
            self.punish = 1
            return Action.D
        if last_x >= self.high_threshold and avg3 >= self.high_threshold:
            self.high_streak += 1
        else:
            self.high_streak = 0
        if self.punish > 0:
            self.punish -= 1
            return Action.D
        if self.high_streak >= 2:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_95(BaseStrategy):
    """
    Adaptive public-goods strategy with threshold tracking, shock cooldown,
    endgame defection, and stability-based cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.k = game_description.k
        self.n_opponents = max(0, self.n_players - 1)
        self.theta_next = max(0.5, 1.0 / self.k) if self.k != 0 else 1.0
        self.cooldown = 0
        self.above_threshold_streak = 0
        self.stable_mode = False
        self.processed_rounds = 0

    def _clamp(self, x: float) -> float:
        return max(0.5, min(1.0, x))

    def _process_observed_round(self, round_index: int, history: PlayerHistory) -> None:
        if round_index < 0 or round_index >= history.round_number:
            return
        opp_count = int(history.opponent_cooperators[round_index])
        if self.n_opponents > 0:
            q_t = opp_count / self.n_opponents
        else:
            q_t = 0.0
        theta_t = self.theta_next
        if q_t >= theta_t:
            self.above_threshold_streak += 1
            if self.above_threshold_streak >= 3:
                self.stable_mode = True
        else:
            self.above_threshold_streak = 0
            self.stable_mode = False
        self.theta_next = self._clamp(0.75 * theta_t + 0.25 * q_t)
        if q_t == 0.0:
            self.cooldown = 2
        elif self.cooldown > 0:
            self.cooldown -= 1

    def __call__(self, history: PlayerHistory) -> Action:
        while self.processed_rounds < history.round_number:
            self._process_observed_round(self.processed_rounds, history)
            self.processed_rounds += 1
        current_round = history.round_number
        if current_round == 0:
            return Action.D
        last_q = 0.0
        if self.n_opponents > 0 and current_round - 1 < len(history.opponent_cooperators):
            last_q = float(history.opponent_cooperators[-1]) / self.n_opponents
        prev_q = None
        if current_round >= 2 and self.n_opponents > 0:
            prev_q = float(history.opponent_cooperators[-2]) / self.n_opponents
        if current_round == self.n_rounds - 1:
            if current_round >= 2 and last_q == 1.0 and (prev_q == 1.0):
                return Action.C
            return Action.D
        if self.cooldown > 0:
            return Action.D
        if current_round >= self.n_rounds - 3 and current_round >= 2:
            if int(history.opponent_cooperators[-1]) - int(history.opponent_cooperators[-2]) <= -2:
                return Action.D
        if self.stable_mode:
            return Action.C
        if last_q >= self.theta_next:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_96(BaseStrategy):
    """
    Threshold-based conditional cooperator for the repeated public goods game.

    Maintains an internal open/closed state:
    - closed: requires two consecutive high-cooperation rounds before cooperating
    - open: cooperates while the observed cooperation level stays at or above threshold
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        denom = k if k > 0 else 1e-12
        self.threshold = int(math.ceil((n - 1) / denom)) if n >= 2 else 0
        self.state = 'closed'
        self.streak = 0
        self._processed_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        r = int(self.game_description.n_rounds)
        t = int(history.round_number)
        while self._processed_rounds < t:
            x = int(history.opponent_cooperators[self._processed_rounds])
            if x >= self.threshold:
                self.streak += 1
            else:
                self.streak = 0
                self.state = 'closed'
            if self.state == 'closed' and self.streak >= 2:
                self.state = 'open'
            self._processed_rounds += 1
        if r <= 2:
            return Action.D
        if r == 3:
            if t == 0:
                return Action.D
            if t == 1:
                return Action.C if int(history.opponent_cooperators[-1]) >= self.threshold else Action.D
            return Action.D
        if t >= r - 2:
            return Action.D
        if t == 0:
            return Action.D
        if t == 1:
            return Action.C if int(history.opponent_cooperators[-1]) >= self.threshold else Action.D
        last_x = int(history.opponent_cooperators[-1])
        if self.state == 'open':
            if last_x >= self.threshold:
                return Action.C
            self.state = 'closed'
            self.streak = 0
            return Action.D
        if self.streak >= 2:
            self.state = 'open'
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_97(BaseStrategy):
    """
    Threshold-and-trend public goods strategy with conservative start,
    conditional cooperation, and lock-in on sustained group behavior.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.best_s = 0
        self.lock_cooperate = False
        self.lock_defect = False
        self._last_seen_rounds = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = max(2, int(self.game_description.n_players))
        r = max(1, int(self.game_description.n_rounds))
        k = float(self.game_description.k)
        rounds_played = int(history.round_number)
        opp = history.opponent_cooperators
        if rounds_played > 0:
            current_best = int(np.max(opp))
            if current_best > self.best_s:
                self.best_s = current_best
            if rounds_played >= 2:
                last_two = opp[-2:]
                if int(last_two[0]) == 0 and int(last_two[1]) == 0:
                    self.lock_defect = True
                    self.lock_cooperate = False
                if int(last_two[0]) == n - 1 and int(last_two[1]) == n - 1:
                    self.lock_cooperate = True
                    self.lock_defect = False
        if self.lock_cooperate:
            return Action.C
        if self.lock_defect:
            return Action.D
        t = rounds_played + 1
        if rounds_played == 0:
            return Action.D
        if t == r:
            return Action.C if int(opp[-1]) == n - 1 else Action.D
        if r <= 2:
            threshold_2 = math.ceil((n - 1) / k) if k > 0 else n
            return Action.C if int(opp[-1]) >= threshold_2 else Action.D
        if t == 2:
            threshold_2 = math.ceil((n - 1) / k) if k > 0 else n
            return Action.C if int(opp[-1]) >= threshold_2 else Action.D
        threshold = math.ceil((n - 1) / k) - 1 if k > 0 else n
        s_prev = int(opp[-1])
        window_t = min(3, rounds_played)
        m_t = float(np.mean(opp[-window_t:])) if window_t > 0 else 0.0
        prev_rounds = rounds_played - 1
        window_prev = min(3, prev_rounds)
        m_prev = float(np.mean(opp[-window_prev - 1:-1])) if window_prev > 0 else 0.0
        trend_t = m_t - m_prev
        if s_prev >= threshold and m_t >= threshold and (trend_t >= 0):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_98(BaseStrategy):
    """
    Self-interested threshold strategy with one-step memory:
    - Defect in the first round
    - Defect in the last round
    - Otherwise cooperate only when recent opponent cooperation is sufficiently high
    - Adapt thresholds based on the average of the last two observed cooperation rates
    - Special case for n=2: cooperate only if the other player cooperated last round
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        n_players = self.n_players
        if round_number == 0:
            return Action.D
        if round_number >= self.n_rounds - 1:
            return Action.D
        if n_players == 2:
            last_opp = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
            return Action.C if last_opp >= 1 else Action.D
        n_opponents = max(n_players - 1, 1)

        def coop_rate(opp_count: int) -> float:
            return opp_count / n_opponents
        p_prev = coop_rate(int(history.opponent_cooperators[-1])) if len(history.opponent_cooperators) > 0 else 0.0
        threshold = 0.5
        if len(history.opponent_cooperators) >= 2:
            p_prev2 = coop_rate(int(history.opponent_cooperators[-2]))
            a_t = (p_prev + p_prev2) / 2.0
            if a_t >= 2.0 / 3.0:
                threshold = 1.0 / 3.0
            elif a_t <= 1.0 / 3.0:
                threshold = 2.0 / 3.0
            else:
                threshold = 0.5
        return Action.C if p_prev >= threshold else Action.D

class Strategy_INDIVIDUALISTIC_99(BaseStrategy):
    """
    Cautious public-goods strategy:
    - Defect in the first round and in the final two rounds.
    - Cooperate only when recent opponent cooperation is sustained, high, and not weakening.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.mode = 'cautious'
        self.ema = 0.0
        self.alpha = 0.8
        self.beta = 0.5

    def __call__(self, history: PlayerHistory) -> Action:
        n = int(self.game_description.n_players)
        r = int(self.game_description.n_rounds)
        current_round = history.round_number + 1
        if current_round == 1 or current_round >= max(1, r - 1):
            return Action.D
        n_opponents = max(0, n - 1)
        ema = 0.0
        p_values = []
        for x in history.opponent_cooperators:
            if n == 2:
                p_t = 1.0 if int(x) > 0 else 0.0
            elif n_opponents > 0:
                p_t = float(x) / float(n_opponents)
            else:
                p_t = 0.0
            p_values.append(p_t)
            ema = 0.7 * ema + 0.3 * p_t
        self.ema = ema
        if not p_values:
            return Action.D
        p_last = p_values[-1]
        trend_ok = True
        if len(p_values) >= 2:
            trend_ok = p_last >= p_values[-2]
        if current_round == 2:
            trend_ok = True
        if ema >= self.alpha and p_last >= self.alpha and trend_ok:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_100(BaseStrategy):
    """
    Defect by default, with cautious cooperation only after sustained near-universal
    opponent cooperation, and a lockout after sharp drops in cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = game_description.n_players
        self.n_rounds = game_description.n_rounds
        self.k = game_description.k
        self.forced_defect = False
        self.recovery_streak = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.n_players
        r = self.n_rounds
        round_number = history.round_number
        if round_number == 0:
            self.forced_defect = False
            self.recovery_streak = 0
            return Action.D
        opp = history.opponent_cooperators
        n_opponents = n - 1
        if round_number >= 2 and n_opponents > 0:
            last = int(opp[-1])
            prev = int(opp[-2])
            if prev - last >= 2:
                self.forced_defect = True
                self.recovery_streak = 0
            elif self.forced_defect:
                last_round_index = round_number - 1
                nonterminal_last = last_round_index < r - 2
                threshold = 1.0 if n == 2 else 0.85
                recent_rate = last / n_opponents if n_opponents > 0 else 0.0
                if nonterminal_last and recent_rate >= threshold:
                    self.recovery_streak += 1
                else:
                    self.recovery_streak = 0
                if self.recovery_streak >= 2:
                    self.forced_defect = False
                    self.recovery_streak = 0
        elif self.forced_defect and n_opponents > 0:
            last = int(opp[-1])
            last_round_index = round_number - 1
            nonterminal_last = last_round_index < r - 2
            threshold = 1.0 if n == 2 else 0.85
            recent_rate = last / n_opponents if n_opponents > 0 else 0.0
            if nonterminal_last and recent_rate >= threshold:
                self.recovery_streak += 1
            else:
                self.recovery_streak = 0
            if self.recovery_streak >= 2:
                self.forced_defect = False
                self.recovery_streak = 0
        if round_number >= max(0, r - 2):
            return Action.D
        if self.forced_defect:
            return Action.D
        threshold = 1.0 if n == 2 else 0.85
        if round_number == 1:
            x1 = int(opp[-1]) if len(opp) >= 1 else 0
            recent_rate = x1 / n_opponents if n_opponents > 0 else 0.0
            return Action.C if recent_rate >= threshold else Action.D
        x1 = int(opp[-1]) if len(opp) >= 1 else 0
        x2 = int(opp[-2]) if len(opp) >= 2 else 0
        recent_rate = x1 / n_opponents if n_opponents > 0 else 0.0
        stable_rate = (x1 + x2) / (2 * n_opponents) if n_opponents > 0 else 0.0
        if recent_rate >= threshold and stable_rate >= 0.8 and (x1 >= x2):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_101(BaseStrategy):
    """
    Conditional cooperation strategy for the repeated N-player Public Goods Game:
    defect by default, cooperate only after sustained high cooperation, and
    revert quickly to defection when cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.theta_high = 0.7
        self.theta_mid = 0.6
        self.delta = 0.15
        self.lock_short = 2
        self.lock_long = 3

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        m = max(n_players - 1, 1)
        t = history.round_number
        s_hist = np.asarray(history.opponent_cooperators, dtype=float) / float(m)

        def last_round_rule() -> Action:
            if t < 2:
                return Action.D
            s_prev = float(s_hist[-1])
            s_prev2 = float(s_hist[-2])
            trend_prev = s_prev - s_prev2
            if s_prev >= self.theta_high and s_prev2 >= self.theta_high and (trend_prev >= 0.0):
                return Action.C
            return Action.D
        defect_lock = 0
        for i in range(t):
            if i == 0:
                action_i = Action.D
            elif i == 1 and i != n_rounds - 1:
                action_i = Action.C if float(s_hist[0]) == 1.0 else Action.D
            elif i == n_rounds - 1:
                if i >= 2:
                    s_prev = float(s_hist[i - 1])
                    s_prev2 = float(s_hist[i - 2])
                    trend_prev = s_prev - s_prev2
                    action_i = Action.C if s_prev >= self.theta_high and s_prev2 >= self.theta_high and (trend_prev >= 0.0) else Action.D
                else:
                    action_i = Action.D
            elif defect_lock > 0:
                action_i = Action.D
                defect_lock -= 1
            elif i >= 2:
                avg_prev = float(np.mean(s_hist[:i])) if i > 0 else 0.0
                s_prev = float(s_hist[i - 1])
                s_prev2 = float(s_hist[i - 2])
                trend_prev = s_prev - s_prev2
                action_i = Action.C if avg_prev >= self.theta_high and s_prev >= self.theta_mid and (trend_prev >= -self.delta) else Action.D
            else:
                action_i = Action.D
            if i >= 0 and i < len(s_hist):
                s_i = float(s_hist[i])
                if defect_lock > 0 and s_i >= self.theta_high:
                    if i == 0:
                        trend_i = 0.0
                    else:
                        trend_i = s_i - float(s_hist[i - 1])
                    if trend_i > 0.0:
                        defect_lock = 0
                if action_i == Action.C and s_i < self.theta_mid:
                    defect_lock = max(defect_lock, self.lock_short)
                if i >= 1 and float(s_hist[i - 1]) < self.theta_mid and (s_i < self.theta_mid):
                    defect_lock = max(defect_lock, self.lock_long)
            if defect_lock > 0 and i < t - 1:
                defect_lock -= 1
        if t == 0:
            return Action.D
        if t == 1 and n_rounds != 2:
            return Action.C if float(s_hist[0]) == 1.0 else Action.D
        if t == n_rounds - 1:
            return last_round_rule()
        if defect_lock > 0:
            return Action.D
        if t >= 2:
            avg_prev = float(np.mean(s_hist[:t])) if t > 0 else 0.0
            s_prev = float(s_hist[t - 1])
            s_prev2 = float(s_hist[t - 2])
            trend_prev = s_prev - s_prev2
            if avg_prev >= self.theta_high and s_prev >= self.theta_mid and (trend_prev >= -self.delta):
                return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_102(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Probes cooperation early if the public good is potentially worthwhile.
    - Tracks opponent cooperation with exponential smoothing.
    - Cooperates only when cooperation appears high and stable.
    - Defects permanently after repeated low-cooperation signals.
    - Always defects in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n_players - 1)
        self.initial_q = 0.5

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number >= self.n_rounds - 1:
            return Action.D
        if round_number == 0:
            return Action.D if self.k <= 1.2 else Action.C
        prev_action = Action.C if bool(history.my_actions[-1]) else Action.D
        last_opponents = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        last_q_observed = last_opponents / self.n_opponents if self.n_opponents > 0 else 0.0
        if round_number >= 2 and len(history.opponent_cooperators) >= 2:
            prev_q_observed = int(history.opponent_cooperators[-2]) / self.n_opponents if self.n_opponents > 0 else 0.0
            if last_q_observed < 0.5 and prev_q_observed < 0.5:
                return Action.D
        if round_number == 1:
            q = last_q_observed
        else:
            q = self.initial_q
            for idx in range(round_number):
                q_obs = int(history.opponent_cooperators[idx]) / self.n_opponents if self.n_opponents > 0 else 0.0
                if idx == 0:
                    q = q_obs
                else:
                    q = 0.7 * q + 0.3 * q_obs
        if round_number == 1:
            return Action.C if q >= 0.8 else Action.D
        if round_number == self.n_rounds - 2:
            return Action.C if q >= 0.85 and last_q_observed >= 0.7 else Action.D
        if prev_action == Action.D and last_q_observed >= 0.9:
            if q >= 0.65:
                return Action.C
            return Action.D
        if q >= 0.75 and last_q_observed >= 0.6:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_103(BaseStrategy):
    """
    Adaptive threshold strategy for the N-player Public Goods Game.

    - Cooperates immediately when the threshold is trivial (T = 0).
    - Starts guarded in round 1.
    - Requires sustained recent cooperation from others to keep cooperating.
    - Defects in the final round unless cooperation has remained stable.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        k = float(game_description.k)
        if n <= 2:
            t = 1
        else:
            t = math.ceil(n / k) - 1 if k != 0 else n - 1
        if t < 0:
            t = 0
        if t > n - 1:
            t = n - 1
        self.threshold = int(t)
        self.n = n
        self.r = int(game_description.n_rounds)
        self.k = k

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        opp = history.opponent_cooperators
        if opp is None:
            return Action.D
        if round_number != len(opp):
            return Action.D
        if round_number < 0:
            return Action.D
        T = self.threshold
        n = self.n
        r = self.r
        if T == 0:
            return Action.C

        def compute_streak(values: NDArray[np.int_]) -> int:
            streak = 0
            for v in values[::-1]:
                if int(v) >= T:
                    streak += 1
                else:
                    break
            return streak
        if round_number == 0:
            return Action.C if T >= n - 2 else Action.D
        last_x = int(opp[-1]) if len(opp) > 0 else -1
        streak_prev = compute_streak(opp)
        if last_x < 0:
            return Action.D
        L = min(3, round_number)
        if L <= 0:
            m_t = -1.0
        else:
            recent = opp[-L:]
            if len(recent) != L:
                return Action.D
            m_t = float(np.mean(recent))
        if round_number == r - 1:
            if last_x >= T and m_t >= T and (streak_prev >= 2):
                return Action.C
            return Action.D
        if last_x >= T and m_t >= T:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_104(BaseStrategy):
    """
    Conservative conditional cooperator for the repeated N-player public goods game.

    Default to defection, cooperate only after sufficiently strong recent cooperation
    by others, and immediately revert to defection when cooperation appears to be
    declining or absent.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 2))
        k = float(getattr(game_description, 'k', 1.0))
        self.n_players = max(2, n)
        self.k = k
        if k > 0:
            self.threshold = int(math.ceil(self.n_players / k))
        else:
            self.threshold = self.n_players
        self.required_opponents = max(0, self.threshold - 1)
        self.total_rounds = int(getattr(game_description, 'n_rounds', 1))

    def _main_rule(self, history: PlayerHistory) -> Action:
        rn = history.round_number
        opp = history.opponent_cooperators
        if rn <= 0:
            return Action.D
        last = int(opp[-1])
        if last < self.required_opponents:
            return Action.D
        if rn >= 2:
            prev = int(opp[-2])
            if last < self.required_opponents and prev < self.required_opponents:
                return Action.D
            if last < self.required_opponents or prev < self.required_opponents:
                pass
        if rn >= 3:
            a = int(opp[-1])
            b = int(opp[-2])
            c = int(opp[-3])
            if a < b < c:
                return Action.D
        return Action.C

    def __call__(self, history: PlayerHistory) -> Action:
        rn = history.round_number
        next_round = rn + 1
        n = self.n_players
        opp = history.opponent_cooperators
        if rn == 0:
            return Action.D
        if next_round >= self.total_rounds:
            return Action.D
        if n == 2 or self.threshold == 1:
            return Action.C if int(opp[-1]) >= 1 else Action.D
        if next_round == self.total_rounds - 1:
            if rn < 2:
                return Action.D
            m_r2 = int(opp[-1])
            m_r3 = int(opp[-2]) if rn >= 2 else 0
            m_r4 = int(opp[-3]) if rn >= 3 else 0
            if m_r2 >= self.required_opponents and (m_r3 >= self.required_opponents or m_r4 >= self.required_opponents):
                return Action.C
            return Action.D
        return self._main_rule(history)

class Strategy_INDIVIDUALISTIC_105(BaseStrategy):
    """
    Self-protective conditional cooperator for the repeated N-player Public Goods Game.

    - Defaults to defection.
    - Cooperates only when recent cooperation is consistently high and stable.
    - Updates an internal smoothed cooperation estimate from observed opponent cooperation.
    - Resets cooperation state immediately when cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 0) or 0)
        k = float(getattr(game_description, 'k', 0.0) or 0.0)
        self.n_players = n
        self.k = k
        self.threshold = math.ceil(n / k - 1) if k > 0 else n
        self.smooth_coop = 0.0
        self.last_x = None
        self.last_last_x = None
        self.my_coop_streak = 0
        self.last_decision = Action.D
        self.tested_high_coop = False

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        n = self.n_players
        k = self.k
        T = self.threshold
        if t == 0:
            self.last_decision = Action.D
            return Action.D
        x_t = int(history.opponent_cooperators[-1])
        prev_s = self.smooth_coop
        self.smooth_coop = 0.7 * prev_s + 0.3 * x_t
        x_prev = self.last_x
        x_prev_prev = self.last_last_x
        if t >= int(getattr(self.game_description, 'n_rounds', t)):
            self.last_last_x = self.last_x
            self.last_x = x_t
            self.last_decision = Action.D
            return Action.D
        if T <= 0:
            cooperate = x_t == max(0, n - 1)
        elif T >= n - 1:
            cooperate = x_t == max(0, n - 1)
        else:
            threshold_ok = x_t >= T and self.smooth_coop >= T
            trend_ok = True
            if x_prev is not None:
                trend_ok = x_t >= x_prev
                if x_prev_prev is not None:
                    trend_ok = trend_ok and x_prev >= x_prev_prev
            test_ok = False
            if t in (1, 2) and self.last_decision == Action.D:
                if x_prev is not None and x_prev == max(0, n - 1):
                    test_ok = True
            cooperate = threshold_ok and trend_ok
            if not cooperate and test_ok and (x_t >= T):
                cooperate = True
                self.tested_high_coop = True
            if self.my_coop_streak > 0 and x_t < T:
                cooperate = False
                self.my_coop_streak = 0
        action = Action.C if cooperate else Action.D
        if action == Action.C:
            self.my_coop_streak += 1
        else:
            self.my_coop_streak = 0
        self.last_last_x = self.last_x
        self.last_x = x_t
        self.last_decision = action
        return action

class Strategy_INDIVIDUALISTIC_106(BaseStrategy):
    """
    Defect by default, but cooperate only in a stable, strongly cooperative environment.
    Starts with D, uses a short-run average and monotonicity check, and falls back to
    a two-round defection cooldown after cooperation collapses.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(getattr(game_description, 'n_players', 0) or 0)
        self.n_rounds = int(getattr(game_description, 'n_rounds', 0) or 0)
        self.opponent_count = max(0, self.n_players - 1)
        self.coop_threshold = 2.0 * self.opponent_count / 3.0
        self.round2_threshold = math.ceil(2.0 * self.opponent_count / 3.0)
        self.collapse_threshold = self.opponent_count / 2.0
        self._last_processed_round = 0
        self._cooldown = 0
        self._recovery_streak = 0
        self._in_recovery = False

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number < self._last_processed_round:
            self._last_processed_round = 0
            self._cooldown = 0
            self._recovery_streak = 0
            self._in_recovery = False
        while self._last_processed_round < round_number:
            idx = self._last_processed_round
            s_t = int(history.opponent_cooperators[idx]) if idx < len(history.opponent_cooperators) else 0
            if s_t >= self.coop_threshold:
                self._recovery_streak += 1
            else:
                self._recovery_streak = 0
            if s_t < self.collapse_threshold:
                self._cooldown = 2
                self._in_recovery = True
                self._recovery_streak = 0
            if self._cooldown > 0:
                self._cooldown -= 1
            self._last_processed_round += 1
        if round_number == 0:
            return Action.D
        if self._cooldown > 0:
            return Action.D
        if self._in_recovery and self._recovery_streak < 2:
            return Action.D
        if self._in_recovery and self._recovery_streak >= 2:
            self._in_recovery = False
        if round_number == 1:
            s1 = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) >= 1 else 0
            return Action.C if s1 >= self.round2_threshold else Action.D
        if round_number == self.n_rounds - 1:
            if len(history.opponent_cooperators) >= 3:
                s_a = int(history.opponent_cooperators[-1])
                s_b = int(history.opponent_cooperators[-2])
                s_c = int(history.opponent_cooperators[-3])
                if s_a >= self.coop_threshold and s_b >= self.coop_threshold and (s_c >= self.coop_threshold) and (s_a >= s_b >= s_c):
                    return Action.C
            return Action.D
        recent_len = min(3, round_number)
        if recent_len <= 0:
            return Action.D
        recent_vals = history.opponent_cooperators[-recent_len:]
        if len(recent_vals) == 0:
            return Action.D
        avg = float(np.mean(recent_vals))
        latest = int(recent_vals[-1])
        prev = int(recent_vals[-2]) if len(recent_vals) >= 2 else latest
        if avg >= self.coop_threshold and latest >= prev:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_107(BaseStrategy):
    """
    Default-defection strategy that only cooperates after sustained,
    near-unanimous cooperation and immediately reverts to defection
    when cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self._high_threshold = 0.8
        self._low_threshold = 0.5
        self._high_mode = 'High'
        self._probe_mode = 'Probe'
        self._low_mode = 'Low'

    def _q_from_count(self, count: int) -> float:
        denom = max(1, self.n_players - 1)
        return count / denom

    def _simulate_mode_history(self, history: PlayerHistory):
        """
        Reconstruct the mode that would apply to the current round, based on
        the observed past rounds only.
        """
        mode = self._low_mode
        opponent_counts = history.opponent_cooperators
        past_rounds = len(opponent_counts)
        for t in range(1, past_rounds + 1):
            q_prev = self._q_from_count(int(opponent_counts[t - 1]))
            q_prev2 = None
            if t - 2 >= 0:
                q_prev2 = self._q_from_count(int(opponent_counts[t - 2]))
            if t >= 2:
                drop = int(opponent_counts[t - 2]) - int(opponent_counts[t - 1])
                if drop >= 2:
                    mode = self._low_mode
            if t >= 2:
                if self._q_from_count(int(opponent_counts[t - 1])) == 1.0 and self._q_from_count(int(opponent_counts[t - 2])) == 1.0:
                    mode = self._high_mode
            if q_prev == 1.0:
                mode = self._high_mode
            elif q_prev >= self._high_threshold and q_prev2 is not None and (q_prev2 >= self._high_threshold):
                if mode != self._high_mode:
                    mode = self._probe_mode
            elif q_prev < self._low_threshold:
                mode = self._low_mode
        return mode

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0 or round_number == self.n_rounds - 1:
            return Action.D
        opponent_counts = history.opponent_cooperators
        prev_count = int(opponent_counts[-1]) if len(opponent_counts) > 0 else 0
        prev_q = self._q_from_count(prev_count)
        if round_number >= self.n_rounds - 2:
            mode_now = self._simulate_mode_history(history)
            previous_mode = self._simulate_mode_history(PlayerHistory(my_actions=history.my_actions[:-1], my_payoffs=history.my_payoffs[:-1], opponent_cooperators=history.opponent_cooperators[:-1])) if round_number > 1 else self._low_mode
            last_three_perfect = False
            if len(opponent_counts) >= 3:
                last_three_perfect = self._q_from_count(int(opponent_counts[-1])) == 1.0 and self._q_from_count(int(opponent_counts[-2])) == 1.0 and (self._q_from_count(int(opponent_counts[-3])) == 1.0)
            if previous_mode == self._high_mode and last_three_perfect and (mode_now == self._high_mode):
                return Action.C
            return Action.D
        mode = self._simulate_mode_history(history)
        if mode == self._high_mode:
            return Action.C
        if mode == self._probe_mode:
            if len(opponent_counts) >= 2:
                q_last = self._q_from_count(int(opponent_counts[-1]))
                q_prev = self._q_from_count(int(opponent_counts[-2]))
                if q_last >= self._high_threshold and q_prev >= self._high_threshold:
                    return Action.C
            return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_108(BaseStrategy):
    """
    Conditional cooperator that starts with defection, rewards sustained
    cooperation, withdraws when cooperation weakens, and always defects in
    the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 2))
        k = float(getattr(game_description, 'k', 1.0))
        raw_m = math.ceil((n_players - 1) / k) if k != 0 else n_players - 1
        raw_m = int(raw_m)
        self.m = max(1, min(n_players - 1, raw_m))

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = int(getattr(self.game_description, 'n_rounds', 1))
        t = int(getattr(history, 'round_number', 0))
        if n_rounds <= 1 or t == n_rounds - 1:
            return Action.D
        if t == 0:
            return Action.D
        opp = getattr(history, 'opponent_cooperators', None)
        if opp is None or len(opp) < t:
            return Action.D
        if t == 1:
            return Action.C if int(opp[0]) >= self.m else Action.D
        prev1 = int(opp[t - 1])
        prev2 = int(opp[t - 2])
        return Action.C if prev1 >= self.m and prev1 >= prev2 else Action.D

class Strategy_INDIVIDUALISTIC_109(BaseStrategy):
    """
    Defensive public-goods strategy:
    - Opens with defection.
    - Rewards only sustained, near-universal cooperation.
    - Uses a moving estimate of opponent cooperation.
    - Applies a short punishment after being exploited.
    - Defects near the end unless cooperation has been exceptionally reliable.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(self.n_players - 1, 1)
        self.last_processed_round = -1
        self.punishment_remaining = 0

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        n = self.n_players
        r = self.n_rounds
        opp_count = max(n - 1, 1)
        if t == 0:
            self.last_processed_round = -1
            self.punishment_remaining = 0
            return Action.D
        try:
            my_actions = history.my_actions
            opp_counts = history.opponent_cooperators
        except Exception:
            return Action.D

        def h_of(idx: int) -> float:
            if idx < 0 or idx >= len(opp_counts):
                return 0.0
            val = opp_counts[idx]
            try:
                return float(val) / float(opp_count)
            except Exception:
                return 0.0
        s_prev = 0.0
        for j in range(1, t):
            s_prev = 0.7 * s_prev + 0.3 * h_of(j - 1)
        s_t = s_prev
        punishment = 0
        for j in range(t):
            hj = h_of(j)
            if hj >= 0.75:
                punishment = 0
            else:
                try:
                    played_c = bool(my_actions[j])
                except Exception:
                    played_c = False
                if played_c and hj < 0.5:
                    punishment = 2
                elif punishment > 0:
                    punishment -= 1
        if t == r - 1:
            if t < 3:
                return Action.D
            if h_of(t - 1) >= 1.0 and h_of(t - 2) >= 1.0 and (h_of(t - 3) >= 1.0):
                return Action.C
            return Action.D
        if t >= r - 2:
            if t < 2:
                return Action.D
            if h_of(t - 1) >= 1.0 and h_of(t - 2) >= 1.0:
                if punishment > 0:
                    return Action.D
                return Action.C
            return Action.D
        if punishment > 0:
            return Action.D
        if t == 1:
            return Action.C if h_of(0) >= 1.0 else Action.D
        last = h_of(t - 1)
        prev = h_of(t - 2)
        if s_t >= 0.75 and last >= 0.75 and (last >= prev):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_110(BaseStrategy):
    """
    Conditional threshold strategy with:
    - initial defection
    - moving-average cooperation threshold
    - conservative 2-round retaliation after repeated low cooperation
    - immediate recovery after 2 consecutive high-cooperation rounds
    - final-round defection
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        opponents = max(0, self.n - 1)
        self.opponents = opponents
        self.low_count_threshold = int(math.ceil((self.n - self.k) / self.n * opponents)) if self.n > 0 else 0
        self.cooldown_until = -1
        self.eps = 1e-12

    def _last_m_rounds(self, history: PlayerHistory, m: int) -> NDArray[np.int_]:
        if m <= 0:
            return np.array([], dtype=np.int_)
        start = max(0, history.round_number - m)
        return history.opponent_cooperators[start:history.round_number]

    def _avg_rate(self, counts: NDArray[np.int_]) -> float:
        if counts.size == 0 or self.opponents <= 0:
            return 0.0
        return float(np.mean(counts)) / float(self.opponents)

    def _count_low_rounds_in_last_three(self, history: PlayerHistory) -> int:
        if history.round_number <= 0:
            return 0
        recent = history.opponent_cooperators[max(0, history.round_number - 3):history.round_number]
        if recent.size == 0:
            return 0
        return int(np.sum(recent < self.low_count_threshold))

    def _last_two_meet_threshold(self, history: PlayerHistory) -> bool:
        if history.round_number < 2:
            return False
        recent_two = history.opponent_cooperators[history.round_number - 2:history.round_number]
        return bool(np.all(recent_two >= self.low_count_threshold))

    def _tie_break_allows_cooperation(self, history: PlayerHistory, current_rate: float, threshold: float) -> bool:
        if abs(current_rate - threshold) > self.eps:
            return True
        if history.round_number == 0:
            return False
        prev_rate = 0.0
        prev_count = int(history.opponent_cooperators[history.round_number - 1])
        if self.opponents > 0:
            prev_rate = prev_count / float(self.opponents)
        return prev_rate + self.eps >= threshold

    def __call__(self, history: PlayerHistory) -> Action:
        t = int(history.round_number)
        if t == 0:
            return Action.D
        if self.r > 0 and t == self.r - 1:
            return Action.D
        coop_threshold_rate = (self.n - self.k) / self.n if self.n > 0 else 1.0
        half_threshold = 0.5
        m = min(3, t)
        recent_counts = self._last_m_rounds(history, m)
        moving_avg_rate = self._avg_rate(recent_counts)
        recent_all_half = True
        if recent_counts.size > 0:
            recent_rates = recent_counts / float(self.opponents) if self.opponents > 0 else np.zeros_like(recent_counts, dtype=np.float64)
            recent_all_half = bool(np.all(recent_rates >= half_threshold))
            if self.opponents > 0 and np.any(np.abs(recent_rates - half_threshold) <= self.eps):
                prev_ok = False
                if t >= 2:
                    prev_count = int(history.opponent_cooperators[t - 2])
                    prev_rate = prev_count / float(self.opponents)
                    prev_ok = prev_rate + self.eps >= half_threshold
                recent_all_half = recent_all_half and prev_ok
        if t < self.cooldown_until:
            if self._last_two_meet_threshold(history):
                self.cooldown_until = t
            else:
                return Action.D
        low_in_last_three = self._count_low_rounds_in_last_three(history)
        if low_in_last_three >= 2 and t >= self.cooldown_until:
            self.cooldown_until = t + 2
            return Action.D
        if self.r > 1 and t == self.r - 2:
            if self._last_two_meet_threshold(history) and moving_avg_rate + self.eps >= coop_threshold_rate:
                return Action.C
            return Action.D
        threshold_ok = moving_avg_rate + self.eps >= coop_threshold_rate
        if abs(moving_avg_rate - coop_threshold_rate) <= self.eps:
            threshold_ok = threshold_ok and self._tie_break_allows_cooperation(history, moving_avg_rate, coop_threshold_rate)
        if threshold_ok and recent_all_half:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_111(BaseStrategy):
    """
    Always defect in every round, regardless of history or observed behavior.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._defect_action = Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        return self._defect_action

class Strategy_INDIVIDUALISTIC_112(BaseStrategy):
    """
    Conservative conditional cooperator for repeated N-player public goods games.

    - Starts with defection.
    - Tracks recent opponent cooperation via an exponential moving average.
    - Cooperates only when cooperation is sufficiently widespread or sustained.
    - Avoids cooperating in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.n_opponents = max(0, self.n - 1)
        self.threshold = self.n / self.k - 1.0 if self.k != 0 else float('inf')
        self.threshold_ceil = math.ceil(self.threshold) if math.isfinite(self.threshold) else self.n_opponents

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        next_round = round_number + 1
        if round_number == 0:
            return Action.D
        if next_round >= self.r:
            return Action.D
        m_t = int(history.opponent_cooperators[-1]) if round_number > 0 else 0
        prev_m = int(history.opponent_cooperators[-2]) if round_number > 1 else m_t
        h = 0.0
        s = 0
        for m in history.opponent_cooperators:
            if self.n_opponents > 0:
                h = 0.7 * h + 0.3 * (float(m) / float(self.n_opponents))
            else:
                h = 0.0
            if m > 0:
                s += 1
            else:
                s = 0
        last_action = Action.C if bool(history.my_actions[-1]) else Action.D
        if s == 0 or h < 0.25:
            return Action.D
        rounds_remaining = self.r - next_round
        final_window = math.ceil(0.2 * self.r)
        in_final_20pct = rounds_remaining < final_window
        if in_final_20pct:
            if m_t >= self.threshold_ceil:
                return Action.C
            return Action.D
        if m_t >= self.n_opponents and self.n_opponents > 0:
            return Action.C
        action = Action.D
        if m_t > self.threshold:
            action = Action.C
        elif abs(m_t - self.threshold) <= 1e-12:
            action = last_action
        if last_action == Action.C and m_t <= prev_m:
            action = Action.D
        elif last_action == Action.D and m_t > prev_m:
            pass
        if s >= 2 and h >= 0.5:
            action = Action.C
        return action

class Strategy_INDIVIDUALISTIC_113(BaseStrategy):
    """
    Always defect in every round, ignoring all history and remaining rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = getattr(game_description, 'n_players', 0)
        self.n_rounds = getattr(game_description, 'n_rounds', 0)
        self.k = getattr(game_description, 'k', 0.0)

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_INDIVIDUALISTIC_114(BaseStrategy):
    """
    Defect initially, then cooperate only after repeated and stable evidence of
    strong opponent cooperation. Uses a cooldown period after poor cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(getattr(game_description, 'n_players', 2) or 2)
        k = float(getattr(game_description, 'k', 1.0) or 1.0)
        self.threshold = int(math.ceil(n / k)) if k != 0 else n
        self.cooldown = 0
        self._last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        r = int(getattr(self.game_description, 'n_rounds', 0) or 0)
        t = int(history.round_number)
        if r > 0 and t >= r - 1:
            return Action.D
        if t == 0:
            return Action.D
        start = self._last_processed_round
        end = t
        if start < end:
            for idx in range(start, end):
                o = int(history.opponent_cooperators[idx])
                if o == 0:
                    self.cooldown = 3
                elif o < self.threshold - 1:
                    self.cooldown = 2
            self._last_processed_round = end
        if self.cooldown > 0:
            self.cooldown -= 1
            return Action.D
        if t == 1:
            return Action.C if int(history.opponent_cooperators[-1]) >= self.threshold else Action.D
        o_t = int(history.opponent_cooperators[-1])
        o_prev = int(history.opponent_cooperators[-2])
        strong = o_t >= self.threshold and o_prev >= self.threshold
        stable = abs(o_t - o_prev) <= 1
        if strong and stable:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_115(BaseStrategy):
    """
    Adaptive public-goods strategy:
    - Defect initially and in the final round.
    - Estimate opponent cooperation with exponential smoothing.
    - Cooperate only when estimated cooperation is clearly above the threshold.
    - Switch quickly back to defection if cooperation weakens.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.alpha = 0.7
        self.margin = 0.1
        self.switch_drop = 0.2
        self.estimate = 0.5
        self.last_action = Action.D
        self.last_processed_round = 0
        self.force_cooperate_next = False
        self.force_defect_next = False

    def _threshold(self) -> float:
        n = self.game_description.n_players
        k = self.game_description.k
        if n <= 1 or k <= 0:
            return 1.0
        return (n / k - 1.0) / (n - 1.0)

    def _action_from_bool(self, b: bool) -> Action:
        return Action.C if b else Action.D

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        n_players = self.game_description.n_players
        current_round = history.round_number
        start = self.last_processed_round
        end = current_round
        if end > start:
            n_opponents = max(1, n_players - 1)
            for idx in range(start, end):
                s = float(history.opponent_cooperators[idx]) / float(n_opponents)
                prev_estimate = self.estimate
                self.estimate = self.alpha * self.estimate + (1.0 - self.alpha) * s
                my_action = self._action_from_bool(bool(history.my_actions[idx]))
                self.force_cooperate_next = False
                self.force_defect_next = False
                if my_action == Action.C and s <= prev_estimate - self.switch_drop:
                    self.force_defect_next = True
                elif my_action == Action.D:
                    thr = self._threshold()
                    if s >= thr + self.switch_drop:
                        self.force_cooperate_next = True
                self.last_action = my_action
            self.last_processed_round = end
        if current_round == 0:
            action = Action.D
        elif current_round >= n_rounds - 1:
            action = Action.D
        else:
            thr = self._threshold()
            if self.force_cooperate_next:
                action = Action.C
            elif self.force_defect_next:
                action = Action.D
            elif self.estimate >= thr + self.margin:
                action = Action.C
            elif self.estimate <= thr - self.margin:
                action = Action.D
            else:
                action = self.last_action
        self.last_action = action
        return action

class Strategy_INDIVIDUALISTIC_116(BaseStrategy):
    """
    Threshold-based public goods strategy with smoothing, cooldown punishment,
    opportunistic cooperation, and endgame defection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.s_est = 0.0
        self.prev_m = None
        self.cooldown = 0
        self.processed_rounds = 0

    def _update_state_from_history(self, history: PlayerHistory) -> None:
        """Advance internal state to match all completed rounds in history."""
        n_opponents = max(self.n - 1, 1)
        while self.processed_rounds < history.round_number:
            idx = self.processed_rounds
            m_t = int(history.opponent_cooperators[idx])
            self.s_est = 2.0 / 3.0 * self.s_est + 1.0 / 3.0 * (m_t / n_opponents)
            if m_t <= math.floor((self.n - 1) / 3):
                self.cooldown = 2
            self.prev_m = m_t
            self.processed_rounds += 1

    def __call__(self, history: PlayerHistory) -> Action:
        self._update_state_from_history(history)
        t = history.round_number
        if t == 0:
            return Action.D
        if t >= self.r - 1:
            return Action.D
        m_t = int(history.opponent_cooperators[-1])
        m_prev = int(history.opponent_cooperators[-2]) if t >= 2 else m_t
        trend_t = m_t - m_prev
        q = self.s_est
        if self.cooldown > 0:
            self.cooldown -= 1
            return Action.D
        if m_t <= math.floor((self.n - 1) / 3):
            self.cooldown = 2
            return Action.D
        if q >= 2.0 / 3.0 and trend_t < 0:
            return Action.D
        if q >= 2.0 / 3.0 and trend_t == 0 and (m_t >= math.ceil(2.0 * (self.n - 1) / 3.0)):
            return Action.C
        if q >= 0.5 and m_t >= math.ceil((self.n - 1) / 2.0) and (trend_t >= 0):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_117(BaseStrategy):
    """
    Unconditional defection strategy for the repeated public goods game.
    Always plays D, regardless of history or observed cooperation.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description

    def __call__(self, history: PlayerHistory) -> Action:
        return Action.D

class Strategy_INDIVIDUALISTIC_118(BaseStrategy):
    """
    Defect by default, and only switch to cooperation after two consecutive
    rounds of near-universal opponent cooperation (at least n-2 cooperators).
    After leaving cooperation, wait through a two-round cooldown before
    reconsidering. Always defect on the first and last rounds.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self._mode = 'DEFECT'
        self._cooldown = 0
        self._high_count = 0
        self._last_computed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n = self.game_description.n_players
        r = self.game_description.n_rounds
        t = history.round_number
        if t == 0 or t >= r - 1 or n <= 2:
            return Action.D
        mode = 'DEFECT'
        cooldown = 0
        high_count = 0

        def decide_action(round_index: int, current_mode: str, current_cooldown: int, current_high_count: int):
            if round_index > 0:
                x_prev = int(history.opponent_cooperators[round_index - 1])
                if x_prev >= n - 2:
                    current_high_count += 1
                else:
                    current_high_count = 0
            if round_index == r - 1:
                action = Action.D
            elif current_cooldown > 0:
                action = Action.D
                current_cooldown -= 1
            elif round_index > 1 and round_index < r and (current_mode == 'DEFECT') and (current_high_count >= 2):
                action = Action.C
            else:
                action = Action.D
            if action == Action.C:
                current_mode = 'COOPERATE'
            elif action == Action.D and current_mode == 'COOPERATE':
                current_mode = 'DEFECT'
                current_cooldown = 2
            return (action, current_mode, current_cooldown, current_high_count)
        for round_index in range(t):
            _, mode, cooldown, high_count = decide_action(round_index, mode, cooldown, high_count)
        action, mode, cooldown, high_count = decide_action(t, mode, cooldown, high_count)
        self._mode = mode
        self._cooldown = cooldown
        self._high_count = high_count
        self._last_computed_round = t
        return action

class Strategy_INDIVIDUALISTIC_119(BaseStrategy):
    """
    Public goods strategy with waiting, engaged, and disengaged states.
    Starts by defecting, then cooperates only after two consecutive qualifying
    rounds of opponent support, and immediately defects on the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n_players = int(getattr(game_description, 'n_players', 0))
        k = float(getattr(game_description, 'k', 0.0))
        raw_threshold = math.ceil((n_players - 1) / k) if k > 0 else n_players
        self.threshold = max(1, min(n_players - 1, int(raw_threshold)))
        self.final_round = max(0, int(getattr(game_description, 'n_rounds', 0)) - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        if round_number == 0:
            return Action.D
        if round_number >= self.final_round:
            return Action.D
        supports = history.opponent_cooperators
        if supports is None or len(supports) == 0:
            return Action.D
        engaged = False
        prev_support = None
        for t in range(round_number):
            support_t = int(supports[t])
            if engaged:
                if t >= 1:
                    support_prev = int(supports[t - 1])
                    avg_last_two = (support_prev + support_t) / 2.0
                    if support_t >= self.threshold and avg_last_two >= self.threshold:
                        engaged = True
                    else:
                        engaged = False
                else:
                    engaged = False
            elif prev_support is not None and prev_support >= self.threshold and (support_t >= self.threshold):
                engaged = True
            prev_support = support_t
        if not engaged:
            return Action.D
        if round_number < 2:
            return Action.D
        last_support = int(supports[round_number - 1])
        prev_support = int(supports[round_number - 2])
        avg_last_two = (last_support + prev_support) / 2.0
        if last_support >= self.threshold and avg_last_two >= self.threshold:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_120(BaseStrategy):
    """
    Threshold-based adaptive public goods strategy with aspiration tracking,
    cooperation estimation, and terminal defection protection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = int(history.round_number)
        n_opponents = max(self.n_players - 1, 1)
        if round_number == 0:
            return Action.C if self.k >= 1.5 else Action.D
        p = 0.5
        a = 1.0 + self.k / self.n_players
        streak = 0
        collapse = 0
        last_opponent_coop = 0
        last_my_payoff = 0.0
        for t in range(round_number):
            m_t = int(history.opponent_cooperators[t])
            x_t = m_t / n_opponents
            p = 0.7 * p + 0.3 * x_t
            if t < len(history.my_payoffs):
                last_my_payoff = float(history.my_payoffs[t])
            if last_my_payoff >= a:
                a = 0.9 * a + 0.1 * last_my_payoff
            else:
                a = 0.95 * a + 0.05 * last_my_payoff
            if x_t >= 0.5:
                streak += 1
            else:
                streak = 0
            if x_t <= 0.1:
                collapse += 1
            else:
                collapse = 0
            last_opponent_coop = m_t
        remaining_rounds = self.n_rounds - round_number
        if remaining_rounds == 1:
            if p >= 0.75 and last_opponent_coop >= n_opponents / 2.0:
                return Action.C
            return Action.D
        if collapse >= 2:
            return Action.D
        if streak >= 3 and p >= 0.6:
            return Action.C
        expected_coop_return_competitive = self.k * (p + 1.0 / n_opponents) >= 1.0
        recent_behavior_sufficient = p >= 0.45
        if expected_coop_return_competitive and recent_behavior_sufficient:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_121(BaseStrategy):
    """
    Defect by default, cooperate only after sustained high opponent cooperation,
    stop cooperating quickly after drops, and never cooperate on the last round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.recent_x_values = []
        self.cooldown_rounds = 0

    def _compute_trust(self, xs):
        if not xs:
            return 0.0
        weights = [0.5, 0.3, 0.2]
        values = xs[-3:][::-1]
        weighted_sum = 0.0
        weight_sum = 0.0
        for idx, x in enumerate(values):
            w = weights[idx]
            weighted_sum += w * float(x)
            weight_sum += w
        return weighted_sum / weight_sum if weight_sum > 0 else 0.0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = self.game_description.n_rounds
        round_number = history.round_number
        if round_number >= n_rounds - 1:
            return Action.D
        if round_number == 0:
            self.recent_x_values = []
            self.cooldown_rounds = 0
            return Action.D
        n_players = self.game_description.n_players
        n_opponents = max(1, n_players - 1)
        last_opp_coop = int(history.opponent_cooperators[-1])
        x = last_opp_coop / n_opponents
        self.recent_x_values.append(x)
        if len(self.recent_x_values) > 3:
            self.recent_x_values = self.recent_x_values[-3:]
        if round_number >= 2:
            prev_x = float(history.opponent_cooperators[-2]) / n_opponents
            if prev_x - x >= 1.0 / 3.0:
                self.cooldown_rounds = 0
                return Action.D
        trust = self._compute_trust(self.recent_x_values)
        base_cooperate = x >= 2.0 / 3.0 and trust >= 0.5
        if self.cooldown_rounds > 0:
            self.cooldown_rounds -= 1
            return Action.D
        if not base_cooperate:
            if round_number >= 2:
                prev_x = float(history.opponent_cooperators[-2]) / n_opponents
                if x - prev_x >= 1.0 / 3.0:
                    self.cooldown_rounds = 1
            return Action.D
        return Action.C

class Strategy_INDIVIDUALISTIC_122(BaseStrategy):
    """
    Conservative public-goods strategy:
    - Start by cooperating.
    - Continue cooperating only when recent opponent cooperation is stable
      and sufficiently high.
    - Default to defection in weak, unstable, or declining environments.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = int(game_description.n_players)
        self.target = math.ceil((n - 1) / 2)
        self.high = math.ceil(2 * (n - 1) / 3)
        self.low = math.floor((n - 1) / 3)
        if n == 2:
            self.target = 1
            self.high = 1
            self.low = 0
        self.n_rounds = int(game_description.n_rounds)

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        if t == 0:
            return Action.C
        if t >= self.n_rounds - 1:
            return Action.D
        s_arr = history.opponent_cooperators
        s_last = int(s_arr[-1])
        window = s_arr[max(0, t - 3):t]
        m = float(np.mean(window)) if len(window) > 0 else 0.0
        if t >= 2:
            prev = int(s_arr[-2])
            if s_last > prev:
                trend = 'rising'
            elif s_last < prev:
                trend = 'falling'
            else:
                trend = 'flat'
        else:
            trend = 'flat'
        if t >= 2 and int(s_arr[-1]) <= self.low and (int(s_arr[-2]) <= self.low):
            return Action.D
        if t >= 2 and int(s_arr[-1]) >= self.high and (int(s_arr[-2]) >= self.high):
            return Action.C
        if len(s_arr) >= 1 and int(s_arr[0]) == 0:
            if not (t >= 2 and int(s_arr[-1]) >= self.target and (int(s_arr[-2]) >= self.target)):
                return Action.D
        if len(s_arr) >= 4:
            last4 = s_arr[-4:]
            classified = []
            for x in last4:
                xi = int(x)
                if xi <= self.low:
                    classified.append('low')
                elif xi >= self.high:
                    classified.append('high')
                else:
                    classified.append('mid')
            if classified[0] != 'mid' and classified[1] != 'mid' and (classified[2] != 'mid') and (classified[3] != 'mid'):
                if classified[0] != classified[1] and classified[0] == classified[2] and (classified[1] == classified[3]):
                    return Action.D
        if s_last >= self.target and m >= self.target and (trend != 'falling'):
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_123(BaseStrategy):
    """
    Threshold-based conditional cooperator:
    - Defect in round 1.
    - Cooperate in intermediate rounds only if the most recent observed number of cooperating opponents
      meets the threshold ceil(n / k).
    - In the final round, cooperate only after two consecutive threshold-meeting observations.
    - Otherwise defect.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = getattr(game_description, 'n_players', 0)
        k = getattr(game_description, 'k', 0.0)
        if k is None or k <= 0:
            self.threshold = math.inf
        else:
            self.threshold = math.ceil(n / k)
        self.always_defect = bool(self.threshold > n - 1)

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        if round_number == 0:
            return Action.D
        if self.always_defect:
            return Action.D
        last_count = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        meets_threshold = last_count >= self.threshold
        if round_number == n_rounds - 1:
            if n_rounds == 2:
                return Action.D
            if len(history.opponent_cooperators) >= 2:
                prev_count = int(history.opponent_cooperators[-2])
                if meets_threshold and prev_count >= self.threshold:
                    return Action.C
            return Action.D
        return Action.C if meets_threshold else Action.D

class Strategy_INDIVIDUALISTIC_124(BaseStrategy):
    """
    Guarded adaptive threshold strategy for the repeated n-player public goods game.

    - Starts with defection.
    - Requires sustained high cooperation by opponents before cooperating.
    - Defects immediately after meaningful drops in observed cooperation.
    - Tightens behavior near the end of the game.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = max(2, int(game_description.n_players))
        r = max(1, int(game_description.n_rounds))
        self.n = n
        self.r = r
        if n == 2:
            self.t_high = 1
            self.t_mid = 1
        else:
            self.t_high = int(math.ceil(0.75 * (n - 1)))
            self.t_mid = int(math.ceil(0.5 * (n - 1)))

    def __call__(self, history: PlayerHistory) -> Action:
        t = history.round_number
        r = self.r
        n = self.n
        if t == 0:
            return Action.D
        opp = history.opponent_cooperators
        last1 = int(opp[-1]) if len(opp) >= 1 else 0
        last2 = int(opp[-2]) if len(opp) >= 2 else 0
        last3 = int(opp[-3]) if len(opp) >= 3 else 0
        if r == 2:
            if t == 1 and last1 >= 1:
                return Action.C
            return Action.D
        if r == 3 and t == 2:
            if last1 >= self.t_mid and last2 >= self.t_mid:
                return Action.C
            return Action.D
        if t == r - 1:
            if last1 >= self.t_mid and last2 >= self.t_mid:
                return Action.C
            return Action.D
        if t == r - 2:
            if last1 >= self.t_high and last2 >= self.t_high:
                return Action.C
            return Action.D
        if t >= 2:
            if last1 == n - 1 and last2 == n - 1:
                return Action.C
            if last1 >= self.t_high and last2 >= self.t_high:
                return Action.C
            if last1 >= self.t_mid and last2 >= self.t_mid and (t >= 2):
                return Action.C
            if last1 < self.t_mid or last2 < self.t_mid or last3 < self.t_mid:
                return Action.D
        return Action.D

class Strategy_INDIVIDUALISTIC_125(BaseStrategy):
    """
    Adaptive public-goods strategy with a moving cooperation target,
    patience tracking, and stricter late-game defection protection.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n = int(game_description.n_players)
        self.r = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.initial_target = 0.5
        self.success_target_step = 0.1
        self.failure_target_step = 0.15
        self.max_patience = 2

    def _success_threshold(self, opponent_count: int) -> float:
        denom = self.n - 1
        if denom <= 0:
            return 1.0
        return opponent_count / denom

    def _is_immediately_defensible(self, opponent_count: int) -> bool:
        if self.n <= 0:
            return False
        return self.k * (opponent_count + 1) / self.n >= 1.0

    def __call__(self, history: PlayerHistory) -> Action:
        round_number = history.round_number
        if round_number == 0:
            return Action.C if self.k > 2.0 else Action.D
        target = self.initial_target
        patience = 0
        for t in range(1, round_number):
            m_prev = int(history.opponent_cooperators[t - 1]) if t - 1 < len(history.opponent_cooperators) else 0
            q_prev = self._success_threshold(m_prev)
            success = q_prev >= target
            if success:
                target = min(1.0, target + self.success_target_step)
                patience = 0
            else:
                target = max(0.0, target - self.failure_target_step)
                patience += 1
        m_last = int(history.opponent_cooperators[-1]) if len(history.opponent_cooperators) > 0 else 0
        q_last = self._success_threshold(m_last)
        previous_success = q_last >= target
        current_patience = 0 if previous_success else patience + 1
        immediate_ok = self._is_immediately_defensible(m_last)
        current_round_index = round_number
        if current_round_index >= self.r - 2:
            if q_last >= 0.75 and immediate_ok:
                return Action.C
            return Action.D
        if previous_success and current_patience <= self.max_patience and immediate_ok:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_126(BaseStrategy):
    """
    Defect by default, and only cooperate after three consecutive rounds in
    which all opponents cooperated. Always defect in the first and final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.full_streak = 0
        self.last_computed_round = -1

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = getattr(self.game_description, 'n_rounds', 0) or 0
        n_players = getattr(self.game_description, 'n_players', 0) or 0
        n_opponents = max(0, n_players - 1)
        round_number = history.round_number
        if round_number == 0:
            self.full_streak = 0
            self.last_computed_round = 0
            return Action.D
        full_streak = 0
        opp = history.opponent_cooperators
        if len(opp) > 0:
            idx = len(opp) - 1
            while idx >= 0 and opp[idx] == n_opponents:
                full_streak += 1
                idx -= 1
        self.full_streak = full_streak
        self.last_computed_round = round_number
        if n_rounds > 0 and round_number >= n_rounds - 1:
            return Action.D
        if self.full_streak >= 3:
            return Action.C
        return Action.D

class Strategy_INDIVIDUALISTIC_127(BaseStrategy):
    """
    Threshold-based public-goods strategy with two states:
    - probation: default self-protection
    - cooperate-mode: cooperate only after sustained evidence of sufficient cooperation
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        n = getattr(game_description, 'n_players', 0)
        k = getattr(game_description, 'k', 1.0)
        if k > 0:
            threshold = math.ceil((n - 1) * (1 - 1 / k))
        else:
            threshold = n
        self.threshold = max(0, int(threshold))
        self.mode = 'probation'
        self.last_processed_round = 0

    def __call__(self, history: PlayerHistory) -> Action:
        n_rounds = getattr(self.game_description, 'n_rounds', 0)
        r = history.round_number
        if r <= 0:
            self.mode = 'probation'
            self.last_processed_round = 0
            return Action.D
        if n_rounds == 2:
            self.mode = 'probation'
            self.last_processed_round = r
            return Action.D
        opp = history.opponent_cooperators
        mode = 'probation'
        for idx in range(r):
            if idx == 0:
                played = Action.D
            elif idx == n_rounds - 1:
                played = Action.D
            elif mode == 'cooperate-mode':
                played = Action.C if opp[idx - 1] >= self.threshold else Action.D
            elif idx >= 2 and opp[idx - 1] >= self.threshold and (opp[idx - 2] >= self.threshold):
                played = Action.C
            else:
                played = Action.D
            current_obs = opp[idx]
            if current_obs < self.threshold:
                mode = 'probation'
            elif mode == 'cooperate-mode':
                mode = 'cooperate-mode'
            elif played == Action.C and idx >= 1 and (opp[idx - 1] >= self.threshold):
                mode = 'cooperate-mode'
            else:
                mode = 'probation'
        if r == n_rounds - 1:
            action = Action.D
        elif mode == 'cooperate-mode':
            action = Action.C if opp[r - 1] >= self.threshold else Action.D
        elif r >= 2 and opp[r - 1] >= self.threshold and (opp[r - 2] >= self.threshold):
            action = Action.C
        else:
            action = Action.D
        self.mode = 'cooperate-mode' if action == Action.C and r >= 1 and (opp[r - 1] >= self.threshold) and (r < n_rounds - 1) else 'probation'
        if r == n_rounds - 1:
            self.mode = 'probation'
        self.last_processed_round = r + 1
        return action

class Strategy_INDIVIDUALISTIC_128(BaseStrategy):
    """
    CLOSED by default. Opens only after sustained high cooperation, closes immediately
    on weak cooperation, and never cooperates in the final round.
    """

    def __init__(self, game_description: PublicGoodsDescription):
        self.game_description = game_description
        self.n_players = int(game_description.n_players)
        self.n_rounds = int(game_description.n_rounds)
        self.k = float(game_description.k)
        self.high_threshold = 3.0 / 4.0
        self.low_threshold = 1.0 / 2.0

    def _cooperation_fraction(self, coop_count: int) -> float:
        n_opponents = max(1, self.n_players - 1)
        return float(coop_count) / float(n_opponents)

    def _streaks_from_history(self, history: PlayerHistory) -> tuple[int, int]:
        high_streak = 0
        low_streak = 0
        rounds_observed = history.round_number
        if rounds_observed <= 0:
            return (high_streak, low_streak)
        for idx in range(rounds_observed):
            a_t = self._cooperation_fraction(int(history.opponent_cooperators[idx]))
            if a_t >= self.high_threshold:
                high_streak += 1
                low_streak = 0
            elif a_t <= self.low_threshold:
                low_streak += 1
                high_streak = 0
            else:
                high_streak = 0
                low_streak = 0
        return (high_streak, low_streak)

    def __call__(self, history: PlayerHistory) -> Action:
        current_round_zero_based = int(history.round_number)
        current_round_one_based = current_round_zero_based + 1
        if current_round_zero_based == 0:
            return Action.D
        if current_round_one_based == self.n_rounds:
            return Action.D
        high_streak, low_streak = self._streaks_from_history(history)
        if high_streak >= 2:
            return Action.C
        if low_streak >= 1:
            return Action.D
        if current_round_one_based % 2 == 0 and history.round_number >= 2:
            last_two = history.opponent_cooperators[-2:]
            if len(last_two) == 2:
                frac_1 = self._cooperation_fraction(int(last_two[0]))
                frac_2 = self._cooperation_fraction(int(last_two[1]))
                if self.low_threshold <= frac_1 < self.high_threshold and self.low_threshold <= frac_2 < self.high_threshold:
                    return Action.C
        return Action.D